INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0101113F_670008$$, $$0101113F$$, $$670008$$, $$Resilient Operation Capability$$, 16450000, $$In response to urgent warfighter needs, the Command, Control and Communications Battle Management (C3BM) Resilient Operational Capability Suite (ROCS) program connects B-52 to the Department of the Air Force (DAF) Battle Management Network (BMN) to bring resilient and reliable Beyond Line-Of-Sight (BLOS) capability and an open computing environment. The program will install a rack on the B-52 aircraft with components needed to connect B-52 to the BMN system of systems enabling robust connectivity and data dissemination. The open computing environment will allow faster integration of other capabilities to meet mission requirements such as M-code compliant Global Positioning System (GPS), Digital High Frequency (HF) (ARC-260), Directional Line-Of-Sight waveforms, SATURN enhanced data rate (SEDR) waveforms and Alternate Position, Navigation, and Timing (PNT). Costs include, but are not limited to, any analysis, documentation, and related expenses necessary to establish a program of record and support the B-52 weapon system. Additionally, other costs include Program Management Administration (PMA) and centralized support and initiatives for anticipated weapon system enhancements (to include efforts to improve weapon system operational capabilities, safety, supportability, maintainability, reliability, and total cost of ownership). Funds may be used to address requirements including, but not limited to, emerging and short-notice Diminishing Manufacturing Sources and Material Shortages (DMSMS) for aircraft and associated training systems, Development Testing (DT), and safety of flight issues. Additionally, funds may accommodate PMA and support, civilian pay expenses, rapid technology insertion, and fulfill Federal Aviation Agency (FAA) or other mandates necessary to ensure continued aircrew safety and mission effectiveness. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24 $0.0M was expended for civilian pay expenses in this program element, and in FY25 $0.0M is forecasted for civilian pay expenses in this program element.$$, 16450000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0101113F_670011$$, $$0101113F$$, $$670011$$, $$ARC-260$$, 6301000, $$The B-52 ARC-260 program replaces a legacy HF radio with a modernized radio to ensure Beyond Line of Sight (BLOS) communications in a satellite denied environment. The ARC-190 legacy radio is reaching obsolescence with an estimated End of Life (EOL) in 2029. The scope of the work includes, but is not limited to, the replacement of the existing ARC-190 system with an ARC-260 Remote Control Unit (RCU) and Receiver/Transmitter (R/T). The current program intent is to reuse the existing HF antenna/coupler and reuse Group A items to the maximum extent. The ARC-260 will be integrated into the B-52 platform to improve HF voice communications and take full advantage of the HF Automatic Link Establishment (ALE) capabilities. The ARC-260 radio integration on the B-52 aircraft is essential to maintaining BLOS communications and improving mission capabilities well into the future. Funds may be used to address requirements including, but not limited to, emerging and short-notice Diminishing Manufacturing Sources and Material Shortages (DMSMS) for both aircraft and associated training systems, Development Testing (DT)/ Operational Testing (OT), and safety of flight issues. Additionally, funds may accommodate Program Management Administration (PMA) and support, civilian pay expenses, rapid technology insertion, and fulfill Federal Aviation Agency (FAA) or other mandates necessary to ensure continued aircrew safety and mission effectiveness. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24 0M was expended for civilian pay expenses in this program element, and in FY25 0M is forecasted for civilian pay expenses in this program element.$$, 6301000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0101113F_670132$$, $$0101113F$$, $$670132$$, $$B-52 Mission Employment Trainer$$, 20039000, $$The B-52 Mission Employment Trainer (MET) program is for the development of the B-52 Family of Systems (FoS) Trainers. The FoS Trainers includes, but is not limited to, new training devices and Systems Integration Labs (SIL) that will augment and eventually replace the existing B-52 legacy training systems and SIL that are antiquated, not concurrent with the B-52 aircraft, and cost-prohibitive for modernization or sustainment. The current B-52 trainers are non-concurrent and only account for 17% of training on the Training Task Lists specified in various course syllabi. In conjunction with the AFGSC A3/6 signed Future Training Concept, this new FoS approach will train Air Force personnel utilizing low, medium, and high-fidelity training devices. These training devices will leverage a common software architecture, include modularity and open mission systems, be rapidly reprogrammable and network capable, enable accelerated future upgrades, and support affordable sustainment. This FoS concept fulfills the future training needs of the formal training unit (FTU), combat units, and weapons school students spanning the continuum of learning. These new devices/trainers are of paramount importance because of their critical role to future B-52 combat capabilities that must advance through 2050. Funds will be used to develop B-52 training devices that will provide an interactive and immersive environment to provide proficiency-based and initial qualification training for full-crew mission training and coordination, and related programmatic support. The MET FoS will reuse a virtualized version of the aircraft's Operational Flight Programs (OFP) and will execute on commercial-grade, off-the-shelf computational hardware. The virtualized OFP software will be developed to run on multiple training devices of varying physical fidelity. The MET devices will be rapidly reconfigurable to different aircraft configurations, and the non-motion simulator will be capable of worldwide deployment. From initial development, the open architecture lays the groundwork for a roadmap to aircraft concurrency, upgradability, and feature sets that can be added in a cost-effective manner, keeping pace with the speed of technology and future B-52 aircraft upgrades. Funds may be used to address requirements including, but not limited to, emerging and short-notice Diminishing Manufacturing Sources and Material Shortages (DMSMS) for training systems, Development Testing (DT)/ Operational Testing (OT), and safety of flight issues. Additionally, funds may accommodate Program Management Administration (PMA) and support, civilian pay expenses, rapid technology insertion, and fulfill Federal Aviation Agency (FAA) or other mandates necessary to ensure continued aircrew safety and mission effectiveness. Funds may be used to purchase long-lead items following completion of Preliminary Design Review (PDR). As MET Integration provides future communication growth to the B-52, emerging security/certification requirements (nuclear certification, cyber security, program protection, crypto modernization, etc.) as well as other aircraft upgrades may require studies and/or support for potential impact to MET. Funds may be used to conduct development and test activities.$$, 20039000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0101113F_671803$$, $$0101113F$$, $$671803$$, $$B-52 AFMC Test Assets$$, 1509000, $$The B-52 AFMC Test Assets project will provide funding for the test aircraft, manpower, and facilities at the Air Force Test Center located at Edwards AFB, California. The project will support the development testing and Bomber Modular Data Acquisition System (BMDAS) integration on B-52 test aircraft. The project can support Programmed Depot Maintenance (PDM) costs supporting test aircraft modifications occurring at Tinker AFB, OK. Costs include, but are not limited to, any analysis, documentation, and related expenses necessary to establish a program of record and support the B-52 weapon system. Additionally, other costs include Program Management Administration (PMA) and centralized support and initiatives for anticipated weapon system enhancements (to include efforts to improve weapon system operational capabilities, safety, supportability, maintainability, reliability, and total cost of ownership). Funds may be used to address requirements including, but not limited to, emerging and short notice Diminishing Manufacturing Sources and Material Shortages (DMSMS) for both aircraft and associated training systems, Development Testing (DT), and safety of flight issues. Additionally, funds may accommodate PMA and support, civilian pay expenses, rapid technology insertion, and fulfill Federal Aviation Agency (FAA) or other mandates necessary to ensure continued aircrew safety and mission effectiveness. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $0M was expended for civilian pay expenses in this program element, and in FY 2025 $0M is forecast for civilian pay expenses in this program element.$$, 1509000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0101113F_671810$$, $$0101113F$$, $$671810$$, $$B-52 AEHF Integration$$, 18324000, $$The B-52 Advanced Extremely High Frequency (AEHF) Integration satellite communications (SATCOM) system provides a survivable, low probability of intercept/ detection, high bandwidth system that ensures secure intra/inter-flight and two-way command and control communications in the modern anti-access/aerial denial battle space. This communications upgrade replaces the Military Strategic and Tactical Relay (MILSTAR) Ultra High Frequency (UHF) SATCOM capability (MILSTAR is nearing system end of life) on the B-52. The AEHF Integration effort will integrate the Family of Advanced Beyond Line-of-Sight Terminals (FAB-T) Force Element Terminal (FET) onto the B-52 to provide two-way satellite communication for the B-52. Funds may be used to address requirements including, but not limited to, emerging and short-notice Diminishing Manufacturing Sources and Material Shortages (DMSMS) for both aircraft and associated training systems, Development Testing (DT)/ Operational Testing (OT), and safety of flight issues. Additionally, funds may accommodate Program Management Administration (PMA) and support, civilian pay expenses, rapid technology insertion, and fulfill Federal Aviation Agency (FAA) or other mandates necessary to ensure continued aircrew safety and mission effectiveness. As AEHF Integration provides future communication growth to the B-52, emerging security/certification requirements (nuclear certification, cyber security, program protection, crypto modernization, etc.) as well as other aircraft upgrades may require studies and/or support for potential impact to AEHF. Funds will be used to conduct development and test activities. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $2.147M was expended for civilian pay expenses in this program element, and in FY 2025 $2.983M is forecast for civilian pay expenses in this program element.$$, 18324000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601153N_1393$$, $$0601153N$$, $$1393$$, $$Kinetic Weapons$$, 0, $$The Kinetic Weapons activity develops technologies to address the Navy and Marine Corps fires requirements for extended range, increased precision, decreased weapons fly-out times, greater destructive power, novel weapons effects, autonomy, human-machine teaming, reduced weapons costs, mission planning, and mass- producible swarming munitions.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603570N_2370$$, $$0603570N$$, $$2370$$, $$Next Generation Fast Attack Nuclear$$, 256801000, $$The details of this program element are classified CONFIDENTIAL and are submitted annually to Congress in the classified budget justification books.$$, 256801000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0101113F_675039$$, $$0101113F$$, $$675039$$, $$B-52 System Improvements$$, 16450000, $$B-52 System Improvements is a comprehensive project to facilitate future capabilities and ensure the B-52's viability in performing current and future wartime missions. The scope of work may include, but not limited to, the development of an Analysis of Alternative (AoA), studies and analyses, a Capability Development Document (CDD), and/or any other analyses or documentation necessary to establish a Program of Record (POR). Additionally, this project may include airborne integration experiments or demonstrations of emerging technologies. Support of the platform integration efforts are necessary to identify and resolve challenges associated with integrating multiple programs and activities planned for the B-52 fleet. Costs include any analysis, documentation, and related expenses necessary to establish a POR and support the B-52 weapon system. Additionally, other costs include, but are not limited to Program Management Administration (PMA), civilian pay expenses, rapid technology insertion, centralized support and initiatives for anticipated weapon system enhancements (to include efforts to improve weapon system operational capabilities, safety, supportability, maintainability, reliability, and total cost of ownership), emerging and short-notice Diminishing Manufacturing Sources and Material Shortages (DMSMS) for both aircraft and associated training systems, Development Testing (DT)/ Operational Testing (OT), safety of flight issues and to fulfill Federal Aviation Agency (FAA) or other mandates necessary to ensure continued aircrew safety and mission effectiveness. Systems Improvement is permitted to fund software development, test, and modernization efforts, updates to Operational Flight Programs (OFPs), and software merges to integrate and operationally implement new capabilities on the B-52. These capabilities include hardware and software updates in the areas of communications, avionics, advanced weapons and targeting pods. Updates to System Integration Laboratories (SILs) are required to integrate software into the various hardware, validate user requirements, and review system safety and security prior to release to flight test. The labs require continual upgrades to increase development and test efficiencies and to remain in compliance with all security and cyber requirements. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $0M was expended for civilian pay expenses in this program element, and in FY 2025 $0M is forecast for civilian pay expenses in this program element.$$, 16450000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0101113F_675056$$, $$0101113F$$, $$675056$$, $$B-52 Radar Modernization$$, 163169000, $$The B-52 Radar Modernization Program (RMP) supports nuclear and conventional operations by replacing the current APQ-166 radar on the B-52 aircraft with the AN/ APQ-188 radar. The APQ-166 system is increasingly difficult to sustain due to Diminishing Manufacturing Sources, obsolescent technologies, and the current failure rate places long-duration missions at risk. This modernization program will encompass the radar antenna array, 12 individual Line Replaceable Units (LRU), radar control panel, and Group A allocation that comprise the entire radar system. RMP will take advantage of advances in technology and on-going development efforts to acquire, to the maximum extent possible, previously developed radar systems and integrate them into the B-52. The use of new technology will increase both the overall reliability of the radar system and the capabilities for new missions. RMP will allow the operational command (AF Global Strike Command) to fully utilize the capabilities of the B-52 aircraft to employ an array of nuclear and conventional weapons and perform mission-essential navigation and weather avoidance functions. AF Global Strike Command approved the removal of the radome from the baseline program for considerations of cost control and satisfactory legacy radome performance. In addition, applicable training devices for the new radar subsystem must also be developed, modified and/or upgraded in conjunction with the aircraft modifications. This modification includes the installation of Engineering and Manufacturing Development (EMD) kits on two B-52 test aircraft to support Developmental/Operational Test and Evaluation (DT/OT). This program upgrades one B-52 Software Integration Lab (SIL) with radar functionality and builds a new Radar Development Lab and a new Radar SIL. Additionally, this program will develop a desktop training tool. As the RMP upgrade brings additional capability to the B-52, funds may be used to address emerging security/ certification requirements (nuclear certification, cyber security, program protection, simulator common standards, etc.) in addition to increased radar integration (advanced targeting pod, Communication Technology (CONECT), Tactical Data Link (TDL), offensive avionics system, Crypto modernization, mission planning, Modular Open System Architecture (MOSA) considerations, crew vehicle interfaces, B-52 Software Block (BSB), etc.) Funds may be used to address requirements including, but not limited to, emerging and short-notice Diminishing Manufacturing Sources and Material Shortages (DMSMS) for both aircraft and associated training systems, DT/OT, safety of flight issues, and associated components in the RMP configuration baseline. DMSMS efforts may include removal of end-of-life/obsolete software/hardware within the weapons system, simulators systems, and MOSA implementation. Additionally, funds may accommodate Program Management Administration (PMA) and support, civilian pay expenses, rapid technology insertion, and fulfill Federal Aviation Agency (FAA) or other mandates necessary to ensure continued aircrew safety and mission effectiveness. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $5.911M was expended for civilian pay expenses in this program element, and in FY 2025 $4.924M is forecast for civilian pay expenses in this program element.$$, 163169000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0101113F_675129$$, $$0101113F$$, $$675129$$, $$B-52 CERP$$, 595650000, $$The B-52J Commercial Engine Replacement Program (CERP) supports nuclear and conventional operations by replacing the current TF33-PW-103 engine on the B-52H aircraft. The TF33-PW-103 engine is experiencing significant supportability challenges due to diminished manufacturing sources and obsolescent technologies. This program will replace the current TF33-PW-103 engine with new military derivative commercial Rolls-Royce F130 engines of similar size, weight, and thrust characteristics. Along with the new engines, CERP will replace associated subsystems, such as engine struts and nacelles, the electrical power generation system, and cockpit displays. The development, production and installation of new engines and related subsystems will replace the legacy equipment on all 76 B-52H aircraft. Any B-52H aircraft modified with the new commercial engines and associated subsystems will be designated as B-52J. B-52J CERP is taking advantage of advances in technology and on-going development efforts to acquire engines and integrate them into the B-52. The new technology will increase both the overall reliability and maintainability of the propulsion system and produce additional electrical power generation capabilities for emerging requirements. The B-52J CERP will allow the operational command (Air Force Global Strike Command) to fully utilize the capabilities of the B-52 aircraft to employ an array of nuclear and conventional weapons while increasing fuel efficiency and extending the range/loiter capabilities of the aircraft. In addition, applicable training devices must be developed, modified and/or upgraded in conjunction with the aircraft modifications. As B-52J CERP brings additional capability to the B-52, emerging security/certification requirements (nuclear hardening, cyber security, program protection, etc.) are being addressed. Several concurrent aircraft upgrades during the B-52J CERP necessitate temporary facilities or facility upgrades/modifications. In addition, the upgrades may necessitate studies be performed to determine optimal engine installation and deployment options. Additionally, funds will be used to procure long lead material and installation for test aircraft to include engines and all required associated components in the B-52J CERP configuration baseline (i.e. RMP A & B EMD kits). Cost includes any other analysis or documentation and related expenses necessary to establish a program of record and support the B-52 Weapon System. Cost includes Program Management Administration (PMA) costs, centralized support, and initiatives for digital engineering and anticipated weapon system enhancements, to include efforts to improve weapon system operational capabilities, safety, supportability, maintainability, reliability, and total cost of ownership. Funds may be used to address requirements including, but not limited to, emerging and short-notice Diminishing Manufacturing Sources and Material Shortages (DMSMS) for both aircraft and associated training systems, Development Testing (DT)/Operational Testing (OT), and safety of flight issues. Additionally, funds may accommodate PMA and support, civilian pay expenses, rapid technology insertion, and fulfill Federal Aviation Administration (FAA) or other mandates necessary to ensure continued aircrew safety and mission effectiveness. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $13.394M was expended for civilian pay expenses in this program element, and in FY 2025 $16.276M is forecasted for civilian pay expenses in this program element.$$, 595650000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0101113F_675160$$, $$0101113F$$, $$675160$$, $$B-52 Crypto Modernization$$, 1198000, $$B-52 Crypto Modernization upgrades aircraft with Mobile User Objective System (MUOS) capable ARC-210 radio systems that prevent loss of beyond line of sight (BLOS) voice and data communications capability. The program will upgrade the B-52 aircraft with secure voice and data communications via SATURN (Second Generation Anti-Jam Technical UHF Radio for NATO) network, MUOS (Mobile User Objective System) Satellite constellation, and DAMA-IW (Demand Assigned Multiple Access - Integrated Waveform) SATCOM connection. These updates are required by the National Security Agency (NSA), DoD mandates, and directives. Funds may be used to address requirements including, but not limited to, emerging and short-notice Diminishing Manufacturing Sources and Material Shortages (DMSMS) for both aircraft and associated training systems, Development Testing (DT)/ Operational Testing (OT), and safety of flight issues. Additionally, funds may accommodate Program Management Administration (PMA) and support, civilian pay expenses, rapid technology insertion, and fulfill Federal Aviation Agency (FAA) or other mandates necessary to ensure continued aircrew safety and mission effectiveness. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $0M was expended for civilian pay expenses in this program element, and in FY 2025 $0M is forecast for civilian pay expenses in this program element.$$, 1198000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0101113F_675165$$, $$0101113F$$, $$675165$$, $$B-52 Quad Crew$$, 11549000, $$The Quad Crew program reduces B-52 crew size from five to four personnel. The program will transition controls and displays for the electronic warfare system from the Electronic Warfare Officer (EWO) station to the B-52 Navigator (NAV) Station supporting situational awareness, self-protection, and survivability in a contested environment. AFGSC has defunded the following requirements of the Quad Crew program: To facilitate this, the program upgrades & modifies the ALQ-172 Electronic Warfare Countermeasure System on the B-52 aircraft. A planned expansion of frequency bands within the ALQ-172 system, to restore frequencies previously covered by the deactivated AN/ALQ-155 system, will be included in the program once funding is obtained. In November 2024, Air Force Global Strike Command placed Phase II of the program on hold indefinitely due to operational utility, fiscal constraints, and production device availability. Funds may be used to address requirements including, but not limited to, system integration, emerging and short notice Diminishing Manufacturing Sources and Material Shortages (DMSMS) for both aircraft and associated training systems, Development Testing (DT)/Operational Testing (OT), and safety of flight issues. Additionally, funds may accommodate Program Management Administration (PMA) and support, civilian pay expenses, rapid technology insertion, and fulfill Federal Aviation Agency (FAA) or other mandates necessary to ensure continued aircrew safety and mission effectiveness. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $0M was expended for civilian pay expenses in this program element, and in FY 2025 $0M is forecast for civilian pay expenses in this program element.$$, 11549000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0101113F_676039$$, $$0101113F$$, $$676039$$, $$B-52 Airspace Compliance$$, 80525000, $$The B-52 Airspace Compliance Program ensures the B-52 meets regulatory Airspace Compliance, DoD and FAA mandates by integrated required hardware, software and firmware. Integrates a new Global Positioning System that provides advanced encryption to prevent spoofing and increases jamming protection for the fleet. This also includes the new Global Positioning System (GPS) Military Code (M-Code) signal design that provides a robust signal for the B-52 Fleet, enhancing Anti-Jam/Anti- Spoof capabilities and improving security to the GPS data message as military applications, technology, and mission requirements evolve. The scope of work may include, but not limited to studies and analyses, and/or any additional analyses or documentation necessary to establish a Programs of Record (POR) the meet mandated functions. Funds may also be used to address emerging and short-notice Diminishing Manufacturing and Material Shortages (DMSMS) for both aircraft and associated training systems, Development Testing (DT)/Operational Testing (OT), safety of flight issues, and associated components of the B-52 baseline configurations. DMSMS efforts may include removal of end-of-life/obsolete software and hardware due to the future emergence of Modular Open Systems Approach (MOSA) implementation. This Program may also include necessary civilian pay expenses required to manage, execute, and deliver M-Code GPS signal capability, as well as PM Administration (PMA) and support, rapid technology insertion, and fulfill Federal Aviation Agency (FAA) or other mandates necessary to ensure continued aircrew safety and mission effectiveness. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $0M was expended for civilian pay expenses in this program element, and in FY 2025 $0M is forecasted for civilian pay expenses in this program element.$$, 80525000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0205219F_675247$$, $$0205219F$$, $$675247$$, $$Squadron Operations Centers$$, 296000, $$The SOC is required to employ Remote Split Operations (RSO). It provides the communications, network, aircraft control and sensor distribution circuits to effectively execute RSO missions. The SOC provides CONUS-based aircrews mission data, tasking, and ability to disseminate and exchange mission data with decision-makers and intelligence entities. This effort defines component standards, develops, and integrates new technologies to maintain currency with technological and platform advancements. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F.$$, 296000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603570N_3219$$, $$0603570N$$, $$3219$$, $$SBSD Nuclear Technology$$, 39173000, $$The details of this program element are classified CONFIDENTIAL and are submitted annually to Congress in the classified budget justification books.$$, 39173000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0101122F_674797$$, $$0101122F$$, $$674797$$, $$ALCM Upgrades$$, 555000, $$The AGM-86B, Air Launched Cruise Missile (ALCM), is a subsonic, air-to-surface strategic nuclear missile, operational since 1982. Armed with a W-80 warhead, it is designed to evade air and ground-based defenses in order to strike targets at any location within any enemy's territory. The ALCM is designed for B-52H internal and external carriage. RDT&E funds support development of new test and evaluation procedures, software, and equipment. RDT&E funds also provide sustainment solutions for Line Replaceable Units (LRU) and technology insertion to ensure ALCM sustainability supports Air Force strategic nuclear deterrence and Global Strike mission requirements until the capability is replaced by the Long Range Stand Off (LRSO) cruise missile. Additionally, RDT&E funds support aging and surveillance analysis to pro-actively identify components which will degrade system reliability. The ALCM Test Plan Development and Evaluation program develops plans and procedures for testing nuclear systems, and implements those procedures as directed by the Chairman, Joint Chiefs of Staff (CJCS) and to satisfy the recurring requirements to test Chemical, Biological, Radiological, and Nuclear (CBRN) susceptibility. An extensive Service Life Extension Program (SLEP) is in place to address age related issues and to ensure reliability and sustainability until replaced by the Long Range Stand Off (LRSO) cruise missile. Technology insertion is anticipated to address serviceability of components at or near end of life. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $0.0M was expended for civilian pay expenses in this program element, and in FY 2025 $0.0M is forecast for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                     Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0101122F / Air-Launched Cruise Missile (ALCM) Operational Systems Development$$, 555000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0101126F_675344$$, $$0101126F$$, $$675344$$, $$B-1B Modernization$$, 116589000, $$The B-1B Lancer is a swing-wing, supersonic, long-range conventional bomber. It carries the largest payload of both guided and unguided weapons in the AF inventory. The multi-mission B-1B is the backbone of America's long-range conventional bomber force and can rapidly deliver massive quantities of precision (and non-precision) weapons against any adversary, anywhere in the world, at any time. The B-1B modernization projects alleviate aircraft obsolescence issues due to Diminishing Manufacturing Sources and Material Shortages (DMSMS) while at the same time providing improved capabilities to the B-1B weapon system that require significant hardware and software development and testing. RADIO-CRYPTO MODERNIZATION: The B-1B Radio Crypto program originates from JROCM 040-11, VACM Cease Key CED-026-11, UHF SATCOM (Ultra-High Frequency Satellite Communication) Decommission and Cease Key for Demand Assigned Multi Access (DAMA) Orderwire, HAVE QUICK II Cease use date, and DoD CIO Mobile User Objective System (MUOS) transition directive. If the requirements/directives are not met, B-1B will lose its secure line of sight, beyond line of sight, and anti-jam communication with ground and air forces. The initiative will replace the existing ARC-210 (Gen 3/4) with ARC-210 (Gen 6) next generation radios. Additionally, the program will provide MUOS Satellite Communication capability that supports the DoD Chief Information Officer (CIO) directive to move all DoD assets to MUOS constellation (70% by FY26). This effort will lay in Ethernet cable required by MUOS Data (J-REAP C), install MUOS ancillaries High Power Amplifier/Low Noise Amplifier (HPA/LNA) and additional software to execute MUOS capability on the aircraft. The B-1B Radio Crypto program received an updated Acquisition Decision Memorandum (ADM) in March 2023 approving an updated acquisition strategy that combined the program increments into one technical baseline and accelerated the schedule. A further updated ADM signed January 2024 accelerated the full production lot buys. Preliminary Design Review (PDR) was completed in Q4 FY23, Critical Design Review (CDR) approval was completed Q1 FY24, and Ground / Flight Testing is currently ongoing and is expected to conclude Q3 FY25. EXTERNAL HEAVY-STORES PYLON: This is a FY26 New Start. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                              Date: June 2025 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                   PE 0101126F / B-1B Squadrons Operational Systems Development External Heavy-Stores Pylon program expands on the accomplishments of the Hypersonic Integration Program, a Congressional Add, by providing increased carriage capacity of standoff munition on B-1B aircraft. Maximum carriage of existing standoff munitions on the B-1B provides near-term increased volume of fires from standoff ranges and serves to mitigate transition risk of the Air Force bomber fleet prior to the emergence of the B-21 as a combat bomber. - HYPERSONIC INTEGRATION: -- The FY22 and FY23 Conference Appropriations, detailed in the Congressional Conference Reports of Interest, added 20.0M (10.0M in FY22 and 10.0M in FY23) RTD&E appropriation for B-1B hypersonic weapon integration. This funding developed an external carry-enabled testbed facilitating rapid integration of priority hypersonic weapons in support of national security objectives, leading to potential investment opportunities for weapon programs. This program provides an opportunity to significantly reduce risk for an operational external carry capability on the B-1B if directed. The Hypersonic Integration Program successfully demonstrated the B-1's ability to execute a captive carry of a 5,000-pound class store and the release of a proven weapon shape from a Load Adaptable Modular (LAM) pylon. LONG-RANGE ANTI-SHIP MISSILE (LRASM) C-3 INTEGRATION: This is a FY26 New Start. The Long-Range Anti-Ship Missile (LRASM) C-3 is increment 1 of the Offensive Anti-Surface Warfare (OASuW) weapon development program. LRASM (AGM-158C-3) addresses an air-launch capability gap by providing flexible, long-range, advanced, anti-surface capability against high-threat maritime targets. The LRASM AGM-158C-3 variant will be a forward fit Engineering Change Proposal (ECP) to the AGM-158C, to enhance long range strike and existing OASuW capability. Beginning in FY26 through the outyears, the USAF will procure AGM-158C-3 missiles only until the missile inventory objective is met. The first USAF LRASM C-3 missile deliveries are targeted in Q4 CY27. LRASM is highly leveraged on the design of the Joint Air-to-Surface Standoff Missile-Extended Range (JASSM-ER, AGM-158B). LRASM and JASSM-ER have over 70% hardware commonality and share the same production assembly line. The USN is the lead service for the LRASM program, and the B-1 is a threshold platform. The USAF and USN jointly procure LRASMs via a USAF contract that benefits from cost savings when aligned with JASSM-ER procurements. B-1B HYBRID SATCOM: This is a FY26 New Start. Hybrid-SATCOM provides resilient pLEO in contested environments. INDOPACOM has an urgent requirement to interface and exchange classified data with B-1 in support of INDOPACOM activities in CY26. Securing alternate network connectivity and pathways will restore long-range integration capability and increase combat effectiveness through a modern, resilient, and reliable construct. Without this capability, there is a risk of isolating combat air forces from the Air Operations Center and the Combatant Commander. B-1B TEST JET MAINTENANCE (MX): Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                               Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                 PE 0101126F / B-1B Squadrons Operational Systems Development This is a FY26 New Start. The B-1B AFMC Test Jet maintenance project will provide funding for the test aircraft, manpower, and facilities at the Air Force Test Center located at Edwards Air Force Base (AFB), California. This will support the developmental testing and sustainment needs of the B-1B weapon system. It funds support for maintenance activities for test aircraft, which is performed at Tinker AFB, Oklahoma. Funds also support analysis, documentation, and related activities necessary to establish a program of record and support the B-1B weapon system. Additionally, other costs include Program Management Administration (PMA) and centralized support as well as initiatives for anticipated weapon system enhancements (to include efforts to improve weapon system operational capabilities, safety, supportability, maintainability, reliability, digital engineering and total cost of ownership). GAP AND INTEGRATION ANALYSIS: Program funds cover engineering/planning studies, related engineering efforts, and the auxiliary equipment needed for development projects that have not yet been fielded. Funds may be used to resolve emerging safety of flight and DMSMS issues, accommodate technology insertion, and fulfill FAA (or other) mandates necessary to ensure continued aircrew safety and mission effectiveness. Costs include PMA costs, total ownership cost, as well as initiatives for anticipated weapon system enhancements (to include efforts for improving weapon system operational capabilities, safety, supportability, maintainability, reliability, digital engineering and total cost of ownership). B-1B funding also supports innovation activities to include studies, analyses, requirements definition, digital engineering initiatives and quick-reaction capability prototypes… [truncated]$$, 116589000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0101127F_675345$$, $$0101127F$$, $$675345$$, $$B-2 Modernization$$, 4527000, $$The B-2 is currently undergoing modernization of avionics, communications systems, cockpit displays, armament systems, low observable components, core training system components, aircraft supportability improvements, and support equipment development. The Air Force will continue to study multiple structural, avionics, and engine modifications, as well as advanced weapons integration, communications upgrades, and innovative low observable enhancements, that could improve the performance of the aircraft and engines and reduce maintenance man-hours and the logistics footprint of the fleet. The Adaptable Communications Suite (ACS) Increment 4.0 provides secure beyond line-of-sight SATCOM Command and Control connectivity. ACS 4.0 will replace the current radios and ancillaries to transition the B-2 SATCOM's capability from the Ultra High Frequency Follow-On (UFO) satellite constellation to the Mobile User Objective System satellite constellation bringing enhanced capability over UFO's waveform. Along with the aircraft system, the ACS ground systems and infrastructure will be redesigned to support this new waveform. ACS 4.0 significantly improves the transfer time for real-time mission planning data, and allows for simultaneous use of SATCOM voice and data. Funds will support the development and integration of a highly secure communications pathway that will enable the B-2 warfighter's to communicate and receive updated targeting data while operating in highly contested environments. This capability can be used globally, but it is critical once the B-2 enters a highly contested airspace. B-2 Battlespace Collaborative Combat Communications (B2C3) effort integrates an independent Open Mission Systems (OMS) avionics architecture on the B-2, as well as upgrades the B-2's current line-of-site capability. B2C3's objective is to identify, leverage, and integrate existing capabilities to meet Air Force Global Strike's B-2 communications requirements. B2C3 will be implemented in two main increments defined as Spiral 1 and Spiral 2. Spiral 1 will provide the OMS architecture (multi- mission domain) within the B-2 and Spiral 2 will implement Airborne Integrated Terminal Group (AITG) providing Line-of-Sight Ultra High Frequency (UHF) and Very High Frequency (VHF) anti-jam, encrypted, and unencrypted voice communications. AITG will replace the AN/ARC-234 radio (reaches end-of-life effective 01 Oct 2026) with two AN/ARC-210 radios and will transition from the HAVEQUICK waveform (sunsetted 01 Oct 2024) to the SATURN anti-jam waveform for voice communications. The Low Observable Signature and Supportability Modifications (LOSSM) is a Continuous Improvement Program that supports the B-2's survivability against pacing and enhancing threats. LOSSM also serves other low observable (LO) platforms by advancing their ability to penetrate anti-access combat environments, perform missions directed by the National Command Authority while ensuring aircrew survivability. The LOSSM program reduces low observable (LO) maintenance, which is the B-2's highest maintenance driver, to improve combat readiness. Additionally, this program encompasses multiple improvement projects including, but not limited to, improved LO materials (electrically conductive materials, adhesives, electrically resistive materials, radar absorbing material, fastener fills, coatings, welds, material removal tools, and improved processes), LO structures (radar radomes, antennas, hot trailing edges and tiles, intermediate section doors, tailpipes, windows, lib bay panels, leading edge, permanent fasteners, exhaust pockets, gust load alleviation system, inlets, radar absorbing structures, overall signature stability, and Alternate High Frequency Material expansion) and additional efforts that enhance LO aircraft survivability; and radio frequency diagnostic tools, evaluation systems, and other$$, 4527000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0101127F_676021$$, $$0101127F$$, $$676021$$, $$BASELINE SUPPORT$$, 7992000, $$Baseline Support maintains and upgrades the B-2 unique flight test aircraft as well as hardware/software and instrumentation and test equipment to support developmental systems integration, and flight test, reducing the need for additional operational aircraft and accelerating deployment of advanced operational capabilities to the warfighter. Baseline Support also provides for other B-2 unique government costs and includes assorted studies of aircraft performance as well as acquisition planning activities, up to and including proposal preparation, for future aircraft, engine, weapon, communication, navigation or other capabilities. B-2 funding may be used to resolve emerging safety of flight and diminishing manufacturing sources issues, and fulfill FAA or other mandates necessary to ensure continued aircrew safety and mission effectiveness. Funding may also support innovation activities including, but not limited to, studies, analyses, requirements definition, and quick-reaction capability prototypes/demonstrations to accelerate planning for technology transition, technology insertion, and future acquisition programs.$$, 7992000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0101213F_672983$$, $$0101213F$$, $$672983$$, $$MM Ground and Comm Equipment$$, 5433000, $$The MM Ground and Comm Equipment program replaces obsolete/unsupportable ground-based weapon system equipment located at Launch Control Centers (LCCs) and Launch Facilities (LFs) necessary to continue Minuteman III operations until replaced by Sentinel. Current efforts include development, qualification, integration, and testing of replacement equipment such as the LGM-30G Fast Rising B-Plug Energy Storage System-Replacement (FRBP ESS-R). MM Ground and Comm Equipment also includes unforeseen costs arising for various reasons on programs from prior President's Budgets. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2024, 0.000M was expended for civilian pay expenses. 0.000M is forecasted in FY2025 for civilian pay expenses.$$, 5433000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0101213F_672984$$, $$0101213F$$, $$672984$$, $$MM III Baseline Support$$, 79742000, $$Minuteman III (MM III) Baseline Support program replaces or upgrades obsolete/unsupportable flight test unique equipment installed on the missile during flight test, used to test MM III systems on the ground, or located at test facilities to collect, process, and analyze test data. Flight test equipment supports test and evaluation of MM III capabilities, and MM III Operational Test Launches (OTLs) to determine ICBM force readiness, reliability, and capability shortfalls. Efforts include development, qualification, integration and testing of replacement equipment such as LGM-30G Flight Test, Telemetry, and Termination System (FT3); LGM-30G Higher Authority Command Test System (HACTS) 2.0; LGM-30G Little Mountain Test Facility (LMTF), and LGM-30G Depot Reentry Support Equipment Replacement Program (DRSERP). As other similar equipment is identified for replacement, it will be added to this program. MM III Baseline Support also provides for other MM III unique government costs, studies of system performance, contract closeout costs, cost trades and acquisition planning activities, up to and including proposal preparation, to meet Capability Development Document requirements in an evolving threat landscape by leveraging advanced technologies. MM III Baseline Support also includes unforeseen costs arising for various reasons for programs from prior President's Budgets. The FY2026 request was reduced by $1.864 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2024, 0.000M was expended for civilian pay expenses. 0.000M is forecasted in FY2025 for civilian pay expenses.$$, 79742000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0101213F_672985$$, $$0101213F$$, $$672985$$, $$MM Support Equip$$, 20857000, $$Minuteman (MM) III Support Equipment program designs, develops, and tests replacement of obsolete/non-serviceable weapon system support equipment. These programs will also implement processes, procedures, and data systems to mitigate the transition risk from MM III to Sentinel. Efforts include design, development, and testing of support equipment such as LGM-30G MM III Acquisition of Transportation & Handling (MATH), MM III Acquisition of Transportation & Handling Support Equipment (MATH SE) effort, and Missile Transporter Acquisition Procurement (MTAP) efforts. MM Support Equipment also includes unforeseen costs arising for various reasons for programs from prior President's Budgets. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2024, 0.000M was expended for civilian pay expenses. 0.000M is forecasted in FY2025 for civilian pay expenses.$$, 20857000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0101316F_671820$$, $$0101316F$$, $$671820$$, $$Strategic Automated$$, 24081000, $$Worldwide Joint Strategic Communication efforts include Nuclear Command, Control, and Communications (NC3) systems to include the Defense Injection Reception Emergency Action Message (EAM) C2 Terminals (DIRECT) and the Strategic Automated Command and Control System (SACCS). Funding may be used to modernize these, and other, NC3 systems. Funding may also be used for research, testing, validation, certification, configuration management, and assessment of the Air Force NC3 Weapon System. SACCS is a dedicated, high speed, multi-level secure, data transmission, processing, and display system. SACCS provides the primary non-survivable command and control capability for receiving and disseminating secure Emergency Action Messages (EAM), Force Direction Messages (FDM), Force Status Reporting (FSR), and exchanging information type messages from USSTRATCOM. SACCS provides messages for effective deployment of strategic bombers, reconnaissance aircraft, mobilization aircraft, tanker support aircraft, and the Intercontinental Ballistic Missile (ICBM) force to include Minuteman III (MM III) and Sentinel. SACCS has equipment that has reached its end of life and is no longer repairable due to diminished manufacturing sources and parts obsolescence. This jeopardizes Air Force Global Strike Command's (AFGSC) ability to meet mission requirements as required by Chairman Joint Chiefs of Staff Nuclear Technical Performance Criteria and Operational Standards (CJCSI 6811.01). In order to mitigate the risk of SACCS inability to operate once the current spares are completely diminished and ensure the system remains secure against modern/future threats, the Air Force is developing a replacement system (SACCS-R). SACCS-R is currently pursuing Technology Maturation and Risk Reduction (TMRR) efforts to transition from Time-Division Multiplexing (TDM) to Internet Protocol (IP) architecture, monitor and secure the new IP- based network, and provide requisite support to Sentinel fielding plans. This program element may include necessary civilian pay expenses required to manage, execute, and deliver SACCS capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 0.000M was expended for civilian pay expenses in this program element, and in FY 2025 0.000M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                     Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0101316F / Worldwide Joint Strategic Communications Operational Systems Development$$, 24081000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0101318F_675368$$, $$0101318F$$, $$675368$$, $$Global Data Integration$$, 6928000, $$The mission of USSTRATCOM is to deter strategic attack through a safe, secure, effective, and credible, global combat capability and, when directed, is ready to prevail in conflict. The command enables Joint Force operations and is the combatant command responsible for Strategic Deterrence, Nuclear Operations, Nuclear Command, Control, and Communications (NC3) Enterprise Operations, Joint Electromagnetic Spectrum Operations, Global Strike, Analysis and Targeting, and Missile Threat Assessment. USSTRATCOM integrates and coordinates the necessary command and control capability to provide support with the most accurate and timely information for the President, the Secretary of Defense, other national leadership and combatant commanders. The Nation's strategic C2 sensors, and mission planning programs cannot rapidly exchange information across multiple missions creating ambiguity that delays time critical national C2 decision making processes. GDI developed and established a unified schema that integrates disparate Missile Warning/Missile Defense (MW/MD), Technical Intelligence (TI) and other data into a single, exposed data set, providing redundant and unambiguous Situational Awareness data to national leadership. GDI also enables existing radars and sensors to provide data in net-centric formats consumable by other authorized systems and mission areas, thus reducing the need to acquire more systems. Activities also include studies and analysis to support current program planning, execution, and future program planning. GDI directly supports USSTRATCOM and other Combatant Command and MAJCOM mission sets. GDI meshes together selected systems and sensors (from tactical to strategic), including the Nation's most modern and capable assets, taking advantage of their larger numbers, improved algorithms, mobility, and forward deployment to provide earlier cross-cueing and expanded decision space when every second counts. Repurposing these traditionally stove-piped systems and sensors, GDI enables the warfighter in several ways. GDI enables creation of a User Defined Operating Picture (UDOP) to provide a single, unambiguous missile event picture allowing real- time collaboration for nuclear C2 and improved senior leader situational awareness (SA) for effective decision-making. GDI also improves Space Situational Awareness (SSA) by tapping additional sensor capability and provides this data for the larger space order of battle capabilities. GDI dramatically improves the ingestion of non- traditional, but readily available, non-US government and commercial data to the United States Space Force (USSF) satellite catalog. GDI addresses NORTHCOM/ STRATCOM's signed Joint Emergent Operational Need (JEON) ST-0010 request for uninterrupted traditional and non-traditional sensor data integration and the Global Threat Characterization Assessment (GTCA) Operational Planning Team report. Finally, GDI provides Data Analysis functions to optimize and operate situational awareness in the field, including units operating in Denied-Disconnected, Intermittent, Limited (D-DIL) and emissions controlled (EMCON) conditions. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                 PE 0101318F / Service Support to STRATCOM - Global Strike Operational Systems Development Leveraging the appropriate acquisition authorities and contract mechanisms to deliver capability sooner, USSTRATCOM will strategically execute experimentation, prototyping, risk reduction, and other efforts to develop new or repurpose capabilities. GDI may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability but the civilian pay is expended from program element 0101890F. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 6928000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601153N_1394$$, $$0601153N$$, $$1394$$, $$Manufacturing$$, 2361000, $$This Focus Area (FA) develops processes technologies that acquisition programs need to make the design, fabrication, construction, repair, and sustainment of naval platforms more affordable. This FA also supports manufacturing S&T that accelerates the delivery of capabilities to the fleet and force. Advanced manufacturing technologies include additive manufacturing, repair and sustainment technologies, and coupling computational tools from design to sustainment.$$, 2361000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0101328F_674920$$, $$0101328F$$, $$674920$$, $$Mk21A Reentry Vehicle$$, 209709000, $$The Mk21A Reentry Vehicle (RV) program will design, develop, produce, and deploy an integrated RV capable of delivering the W87-1 warhead when released from the LGM-35A Sentinel weapon system. The Mk21A program will provide needed performance and security enhancements over the Mk21 RV to meet the upgraded requirements for the Department of Energy (DOE)/ National Nuclear Security Administration (NNSA) W87-1 warhead, while ensuring the time certain delivery of both the W87-1 and Mk21A programs. The Mk21A will also meet the requirements laid out in the LGM-35A Sentinel weapon system Capability Development Document (CDD) as directed by Air Force Global Strike Command. The Mk21A RV includes: shape-stable nose tip; high-impulse transducer; arming and fuzing subsystem (AFS); aeroshell forward section, body section, and rear cover; radio frequency subsystem with antennas; RV spin subsystem; in-flight disconnect cable; and other electrical cables. During the Engineering and Manufacturing Development (EMD) phase, the Mk21A program will include prime contractor development of a critical RV design, applicable support equipment, data, flight test hardware, infrastructure, and training materials while examining and mitigating weapon system integration risks, nuclear surety, hardness and certification, and system vulnerability assessments. Additionally, the program, in conjunction with the DOE/NNSA, will develop test assets to ensure the integration and qualification of the Mk21A and W87-1 on the LGM-35A Sentinel weapon system. IAW 10 USC 4252, this program has not yet fully satisfied the certification requirement that the heatshield technology has been demonstrated in a relevant environment as required prior to Milestone B approval. The Mk21A uses similar materials and process as currently fielded and the program performed a successful flight test in 3QFY24. The program provided a Technology Readiness Level (TRL) update to SAF/AQR in April 2025 after analysis of flight test data was completed; final decision anticipated 3QFY25. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program elements 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, and 0606398F. In FY 2024 0.000M was expended for civilian pay expenses in this budget program activity code (BPAC), and in FY 2025 0.000M is forecasted for civilian pay expenses in this BPAC.$$, 209709000, NULL, NULL, NULL, NULL, 414401000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0101328F_675920$$, $$0101328F$$, $$675920$$, $$Next Generation Reentry$$, 49896000, $$The Next Generation Reentry Capabilities (NGRC) program will design, develop, produce, and deploy new payload system suites (reentry vehicles and/or countermeasures) and integrate them into ICBM weapon systems. Key next generation payload attributes include enhancements in accuracy and lethality. Next Generation Reentry Vehicle (NGRV) and advanced countermeasure capabilities are based on emerging threats, warfighter priorities, and development capacity. Program activities will also include the employment of digital acquisitions through the application of digital engineering, agile software development, and open systems architectures. The NGRC program will leverage investments by the ICBM Demonstration/Validation program, the Science & Technology community, and Navy reentry systems application program. FY2026 funding supports early acquisition activities that lead to competitive contract awards. NGRC will continue its early concept, acquisition and integration studies to strengthen the atrophied industrial base, posturing the nation and to counter adversary threats both projected and unforeseen. This strategy enables a diverse pool of vendors to contribute in the development of materiel solutions which support mission requirements that combat future and immediate threats to drive ultimate effectiveness requirements for the weapon system. This funding includes program management support, operational concept exploration, technology trade studies, operational and system architecture development, maturation and risk reduction of RV/countermeasure-related technologies, including weapons system and integrated system concept development/demonstration. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 1.249M was expended for civilian pay expenses in this budget program activity code (BPAC), and in FY 2025 5.104M is forecasted for civilian pay expenses in this BPAC.$$, 49896000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0102110F_672021$$, $$0102110F$$, $$672021$$, $$MH-139A$$, 0, $$The MH-139A program will replace the Air Force fleet of UH-1N aircraft with modern helicopters that will close significant mission capability gaps associated with the current fleet of UH-1N aircraft. The replacement aircraft will provide vertical airlift and support the requirements for Air Force Global Strike Command (AFGSC) and Air Force Reserve Command (AFRC). AFGSC is the Air Force lead command and operational capability requirements sponsor. This program is an element of the Air Force's nuclear enterprise reform initiatives. Program includes, but is not limited to, funding for four test aircraft and two System Demonstration Test Article (SDTA) aircraft, support equipment, Interim Contractor Support (ICS), training system devices, Type I training and course ware, extension of NDI integration as a result of Identification Friend or Foe (IFF) and security forces communication capability, cyber test articles, associated Government support activities, completion of Engineering and Manufacturing Development (EMD) Development Test (DT) and live-fire test and evaluation (LFT&E), and remedy of developmental test deficiencies. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program elements 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, and 0606398F. In FY 2024, $2.750 million was expended for civilian pay expenses in this program element, and in FY 2025 $0.00 million is forecast for civilian pay expenses in this program element.$$, 0, NULL, NULL, NULL, NULL, 613663000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0102110F_672023$$, $$0102110F$$, $$672023$$, $$MH-139A PE/PI$$, 5982000, $$The MH-139A program will replace the Air Force fleet of UH-1N aircraft with modern helicopters that will close significant mission capability gaps associated with the current fleet of UH-1N aircraft. The replacement aircraft will provide vertical airlift and support the requirements for Air Force Global Strike Command (AFGSC) and Air Force Reserve Command (AFRC). AFGSC is the Air Force lead command and operational capability requirements sponsor. The MH-139A program is an element of the Air Force's nuclear enterprise reform initiatives. The MH-139A Performance Enhancements and Product Improvements (PE/PI) Program is for the development of solutions to solve capability gaps found during the development and test of the MH-139A to include communication and gun systems deficiencies, improve mission planning capability, resolve usability concerns, and other critical capabilities, and includes associated Government test and support activities. The program office will continue flight testing in support of modernization efforts to address emerging threats, evolving mission needs, AFGSC requirements, and support of the nuclear mission. MH-139A funding also supports obsolescence solutions and innovation activities to include studies, analyses, requirements definition, and quick-reaction capability prototypes/demonstrations to accelerate planning for technology transition, technology insertion and future acquisition programs. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program elements 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, and 0606398F. In FY 2024, $0.000 million was expended for civilian pay expenses in this program element, and in FY 2025 $0.000 million is forecast for civilian pay expenses in this program element.$$, 5982000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0102326F_3600$$, $$0102326F$$, $$3600$$, $$Research, Development, Test & Evaluation, Air Force / BA 7:$$, NULL, $$The Regional/Sector Operation Center Modernization program supports the North American Aerospace Defense Command (NORAD)/ US Northern Command (USNORTHCOM) homeland defense and air sovereignty mission for fixed Air Defense Sectors. BATTLE CONTROL SYSTEM-FIXED (BCS-F): BCS-F is a bi-national development program with Canada. The BCS-F Program is a USAF Homeland Defense battle management command and control system with the capability to integrate data from existing and future civil and military defense surveillance systems into a comprehensive air picture. BCS-F provides tactical communications and data link capabilities with other military and civil systems responsible for planning, directing, coordinating and controlling forces for air surveillance, air defense, and control of sovereign US air space. This integrated air picture enhances the capability to conduct peacetime air sovereignty operations and transition to active air defense operations in the event of aggression. BATTLE CONTROL SYSTEM-FIXED MODIFICATION ONE (BCS-F Modification 1): BCS-F Modification 1 effort will support the implementation of Earth Center Earth Fixed (ECEF). The BCS-F Modification 1 effort is executed as a Cooperative Development Program between the US and Canada. This program aligns with Air Battle Management System (ABMS) Cloud-Based Command and Control (CBC2) (0604003F), which is planned to replace BCS-F as the Air Defense Sectors' C2 system of record. Activities in this FY are planned overlap with ABMS CBC2 to minimize operational risk during the transition. NATIONAL CAPITOL REGION - INTEGRATED AIR DEFENSE SYSTEM (NCR-IADS): NCR-IADS is a post-September 11, 2001 rapidly fielded capability that provides ground-based air defense of the NCR airspace by delivering an integrated air picture, air defense weapons, enhanced regional situational awareness, and forensic data collection capabilities. Life cycle replacement will be required to prevent system obsolescence, account for new cyber security requirements, and posture the program to seamlessly integrate future capabilities. Reduces contracts for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, Implementing the President's Department of Government Efficiency Cost Efficiency Initiative. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY25 $0.000M was expended for civilian pay expenses in this program element and in FY26 $0.000M is forecasted for civilian pay expenses in this program element. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0102326F / Region/Sector Operation Control Center Modernization Program Operational Systems Development This program element may include necessary emergent or unanticipated civilian pay expenses required to manage, execute and deliver Battle Control Systems-Fixed Modification 1. The use of such programs would be in addition to the civilian pay expenses budgeted in program element 0102326F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0102326F_674592$$, $$0102326F$$, $$674592$$, $$BA7 0102326F 674592$$, 726000, $$The Regional/Sector Operation Center Modernization program supports the North American Aerospace Defense Command (NORAD)/ US Northern Command (USNORTHCOM) homeland defense and air sovereignty mission for fixed Air Defense Sectors. BATTLE CONTROL SYSTEM-FIXED (BCS-F): BCS-F is a bi-national development program with Canada. The BCS-F Program is a USAF Homeland Defense battle management command and control system with the capability to integrate data from existing and future civil and military defense surveillance systems into a comprehensive air picture. BCS-F provides tactical communications and data link capabilities with other military and civil systems responsible for planning, directing, coordinating and controlling forces for air surveillance, air defense, and control of sovereign US air space. This integrated air picture enhances the capability to conduct peacetime air sovereignty operations and transition to active air defense operations in the event of aggression. BATTLE CONTROL SYSTEM-FIXED MODIFICATION ONE (BCS-F Modification 1): BCS-F Modification 1 effort will support the implementation of Earth Center Earth Fixed (ECEF). The BCS-F Modification 1 effort is executed as a Cooperative Development Program between the US and Canada. This program aligns with Air Battle Management System (ABMS) Cloud-Based Command and Control (CBC2) (0604003F), which is planned to replace BCS-F as the Air Defense Sectors' C2 system of record. Activities in this FY are planned overlap with ABMS CBC2 to minimize operational risk during the transition. NATIONAL CAPITOL REGION - INTEGRATED AIR DEFENSE SYSTEM (NCR-IADS): NCR-IADS is a post-September 11, 2001 rapidly fielded capability that provides ground-based air defense of the NCR airspace by delivering an integrated air picture, air defense weapons, enhanced regional situational awareness, and forensic data collection capabilities. Life cycle replacement will be required to prevent system obsolescence, account for new cyber security requirements, and posture the program to seamlessly integrate future capabilities. Reduces contracts for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, Implementing the President's Department of Government Efficiency Cost Efficiency Initiative. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY25 $0.000M was expended for civilian pay expenses in this program element and in FY26 $0.000M is forecasted for civilian pay expenses in this program element. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0102326F / Region/Sector Operation Control Center Modernization Program Operational Systems Development This program element may include necessary emergent or unanticipated civilian pay expenses required to manage, execute and deliver Battle Control Systems-Fixed Modification 1. The use of such programs would be in addition to the civilian pay expenses budgeted in program element 0102326F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 726000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0205412A_EE6$$, $$0205412A$$, $$EE6$$, $$Environmental Information Tech$$, NULL, $$The Environmental Information Technology Management (EITM) program includes support for the Defense Environment, Safety & Occupational Health Network and Information Exchange (DENIX) defense business system, as well as its database and reporting application, the Knowledge Based Corporate Reporting System (KBCRS). This request for research, development, test, and evaluation (RDTE) is to implement necessary enhancements to facilitate DENIX's Platform-as-a-Service (PaaS) capabilities, with additional modernizations that will improve the DoD's ESOH system of record and reporting tool set. This also includes upgrades to incorporate ongoing cybersecurity, cloud computing, and other information technology requirements.$$, NULL, NULL, NULL, NULL, NULL, 271000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601153N_1395$$, $$0601153N$$, $$1395$$, $$Materials$$, 0, $$This Focus Area (FA) enhances the performance, affordability, survivability, and reliability of the future fleet and force by developing materials with novel or enhanced properties suited to the unique needs of Navy and Marine Corps platforms and systems. Research relevant to enabling enhanced performance and resiliency of naval systems and platforms are included in this R-2 Activity$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603573N_2471$$, $$0603573N$$, $$2471$$, $$Integrated Power Systems (IPS)$$, 101136000, $$This Project Unit includes the development and risk reduction of advanced surface ship Hull, Mechanical, and Electrical (HM&E) components and systems, power and energy systems, and for all future ships and back-fit ships where appropriate HM&E cyber security. Specific sub-projects include: The DDG(X) power and propulsion risk mitigation demonstration sub-project will be used to de-risk the DDG(X) Integrated Power System (IPS) and satisfy the FY 2020 National Defense Authorization Act (NDAA) Section 131 requirements for land based testing of propulsion systems in a realistic environment and FY 2022 NDAA Section 221 requirement for a land based test program for the engineering plant prior to DDG(X) construction start. The DDG(X) hardware development and procurement and land-based testing efforts executed under this PE are informed by DDG(X) Ship Design specifications developed under PE 0603564N / PU 0411. IPS test findings will inform decisions in baseline specifications and design products, developed under PE 0603564N / PU 0411, ensuring that the ship can accommodate the space, weight, power, cooling (SWAP-C) required by the IPS and that the IPS can meet DDG(X) power and energy requirements. The interdependency of DDG(X) design and IPS risk reduction is critical. This subproject will employ a four-phased testing and risk reduction approach (updated to align with FY 2020 and FY 2022 NDAA land-based testing requirements) to build assurance that the DDG(X) IPS system can be installed and activated efficiently by the shipbuilder with performance characteristics that are well understood. - Phase 1 (IPS Modeling & Simulation (M&S)), commenced in FY 2021, establishes a description of the components and system non-real-time models that are needed for the DDG(X) IPS digital engineering effort to provide performance feedback to DDG(X) IPS design and specification. Persistent digital engineering efforts initiated as part of Phase 1 extend through the life of the DDG(X) program. - Phase 2 (Land based testing) commenced in FY 2021, initially employs refined digital models and scaled integrated surrogate components that functionally represent the intended DDG(X) IPS and transitions to full scale testing by procurement, integration and test of DDG(X) specific major long lead hardware components. - Phase 3 (Land Based Engineering Site (LBES)) builds a tactical representation of the DDG(X) shipboard power and propulsion system based on the DDG(X) full scale hardware procured in phase 2. The LBES will be an enduring activity over the life of the ship and provides capability to perform performance & endurance testing of the IPS. - Phase 4 (Shipboard Test & Activation), funded by future DDG(X) Shipbuilding and Conversion, Navy (SCN), conducts shipboard integration testing of the power and propulsion system with other ship systems to confirm performance as specified in the contract requirements and interoperability at the platform level. Naval Power and Energy Systems developments and transitions including power generation, power conversion, power distribution, energy storage, power utilization and automation and control functions for fully integrated electric propulsion (such as T-AKE -1 class or DDG 1000 class), hybrid electric propulsion (such as LHD 8 and LHA(R) class), as well as legacy mechanical propulsion ships (such as DDG 51 class). Naval Power and Energy Systems sub-project supports optimized integration of naval warship power and energy systems to support Directed Energy (DE) and other high powered mission systems, ship power quality requirements including frequency and voltage control for AC systems, DE and other high powered mission systems, appropriate component and system controls, integration of components and systems into future and current ships, and providing power and energy system solution alternatives to new and existing platforms. Existing ships' power systems require$$, 101136000, NULL, NULL, NULL, NULL, 546704000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0102417F_650010$$, $$0102417F$$, $$650010$$, $$Ops Control Center HLD$$, 0, $$Efforts funded in this PE focus on development, testing, and fielding, of a long-range early detection capability for airborne and surface targets of interest. Each line of effort acquires and fields a land based, high-frequency (HF) ionospheric backscatter radar for over the horizon detection and tracking of airborne and surface targets over wide geographic areas. Fielding of this capability will enable detection, tracking and reporting of airborne and surface targets that may be obscured from conventional line of sight radar systems by the curvature of the earth. HLD-OTHR efforts are focused on the development, testing, and fielding of capabilities to extend current NWS surveillance of long-range early warning for North America in response to emerging threats. The system was to be comprised of two OTHR systems and an Operational Control Center. HLD-OTHR data will be distributed and integrated into existing air, missile and maritime defense early warning networks, as applicable. This project will continue to focus investments to enhance capability for the Air and Cruise Missile Defense of the Homeland mission. The programs intent is to design, develop, test and field advanced OTHR systems operating at levels of sensitivity that exceed current US OTHR systems in operation. Program activities include C2 interface design and integration, HF sensor and digital receiver technology advancement, ionospheric characterization research, remote sensor management capability development, and sensor data fusion research. HLD-OTHR data was to be distributed and integrated into existing integrated air and missile defense (IAMD) early warning networks, to include the emerging DAF Battle Network and Cloud Based C2 architectures as applicable. In support of the Air and Cruise Missile Defense of the Homeland mission and NORAD/USNORTHCOM Defense of North America mission, the project will continue to focus investments to enhance capability for Over-the-Horizon Radars. HLD OTHR will continue executing experimental efforts with the DoD science and technology community to characterize ionospheric conditions in the CONUS. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in PE 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0102417F_650011$$, $$0102417F$$, $$650011$$, $$HLD - OTHR$$, 0, $$HLD-OTHR efforts focus on the development of a capability to extend current NWS surveillance to long range early warning for North America in response to emerging threats. The intent of the program is to design, develop, test and field advanced 6th generation OTHR systems operating at levels of transmit power and receiver sensitivity that should exceed current OTHR systems in operation. Program activities include C2 interface design and integration, HF sensor and digital receiver technology advancement, ionospheric characterization research, remote sensor management capability development, and sensor data fusion research. HLD-OTHR data will be distributed and integrated into existing integrated air and missile defense (IAMD) early warning networks, to include the emerging DAF Battle Network and Cloud Based C2 architectures as applicable. The emphasis of the work performed in this program are to evaluate and develop improvements to the OTHR sensors tracking algorithms to increase probability of detection of high-altitude air vehicles such as stratospheric balloons and other unidentified aerial phenomena. Fielding involves land-based installation of Transmit and Receive site arrays for bi-static operations. Additional development will include the establishment of an initial Operations Control Center (OCC) capability and associated Command and Control Battle Management to enable the dissemination of track data and other targets of interest for Air and Cruise Missile Defense of the Homeland (ACMD-H) air domain awareness requirements. Program Element will also be utilized to fund any emerging or urgent joint operational OTHR needs as required. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24 4.2M was expended for civilian pay expenses in this program element, and in FY25 4.3M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0102417F_650012$$, $$0102417F$$, $$650012$$, $$TACMOR Development$$, 0, $$TACMOR capability is being developed for employment in the Republic of Palau to provide enhanced Air Domain Awareness in the USINDOPACOM area of responsibility. TACMOR will be operated by the United States and located in the Republic of Palau, with the agreement of the government of Palau. Development, test and evaluation, and acquisition of the system and associated components will provide warfighters with the capability to close gaps in surveillance coverage in key regions of the Pacific area of interest to the United States and our Allies. TACMOR radar system development, integration and test activities have been delayed from FY22 - 24 but the DAF has been able to. TACMOR efforts funded in this Program Element will include but are not limited to: A Transmit site consisting of fourteen elements and high-power amplifiers transmitting High Frequency [HF] Skywave Over-The-Horizon Radar [OTHR] waveforms. The transmit site will also consists of a HF vertical sounder antenna and a HF backscatter sounder providing ionosphere environmental information for optimizing frequency selection. Also includes a Receive site consisting of 128 dual-monopole antenna elements receiving the over- the-horizon reflected energy from the transmit site. The receive site also contains the secure facilities for signal processing of the received data and real-time target extraction information. This effort will also fund the communications infrastructure necessary to enable the data flow from the Transmit and Receive sites to an off-site operations control center. The operations control center plans and executes missions in support of the Combatant Command [CCMD] and provides real-time, target tracking information to all- source information fusion and dissemination systems. TACMOR data will also be accessible to and exploited by the National Air and Space Intelligence Center [NASIC] for detailed, post-event analysis. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2024 0 was expended for civilian pay expenses in this program element, and in FY2025 0 is forecasted for civilian pay expenses in this program element.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0202057C_MDSH$$, $$0202057C$$, $$MDSH$$, $$Safety Program Management$$, 1806000, $$The Missile Defense Agency (MDA) Occupational Safety and Health (OSH) establishes the program plans, policy, responsibilities, and guidelines for compliance with statutory, regulatory, and Department of Defense (DoD) policy/program directives. It also establishes MDA OSH programs designed for the protection of human resources through accident prevention; protection of MDA systems, property, and equipment; and the compliance with appropriate statutes, regulations, Executive Orders, and DoD policies. OSH develops and ensures implementation of safety requirements, mitigates safety risks to the lowest practical level, and ensures a safe workplace for all MDA employees and contractors by implementing a Safety and Occupational Health program.$$, 1806000, NULL, NULL, NULL, NULL, 4758000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0202834F_3600$$, $$0202834F$$, $$3600$$, $$Research, Development, Test & Evaluation, Air Force / BA 7:$$, NULL, $$Aviation Support Equipment Modernization provides funding for the modernization of organizational and intermediate level support equipment for out-of-production and emerging aircraft, munitions and external stowage to maximize commonality of equipment, improve aircraft readiness/availability and to reduce life cycle sustainment costs. These items, common (used on more than one weapon system) and peculiar (unique to one weapon system), directly support aircraft maintenance, servicing, and sortie generation requirements. To support aircraft generation requirements, support equipment may be studied, reviewed, modified and/or re-developed in order to maintain operational readiness. Examples of equipment under review and/or modernization includes, but not limited to, power generation, heating, ventilation, and air conditioning (HVAC), munition trailers/accessories, munition lifts/accessories, tow vehicles, munition test/maintenance stands, hydraulic equipment, and engine test stands. Any identified capability gaps may result in the design of a new system. Additionally, modernization is a continuous, deliberate effort and is key to complete lifecycle management. This program element also includes program administrative cost for the Support Equipment and Vehicles program office and funds the cost of studies and research to support the aviation support equipment fleet. This program element may include necessary civilian pay expenses required to manage, execute, and deliver Aviation Support Modernization capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                            Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                 PE 0202834F / Vehicles and Support Equipment - General Operational Systems Development$$, NULL, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603119A_BO3$$, $$0603119A$$, $$BO3$$, $$MILITARY ENGINEERING$$, NULL, $$Congressional Interest Item funding provided for Military Engineering Technology Demonstration. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy.$$, NULL, NULL, NULL, NULL, NULL, 235500000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0202834F_672800$$, $$0202834F$$, $$672800$$, $$AVIATION SUPPORT$$, 744000, $$Aviation Support Equipment Modernization provides funding for the modernization of organizational and intermediate level support equipment for out-of-production and emerging aircraft, munitions and external stowage to maximize commonality of equipment, improve aircraft readiness/availability and to reduce life cycle sustainment costs. These items, common (used on more than one weapon system) and peculiar (unique to one weapon system), directly support aircraft maintenance, servicing, and sortie generation requirements. To support aircraft generation requirements, support equipment may be studied, reviewed, modified and/or re-developed in order to maintain operational readiness. Examples of equipment under review and/or modernization includes, but not limited to, power generation, heating, ventilation, and air conditioning (HVAC), munition trailers/accessories, munition lifts/accessories, tow vehicles, munition test/maintenance stands, hydraulic equipment, and engine test stands. Any identified capability gaps may result in the design of a new system. Additionally, modernization is a continuous, deliberate effort and is key to complete lifecycle management. This program element also includes program administrative cost for the Support Equipment and Vehicles program office and funds the cost of studies and research to support the aviation support equipment fleet. This program element may include necessary civilian pay expenses required to manage, execute, and deliver Aviation Support Modernization capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                            Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                 PE 0202834F / Vehicles and Support Equipment - General Operational Systems Development$$, 744000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0203345D8Z_345$$, $$0203345D8Z$$, $$345$$, $$Defense Operations Security Initiative$$, 2493000, $$DOSI establishes and leads the Department's next-generation OPSEC capability development and affiliated investment strategy. Investments support DoD's current and emerging OPSEC capability gaps, including countering advances in non-U.S. ISR capabilities and denying the understanding of U.S. capability, capacity, readiness, and critical technology and information from adversaries. These investments spur Department innovation and preserve U.S. technology superiority. DOSI analyses and engineering activities lead the community's ability to sustain and maximize technology advantages as they are transitioned to Service and Agency programs for sustainment, maintenance, and capacity programming. Results of tests and evaluations enable the community to identify OPSEC measure and countermeasure effectiveness in current and emerging operational environments.$$, 2493000, NULL, NULL, NULL, NULL, 2933000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0203728A_EF7$$, $$0203728A$$, $$EF7$$, $$Precision Fires Warrior Dismounted &$$, 8424000, $$This funding enables the Army's Next Generation Command and Control (NGC2) initiative to modernize Command and Control (C2) systems. PF-D/M is a software only program that is using a Continuous Integration/Continuous Delivery (CI/CD) approach to software development and capability deployment. This includes utilizing modern software development methodologies, tools/techniques (e.g., DEVSECOPS) and human-centered design processes (e.g., Soldier Touch Points [STPs]) to iteratively develop and deliver software to meet Warfighter priority needs. The CI/CD approach will feature continuous development and integration with testing and user engagements (STPs) as integral parts of the process to ensure delivered capability satisfies requirements and adds value for the Warfighter. PF-D/M is a software application that provides the dismounted and mounted Forward Observer (FO) and Fire Support Teams (FISTs) the ability to execute fire missions. Operating on the Nett Warrior End User Device (EUD), PF-D provides the dismounted FO and FISTs the ability and functionality to locate ground targets accurately and rapidly process a Call for Fires, which is the act of requesting a fire mission against the identified ground target. PF-D answers the Mobile/Handheld Computing Environment requirement that all handheld applications reside on the Nett Warrior EUD. PF-M replaces the Lightweight Forward Entry Device's (LFED) Forward Observer Software (FOS) at the maneuver company FIST, allowing them to identify ground targets and request fire missions. PF-M answers the Mounted Computing Environment (MCE) requirement to reside on the Mounted Family of Computing Systems (MFOCS). FY 2026 funding of $8.424 million will be utilized for continued development of capabilities into the targeted computing environments, including net-enabled weapons capability with joint services. Funding also supports alignment with Nett Warrior architecture changes for Precision Fires software to integrate with Mounted Mission Command-Software (MMC-S) and operate within the MCE on fire support vehicles to include vehicle integration of BFIST and Stryker.$$, 8424000, NULL, NULL, NULL, NULL, 4267000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0203728A_EF8$$, $$0203728A$$, $$EF8$$, $$AFATDS Increment 1$$, NULL, $$Project EF8 funding in FY 2026 and beyond was realigned in support of the Army's Next Generation Command and Control (NGC2) initiative to modernize Command and Control (C2) systems, for the Data and Application Layers. This capability, along with its resources and requirement will transition under the overarching NGC2 capability to eliminate stove-piping, reduce duplication of effort, and provide capability within a single NGC2 core architecture. AFATDS is used to plan, execute, and deliver lethal and non-lethal effects and provides Joint/Coalition Situational Awareness for fires execution and mission management. AFATDS provides the Army and Marine Corps automated fire support command, control and communications and supports Hypersonic and LRPF capabilities by 1) serving as the key sensor-to-shooter link for the Army and Marine Corps; and 2) providing fully automated support for planning, coordinating, controlling and executing fires and effects. The supported LRPF systems include Extended Range Guided Multiple Launch Rocket System (ER-GMLRS) and Precision Strike Missile System (PrSM). AFATDS also provides Joint Targeting support to multi-domain operations and will address emerging sensor-to-shooter initiatives. Other Joint and Multinational capabilities include the Navy Marine Expeditionary Ship Interdiction System (NMESIS), and Australia's AS9 Self-propelled Howitzer and ASSEGAI 155mm family of munitions. The system interoperates and integrates with over 80 different battlefield systems, including Navy and Air Force command and control weapons systems. As a member of the Artillery System Cooperation Agreement (ASCA), AFATDS is interoperable with 17 coalition partner nation fire support C2 systems. The program is currently fielding the AFATDS 6.8 baseline, which automates the planning, coordination, and control of all fire support assets (field artillery, mortars, close air support, naval gunfire, attack helicopters, offensive electronic warfare, fire support meteorological systems, forward observers, and fire support radars). A software only program, AFATDS is using a Continuous Integration/Continuous Delivery (CI/CD) approach to capability development and deployment. This includes employing modern software development methodologies (e.g., agile, etc.), tools/techniques (e.g., DEVSECOPS, etc.) and human-centered design processes (e.g., Soldier Touch Points [STPs], etc.) to iteratively develop and deliver software that meets Warfighter priority needs. The CI/CD approach will feature continuous development and integration with testing and user engagements (STPs) as integral parts of the process to ensure delivered capability satisfies requirements and adds value for the Warfighter.$$, NULL, NULL, NULL, NULL, NULL, 33268000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0203735A_280$$, $$0203735A$$, $$280$$, $$RECOV VEH IMPROV PROG$$, NULL, $$The M88 Heavy Equipment Recovery Combat Utility Lift and Evacuation System (HERCULES), designated as an Acquisition Category (ACAT) IC program on 15 Jun 2016, has been providing towing, winching, and hoisting operations to support battlefield recovery operations and evacuation of heavy tanks and other tracked combat vehicles since its production and deployment in 1998. The M88 HERCULES recovers tanks mired to different depths, removes M1 Abrams turrets and power packs, and uprights overturned heavy combat vehicles. Currently, the M88A2 is unable to safely perform Single Vehicle Recovery (SVR) of the Abrams tank in all conditions, due to added weight/survivability improvements made to the tank. To ensure single vehicle recovery is met, Project Manager-Mounted Armored Vehicle (PM-MAV) will develop and integrate Engineering Change Proposal (ECP) technologies for the M88A2 HERCULES through an initiative to meet its operational requirements of single vehicle recovery throughout its life cycle. This initiative is not intended to exceed current operational capability but will instead regain single vehicle recovery capability of the heaviest tracked combat vehicle.$$, NULL, NULL, NULL, NULL, NULL, 12715000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601153N_1396$$, $$0601153N$$, $$1396$$, $$Naval Engineering$$, 15642000, $$This Focus Area (FA) addresses the design, fabrication, integration, and operation of ground and sea naval warfare platforms, sensors, weapons, networks, and countermeasures to maximize their operational availability and effectiveness. Research efforts regarding all aspects of platform performance, platform survivability in support of future platform-building programs, platform autonomy, autonomous systems, and control for naval systems are included in this R-2 Activity.$$, 15642000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603748N_1978$$, $$0603748N$$, $$1978$$, $$Link Plumeria$$, 153890000, $$The details of this budget justification are classified, per Executive Order 13526, Sec 1.4 (a) and are submitted annually to Congress in the classified budget justification book.$$, 153890000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0203735A_330$$, $$0203735A$$, $$330$$, $$Abrams Tank Improve Prog$$, 723505000, $$The Army approved an Engineering Change Proposal (ECP) for Abrams Modernization focused on reducing the logistical footprint of the current Abrams tank while integrating missile, drone, and other top attack protection. Abrams Modernization will leverage advances in technology to take a different technological approach to current performance requirements called out in approved platform requirements documents. The strategy for Abrams focuses on delivering capability to the warfighter to meet both near-term limitations as well as mitigating gaps and maintaining combat overmatch in the future. This approach builds on the proven ECP strategy from the Army Acquisition Executive in 3rd Quarter Fiscal Year 2011, revalidated in an Army Requirements Oversight Council (AROC) decision in 2018, and recently refocused by Army Senior Leaders in 3rd Quarter Fiscal Year 2023. The Army will modernize the tank fleet through development of the Modernization Engineering Change Proposal (ECP) which will include the best features of prior ECPs and will comply with the latest modular open systems architecture standards, allowing quicker technology upgrades. This will enable the Army and its commercial partners to design a more survivable, lighter tank that will be more effective on the battlefield at initial fielding and easier to upgrade in the future. FY 2026 base funding in the amount of $723.505 million represents a significant investment in Abrams Modernization. This funding will support, but not limited to, the continued identification, development, maturation, future integration, and demonstration of critical high priority technology candidates through FY 2026.$$, 723505000, NULL, NULL, NULL, NULL, 181027000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0203735A_DD4$$, $$0203735A$$, $$DD4$$, $$AMPV Improvement Program$$, 10757000, $$The Armored Multi-Purpose Vehicle (AMPV) is the materiel solution replacing the Army's Armored Personnel Carrier M113 Family of Vehicles within the Armored Brigade Combat Team (ABCT). It mitigates current and future capability gaps in force protection, survivability, mobility, reliability, and interoperability across the Spectrum of Conflict. Armored Multi-Purpose Vehicle improvements will address the development of Survivability, Lethality, Mobility, Network Lethality, and Communication, Command and Control (C3) improvements within the Armored Multi-Purpose Vehicle Family of Vehicles. The strategy for the Armored Multi-Purpose Vehicle Combat Vehicle Improvement line will focus on incrementally delivering enhanced capabilities to the warfighter to meet both near-term limitations as well as mitigating gaps and maintaining combat overmatch in the future while transitioning material capabilities for integration and implementation to the Armored Multi-Purpose Vehicle Family of Vehicles fleet to increase combat capability. Fiscal year 2026 base funding in the amount of $10.757 million supports funding for: Army requested changes and requests stemming from the Initial Operational Test, continues development and integration of Composite Rubber Track, Vehicular Situational Awareness (formerly Enhanced Driver Viewer System), and Armored Multi- Purpose Vehicle mission equipment packages. As required, supports Army assessment, experimentation, and testing from emerging Army requirements impacting the Armored Multi-Purpose Vehicle. The Composite Rubber Track is a single continuous 'band' of track manufactured from multiple rubber compounds, Kevlar, steel reinforcement, and metallic composite stiffeners. The Composite Rubber Track as well as segmented track offers significant advantages compared to traditional linked steel track to include vehicle weight savings, improved fuel economy, improved track and road wheel durability, and reduced soldier maintenance. Vehicular situational awareness will provide the driver and vehicle commander improved visibility surrounding the vehicle to prevent safety incidents, such as vehicle rollovers, that may lead to soldier injuries. The future Armored Multi-Purpose Vehicle mission equipment packages will configure the vehicle to meet emerging Army requirements to support combat operations with the Engineers, Field Artillery, Remote Control Vehicle, and any other mission set to include counter unmanned aerial systems (C-UAS).$$, 10757000, NULL, NULL, NULL, NULL, 11903000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0203735A_EE2$$, $$0203735A$$, $$EE2$$, $$Stryker Improvement$$, 9823000, $$Stryker Improvement will address the development of Lethality, Survivability, Mobility, Network Lethality, and Communication, Command, Control, Computers and Cyber (C5) improvements within the Stryker Family of Vehicles (FOVs). Principal development efforts include upgrades associated with the Stryker Double V-Hull A1 (DVH A1) Engineering Change Proposal (ECP), Common Remotely Operated Weapon Station-Javelin (CROWS-J) Operational Need Statement (ONS), Stryker Survivability Enhancement, and Stryker Lethality ECPs. DVH A1 ECP upgrades restore Stryker DVH Space, Weight, and Power-Cooling (SWaP-C) lost as a result of incorporating vehicle changes to counter threats encountered during deployment operations while allowing the future network to be hosted without further degradation in vehicle protection and mobility. The Stryker CROWS-J ONS efforts addressed Urgent Operational Need to increase the lethality of Stryker Infantry Carrier Vehicles (ICV) within the United States Army European Command (USAREUR). The Stryker Survivability Enhancements address evolving threats by assessing survivability improvements and advancing technologies and integrating emerging and existing technologies and other Stryker based platform solutions. The Stryker program will also integrate future Mission Equipment Packages (MEP), including the Fire Direction Center (FDC). The FDC provides an on-the move capability that processes voice and digital data while maintaining contact with the indirect fire team over extended distances. Stryker Lethality ECP efforts (CROWS-J, Anti-Tank Guided Missile (ATGM), and other capabilities) focus on the integration of a suite of complementary MEP lethality upgrades that will improve the suppressive fire and armored vehicle engagement capabilities across the Army's Stryker Brigade Combat Teams (SBCTs). Additionally, the Lethality Mission Equipment Package (MEP) upgrades address existing Remote Weapon Station (RWS) obsolescence issues with the CROWS and CROWS-J upgrade, as well as Network Lethality capability and improvements such as Counter Unmanned Aerial Systems. The ATGM ECP upgrades the Modified Improved Target Acquisitions System (MITAS), incorporating far target locator and enabling the dissemination of target acquirement information utilizing networked lethality, providing a common operating picture. The ATGM ECP also added the Embedded Training System Software (ETSS) and integrated the M-Code Global Positioning System (GPS) Receiver into the MITAS. Adding these capabilities addressed the obsolescence of the following: Basic Skills Trainer, Card Rack Assembly that is the controller of the ATGM primary weapon system, and SAASM GPS receiver of the MITAS Precision Far Target Locator. Stryker Network Modernization formalizes the system integration of the network modernization efforts, including Integrated Tactical Network (ITN). In support of Readiness/Training-Rapid Fielding of Digitization of Stryker, Army Rapid Sustainment Improvement Process (RSIP) supports development of data transfers of maintenance work orders, parts ordering and updating of maintenance plans. Predictive logistics development and integration improvements focus on incorporation of health data elements from platform diagnostics.$$, 9823000, NULL, NULL, NULL, NULL, 18074000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0203743A_FF9$$, $$0203743A$$, $$FF9$$, $$PIM Improvement Program$$, 107826000, $$Self-Propelled Howitzer Modernization effort improves self-propelled howitzer lethality through increased range and increased rate of fire, using mature technology to improve mobility, survivability, reliability, supportability, and lethality. This effort will analyze and evaluate new cannon technology, including existing and future artillery systems as well as technology to improve mission cycle time and enable future platform autonomy. This effort will also inform requirements, release request for vendor proposals and evaluate vendor offerings.$$, 107826000, NULL, NULL, NULL, NULL, 22066000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0203752A_106$$, $$0203752A$$, $$106$$, $$A/C Compon Improv Prog$$, 237000, $$The Aircraft Engine Component Improvement Program (CIP) develops, tests, and qualifies improvements to aircraft engine components to correct service-revealed deficiencies, improve flight safety, enhance readiness and reduce operating and support (O&S) costs. In addition, CIP provides the test vehicles for the testing and qualification efforts required as a part of the Army's Critical Safety Item (CSI) program. Non-program specific Auxiliary Power Unit (APU) as well as Unmanned Aircraft Systems (UAS) safety and readiness issues are also addressed. Work in this Project is performed by the United States Army Futures Command (AFC), U.S. Army Combat Capabilities Development Command (DEVCOM) Aviation & Missile Center (AvMC), Redstone Arsenal, AL.$$, 237000, NULL, NULL, NULL, NULL, 146000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0203758A_374$$, $$0203758A$$, $$374$$, $$HOR Battlefld Digitizn$$, 1013000, $$As the Army Equipping methodology transitions to the Army Modernization Enterprise or AME, the information technology used to support Army Equipping must grow and change. The development of an upgraded Army Equipping Enterprise System (AE2S) will integrate and share programming data (dollars and quantities) with information from IT systems that support the Army Futures Command (AFC), ASA(ALT), ASA(FM&C) and Army G3/5/7. This data sharing will allow the AME to provide Army Senior Leaders with a complete picture of how well programs are executing, the impacts of programming decisions on Army current and future readiness and modernization and will help to develop a road map needed to transition the current force to a fully modernize Army. The AE2S next generation capability requirements include a flexible data and software architectures that allows the user to integrate disparate data from differing architectures in order to develop new information that can be turned into actionable knowledge by senior leaders. The software architecture must have data visualization capabilities that allow the user to display data in ways that can articulate how AME decisions made impact warfighting effectiveness and plans.$$, 1013000, NULL, NULL, NULL, NULL, 1460000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0205219F_675249$$, $$0205219F$$, $$675249$$, $$MQ-9 Upgrade$$, 0, $$The MQ-9 Upgrade Program delivers new software, hardware, and integrations to the MQ-9 fleet to keep pace with changing mission demands. The goal is to introduce improvements in software, hardware, and sustainability, addressing requirements outlined in the Combat Capability List (CCL). These requirements encompass a wide range of areas, including MQ-9 Multi-Domain Operations (M2DO), simplified system configurations, technology upgrades, enhanced pilot awareness, improved reconnaissance and targeting, expanded weapon options, increased adaptability to different environments, better security, reduced logistical burden, warfighter training, and addressing parts obsolescence. The MQ-9 program is currently supporting Joint Urgent Operational Needs requests CC-0575, CC-0578, and EC-0020. M2DO configuration consists of Anti-Jamming GPS, Enhanced Power, Link 16, Open Mission System (OMS) (to include Stellar Relay and Intelligent Electronics Unit (iEU)), and Command and Control (C2) Resiliency to maintain its viability in modern conflict. In the FY2025 PB there was a database error which incorrectly placed the entire budget of $6.814M in the MQ-9 Upgrade BPAC (675249). The Air Force will execute the FY2025 budget out of both the MQ-9 Upgrade BPAC (675249) and the MQ-9 SLAM BPAC (675212). This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0203801A_038$$, $$0203801A$$, $$038$$, $$Avenger PIP$$, 1338000, $$Avenger is a lightweight, ground-to-air missile and gun weapon system mounted on a High Mobility Multi-Purpose Wheeled Vehicle. The system protects against unmanned aircraft systems, cruise missiles, and fixed and rotary wing threats. Avenger provides day/night adverse weather operations, shoot on the move capability, rapid target engagement, and remote firing capability. It can be air dropped, lifted by helicopter and is air transportable. The system employs up to eight Stinger missiles to counter aerial threats and a .50 Caliber Machine Gun (M3P) for close-in ground and air threats. An Identification Friend or Foe (IFF) system aids in the identification of friendly aircraft in order to minimize the potential for fratricide. The Avenger fleet of 421 systems includes 169 systems that are equipped with a digital Slew-to-Cue (STC) capability to speed target detection and engagement. The Avenger Modification - Service Life Extension Program (MOD-SLEP) consists of Project 038: Avenger Production Improvement Program (PIP) and Program Element CE8710: Avenger MODS. The ongoing MOD-SLEP addresses obsolescence of Avenger components to ensure Avenger maintains operational capability through the end of its economic useful life. Key MOD-SLEP components are: the Targeting Console (TC), the M3P, the Avenger Fire Control Computer (AFCC), the Mode 5 IFF, the Vehicle Internal Communications (VIC-5), and the Assured Positioning Navigation and Timing (A-PNT) capability. The AFCC and TC are fielded to the STC Avengers. All other components are fielded to the entire Avenger fleet. FY 2026 funding of $1.338 million provides continues system testing requirements and system improvements to address evolving threats.$$, 1338000, NULL, NULL, NULL, NULL, 4203000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0203802A_VV2$$, $$0203802A$$, $$VV2$$, $$TOW$$, NULL, $$PE 0203802A VV2: TOW Weapon System includes the Improved Target Acquisition System (ITAS) and other TOW missile launchers, TOW missiles (BGM-71 series) and other missiles capable of being fired from TOW Missile launchers, and associated tactical training aids/devices. The TOW Weapon System provides long-range, lethal anti-armor and precision assault fires capability for Army Infantry Brigade Combat Teams (IBCT), Stryker Brigade Combat Teams (SBCT) and Armor Brigade Combat Teams (ABCT) within the Active, Reserve, and National Guard components. The United States Marine Corps (USMC) employs the TOW missile from its ITAS derived M41A7 Saber launchers and Anti-Tank Guided Missile (ATGM) vehicles. The TOW Weapon System improvement program integrates U.S. Army missile and launcher modifications to improve missile safety and reliability, increase system survivability and lethality, and enhance system network capabilities. These capability improvements support Multi-Domain Operations (MDO) as a part of Joint All Domain Operations (JADO) and the Functional Concept for Movement and Maneuver by providing precise lethal capabilities in multiple domains against armored threat systems. PE 0203802A VV2: TOW has no FY 2026 funding request. FY 2025 Program Change of $3.000 million for Congressional Add: Containerized Weapon System-APKWS (CWS-A). CWS-A has demonstrated ability to defeat Group II through III UAS threats. It provides networked sensor to shooter interface enabling multiple stations remotely controlled by a single operator from a protected location. CWS-A increases stand-off situational awareness and security of Command Posts and other Critical Capabilities Assets and Activities (CCAA) and reduces the manpower required to protect semi-fixed locations enabling increased patrols for area security, movement corridors, and response force operations.$$, NULL, NULL, NULL, NULL, NULL, 9677000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0204202N_2464$$, $$0204202N$$, $$2464$$, $$DD(X) Sys Design, Dev & Integration$$, 58817000, $$The Zumwalt class destroyer (DDG 1000) program is developing the naval surface hypersonic strike capability, able to conduct independent forward deployed operations and prosecute deep-inland, time-critical, soft and medium-hardened targets in a contested environment. With the addition of surface hypersonic strike to legacy capabilities, Zumwalt will provide means to conduct Joint Surface Strike, deliver local area defense against air, surface and undersea threats, and incorporate signature reduction to operate in all threat environments. The Zumwalt class will have seamless Joint Interoperability to integrate all source information for battlespace awareness and weapons direction. The surface hypersonic strike capability, combined with the low observable characteristics of the Zumwalt platform, creates a uniquely lethal and survivable naval surface platform. The Zumwalt class supports the National Defense Strategy by supporting modernization initiatives for fielding hypersonic technologies and enabling a more lethal force. Overall, the Zumwalt class will enhance U.S. conventional power projection by providing an independent forward deployed strike platform, with longer range, shorter time of flight, and higher survivability against enemy defenses compared to current capabilities. The Acquisition Decision Memorandum signed by The Assistant Secretary of the Navy (Research, Development and Acquisition) (ASN(RDA)) directed PEO Ships to integrate Conventional Prompt Strike (CPS) into USS Zumwalt (DDG 1000) and USS Michael Monsoor (DDG 1001) by conducting a Building Yard Modernization Period (BYMP) and into USS Lyndon B. Johnson (DDG 1002) during new construction, prior to the ship's arrival in homeport, in order to maximize its fleet availability time. Full operational capability is achieved when the Zumwalt CPS Weapon System modernizations are completed, and all the three ships are turned over to the Fleet. The Zumwalt program strategy is to leverage the development efforts for a CPS capability on Virginia submarines, using a minimal integration solution to rapidly provide a surface hypersonic strike capability to the Fleet. Funding provided is for development activities necessary to integrate CPS onto all three Zumwalt class destroyers and to perform the required systems engineering, analysis, modeling, and simulation, to modify the CPS Virginia design as necessary to install, field, and sustain CPS capability on Zumwalt class through the ships' remaining service life. Key activities to support CPS integration are: 1. Product and Software Development: Efforts required to modernize Zumwalt class destroyers to support the CPS Weapon System and delivery of a surface hypersonic strike capability to the Fleet. 2. Test and Evaluation: Platform level testing requirements resulting from the integration of CPS. 3. Management Services: Modifications to Zumwalt manpower, logistics, and sustainment requirements resulting from the integration of CPS.$$, 58817000, NULL, NULL, NULL, NULL, 2309920000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0205219F_675212$$, $$0205219F$$, $$675212$$, $$MQ-9 SLAM$$, 26393000, $$The MQ-9 System Lifecycle Agile Modernization (SLAM) Program enables rapid fielding of new software, hardware, and integration for the MQ-9 fleet to meet evolving mission needs. The objective is to rapidly field new software, hardware, and sustainability improvements into the MQ-9 fleet, addressing requirements from the Combat Capability List (CCL). These requirements include but are not limited to: MQ-9 Multi-Domain Operations (M2DO); streamlining system configurations; performing technology upgrades; enhancing pilot awareness and usability; improving reconnaissance, targeting, and exploitation capabilities; expanding weapons system selection and lethality; increasing suitability for diverse operational theaters; improving security and self-protection measures; reducing the logistics footprint; providing warfighter training; concept exploration; Diminishing Manufacturing Source (DMS); and developing prototypes. MQ-9 is currently supporting Joint Urgent Operational Need (JUON) CC-0575, CC-0578, and EC-0020. M2DO configuration consists of Anti-Jamming GPS, Enhanced Power, Link 16, Open Mission System (OMS) (to include Stellar Relay and Intelligent Electronics Unit (iEU)), and Command and Control (C2) Resiliency to maintain its viability in modern conflict. In the FY2025 PB there was a database error which incorrectly placed the entire budget of $6.814M in the MQ-9 Upgrade BPAC (675249). The Air Force will execute the FY2025 budget out of both the MQ-9 Upgrade BPAC (675249) and the MQ-9 SLAM BPAC (675212). This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F.$$, 26393000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601153N_1508$$, $$0601153N$$, $$1508$$, $$Undersea Systems$$, 6916000, $$This Focus Area (FA) addresses innovative affordable, persistent, and stealthy undersea systems that leverage the asymmetric US Navy advantage afforded by subsurface operations$$, 6916000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0205671F_674518$$, $$0205671F$$, $$674518$$, $$JCREW VEHICLE$$, 3424000, $$Program funds Counter Radio-Controlled Improvised Explosive Device Electronic Warfare (CREW) Mounted, Dismounted, and Fixed systems. CREW devices are self- protection systems critical to Mine Resistant, Ambush Protected (MRAP) vehicle mounted, Joint Light Tactical Vehicle (JLTV) mounted, Explosive Ordinance Disposal and Tactical Air Control Party (TACP) dismounted and Security Forces (SF) Entry Control Point fixed operations. Includes integration of the devices into currently fielded systems. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24 $0.00M was expended for civilian pay expenses in this program element, and in FY25 $0.00M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 3424000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0205778A_DL1$$, $$0205778A$$, $$DL1$$, $$Extended Range GMLRS$$, 30776000, $$The DL1 project code funds efforts to enhance Extended Range Guided Multiple Launch Rocket System (ER-GMLRS) rockets and common components under Project DL1: Extended Range GMLRS. The Army is requesting funding for ER-GMLRS Research, Development, Test and Evaluation (RDT&E) development, integration, and test activities to enhance operational capabilities including increased range, improved lethality and survivability, enhanced flight performance, and Assured Positioning, Navigation and Timing (APNT). FY 2026 dollars in the amount of $30.776 million will fund system level qualification of the ER-GMLRS with a redesigned Side Mounted Proximity Sensor and the Enhanced Alternative Warhead.$$, 30776000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0205778A_EG2$$, $$0205778A$$, $$EG2$$, $$GMLRS Alternative Warheads$$, NULL, $$Continuation of the EAW qualification effort beyond FY 2024 is funded under Projects EG3 / Guided MLRS and DL1 / Extended Range GMLRS. The U.S. Army initially funded the development of the Guided Multiple Launch Rocket System (GMLRS) Alternative Warhead (AW) increment under the Project EG2: GMLRS Alternative Warheads project code. GMLRS AW entered full rate production in 2015. The 26 October 2016 Deputy Secretary's Management Action Group (DMAG) directed the Army to define and execute an effort for a GMLRS modification that would integrate a seeker into the rocket. The Army prioritized integration of an Enhanced Alternative Warhead (EAW) into a standard range GMLRS rocket over continuation of the seeker spiral.$$, NULL, NULL, NULL, NULL, NULL, 23475000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0205778A_EG3$$, $$0205778A$$, $$EG3$$, $$Guided MLRS$$, 2531000, $$The U.S. Army continues to explore ways to enhance Guided Multiple Launch Rocket System (GMLRS) rockets and common components under Project EG3: Guided MLRS. The Army is requesting funding for GMLRS Research, Development, Test and Evaluation (RDT&E) development, integration, and test activities to enhance operational capabilities including increased range, improved lethality and survivability, enhanced flight performance, and Assured Positioning, Navigation and Timing (APNT). FY 2026 dollars in the amount of $2.531 million will fund continuation of APNT development activities.$$, 2531000, NULL, NULL, NULL, NULL, 47333000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207039F_650099$$, $$0207039F$$, $$650099$$, $$Cognitive Electronic$$, 44267000, $$Cognitive Electromagnetic Warfare is an Air Force capability to analyze adversaries' use of the electromagnetic spectrum (EMS), make real-time decisions assisted by machine learning/artificial intelligence, preform effective electromagnetic attack (EA), and share EA techniques and identification/targeting criteria to the joint warfighting force. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 060531F, 0605833F, 0605898F, 0606398F. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System        PE 0207039F / Cognitive Electromagnetic Warfare Development & Demonstration (SDD)$$, 44267000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207040F_670400$$, $$0207040F$$, $$670400$$, $$SPECTRUM$$, 0, $$The Angry Kitten Combat System (AKCS) program has developed electronic attack capabilities supporting USAF fighter and attack platforms. The current 4th generation electronic warfare (EW) pods have diminishing manufacturing sources and require advanced capabilities. The AKCS program developed prototype EW systems for 4th/5th generation aircraft that improve threat detection techniques, incorporate open system architecture, and advance rapid reprogramming capabilities. Funds were utilized to leverage existing EW pod components and develop a relevant EW system supporting fighter and attack platforms. No funding required in FY26. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY23 0.0M was expended for civilian pay expenses in this program element. In FY24, FY25 & FY26 0.0M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0207040F / Multi-Platform Electronic Warfare Equipment Operational Systems Development$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0303260F_674550$$, $$0303260F$$, $$674550$$, $$Air Base Resiliency$$, 356000, $$Air Base Resiliency information remain classified and will be provided in the appropriate forum on a need-to-know basis. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898, 0606398F. In FY 2024 $0 million was expended for civilian pay expenses in this program element, and in FY 2025 $0 million is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 356000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207110F_656009$$, $$0207110F$$, $$656009$$, $$F-47$$, 2579362000, $$F-47 enables Air Superiority for the Joint Force in the most challenging operational environments. Key F-47 attributes include enhancements to survivability, lethality, persistence, crewed/uncrewed teaming and interoperability across a range of military operations. Program activities include the employment of digital acquisitions through the application of digital engineering, agile software development, open systems architectures and digital systems infrastructure as well as the design, build, and test of full weapon systems with supporting elements. Funding provides for operational concept exploration, technology studies, multi-domain integration assessments, operational and system architecture development, maturation/risk reduction, prototyping, and Engineering and Manufacturing Development (EMD) of F-47 and related technologies. These technologies include autonomy, weapon systems, mission systems, government referenced architectures for standards and interfaces, terrestrial systems, training, product support, integrated system concept development and demonstration, as well as activities for full weapon system design, build, test, and program management support. Program management support costs include, but are not limited to, contractor support services, civilian pay, supplies, and facility related expenses. F-47 technologies are available to other DoD systems based on emerging threats, AF priorities, and development capacity. The FY 2026 request for F-47 includes 2,579,362 thousand of discretionary and 900,000 thousand of mandatory (reconciliation) for a total of 3,479,632 thousand. The mandatory funds address Air Superiority in FY 2026. Further information for this reconciliation request is provided in Section 20007 (Air Superiority) of the Reconciliation Exhibit. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                            Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System          PE 0207110F / F-47 Development & Demonstration (SDD)$$, 2579362000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207133F_672671$$, $$0207133F$$, $$672671$$, $$F-16 Squadrons$$, 216638000, $$The F-16 is a multi-role fighter that comprises roughly 40% of the USAF fighter fleet with over 830 aircraft supporting a variety of air-to-air and air-to-surface missions, such as offensive and defensive counter-air, close air support, forward air control, air interdiction (day/night and all-weather) and Suppression of Enemy Air Defenses (SEAD)/Destruction of Enemy Air Defenses (DEAD). F-16 posture and readiness combined with low operating costs deliver affordable capacity for the USAF and partner nations. Its capabilities continue to evolve, capitalizing upon advancements made in computers, avionics systems, engines, and structural technologies. These advancements meet emerging warfighter requirements to combat current and evolving enemy threats. Funding described in this document provides upgrades to the F-16 platform necessary for the delivery of joint lethality in the coming decades. These computer processing and avionics upgrades are critical to a modernized architecture compatible with current open, agile, and digital concepts that will maintain platform viability into the 2040s. Post-Block and Pre-Block F-16s have similar capabilities and are interoperable but require some independent modernization and sustainment of hardware, software, and training. The F-16 Foreign Military Sales (FMS) Program is one of the largest in DoD, providing assurance to 29 partners and growing. F-16 remains in production in South Carolina and additional nations continue to commit to new aircraft purchases. RDT&E efforts include, but are not limited to, enduring programs for Operational Flight Program (OFP) Software (SW) development, Integrated Test activities, Active Electronically Scanned Array (AESA) radar, Simulators/Trainers, Engineering Manufacturing and Design (EMD) Hardware/Advanced capability improvements, and Diminishing Manufacturing Sources (DMS). Programs ending funded development activities for Integrated Viper Electronic Warfare Suite (IVEWS) and M-Code. Programs complete or nearing full development completion for Modular Mission Computer (MMC) Upgrade/Programmable Display Generator (PDG) Upgrade, Advanced Identification Friend or Foe (AIFF-Mode 5) APX-127, and Data Bus Cybersecurity. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, 0605898F. In FY24, 7.067M is the estimate for civilian pay expenses in this program element, and in FY25 7.397M is forecasted for civilian pay expenses in this program element. This program element may include necessary emergent or unanticipated civilian pay expenses required to manage, execute, and delivery F-16 modifications for emergent or unanticipated weapon system capability. The use of such program funds would be in addition to civilian pay expenses budgeted in program element 0605828F. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0207133F / F-16 Squadrons Operational Systems Development The FY 2026 request was reduced by $2.148 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 216638000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207134F_676020$$, $$0207134F$$, $$676020$$, $$F-15 Modernization$$, 233018000, $$F-15 Modernization development efforts continue the weapon system's evolution in support of the National Defense Strategy (NDS), ensuring the fleet can meet urgent and future capability needs, as well as compliment 5th-generation aircraft by bringing substantial capacity for long-range fires, sensors, and electronic warfare (EW) capabilities. The programs below provide the F-15 fleet with electronic protection (EP) improvements, electronic attack (EA) improvements, advanced capabilities, threat and vulnerability mitigation, continued nuclear mission certification, and integration of new and upgraded weapons. Operational Flight Program (OFP) funding provides for ongoing software and hardware upgrades needed to meet and defeat emerging threats; integrate new and changing weapons, offensive and defensive avionics capabilities, and sensor capabilities; and support nuclear certification and aircraft subsystems. Funds also provide for resolution of emerging safety of flight issues, technology insertion, training system updates, and compliance with Federal, Department of Defense, or Air Force mandates that are necessary to ensure continued aircrew safety and mission effectiveness. Funds may also help resolve diminishing manufacturing sources issues. In 2023, the OFP program transitioned to a Continuous Development and Integration (CD&I) approach to deliver annual software releases via agile development techniques. This approach has demonstrated the ability to combat the speed of adversary technology evolution and ensure the F-15 fleet maintains a competitive advantage. At any one time there will be up to three OFP upgrades in work: one in requirements definition, one in code writing and test, and one in flight test and release preparation. Flight Test funding supports ongoing F-15 Modernization by providing baseline infrastructure and personnel support for developmental test (DT) and operational test (OT) operations. In FY 2026, the Flight Test budget request includes funds for upgrading test jets to meet DT & OT requirements. Radar Enhancements (RE) will continue the upgrade for digital Active Electronic Scanned Array (AESA) radar capabilities to counter sophisticated electronic threats and provide other capability improvements. OFP updates are required to ensure radar EP and EA improvements, and advanced capabilities, are seamlessly integrated into the F-15 fleet. Infrared Search and Track (IRST) system provides air to air detection, tracking, and ranging capabilities in a radar-contested environment. Multifunctional Information Distribution System - Joint Tactical Radio System (MIDS-JTRS) integrates a new Link 16 system that complies with a National Security Agency (NSA) mandate on cryptographic modernization and a Federal Aviation Administration (FAA) mandate on frequency remapping. The FAA mandate requires all fielded Link-16 terminals incorporate the frequency re-mapping capability by 2025.$$, 233018000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207136F_674595$$, $$0207136F$$, $$674595$$, $$F-16 HARM Targeting$$, 17680000, $$The FY 2026 request was reduced by .186 Million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” The Manned Destructive Suppression (MDS) program funds the development and sustainment of the Air Force's Suppression of Enemy Air Defenses (SEAD) and Destruction of Enemy Air Defenses (DEAD) capabilities. The F-16 High-speed Anti-Radiation Missile (HARM) Targeting System (HTS) is currently the only programmed reactive SEAD/DEAD capability and enables targeting the HARM missile in its most lethal 'range known' mode. The program provides F-16 Block 50/52 and Block 40/42 aircraft with the ability to employ the AN/ASQ-213 targeting Pod. With the introduction of Pre-Planned Product Improvement (P3I) HTS Revision 7 in 2007, the AN/ASQ-213 Pod now has a precision geo-location capability to target Precision Guided Munitions (PGMs) to destroy fixed and mobile enemy air defense elements. Additionally, by relocating the AN/ASQ-213 HTS R7 Pod on the aircraft, the F-16 can simultaneously carry the HTS R7 Pod and an Advanced Targeting Pod (ATP). HTS R7 fielding is complete and represents the Air Force's near-term solution for reactive time-critical targeting for DEAD until this mission can be transferred to the F-35. HTS R7 derived precision targeting data can be provided to all Joint Forces via Link-16. This effort continues upgrades for the HTS and applies technologies similar to those demonstrated in the Advanced Tactical Targeting Technologies (AT3) program and HTS R7 development. Funds may be used to address emerging and short-notice Diminishing Manufacturing Sources and Material Shortage (DMSMS) issues. HTS leverages Digital acquisition tenets of open, agile and digital. This may include providing funds to prime contractors; program office contract support; facility, security and IT upgrades; common component development with other weapon systems to reduce redundant costs. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program elements 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2024 0.00M was expended for civilian pay expenses in this program element, and in FY2025 0.00M is forecasted for civilian pay expenses in this program. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0207136F / Manned Destructive Suppression Operational Systems Development$$, 17680000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207138F_674785$$, $$0207138F$$, $$674785$$, $$F-22$$, 852332000, $$The F-22 Raptor is a multi-mission fighter aircraft that combines low observability, supercruise, maneuverability and integrated avionics providing air superiority to the Joint Force, access in highly contested environments, as well as homeland and cruise missile defense. To maintain operational relevance, the program continues planned, incremental modernization efforts that enhance both F-22 air superiority and strike capabilities. The F-22 modernization enterprise develops, tests, and fields hardware/software of the air vehicle, engine, Operational Flight Program (OFP), and training systems to improve F-22 weapons, communications, navigation, pilot- vehicle interface, and electronic warfare suite. Funds may be used to resolve emerging safety of flight and diminishing manufacturing sources issues, accommodate technology insertion and fulfill Federal Aviation Administration (FAA) or other mandates necessary to ensure continued aircrew safety and mission effectiveness. The FY 2026 cost of Middle Tier of Acquisition (MTA) effort F-22 is reflected in the budget request, including RDT&E and procurement of prototype units. The Department will certify Future Years Defense Program (FYDP) funding in a future budget submission. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY2024, 5.967M was expended for civilian pay expenses in this program element, and in FY2025, 7.311M is forecasted for civilian pay expenses in this program element. The FY 2026 request was reduced by 1.977 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, Implementing the President's Department of Government Efficiency Cost Efficiency Initiative. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0207138F / F-22A Squadrons Operational Systems Development$$, 852332000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207142F_675346$$, $$0207142F$$, $$675346$$, $$F-35$$, 26595000, $$The AFSEO delivers warfighting capability through aircraft/store compatibility testing and evaluation and provides accurate combat weapon delivery and mission planning software. Beginning in FY 2020, the USAF supported FTI wiring and weapons integration tasks related to SEEK EAGLE requests. These tasks include, but are not limited to, envelope expansion, mixed loads testing, adding additional stores, and F-35A specific risk reduction efforts and studies. The QRIP / CSFD system is a government-owned, off-the-shelf solution from the 59 TES for F-35 high-capacity data recording needs. Designed for operational test and evaluation, the system serves multiple emerging needs for data collection. By capturing Crowd Sourced Flight Data (CSFD) from operational aircraft, QRIP reduces the need for deliberate regression flight testing and allows the test enterprise to focus on Block 4 and future capability development. Working with F-35 Joint Program Office Combat Data Systems, the 59 TES will increase data ingest capable systems that will be utilized to support the data processing, storage, and transmission of all F-35 generated CSFD sources. The 59 TES will continue studying means to increase the operational viability of CSFD, including the use of data science teams, artificial intelligence, and machine learning algorithms.$$, 26595000, NULL, NULL, NULL, NULL, 34519000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207142F_676011$$, $$0207142F$$, $$676011$$, $$JSF DUAL CAPABLE AIRCRAFT$$, 21851000, $$The F-35 Joint Strike Fighter (JSF) Operational Requirements Document (ORD) calls for the F-35A variant to have the capabilities and provisions for Dual Capable Aircraft (DCA) operations in the first post System Development and Demonstration (SDD) block upgrade. DCA refers to the capability to carry and deliver conventional and non-conventional weapons. DCA operation for the F-35A is internal carriage of up to two (2) B61-12 weapons.$$, 21851000, NULL, NULL, NULL, NULL, 186565000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207146F_670131$$, $$0207146F$$, $$670131$$, $$F-15EX$$, 78345000, $$The F-15EX is a new multirole-capable fighter jet based on the 2-seat F-15QA (Qatar) configuration upgraded with advanced capabilities, including the Eagle Passive Active Warning Survivability System (EPAWSS) and the USAF F-15 Continuous Delivery & Integration (CD&I) Operational Flight Program (OFP) software. The F-15EX provides significant operational flexibility, enabling it to perform a wide range of missions sets with one or two aircrew. It will be used predominantly in defensive and offensive counter-air missions at both Air National Guard (ANG) and Air Combat Command (ACC) operational squadrons. F-15EX will perform the Homeland Defense mission and provide Combatant Commanders (CCDR) with strike packages capable of operating in Highly Contested Environments (HCE). The FY 2026 RDT&E funding request continues incremental funding of development activities started in prior years and adds funding for Long-Range Kill Chain (LRKC) and Hybrid SATCOM (Beyond Line-of-Sight communications) development, a FY 2026 new start. The FY 2026 request for the Research & Development appropriation for F-15EX includes $78,345 thousand of discretionary and $2,100 thousand of mandatory (reconciliation) for a total of $80,445 thousand. The mandatory funds will support LRKC efforts. Further information for this reconciliation request is Provided in Section 20007 (Air Superiority) of the Reconciliation Exhibit. The FY 2026 request was reduced by $0.811 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, Implementing the President's Department of Government Efficiency Cost Efficiency Initiative. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F or 0605898F. In FY 2024, 9.536M was executed for civilian pay expenses in this program element. In FY 2025, 6.206M is forecasted for civilian pay expenses in this program element. In FY 2025, the F-15EX program reduced civilian personnel to 38 positions which aligned to the Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative.” The FY 2026 request was reduced by 2.132 million from FY 2024 as reflected in the Direct Cite Authority line in Exhibit R-3. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                     Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0207146F / F-15EX Operational Systems Development FY 2020 Prior Years RDT&E funding of $385.000 million was executed in PE 0207134F (F-15E Squadrons) and is not included in this exhibit. FY 2020 RDT&E funded two F-15EX test aircraft. In FY 2021, F-15EX RDT&E efforts were continued in PE 0207146F (F-15EX). This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 78345000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602131M_9999$$, $$0602131M$$, $$9999$$, $$Congressional Adds$$, 0, $$Congressional add projects not included in other efforts.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207147F_640017$$, $$0207147F$$, $$640017$$, $$Collaborative Combat Aircraft$$, 111365000, $$Collaborative Combat Aircraft (CCA) are uncrewed weapon systems capable of enhancing crewed weapon systems ability to achieve air superiority. The program matures and leverages relevant Science and Technology investments to reduce risk by conducting targeted development, integration, and test activities. Key CCA attributes include cost of platforms, mission integrated autonomy, multi-platform interoperability, and lethality enhancement. Program activities include digital engineering, agile software development, open systems architectures, autonomy architecture, mission autonomy, crewed-uncrewed teaming, as well as the design, build, and test of full weapon systems with supporting elements. Funding provides information technology/test/training infrastructure investments, operational concept exploration, technology studies, multi-domain integration, operational assessments, architecture development, integrated weapons systems development, demonstration of air superiority related technologies, multi-level prototyping, and program management support. Program management support costs include, but are not limited to, contractor support services, civilian pay, supplies, and facility related expenses. CCA technologies are designed to become available to other DoD systems based on emerging threats, AF priorities, and development capacity. The FY 2026 request for CCA includes 111.365 million of discretionary and 678.000 million of mandatory (reconciliation) for a total of 789.365 million. The mandatory funds address Air Superiority in FY 2026. Further information for this reconciliation request is provided in Section 20007 of the Reconciliation Exhibit. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2025 9.96 million was expended for civilian pay expenses in program element 0207110F, and in FY 2026 13.537 million is forecasted for civilian pay expenses in this program element.$$, 111365000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207147M_3148$$, $$0207147M$$, $$3148$$, $$MUX TACAIR Increment I$$, 58000000, $$MAGTF Unmanned Aerial System Expeditionary Tactical Aircraft (MUX TACAIR) is a component of the USMC initiative to field a Collaborative Combat Aircraft (CCA) capability that supports mass buildup of a Joint Force against a peer/near-peer adversary. Project efforts focus on operations from austere Expeditionary Advanced Basing Operations (EABO) airfields in support of Marine Littoral Regiment (MLR) and/or Marine Expeditionary Unit (MEU) operations serving as the Stand in Force (SiF) for a Joint Force, providing lethal and flexible support to support from the land and sea. This project increases MAGTF lethality, capacity and interoperability in the reconnaissance and electronic warfare mission areas, complementing existing and future TACAIR capabilities and enhancing combat reach into the INDOPACOM Area of Responsibility (AoR), or wherever enhanced, stand-off lethality is needed by the Joint Force. MUX TACAIR will increase the survivability, lethality, interoperability, and sustainability of the Marine Corps in support of the Joint Force.$$, 58000000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207161F_674132$$, $$0207161F$$, $$674132$$, $$AIM-9 Product$$, 86549000, $$The AIM-9X Block II Sidewinder (AIM-9X Blk II) continues the evolution of the AIM-9 series of missiles. This missile program delivers a launch and leave, air combat munition that uses passive Infrared (IR) energy to acquire and track enemy air targets and complements the radar guided Advanced Medium Range Air-to-Air Missile (AMRAAM). The missile provides fighter aircrew with the first shot, first kill opportunities that are essential for survival during air combat maneuvering in the visual arena. The AIM-9X delivers these opportunities with unmatched offensive and defensive capabilities against inner boundary threats, even when IR countermeasures are employed. The AIM-9X also supports air superiority in the Beyond Visual Range air-to-air battle. Anti-tamper features have been incorporated to protect improvements inherent in this design. The AIM-9X Block II missile provides the Joint Force with fighter aircraft lethality and survivability necessary to counter threats identified in the National Defense Strategy. AIM-9X is a Post Milestone C, Acquisition Category IC joint service program led by the Department of the Navy. The Block II program has completed independent operational testing and was found to be operationally effective and suitable. The program achieved Initial Operational Capability in March 2015 and received Full Rate Production decision in August 2015. This budget line item continues technical refresh hardware and software and develops advanced capabilities to meet requirements of the Capability Production Document against evolving threat aircraft countermeasures and unmanned aircraft systems. This program element leverages Digital acquisition tenets of open, agile and digital. This may include providing funds to prime contractors; program office contract support; facility, security and IT upgrades; common component development with other weapon systems to reduce redundant costs. The FY 2026 request was reduced by -$.841 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, Implementing the President's Department of Government Efficiency Cost Efficiency Initiative. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0207161F / Tactical AIM Missiles Operational Systems Development This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, or 0606398F. In FY 2024, 100K were expended for civilian pay expenses in this program element, and in FY 2025, 100K are forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 86549000, NULL, NULL, NULL, NULL, 317629000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207163F_3600$$, $$0207163F$$, $$3600$$, $$Research, Development, Test & Evaluation, Air Force / BA 7:$$, NULL, $$The Advanced Medium Range Air-to-Air Missile (AMRAAM) is a joint Air Force/Navy, Acquisition Category 1C program with Air Force as lead service. AMRAAM is the premier all-weather, all-environment, radar guided missile with improved capabilities against very low and high-altitude targets in an electronic attack environment. The current AMRAAM variant, the AIM-120D, delivers improved performance via Global Positioning System (GPS) aided navigation; two way datalink capability for enhanced aircrew survivability and improved network compatibility; and incorporates new guidance software that improves kinematic performance and weapon effectiveness. This Air Force/Navy program is structured in response to the Joint Service Operational Requirement Document and Mission Element Need Statement to develop an air superiority air-to-air missile with significant improvements in operational utility and combat effectiveness. The development program enhances AMRAAM capability and operational flexibility against current and projected threats, incorporates high payoff technology development, performs risk reduction activities, and investigates new variants and/or alternate missions that may use AMRAAM attributes. To maximize effectiveness of existing inventory and address findings from the field, the Navy and Air Force also develop, test, and field improvements via software upgrades into fielded missiles and/or hardware upgrades inserted into the production line. This program supports the integration of the Advanced Medium Range Air-to-Air Missile (AMRAAM) into Air Force aircraft with analysis of Air Force unique applications, aircraft missile integration tasks, product improvement efforts including missile software upgrade development and procurement of hardware to support Air Force test and evaluation tasks. Leverages Digital acquisition tenets of open, agile and digital. This may include providing funds to prime contractors; program office contract support; facility, security and IT upgrades; common component development with other weapon systems to reduce redundant costs; and program management administration (PMA). The FY 2026 request was reduced by -$.582 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, Implementing the President's Department of Government Efficiency Cost Efficiency Initiative. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, or 0606398F. In FY24, $0.00 were expended for civilian pay expenses in this program element and in FY25, $0.00 are forecasted for civilian pay expenses in this program element. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                PE 0207163F / Advanced Medium Range Air-to-Air Missile (AMRAAM) Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207163F_673777$$, $$0207163F$$, $$673777$$, $$AMRAAM$$, 51242000, $$The Advanced Medium Range Air-to-Air Missile (AMRAAM) is a joint Air Force/Navy, Acquisition Category 1C program with Air Force as lead service. AMRAAM is the premier all-weather, all-environment, radar guided missile with improved capabilities against very low and high-altitude targets in an electronic attack environment. The current AMRAAM variant, the AIM-120D, delivers improved performance via Global Positioning System (GPS) aided navigation; two way datalink capability for enhanced aircrew survivability and improved network compatibility; and incorporates new guidance software that improves kinematic performance and weapon effectiveness. This Air Force/Navy program is structured in response to the Joint Service Operational Requirement Document and Mission Element Need Statement to develop an air superiority air-to-air missile with significant improvements in operational utility and combat effectiveness. The development program enhances AMRAAM capability and operational flexibility against current and projected threats, incorporates high payoff technology development, performs risk reduction activities, and investigates new variants and/or alternate missions that may use AMRAAM attributes. To maximize effectiveness of existing inventory and address findings from the field, the Navy and Air Force also develop, test, and field improvements via software upgrades into fielded missiles and/or hardware upgrades inserted into the production line. This program supports the integration of the Advanced Medium Range Air-to-Air Missile (AMRAAM) into Air Force aircraft with analysis of Air Force unique applications, aircraft missile integration tasks, product improvement efforts including missile software upgrade development and procurement of hardware to support Air Force test and evaluation tasks. Leverages Digital acquisition tenets of open, agile and digital. This may include providing funds to prime contractors; program office contract support; facility, security and IT upgrades; common component development with other weapon systems to reduce redundant costs; and program management administration (PMA). The FY 2026 request was reduced by -$.582 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, Implementing the President's Department of Government Efficiency Cost Efficiency Initiative. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, or 0606398F. In FY24, $0.00 were expended for civilian pay expenses in this program element and in FY25, $0.00 are forecasted for civilian pay expenses in this program element. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                PE 0207163F / Advanced Medium Range Air-to-Air Missile (AMRAAM) Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 51242000, NULL, NULL, NULL, NULL, 845446000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207171F_657108$$, $$0207171F$$, $$657108$$, $$EPAWSS$$, 0, $$The legacy F-15 Tactical Electronic Warfare System (TEWS) is functionally obsolete. It uses 1970's analog technology to combat 1980s-era radar-based ground and air threats. In addition, this aging system is becoming more difficult and expensive to sustain. As a result, the Air Force is replacing TEWS with the F-15 Eagle Passive/Active Warning and Survivability System (EPAWSS). F-15 EPAWSS is an advanced digital electronic warfare system capable of detecting, identifying, locating, denying, degrading, disrupting, and defeating modern and emerging threat systems in contested airspace with dense radio-frequency (RF) background environments. F-15 EPAWSS will provide indication, type, and position of ground-based RF threats as well as the indication, type, and bearing of airborne threats with the situational awareness needed to avoid, engage, or negate the threat. It will also prevent RF threat systems from detecting or acquiring accurate targeting information to complicate and/or negate an enemy threat targeting solution. Finally, EPAWSS will counter RF and infrared threat systems at end-game via electronic countermeasures (jamming), chaff, and/or flares. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, 0605898F, 0606398F. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                  Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System     PE 0207171F / F-15 EPAWSS Development & Demonstration (SDD)$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207172F_673777$$, $$0207172F$$, $$673777$$, $$AMRAAM$$, 425029000, $$The Joint Advanced Tactical Missile (JATM), designated the AIM-260A, is a high speed, long range, air dominance missile designed to defeat current and projected enemy air threats. JATM is compatible with Air Force and Navy aircraft and is critical to preserving our nation's air dominance capability for the future. JATM is a joint Air Force and Navy program with the Air Force as the lead service. Funding supports development activities associated with the JATM program. These activities include development as well as system improvement, developmental and operational test, and continued threshold platform integration. Funding will also continue science and technology (S&T) and risk reduction efforts to mature critical technologies and packaging designs for future JATM improvements and will enhance system performance to defeat pacing threats through targeted hardware and software enhancements. Notes: This program is reported in accordance with Title 10, United States Code, Section 119(a)(1) in the Special Access Program Annual Report to Congress. For further information, please contact the Director of Special Programs, OUSD(A&S)/DSP. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 425029000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207179F_643721$$, $$0207179F$$, $$643721$$, $$Experimental Operations Unit$$, 55447000, $$The Experimental Operations Unit (EOU) effort explores Doctrine, Organization, Training, Materiel, Leadership, Personnel, Facilities, and Policy (DOTMLPF-P) concepts for Collaborative Combat Aircraft (CCA). Program activities serve as early risk reduction for employment of CCA with crewed aircraft to mature operational concept development and evaluate supporting force structure to execute CCA operations. Funding provides operational concepts and studies, flight test and test support, prototypes, infrastructure investment for information technology, training and demonstration, and program management support to mature autonomous operational concepts. Program management support costs include but are not limited to contractor support services, supplies, and facility related expenses. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F.$$, 55447000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0303260N_3787$$, $$0303260N$$, $$3787$$, $$MILDEC Initiative$$, 1980000, $$The details of this program element are classified SECRET and are submitted annually to Congress in the classified budget justification books.$$, 1980000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603211F_634920$$, $$0603211F$$, $$634920$$, $$Flight Vehicle Tech Integration$$, 12221000, $$This project demonstrates advanced aerospace vehicle technologies. Aerospace Vehicle Technology Integration efforts are accomplished through integration of various technologies to include avionics, advanced propulsion, and weapon systems for demonstration in near-realistic operational environments. Advanced aerospace structures technologies are demonstrated to enhance the capability of current and future aerospace vehicles.$$, 12221000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207179F_645340$$, $$0207179F$$, $$645340$$, $$Viper Experimentation and Next-$$, 6572000, $$The Viper Experimentation and Next-gen Operations Model (VENOM) effort serves as a flying autonomy testbed for Autonomous Collaborative Platforms (ACP). Program activities reduce risk to ACP through test and demonstration of the autonomy reference architecture and autonomy software on a F-16, or other human-on- the-loop testbed. Funding provides flight test and test support (including modifications), infrastructure investments for information technology, training, and program management support to mature autonomy architecture and software. Program management support costs include but are not limited to contractor support services, supplies, and facility related expenses. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F.$$, 6572000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207227F_675352$$, $$0207227F$$, $$675352$$, $$Guardian Angel RDT&E$$, 0, $$Beginning in FY26 this funding is reported in BA 07 Project 0207457F. GA is a Family of Systems (FoS) based in both human and equipment capabilities formulated to execute Air Force Personnel Recovery (PR) across the full spectrum of military operations. Established by the Air Force Chief of Staff in 2003 and officially captured in AFPD 10-9, the GA FoS is employed by three distinct Air Force specialties: Pararescuemen (PJ), Combat Rescue Officer (CRO), and Survival, Evasion, Resistance, Escape (SERE). The GA FoS is comprised of nine critical mission areas: Precision Aerial Insertion, Information Management, Force Application, Visual Augmentation, Maritime Recovery, Ground Mobility, Technical Rescue, Medical, and SERE. GA focus is on maintaining legacy weapon system capability while modernizing/improving subsystems for better mission effectiveness. Mission Description and Budget Item Justification: To stay aligned with SECAF Operational Imperatives, with OSD Focus Area C2, logistics mobility (land/water), funds will be used to obtain significant improvements in operational capability and develop items within the GA FoS to include but not limited to: Maritime Recovery (open ocean boat ), Ground Mobility, Technical Recovery, Precision Aerial Insertion (cargo & personnel parachutes), Medical (Simulators), Information Management, SERE, Visual Augmentation (night vision, augmented reality) and Force Protection. This may be conducted through industry technology demonstrations, prototypes, and associated engineering support to posture the GA program for technology insertion. The Guardian Angel weapon system development/Innovation activities also include studies, analysis, requirements development and developmental testing to support both current and future program planning and execution, quick-reaction capability prototypes/demonstrations to accelerate planning for technology transition, technology insertion and future acquisition programs. Funding will deliver enhanced capability for the dismounted Guardian Angel Operators in terms of dramatic weight reduction, standardization of items across units, and increased mission effectiveness across the conflict spectrum. This funding request will support potential DMS and obsolescence solutions, to include if optimal, life of type buys or bridge buys limited to the program of record quantity. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 0.443M was expended for civilian pay expenses in this program element, and in FY 2025 0.361M is forecast for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                 PE 0207227F / Combat Rescue - Pararescue Operational Systems Development$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207238F_671201$$, $$0207238F$$, $$671201$$, $$E-11 Development$$, 10332000, $$Budget Program Activity Code (BPAC) 671201 is primarily focused Operational Systems Development for the E-11 BACN platform. Battlefield Airborne Communication Node (BACN) enables tactical edge Joint and Coalition information interoperability via air, space, and surface systems, to include a network for high-capacity data transfer. As requirements emerge, BACN will integrate new hardware and software capabilities that improve system performance, interoperability, availability, prototyping of activities in line with department approach of system development upgrades to support current/future Open Mission System (OMS) technologies. Efforts may include onboard enhancements such as datalink receiving capability in platform cockpit to include but not limited to Link-16, as well as analysis and developmental efforts to explore feasibility of onboard operators to support onboard payload control capabilities. Efforts include, but are not limited to, expansion of external time reference capabilities, development/integration of additional communications systems/subsystems and components such as Military Global Positioning System (MilGPS), M-code or future software and integration of advanced antennas and waveforms, development efforts enabling integration of ABMS/ JADC2 capabilities, enhancements to ground support capabilities. Additionally, safety of flight considerations, to include weapon system performance, aircraft structural integrity, availability, continuity of service requirements will be addressed, as well as aircraft avionics upgrades, early system engineering assessments and risk reduction activities associated with weapon system "payload” and "platform” survivability in non-contested through contested environments. Efforts include required non-recurring engineering and Diminishing Manufacturing Sources (DMS) issues, the development of simulators/trainers, development of training materials, the development of future waveforms that are backward compatible with existing communications, and technical publications as well as the assimilation of any mandates levied on the BACN weapon system. Execute risk reduction activities for development of future capabilities on BACN payload/aircraft efforts. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 $0.671M was expended for civilian pay expenses in this program element, and in FY 2025 $0.949M is forecast for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 10332000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207238F_675383$$, $$0207238F$$, $$675383$$, $$BATTLEFIELD AIRBORNE COMM$$, 4912000, $$Budget Program Activity Code (BPAC) 675383 is primarily focused on BACN payload weapon system components. Battlefield Airborne Communication Node (BACN) enables tactical edge Joint and Coalition information interoperability via air, space, and surface systems, to include a network for high-capacity data transfer. As requirements emerge, BACN and ROBE systems will integrate new hardware and software capabilities that improve system performance, interoperability, availability, prototyping of activities in line with department approach of system development upgrades to support current/future Open Mission System (OMS) technologies. Efforts may include onboard enhancements such as datalink receiving capability in platform cockpit to include but not limited to Link-16, as well as analysis and developmental efforts to explore feasibility of onboard operators to support onboard payload control capabilities. Efforts include, but are not limited to, expansion of external time reference capabilities, development/integration of additional communications systems/subsystems and components such as Ka-Band Satellite Communications (Ka-SATCOM), Integrated Broadcast System (IBS)The BACN payload will integrate higher capacity/low latency payload control links that possess advanced capabilities, including improved frequency hopping, anti-jamming techniques to ensure reliable and secure communication. Integration of advanced antennas and waveforms, development efforts enabling integration of ABMS/ JADC2 capabilities, enhancements to ground support capabilities. Additionally, safety of flight considerations, to include weapon system performance, aircraft structural integrity, availability, continuity of service requirements will be addressed, aircraft avionics upgrades, as well as early system engineering assessments and risk reduction activities associated with weapon system payload & platform survivability in non-contested through contested environments. Efforts include required non-recurring engineering and Diminishing Manufacturing Sources (DMS) issues, the development of simulators/trainers, development of training materials, the development of future waveforms that are backwards compatible with existing communications, and technical publications as well as the assimilation of any mandates levied on the BACN weapon system. Execute risk reduction activities for development of future capabilities on BACN payload/aircraft efforts. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 $0.671M was expended for civilian pay expenses in this program element, and in FY 2025 $0.949M is forecast for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 4912000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207247F_670001$$, $$0207247F$$, $$670001$$, $$Air Force TENCAP$$, 52492000, $$Air Force Tactical Exploitation of National Capabilities (TENCAP) increases warfighter effectiveness through the exploitation of national capabilities and promotes cross- domain integration of these capabilities into military operations/training and intelligence, surveillance and reconnaissance (ISR) activities. In FY 2026, AF TENCAP exploits existing National, global, and Non-Traditional ISR in air, space, and cyber domains for operational and tactical applications by rapidly prototyping and providing capability demonstrations. The program consists of multiple small projects supporting the Air Force warfighter. Projects are designed to transition to warfighters or national intelligence agencies for operational use and to appropriate acquisition Programs of Record for sustainment and further development. AF TENCAP projects influence the design and operation of current and future National, global, and Non-Traditional systems in air, space, and cyber while providing situational awareness to warfighters and intelligence organizations. AF TENCAP requirements and existing resources may be rapidly re-prioritized in response to emerging warfighter needs. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024, $0.000M was expected to expend for civilian pay expenses in this program element, and in FY 2025, $0.000M is forecasted for civilian pay expenses in this program element. This program element received $4.9M Ukraine Supplemental Funds in FY 2024. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                               Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0207247F / AF TENCAP Operational Systems Development$$, 52492000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207431F_675307$$, $$0207431F$$, $$675307$$, $$TARGETING ENTERPRISE$$, 32739000, $$Provides support to personnel utilizing Target Development, Planning, and Execution applications; Unit Level Intelligence; Tactical Intelligence Applications; shorten the kill chain through automation and direct support to national, combatant command, and Air Force intelligence missions. Funds enhanced dynamic F2T2EA sensor-to-shooter intel and advanced training on cloud-based apps to shorten LRKC with automated and AI-enabled Sensing Grid/ targeting tools and applications. Analyzes, visualizes, and shares National, Tactical, and open source Intel to close the capability gap against adversary's truncated kill chains. IC-ITE - IC-ITE mission is enabling greater integration, information sharing, and safeguarding with the Intelligence Community (IC) by adopting IC standards, data, and technology frameworks, and using systems of common concerns for unmatched decision advantage. This program element may include necessary emergent or unanticipated civilian pay expenses required to manage, execute, and deliver Targeting Intelligence for emergent or unanticipated weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024, 1.511M was expended for civilian pay expenses in this program element, and in FY 2025, 1.750M is forecasted for civilian pay expenses in this program element."$$, 32739000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207249F_675347$$, $$0207249F$$, $$675347$$, $$Advanced Targeting$$, 13613000, $$Advanced Targeting Pods (ATPs) provide long-range target acquisition and expanded weapon delivery envelopes for greater aircraft survivability which are imperative in supporting Long Range Kill Chain, as well as target identification, reduction in collateral damage, and fratricide prevention for F-15C/E/EX, F-16 (all blocks), A-10C, B-52H, B-1B. ATP expanded range capabilities (in all domains), such as high resolution imagery, larger aperture, eye safe laser, high system reliability and smaller deployment footprint provide greater combat effectiveness across several mission areas. Demonstrated capability to support Counter-Unmanned Aircraft System (cUAS) and Homeland Missile Defense missions. Each targeting pod provides long-range target acquisition and expanded weapon delivery envelopes during day, night, and all- weather conditions. Targeting pods are equipped with infrared (Longwave/Midwave/Shortwave Infrared, Color TV) sensor, laser designator, digital video, and real time video data link for connectivity with ground forces. FY 2026 funds will support integrating ATP advanced technology with aircraft Operational Flight Programs, upgrading pod capability, technical analysis, and testing. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 0.170M was expended for civilian pay expenses in this program element, and in FY 2025 0.489M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                 PE 0207249F / Precision Attack Systems Procurement Operational Systems Development$$, 13613000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207253F_674804$$, $$0207253F$$, $$674804$$, $$Compass Call$$, 0, $$Compass Call is the Air Force's wide-area, standoff, Airborne Electromagnetic Attack (AEA) Command and Control Warfare/Information Operations (C2W/IO) weapon system. The employment of this weapon system interrupts the adversary's use of the electromagnetic battlespace and is a key active component in the information battlespace and prosecution of current ground and airborne threats. Compass Call's sophisticated electromagnetic attack system is capable of surgical denial and/or disruption of adversary Radio Frequency (RF) communications, radar and sensor systems. Due to rapid advances in Electromagnetic Attack (EA) techniques and technology, Compass Call is designed to be adaptable, making it well-suited for a continuous modernization strategy. Such a strategy ensures Compass Call techniques evolve at a pace capable of addressing adversary tactics and emerging technologies. The Compass Call weapon system is continuously improved using a rapid development and acquisition process supporting a spiral baseline upgrade strategy. User needs and technology insertion opportunities are continuously reviewed. As a result of technology refresh initiatives, including incorporation of open architectures, "plug and play” systems, software defined radios, and modular software development, Compass Call is implementing agile processes to support weapon system development activities. In FY 2017, the Compass Call re-host program was initiated prompting transition of mission capabilities from the legacy EC-130H airframe to an EA-37B airframe. The re-hosted Compass Call platform is based on a commercial derivative G550 aircraft holding Federal Aviation Administration (FAA) Supplemental Type Certificates (STCs) for airworthiness. The platform will undergo modifications to host Compass Call's Prime Mission Equipment (PME) and antenna arrays and will receive additional STCs and Military Type Certificates (MTCs). The EA-37B aircraft will re-use PME from the EC-130H aircraft that will be upgraded to the latest Baseline. Due to the age of the EC-130H fleet, re-hosting of the PME is crucial to ensuring the longevity of this critical capability. In an effort to put capability into the warfighter's hands as soon as possible, the EA-37B program pursues concurrent developmental and production activities. EA-37B Baseline 3 (BL3) updates fielded EC-130H Mid-Baseline 2 (MBL2) capabilities, while significantly increasing operating altitude and standoff distances through re-host onto the EA-37B airframe. Baseline 4 (BL4) transitions the software baseline to an agile software framework and implements System-Wide Open Reconfigurable Dynamic Architecture (SWORD-A) to enable rapid integration of new capabilities offering increased target capacity. Requirements for Baseline 5 (BL5) are currently being determined and are intended to focus on external communications systems to improve connectivity across the battlespace. FY 2026 RDT&E efforts continue BL4 development activities, BL4 test and evaluation, maturation of AEA technologies, and trade studies for future Baseline efforts. Activities encompassed within the BL4 PME upgrade may include, but are not limited to, aircraft system integration; assembly, test and checkout; mission system Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:           PE 0207253F / Compass Call Operational Systems Development upgrades; obsolescence resolution; software development; systems engineering; test and evaluation; flight test; training systems; training events; support equipment; and Program Support Costs (PSC). Specific mission system developmental activities may include, but are not limited to, studies and analyses for future capabilities and baselines; preparation of white papers and technical reports; maturation of Technology Readiness Level (TRL) capabilities for future insertion; development of QRC applications for integration into Compass Call Software Defined Radios (SDRs); technology roadmap development; power expansion; transmit and receive development; size, weight, power and cooling (SWAP-C) reductions; transition of Compass Call PME to open architecture compliant standards; and continued migration of the Compass Call Operating System (CCOS) to an agile software construct. Compass Call funding also supports innovation activities to include studies, analyses, requirements definition, and QRC prototypes/demonstrations to accelerate planning for technology transition, technology insertion, and future acquisition programs. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605832F, 0605833F, 0605898F or 0606398F. In FY 2024 0.000M was expended for civilian pay expenses in this program element. In FY 2025 1.0M is being expended for civilian pay expenses in this program element. In FY 2026 1.0M is being expended for civilian pay expenses in this program element. The FY 2026 request for Compass Call includes $0 thousand of discretionary and $63,137 thousand of mandatory (reconciliation) for a total of $63,137 thousand. The mandatory funds increase EA-37B production by continuing development, test and evaluation, maturation of AEA technologies, and trade studies for Baseline and Future Baselines. Further information for this reconciliation request is provided in Section 20007 (Air Superiority) of the Reconciliation Exhibit. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207268F_671012$$, $$0207268F$$, $$671012$$, $$Aircraft Engine Component$$, 52734000, $$The Aircraft Engine Component Improvement Program (CIP) provides the only source of critical sustaining engineering support for in-service Air Force engines to maintain flight safety (highest priority), correct deficiencies, improve system Operational Readiness (OR), Reliability & Maintainability (R&M), reduce engine Life Cycle Cost (LCC), and sustain engines throughout their service lives. It also serves as the primary vehicle to implement emerging technology solutions (e.g., additive manufacturing and digital engineering) to resolve these issues and improve engine performance. Past investments have reduced warfighter Class A rates and decreased Engine Related Loss of Aircraft (ERLOA) and generated significant returns on investments. Priority requirements include Accelerated Mission Tests (AMTs) required for complex redesigns. The AMT provides early identification of safety/reliability issues prior to the operational fleets discovering unknown safety and/or reliability issues. Ongoing tasks for this year support eliminating critical safety concerns, addressing obsolescence and Diminishing Manufacturing Sources and Material Shortage (DMSMS), developing critical repairs, and extending life limited parts. Also, improving environmental processes and materials to increase energy efficiency, supply chains and USAF's ability to operate effectively under any climate conditions. Service-related engine deficiencies occur throughout the engine lifecycle. Given the uncertainty with regard to the number and timing of engine-related deficiencies, it is essential for the USAF to have adequate engineering capability and test capacity to rapidly respond to problems as they occur. Engine CIP funding is driven by field events and engine type/maturity, not by the total quantity of fielded engines.$$, 52734000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207268F_675365$$, $$0207268F$$, $$675365$$, $$F135 Aircraft Engine Component$$, 0, $$The F135 Aircraft Engine Component Improvement Program (CIP) supports the F-35 single-engine fighter propulsion system and provides critical sustaining engineering support for the F135 engine. F135 CIP maintains flight safety (highest priority), corrects service revealed deficiencies, improves system Operational Readiness (OR) and Reliability & Maintainability (R&M), reduces propulsion system Life Cycle Cost (LCC), and sustains the propulsion system throughout its service life. Past investments have reduced warfighter Class A rates and decreased Engine Related Loss of Aircraft (ERLOA) and generated significant returns on investments. F135 CIP, through "Lead the Fleet" operational use and accelerated mission testing, identifies and fixes propulsion-related problems ahead of operational impacts. F135 CIP ensures continued improvements in R&M, which reduce out year support costs.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207279F_654522$$, $$0207279F$$, $$654522$$, $$CSAR EMD$$, 97031000, $$The Next Generation Survivor Radio (NGSR) program is an Air Force led effort to replace the aging Combat Survivor Evader Locator (CSEL) Radio supporting the entire Joint force. The Department of Defense (DoD) plans for the NGSR Handheld Radio (HHR) system and support equipment to serve as the primary communications link for all DoD aircrew who become isolated personnel (IP). NGSR will replace legacy satellite communication and encryption methods to deliver communication capability in support of the Joint Personnel Recovery Agency (JPRA) Combat Search and Rescue (CSAR) mission to locate, authenticate, and communicate with Joint forces who become IPs. NGSR provides secure, over-the-horizon, two-way data communications and precise geo-positioning information to rescue forces. Additionally, NGSR is able to operate in anti-access/area denial (A2/AD) environments by providing a National Reconnaissance Office (NRO) approved low probability of intercept/low probability of detection communication pathway for IPs. NGSR is one node of an overall personnel recovery network which includes multiple on-orbit satellite constellations, geographically dispersed satellite ground stations, joint service CSAR communication devices, and a Joint Personnel Recovery Center (JPRC) cloud-based web application. NGSR plans to incorporate modern encryption technology to comply with current National Security Agency (NSA) cryptographic standards. The Air Force will meet system objectives by executing a competitive Rapid Prototyping effort to design and build a production-ready NGSR artifact. Once prototyped, the Air Force, Army, Navy, and Marine Corps will field the NGSR prototype to their respective services via a follow-on sole-source Rapid Fielding production contract. FY 2026 efforts include final development of both organic and Industry-led capabilities. The new Hand Held Radio prototype will complete development and begin the multi-year process of receiving National Security Administration (NSA) certification. FY 2026 funding will accelerate production and fielding of the NGSR system to fulfill the urgent need for a safe and secure communication pathway. FY 2026 funding will also allow for nation agencies to complete development of critical encryption functions and waveforms to increase alternate secured communications capabilities in combat environments. Additionally, FY 2026 funding will enable the organic development of user Web Application to transition from an unsecure to secure operating environment. Finally, FY 2026 funding allows of the development of support equipment to extend the capability of the NGSR system, supporting air and ground forces, and aircraft agnostic capabilities. The individual capabilities will be integrated into a complete system architecture using joint Service test and integration assets. The FY 2026 request was reduced by $0.117 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.”$$, 97031000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207325F_675356$$, $$0207325F$$, $$675356$$, $$JASSM Extended$$, 232252000, $$The Joint Air-to-Surface Standoff Missile (JASSM) family of missiles includes: JASSM Baseline (JASSM-BL/AGM-158A) and JASSM Extended Range (JASSM- ER/AGM-158B, AGM-158B-2, AGM-158B-3, and AGM-158D). JASSM-ER provides a long range, conventional air-to-surface, autonomous, precision-guided, low observable, standoff cruise missile compatible with fighter and bomber aircraft. JASSM-ER provides the capability to attack a variety of high value fixed or relocatable targets with precision, through preplanned missions or target-of-opportunity, deeper into enemy territory than JASSM-BL, all while minimizing the threat to launch aircraft. Aircraft integration of JASSM-ER/AGM-158B is complete on the B-1, F-15E, F-16, B-2, and B-52. Objective aircraft are F-15E, F-16, B-52, B-2, and further integration is required for the F-35. The AGM-158A, AGM-158B, and AGM-158B-2 are fielded. The AGM-158B-3 and AGM-158D are in development and will gradually insert into the production line as the new missile builds are approved and ready. Missiles accepted by the Air Force will not be returned for modification to the newest variant. Threats to JASSM survivability are being rapidly developed and fielded by near-to-peer adversaries. JASSM continued development enhances capability and provides operational flexibility against current and projected threats. This is accomplished by evaluating high payoff technology development, performing risk reduction activities, and investigating new variants and/or alternate missions that may use JASSM attributes. To maximize effectiveness of existing inventory and address findings from the field, the Air Force develops, tests, and fields improvements via software upgrades into fielded missiles and/or hardware upgrades inserted into the production line. The AGM-158B-2 is an upgrade to the existing JASSM-ER/AGM-158B, incorporating multiple development initiatives to respond to rapidly changing threats and is being produced in Lot 19. The AGM-158B-3 provides M-code capability and will begin a production cut-in starting in Lot 22. The AGM-158D provides Weapon Data Link (WDL) capability to re-target the missile, post-launch, against relocatable or higher priority targets during mission execution. The AGM-158D will begin a production cut-in starting in Lot 22. Weapon Data Link (WDL), This effort includes development of the WDL, as well as integration and testing efforts. The WDL allows warfighters to retarget the weapons via line-of-sight and beyond-line-of-sight, allowing the missile to attack relocatable and/or time sensitive targets post aircraft release. Test assets encompass AGM-158B-3 and AGM-158D in FY24-26. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                            Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0207325F / Joint Air-to-Surface Standoff Missile (JASSM) Operational Systems Development This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24, .97M was allocated for civilian pay expenses in this program element. In FY25, 1.216M is forecasted for civilian pay expenses in this program element. Implements tenets of Open, Agile, and Digital acquisition for any new subsystem hardware or software development. Integrates the system in weapon portfolio tradespace studies by conducting trade studies, system engineering, test activities, and system modeling and simulation. Builds and refines a mission modeling framework by incorporating higher-fidelity weapon system designs and updates to the threat landscape to conduct ongoing assessment of weapon system performance against the authoritative threat. Leverages common component development, in collaboration with other weapon systems, to reduce redundant costs between systems with similar subsystems requirements. Invests in analytical, data management, digital environments, networks, facilities, and security infrastructure upgrades supporting development of this program's capabilities, while leveraging DoD and DAF enterprise IT solutions. The Weapon Data link (WDL) allows warfighters to retarget the weapons via line-of-sight and beyond-line-of-sight, allowing the missile to attack relocatable and/or time sensitive targets post aircraft release. The WDL program is designed to use an open-system architecture standard with outside communication nodes. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. Funding for this exhibit is contained in PE 0207325F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 232252000, NULL, NULL, NULL, NULL, 690980000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207327F_675191$$, $$0207327F$$, $$675191$$, $$SDB Increment II$$, 24810000, $$GBU-53/B Small Diameter Bomb Increment II (SDB II) StormBreaker is a joint interest United States Air Force (USAF) and Department of Navy (DoN) Acquisition Category (ACAT) IC program, with the USAF as the lead service. SDB II addresses the following warfighter requirements: attack moving and stationary targets; adverse weather operations; multiple ordnance carriage; precision munitions capability; reduced munitions footprint; increased weapons effectiveness; minimized potential for collateral damage; reduced susceptibility of munitions to countermeasures; and provides a network-enabled weapon capability via Link-16 and Ultra High Frequency (UHF) weapon data link. SDB II is a key component of the Air Force Global Strike Task Force Concept of Operations (CONOPs). The threshold aircraft for the USAF is the F-15E, and the threshold aircraft for the DoN are the F-35B and F-35C. Objective aircraft include the F-22, F-16, F-35A, B-2, A-10, MQ-9, B-1, B-52, AC-130 and the F/A-18E/F. SDB II is compatible with the Bomb Rack Unit-61 (BRU-61) miniature munitions carriage, Type II carriage systems, the Container Numerical Unit-660/E (CNU-660/E) carriage system, the Common Munitions Built In Test (BIT)/Reprogramming Equipment (CMBRE), and the Joint Mission Planning System (JMPS). SDB II will develop and field a single weapon storage container (USAF) and a dual weapon storage container (DoN). SDB II completed a competitive Risk Reduction in October 2009 and entered Milestone B Engineering and Manufacturing Development (EMD) in August 2010. A Fixed Price Incentive Firm EMD contract with five options for annual Low Rate Initial Production (LRIP) lots (FY15-FY19) was awarded in August 2010. SDB II received Milestone C approval to enter LRIP in June 2015 and completed an Acquisition Program Baseline (APB) update. Contract options for LRIP Lots 1-5 have been exercised. Initial Operational Test and Evaluation (IOT&E) started June 2018 and completed December 2019. SDB II was fielded for the F-15E in September 2020. DoN's first production lot (Lot 4/FY19) supports F/A-18E/F Initial Operating Capability (IOC). The Milestone Decision Authority approved an APB update May 2022 to incorporate the new Air Force inventory objective and adjust for new F-35B/C software schedules. Implements tenets of Open, Agile, and Digital acquisition for any new subsystem hardware or software development. Integrates the system in weapon portfolio trade space studies by conducting trade studies, system engineering, test activities, and system modeling and simulation. Builds and refines a mission modeling framework by incorporating higher-fidelity weapon system designs and updates to the threat landscape to conduct ongoing assessment of weapon system performance against the authoritative threat. Leverages common component development, in collaboration with other weapon systems, to reduce redundant costs between systems with similar subsystems requirements. Invests in analytical, information management, data management, digital environments, networks, facilities, and security infrastructure upgrades directly supporting development and sustainment of this program's capabilities, while leveraging Department of Defense (DoD) and Department of Air Force (DAF) enterprise Information Technology (IT) solutions. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                         R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                     PE 0207327F / Small Diameter Bomb (SDB) Operational Systems Development This effort includes design, development, test, integration, and implementation of appropriate modular open systems approach, related components, and efforts, such as, but not limited to electrical, logical, and physical interfaces defined in relevant Open System Architecture (OSA) standards. This approach allows modular and severable subsystems, to include those that are software-defined, at the appropriate level to be incrementally added, removed, or replaced throughout the life cycle. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 $0.718M was expended for civilian pay expenses in this program element, and in FY 2025 $0.752M is forecast for civilian pay expenses in this program element. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D The FY 2026 request was reduced by $0.025 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 24810000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207328F_653133$$, $$0207328F$$, $$653133$$, $$Stand In Attack Weapon$$, 255336000, $$The Stand-in Attack Weapon (SiAW) system will provide capability to strike rapidly re-locatable targets that create the Anti-Access/Area Denial (A2/AD) environment for 5th Generation and Future Advanced Aircraft. SiAW targets include Theater Ballistic Missile Launchers, Land Attack and Anti-Ship Cruise Missile Launchers, Jammers, Anti-Satellite Systems, and Integrated Air Defense Systems. The SiAW missile system is being developed under a Digital Acquisition (DA) approach that emphasizes agility and innovation. Interim combat capability is pursued through the Navy's Advanced Anti-Radiation Guided Missile-Extended Range (AARGM-ER) program with improved warhead/fuze and F-35 integration (including Universal Armament Interface [UAI] and Mission Planning). Implements Digital Acquisition tenants of Open, Agile, and Digital; builds and establishes industrial base innovation around the program's enterprise for modularity and adaptability for the life cycle of the weapons system. Leverages common component development, in collaboration with other weapon systems, to reduce redundant costs between systems with similar subsystems requirements. Invests in analytical, data management, digital environments, networks, facilities, and security infrastructure upgrades supporting development of this program's capabilities, while leveraging DoD and DAF enterprise IT solutions. Expands program office staff, facilities, and security infrastructure to support the required classification levels for this program's activities. Engages with DoD, DAF, and industry stakeholders to refine threat analysis, refine inventory requirements, and plan upgrade requirements. Capitalizes on and incorporates successful laboratory research and development efforts applicable to this program's capability. This effort includes design, development, test, integration, and implementation of appropriate modular open systems approach, related components, and efforts, such as, but not limited to logical interfaces defined in Weapon Open System Architecture (WOSA) and physical interfaces defined/developed in WOSA X. This approach allows modular and severable subsystems, to include those that are software-defined, at the appropriate level to be incrementally added, removed, or replaced throughout the life cycle. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. FY2026 RDT&E funding for PE 0207328F, Program 653133 is in compliance with budgeted end items per the approved test strategy This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY2024 $8.663 million was expended for civilian pay expenses in this program element, and in FY2025 $9.035 million is forecasted for civilian pay expenses in this program element. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System         PE 0207328F / Stand In Attack Weapon Development & Demonstration (SDD) The FY 2026 cost of Middle Tier of Acquisition (MTA) for SiAW is reflected in the budget request, including RDT&E and procurement of prototype units. The Department will certify Future Years Defense Program (FYDP) funding in a future budget submission. The FY2026 request was reduced by $0.515 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, Implementing the President's Department of Government Efficiency Cost Efficiency Initiative. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, 255336000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207407F_650098$$, $$0207407F$$, $$650098$$, $$Electromagnetic Battle$$, 20439000, $$Electromagnetic Battle Management is an Air Force capability to provide electromagnetic spectrum situational awareness, decision support, and command and control linked by common architectures, standards, and data to enable planning, coordination, and synchronization of electromagnetic spectrum operations (EMSO) across the range of military operations. EMBM will consist of five component capabilities; the ability to attain and maintain EMS Situational Awareness (SA), EMS planning and decision support, non-kinetic command and control, spectrum deconfliction, and a training interface - linked by common architecture, standards, and data. EMBM enables the Combined/Joint Force Air Component Commander to prioritize, integrate, synchronize, C2, and de-conflict non-kinetic operations in support of current operations. AF EMBM will feed into EMBM-J at the COCOM-level. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 060531F, 0605833F, 0605898F, 0606398F. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System        PE 0207407F / Electromagnetic Battle Management (EMBM) Development & Demonstration (SDD)$$, 20439000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601103N_1103$$, $$0601103N$$, $$1103$$, $$Future R&D Workforce Development$$, 0, $$The Graduate Student and Postdoctoral Researcher (GSPR) Support Program helps to ensure the quality and vitality of the future DoN scientific and engineering workforce. The program supports graduate students and postdoctoral fellows engaged in research activities of interest to the Department of the Navy (DoN). Research activities supported in high priority Naval science, technology, engineering and mathematics (STEM) disciplines at U.S. institutions, its territories, or possessions, or the Commonwealth of Puerto Rico will provide graduate students and postdoctoral fellows with invaluable experience conducting basic research in areas of priority Naval interest, responsibility and exposure to unique Naval environmental factors of critical importance.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207410F_674596$$, $$0207410F$$, $$674596$$, $$AOC WS Modifications$$, 94188000, $$This budget line funds the Air Operations Center Weapon System (AOC WS), AN/USQ-163 Falconer, the senior element of the Theater Air Control System (TACS). This is the weapon system that the Commander, Air Force Forces (COMAFFOR) provides the Combined/Joint Force Air Component Commander (C/JFACC) for planning, executing, and assessing theater-wide air and space operations. The C/JFACC provides air, space and cyber support to the Combined/Joint Forces Commander (C/ JFC) by coordinating, deconflicting, and assessing the progress of various weapon systems to advance the C/JFC's campaign. The AOC WS develops operations strategy and planning documents. The weapon system also disseminates tasking orders, executes day-to-day peacetime and combat air, space and cyber operations, and provides rapid reaction to immediate situations by exercising positive control of friendly forces. This program is dependent on the All Domain Common Platform (ADCP). The ADCP provides an extensible cloud-based Infrastructure and Platform as a Service (IaaS/PaaS) hosting platform built to deliver highly resilient mission applications and data to Airmen deployed around the world. Funding supports continued software engineering capacity required for AOC WS Modifications to support and enable the transition from legacy systems (e.g., Theater Battle Management Core System - Force Level (TBMCS FL) and AOC 10.1) to Block 20 modernized capabilities. Additionally, funding supports IaaS/PaaS development and operations specific to the AOC program. AOC WS Modifications are required to support mission requirements at geographic AOCs, global (formerly functional) AOCs, and support and manpower augmentation units, and to keep the AOC current and interoperable with the Combatant Commands (CCMDs), cyber requirements, and next generation weapon systems/weapons. Funding also provides software engineering capacity to deliver air operations capabilities improving speed and automation of the full air tasking cycle, including integration with unit-level sortie generation capabilities that feed friendly order of battle (FrOB) information to the Master Air Attack Plan process. AOC WS Modifications modernize the AOC utilizing agile methodologies to deliver capabilities that keep pace with evolving commercial and government off the shelf (COTS/GOTS) software components, DoD directives, operational energy security and efficiency objectives, and changes in the underlying IT environment. Additionally, the modernization ensure the AOC WS remains interoperable, certified, and supportable across the lifecycle of new capabilities and upgrades. This includes utilization of a managed cloud IaaS/PaaS hosting platform. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funding would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024, $19.794M was expended for civilian pay expenses in this program element, and in FY 2025, $18.181M is forecasted for civilian pay expenses in this program element.$$, 94188000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207410F_674597$$, $$0207410F$$, $$674597$$, $$Kessel Run Flight Operations$$, 18898000, $$The Flight Operations (Ops) project modernizes aerospace combat readiness management to enhance Air Force mission readiness. This budget line funds the development of Flight Ops' combat readiness management solution that provides scheduling, records management, standardization and evaluation, and resource allocation for aircrews and other operational units. Funding supports the continued development and sustainment of legacy systems, e.g., Puckboard, PEX, and G/TIMS, and integration into a unified DAF enterprise system. The project leverages best practices and user feedback from existing systems, both within and outside Government, to optimize resource allocation, sortie value, resource efficiency, and total force readiness. The Flight Ops system can: • Optimize unit resource allocation • Maximize sortie value • Optimize fuel use • Increase total force readiness to maximize wing lethality The system offers real-time visibility into aircraft and aircrew status, enabling informed decisions on sortie generation and readiness. Future capabilities may include data analytics and AI-driven scheduling and integration with Collaborative Combat Aircraft (CCA) and autonomous air vehicles. Flight Ops will deliver a unified, modernized, and resilient command and control capability that is integrated with the DAF BATTLE NETWORK. Flight Ops will ultimately enhance the Department of Air Force's ability to deliver mission-ready forces to meet global wartime and peacetime operations, while ensuring compliance with DoD directives, cybersecurity mandates, and National Defense Strategy priorities. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funding would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024, 19.800M was expended for civilian pay expenses in this program element, and in FY 2025, 18.287M is forecasted for civilian pay expenses in this program element.$$, 18898000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207412F_635321$$, $$0207412F$$, $$635321$$, $$C4I Battlespace Dev &$$, 0, $$The Air Force does not have an enterprise solution for multi-domain battlespace awareness and command and control (C2) tools below the Air Operations Center (AOC) level. This presents significant challenges in obtaining a Common Operating Picture (COP) capable of disaggregation from the AOC, particularly at Anderson AFB, Guam which is the center hub in the Air Force's Agile Combat Employment (ACE) capability in the Pacific. Sharing a COP with the AOC is essential at peacetime for defense and at wartime for conducting operations, and the lack of a current solution further complicates the conduct of ACE operations. Incorporating emerging technology into major operational exercises informs and refines Warfighter requirements and provides opportunities for early adoption and Tactics, Techniques, and Procedures (TTPs) development. Utilizing operationally relevant conditions also provides early opportunities for learning and materiel deficiency discovery. Efforts explore technology advancement to provide a common operating picture in support of Agile Combat Employment (ACE). FY2025 funds will be used to develop and incorporate the latest commercial or government solutions into our operations to help identify best-of-breed technology, permit feedback to developers for improvements and refine operational tactics, techniques, and procedures (TTPs) for the conduct of ACE. Deployment will initially be in Guam to enable learning and assessment of tools under real operating conditions and crucially to create a sub-AOC COP at the heart of our ACE operations in the Pacific immediately. Funds will be used to support experimentation with and deployment of the sub-AOC capability including TTP delineation. This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                   Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0207412F / Control and Reporting Center (CRC) Technology Development (ATD)$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207418F_675234$$, $$0207418F$$, $$675234$$, $$TACP Support$$, 0, $$a. The Joint Terminal Control Training and Rehearsal (JTC TRS) Program, under the Tactical Airborne Control System, funds development necessary to provide a Distributed Mission Operations (DMO) capable, high-fidelity simulator for Special Warfare airmen, to include Tactical Air Control Party (TACP), Special Tactics Combat Control Team (CCT), Joint Terminal Attack Controller (JTAC) operations and Air Support Operations Center (ASOC) operations. JTC TRS is essential to provide initial training, mission qualification training, continuation training, and currency control requirements to JTACs and Special Tactics personnel. JTAC control training requirements exceed the ability of live-fly aircraft to meet, and JTC TRS is the only capability enabling JTACs to achieve and maintain minimum required training for both qualification and proficiency in accordance with the U.S and Partner Nation Memorandum of Agreement for JTAC certification and qualification. The JTC TRS Program provides research and development to facilitate interoperability with joint and sister Service air-ground simulation using industry standards. JTC TRS will provide the capability to network aircrew full mission trainers and training centers in a live-virtual-constructive network. This development effort will also integrate ASOCs with the Joint Theater Air Ground Simulation System (JTAGSS) trainer for Joint Fires integration. The simulator will supplement live field training and live-fly sorties to provide realistic introductory, proficiency, currency, and upgrade training in a simulated battlefield, disaster, or humanitarian relief environment. b. JTAGSS is a continuation of the ASOC simulation trainer initially funded in 2009 and complements the JTC TRS trainer by providing a total air-ground constructive simulation environment for integrated networked training and mission rehearsal capability that will develop TACP/CCT/JTAC and ASOC/Special Operations Forces (SOF) Command and Control (C2) battle staff skills. JTAGSS will provide the ASOC, SOF, and TACP with the vertical and horizontal C2 communications and coordination training and mission rehearsal required for mission effectiveness. There are insufficient exercises and live training events available to meet mandated readiness requirements. The system will include a secure network connection, a constructive simulation environment generator with sharable databases, computer workstations that have synthetic reflex agent applications for each ASOC/SOF crew position to execute the Air Tasking Order. Funds may be used to address emerging and short notice Diminishing Manufacturing Sources and Material Shortage (DMSMS) issues. DMS efforts to include removal of end-of-life software/hardware within simulators systems and move to a modular, common open system architecture that is sustainable and cyber-resilient. Implement requirements and standards defined under the Simulator Common Architecture Requirements and Standards initiative. FY26 funding ($4.108M) for BA 07 Project 0207418F was transferred to BA 07 Project 0207457F. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0207418F / AFSPECWAR - TACP Operational Systems Development This program element may include necessary civilian pay expenses required to manage, execute, and deliver JTC TRS capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $0.00M was expended for civilian pay expenses in this program element, and in FY 2025 $0.00M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207420F_642742$$, $$0207420F$$, $$642742$$, $$IFF/ATC Test and$$, 1713000, $$Cooperative Combat Identification employs technologies required to rapidly identify friendly platforms. The program develops, integrates and evaluates technologies that provide Air Force platforms with a means of positively identifying an air or surface (maritime) platform as a friendly, via active (or passive reception) cooperative identification capabilities. The development funded by this project ensures availability of a Mode 5 upgrade path for implementing ground and air platforms across the Air Force fleet. As Executive Agent the Department of Defense International AIMSPO has system level interoperability testing and certification responsibilities for the current Mark XIIB system, development and integration of new Identification Friend or Foe (IFF) system capabilities, and development/integration of civil Mode S capabilities into Mark XIIB Identification Friend or Foe equipment. The AIMSPO ensures Identification Friend or Foe equipment/platform functionality in accordance with established standards and ensures total system interoperability to meet Department of Defense/Service mission areas (e.g. Offensive Counter Air, Defensive Counter Air, and Integrated Air and Missile Defense). The goals will be to test and certify the Mark XIIB system, develop and integrate the new Mark XIIB Identification Friend or Foe system capability (Mode 5 Level 2 Broadcast) and also continue the development/integration of civil Mode S capabilities into Mark XIIB Identification Friend or Foe equipment using newly fielded M-code GPS receivers. The Office of the Secretary of Defense and Federal Aviation Administration guidelines required Mode 5 be fully implemented by FY 2020 but many platforms continue to integrate this capability. The Department of Defense (DoD) AIMS Program will ensure those certifications are current on all applicable platforms/ systems and work with both domestic and foreign military sales partners to ensure compliance. The funds also support representation to several military (United States and NATO) and civil (Federal Aviation Administration, International Civil Aviation Organization and Radio Technical Commission for Aeronautics) requirements meetings for Mode 5, Mode S and ADS-B. These important meetings allow the Department of Defense to remain interoperable with our foreign military partners as well as the United States and international civil aviation community. Department of Defense AIMS Program will continue to update the Department of Defense AIMS Mark XIIB Standards, Security Classification Guide, Handbook, and Test Requirements. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0207420F / Combat Identification Component Development & Prototypes (ACD&P)$$, 1713000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0305103F_671931$$, $$0305103F$$, $$671931$$, $$TECH SURVEIL$$, 310000, $$Integrate MDCO network sensor collections and analytical capabilities to enable data sharing. This program element may include necessary civilian pay expenses required to manage, execute, and deliver Cyber Security Initiative capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605831F, 0605827F, 0605828F, 0605829F, 0605832F, 0605833F, 0605898F, 0606398F. In FY25 $0.0M was expended and in FY26 $0.0M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 310000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207431F_675309$$, $$0207431F$$, $$675309$$, $$GEO Info & Serv Software$$, 862000, $$Provides support to personnel using Geospatial resources utilized in Geospatial Intelligence (GEOINT) databasing applications, technology exploration and refresh initiatives, geospatial imagery data management and dissemination architecture, geospatial information and services modernization, and enablers for intel and targeting capabilities. Provides support to the MAJCOMs to ensure requisite and available target intelligence and GEOINT tools for information directly available to warfighters. The GEOINT information and service software program funds the Air Force Enhanced Geospatial Product Library (EGPL) which is currently fielded to all combatant command air components and subordinate units supporting global air operations. The EGPL provides digital GEOINT data to support mission planning, targeting & intelligence in support of mission objectives. The Enhanced Geospatial Product Library (EGPL) is world-wide distributed United States Air Force (USAF) repository for geospatial products from the National Geospatial Intelligence Agency (NGA) and other government sources. Its purpose is to provide the Geospatial Intelligence (GEOINT) information needed by the Air Force (AF) and other DoD command and control systems. EGPL is on premise, continuously updated, NGA Foundational GEOINT data seamlessly accessible via shared drive or browser. Funds enhanced dynamic F2T2EA sensor-to-shooter intel and advanced training on cloud-based apps to shorten LRKC with automated and AI-enabled Sensing Grid/ targeting tools and applications. Analyzes, visualizes, and shares National, Tactical, and open source Intel to close the capability gap against adversary's truncated kill chains.$$, 862000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207438F_675218$$, $$0207438F$$, $$675218$$, $$Applications$$, 6787000, $$This budget line funds joint partner requirements of the Air Operations Center (AOC) Weapon System Modification effort. Applications Development efforts deliver capabilities identified in the 2013 Joint Command and Control Capability Development Document (CDD) and are executed under the Development, Security, and Operations (DevSecOps) Software Acquisition Pathway Program. Applications Development provides worldwide operational capabilities for Air Force Command and Control (C2) in support of DoD, Coalition Partners, and other government agencies. These efforts focus on support to the Joint Forces Air Component Commander (JFACC), who provides air, space and cyber support to other Air FOrce and Joint Services C2 systems. This program is dependent on the All Domain Common Platform (ADCP), which provides an extensible cloud-based infrastructure and platform as a service (IaaS/PaaS) hosting platform built to deliver highly resilient mission applications and data to Airmen deployed around the world. In FY 2026, Applications Development will focus on providing necessary software capabilities to build, disseminate, and execute the Master Air Attack Plan (MAAP). Applications Development also provides an Airspace Management tool used for building airspaces, evaluating requests, and instantaneously generating the Airspace Control Order (ACO). These efforts deliver modern software for inclusion to the AOC Weapon System modifications program to replace the Master Air Attack Plan- Toolkit (MAAPTK) and components of Theater Battle Management Core System - Force Level (TBMCS FL). Efforts within this PE align with USAF investment in Mission Planning Systems (PE 0208006F), Air Operations Center (0207410F), All Domain Common Platform (0303248F), C2IMERA (0305015F/0305836F) and ABMS (0604003F) to deliver the Theater Air Planning System of Systems (TAP-SoS) architecture for the DAF BATTLE NETWORK. The FY 2026 request was reduced by -$0.015 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funding would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, and 0606398F. In FY 2024 0.000 million was expended for civilian pay expenses in this program element, and in FY 2025 0.000 million is forecasted for civilian pay expenses in this program element. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0207438F / Theater Battle Management (TBM) C4I Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 6787000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207439F_673310$$, $$0207439F$$, $$673310$$, $$Electronic Warefare Integrated$$, 13627000, $$The Electronic Warfare Integrated Reprogramming (EWIR) program element hosts the DoD's first System of System Technology Integration Tool Chain for Heterogeneous Electronic Systems (STITCHES) Warfighter Application Team (SWAT) at the 350th Spectrum Warfare Wing (350 SWW). SWAT is an integration team employing, maintaining, and instructing other teams in the DoD how to use the STITCHES integration platform. STITCHES is a fully government developed, owned, and open-source Modular Open Systems Architecture (MOSA) toolchain and multi-classification information system that creates new capabilities by integrating incompatible DoD fielded systems and architectures together without the need to modify system source code. STITCHES' separable and community-based databases allow disparate teams across the DoD to utilize STITCHES and SWAT in separate security levels without co-mingling data. The 350 SWW will utilize SWAT to generate requested capability using the STITCHES interoperability software on systems both within and external to the 350 SWW and deploy the capabilities created to the requesting organizations. SWAT interfaces and integrates with other DoD systems and their authorities to support 350 SWW missions and HHQ directed activities. SWAT is responsible for testing and deploying STITCHES generated interoperability into DoD systems supported by the 350 SWW, working with existing DoD test and certification organizations, and teaming with organizations outside of the 350 SWW when adapting and creating novel system of systems using capabilities from these organizations. SWAT will deliver adaptive and cutting-edge electromagnetic spectrum capabilities that provide the warfighter a tactical and strategic competitive advantage and freedom to attack, maneuver, and defend. SWAT is a software development team composed of a government tiger team, the STITCHES toolchain developer, a secure cloud infrastructure and repository developer, and mission partners. SWAT includes a revolving team of subsystem subject matter experts when adapting DoD systems using STITCHES. SWAT is responsible for the execution of tasks employing STITCHES outlined in NDAA 2021 Section 804 and supports Joint All Domain Command and Control (JADC2) tasking and integration efforts in support of JADC2. SWAT will conduct regular STITCHES training courses to scale the capability to the DoD. SWAT may team with other DoD organizations utilizing STITCHES to increase the scale of the deployed capabilities. The STITCHES integration platform achieved a Cross Domain Solution (CDS) Authority to Operate (ATO) prior to the DoD's Raise The Bar (RTB) certification requirement process. The STITCHES integration platform will be submitted to the National Cross Domain Strategy and Management Office (NCDSMO) for Cross Domain Solution certification in FY24. This program integrates DoD systems together to create new EW/EMSO capabilities and conducts prototyping activities on emerging and enabling technologies to inform future EMSO capabilities.$$, 13627000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207439F_677722$$, $$0207439F$$, $$677722$$, $$Multispectral Sensing$$, 41205000, $$This program creates new EW/Electromagnetic Spectrum Operations (EMSO) Multispectral Sensing capabilities and conducts prototyping activities on emerging and enabling technologies to inform future EMSO capabilities.$$, 41205000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207444F_676013$$, $$0207444F$$, $$676013$$, $$Equipment Modernization$$, 0, $$This budget line funds the Air Force Special Warfare (AFSPECWAR) Tactical Air Control Party (TACP) Weapon System which executes precision strike, integration, and all-domain command and control missions to meet Air Force power projection for the joint force's expanded maneuver. TACP Airmen are part of the Air Force's premier ground combat units that are highly maneuverable and scalable. They execute ground-based command and control functions and seamlessly integrate kinetic and non-kinetic effects across the entire spectrum of conflict. They do this by providing joint force air component commanders with a highly trained force that operates at the tactical edge in highly contested environments and complicates enemy decision-making processes. Additionally, TACP Airmen conduct precision strike and integration operations at all echelons of maneuver warfare, from dismounted operations on the forward edge of the battlefield to tactical command posts; TACP Airmen plan, request, advise, and control joint fires and air power to meet multinational operations and supported Combatant commander's objectives. The purpose of Tactical Air Control Party - Modernization (TACP-M) programs are to provide TACPs with modernized voice, data, and video communications, including diverse waveforms and software, advanced targeting equipment, and enhanced battlefield awareness/management capabilities across all domains. Improved targeting and data communications capabilities improve kill chain timelines, defeat adversary systems through opening and closing kill webs, extended critical networks to the forward edge, and when required reduce the probability of fratricide or collateral damage. TACP-M programs support include addressing frequent TACP combat deployments that sometimes lead users to change equipment procurement priorities to support urgent operational needs and respond to evolving threat environments. TACP-M programs jointly develop and procure software and hardware with other AFSPECWAR programs to consolidate requirements that are common across the AFSPECWAR enterprise. This teaming arrangement helps standardize equipment, improves efficiency by consolidating acquisition efforts, enabling a common baseline, and reducing overall costs. TACP-M programs provide and modernize capabilities in the following five major areas: (1) Air Support Operations Center (ASOC)/Tactical Operational Center (TOC) systems; also known as TACP Command and Control and communications (C3)(used in static, mobile and maneuverable operations centers), (2) Vehicle Mounted Systems (used in tactical vehicles) and for On-The-Move and At-The-Halt operations, (3) Dismounted Systems (used by TACPs in wearable configurations), (4) Joint all-Domain Command and Control (JADC2) software, and (5) Support distributed and resilient ground-based command and control teams that leverage airpower within the Theater Air Control System. To ensure survivable and effective C3 capabilities, TACP needs to develop equipment capable of sensing (passive and active) enemy activity within the electromagnetic environment and deliver non-kinetic effects through ground-based jamming Electro-Magnetic Spectrum (EMS) awareness, develop and integrate and a Wide Area Infrared System (WAIS) which will provide a 24/7 360 degree infrared imaging capability covering critical areas utilizing artificial intelligence for threat detection, High Capacity Beyond Line of Sight (BLOS) Baseband Backhaul (BB/BH) and other communications support equipment, advanced$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207448F_644413$$, $$0207448F$$, $$644413$$, $$E-7$$, 0, $$Tactical Data Links (TDL), as a subset of the broader airborne network, are used in a combat environment to exchange information such as messages, data, radar tracks, target information, platform status, imagery, and command assignments. TDLs provide interoperability, local and global connectivity, and situational awareness to the user when operating under rapidly changing operational conditions. TDLs provide a jam-resistant; secure digital data transfer network capability with new and standardized waveforms and data formats allowing Line-of-Sight (LOS) and Beyond-Line- of-Sight (BLOS) intra- and inter-flight communications. TDLs increase mission effectiveness, provide positive identification of aircraft in the network, correlate on and off-board sensor data sharing, target, and threat information, and provide the data link to accomplish time critical targeting and other mission update functions. TDLs are used by all service theater Command and Control (C2) elements, weapons platforms, and sensors. This program provides critical capability and enhancements to the airborne network by supporting common development, integration and interoperability among ground and C2 platforms and responds to quick reaction capability integration and demonstration The E-7 program replaces the unsustainable E-3 Airborne Warning and Control System (AWACS). The E-3 AWACS, first fielded in the 1970s, is at the end of its service life, and costly to maintain. The E-7 will serve as the USAF's principal airborne platform for airborne command and control and airborne moving target indicator, providing a reliable, persistent critical node in the long range kill chain for the Joint Force Air Component Commander (JFACC). Project E-7 funds E-7A advanced communications data studies (to include but not limited to hybrid SATCOM, Internet Protocol Beyond Line-of-Sight (IP-BLOS), and datalink), analysis, and further requirements definition, and software and hardware development and testing. These advanced communication capabilities not in the E-7A Rapid Prototyping Baseline are required to increase E-7A communications resiliency, enabling seamless connectivity with the DAF Battle Network and ensuring that the platform can connect to various SATCOM networks and datalinks should one or more SATCOM networks or datalinks become unavailable. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, or 0606398F. In FY 2024, $0.000M was expended for civilian pay expenses in this program element. In FY 2025, $0.000M is forecasted for civilian pay expenses in this program element. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0207448F / C2ISR Tactical Data Link Component Development & Prototypes (ACD&P) This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207452F_674801$$, $$0207452F$$, $$674801$$, $$DCAPES INC 2B$$, 0, $$Deliberate and Crisis Action Planning and Execution System (DCAPES) is the Department of the Air Force (DAF) classified Command and Control (C2) National Security System (NSS) used system used to project air expeditionary forces (includes weapon systems, logistics, and personnel). It enables the DAF to posture mission ready and equipped forces (organized in effects-based operational capability packages) to deliver air, space and cyberspace capabilities to Joint commanders worldwide. DCAPES stores planning and execution information for DAF functional users in the four (4) main DAF disciplines: 1) manpower, 2) personnel, 3) logistics, and 4) operations. These disciplines support joint, combined, and DAF military operations worldwide. Technical requirements were completed for Increment 2B which included enabling the system to support Public Key Infrastructure and elimination of Social Security Account Numbers as the primary key for identifying Air Force military and civilian members by replacing it with the Electronic Data Interchange Personal Identifier. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 0.0M was expended for civilian pay expenses in this program element, and in FY 2025 0.0M is forecasted for civilian pay expenses in this program element.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207452F_674803$$, $$0207452F$$, $$674803$$, $$DCAPES Cont Dev$$, 8507000, $$Deliberate and Crisis Action Planning and Execution System (DCAPES) is the Department of the Air Force (DAF) classified Command and Control (C2) National Security System (NSS) system used to implement the Air Force Force Generation (AFFORGEN) process and project forces (includes weapon systems, logistics, and personnel). It enables the DAF to posture mission ready and equipped forces (organized in effects-based operational capability packages) to deliver air, space and cyberspace capabilities to Joint commanders worldwide. Additionally, DCAPES manages sourcing, scheduling, and deployment of DAF military and/or civilian personnel against Secretary of Defense directed operations while maintaining strength accountability of the deployed forces. FY 2026 funding will be used to continue development efforts include creating a capability for on-demand updates to the Operation Plan (OPLAN) detail which reduces the corrective action time from days to minutes if the data is out of sync or deleted, interfacing with Joint Capabilities Requirements Manager (JCRM) to track when forces are officially ordered to a Combatant Command (COCOM), creating an unclassified server in the production environment for personnel accountability in areas where classified environments are not available, enhancing the Unit Type Availability (UTA) module with Log Assessment for reporting equipment shortfalls, Database Export for printable AFFORGEN dashboards, and Mass Edit for direct dashboard editing of AFFORGEN Force Elements. The FY 2026 funding also supports the development of the system by continuing to enhance the functionality of the system: crucial in supporting war planning. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 0.000M was expended for civilian pay expenses in this program element, and in FY 2025 0.000M is forecasted for civilian pay expenses in this program element.$$, 8507000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0305172D8Z_333$$, $$0305172D8Z$$, $$333$$, $$Combined Advanced$$, 22548000, $$Combined advanced applications details are classified and reported in accordance with Title 10, United States Code, Section 119(a)(1) in the Special Access Program annual report to Congress.$$, 22548000, NULL, NULL, NULL, NULL, 39510000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601103N_9999$$, $$0601103N$$, $$9999$$, $$Congressional Adds$$, 0, $$Congressional Interest Items not included in other projects.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207455F_646002$$, $$0207455F$$, $$646002$$, $$Three Dimensional$$, 17344000, $$The Three-Dimensional Expeditionary Long-Range Radar (3DELRR) program develops the AN/TPY-4 system which is the designated replacement for the AN/TPS-75 radar. The AN/TPS-75 is an outdated and unsustainable system which was first fielded in the early 1970s. The 3DELRR system will be the United States Air Force's (USAF's) principal long-range, ground-based sensor for detecting, identifying, tracking, and reporting aerial tracks for the Joint Force Air Component Commander (JFACC). The 3DELRR system consists of the AN/TPY-4 radar and associated ground support equipment which includes Prime Movers, Generators, and other smaller mission support items. When fielded, the 3DELRR system will provide multiple benefits and increased capabilities to the USAF and the Joint Services, including: the ability to detect and track modern and emerging highly maneuverable, small radar cross-section airborne target; greater battlefield and battlespace awareness through a precise, real-time air picture of sufficient quality to control individual aircraft under a wide range of environmental and operational conditions; and increased reliability, operational availability, maintainability, transportability, survivability, and sustainability. FY 2026 funding will continue system capability development, which include development of electronic protection (EP) techniques, continued software fixes and Non- Recurring Engineering (NRE) costs. Additionally, FY 2026 funding will support continued test and evaluation activity, to include Initial Operational Test and Evaluation (IOT&E) of the system. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2025 $0.12 million was expended for civilian pay expenses in this program element, and in FY 2026 $0.17 million is forecasted for civilian pay expenses in this program element. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0207455F / Three Dimensional Long-Range Radar (3DELRR) Component Development & Prototypes (ACD&P)$$, 17344000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207457F_675138$$, $$0207457F$$, $$675138$$, $$ST System Development$$, 9622000, $$Special Tactics (ST)/Combat Control (ST/CC) is a human-based weapon system, comprised of both human and equipment capabilities formulated to provide the Air Force and Joint Force with support across the following missions: Global Access, Precision Strike, and PR; with additional focus on EMSO, Counter-Unmanned Aircraft Systems (UAS), and Ground-based Suppression of Enemy Air Defenses (SEAD). ST is employed by Air Force Special Operations Command (AFSOC) across two distinct operator specialties: Combat Control, and Special Reconnaissance. Special Warfare Acquisition, Growth and Refresh (SWAGR) is the program of record to develop, integrate, test, procure and field the latest technology and equipment across a wide range of capabilities to ensure AFSPECWAR ST operators can achieve the mission sets outlined above. Specifically, SWAGR delivers modernized capability in the areas of body-worn hardware/software, tactical communications, ground mobility, small UAS, visual augmentation, maritime, special reconnaissance, technical recovery, and assault zones. FY2026 Funding will provide for continued software development and modernization of the body-worn kit to enhance situational awareness, communication, information management, and airpower integration for ST operators in the battlespace. These enhancements will improve the ability recognize, identify, range, nominate, and designate targets during both day and night operations. Improvements will also significantly reduce the time required to find, track, fix targets, and engage the enemy by attacking adversary signals of interest, providing highly accurate target grid coordinates in three dimensions, generating target imagery both pre- and post-strike, and transmitting target data to C2 centers. Funding will also provide for the development and test of emerging technology, and the integration of the latest mature technology into the ST weapon system to conduct mission essential tasks. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 $1.320M was expended for civilian pay expenses in this program element, and in FY 2025 $1.488M is forecast for civilian pay expenses in this program element.$$, 9622000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207457F_675234$$, $$0207457F$$, $$675234$$, $$TACP Support$$, 4108000, $$a. The Joint Terminal Control Training and Rehearsal (JTC TRS) Program, under the Tactical Airborne Control System, funds development necessary to provide a Distributed Mission Operations (DMO) capable, high-fidelity simulator for Special Warfare airmen, to include TACP, ST/CCT, Joint Terminal Attack Controller (JTAC) operations and ASOC operations. JTC TRS is essential to provide initial training, mission qualification training, continuation training, and currency control requirements to JTACs and Special Tactics personnel. JTAC control training requirements exceed the ability of live-fly aircraft to meet, and JTC TRS is the only capability enabling JTACs to achieve and maintain minimum required training for both qualification and proficiency in accordance with the U.S and Partner Nation Memorandum of Agreement for JTAC certification and qualification. The JTC TRS Program provides research and development to facilitate interoperability with joint and sister Service air-ground simulation using industry standards. JTC TRS will provide the capability to network aircrew full mission trainers and training centers in a live-virtual-constructive network. This development effort will also integrate ASOCs with the Joint Theater Air Ground Simulation System (JTAGSS) trainer for Joint Fires integration. The simulator will supplement live field training and live-fly sorties to provide realistic introductory, proficiency, currency, and upgrade training in a simulated battlefield, disaster, or humanitarian relief environment. b. JTAGSS is a continuation of the ASOC simulation trainer initially funded in 2009 and complements the JTC TRS trainer by providing a total air-ground constructive simulation environment for integrated networked training and mission rehearsal capability that will develop TACP/CCT/JTAC and ASOC/Special Operations Forces (SOF) C2 battle staff skills. JTAGSS will provide the ASOC, SOF, and TACP with the vertical and horizontal C2 communications and coordination training and mission rehearsal required for mission effectiveness. There are insufficient exercises and live training events available to meet mandated readiness requirements. The system will include a secure network connection, a constructive simulation environment generator with sharable databases, computer workstations that have synthetic reflex agent applications for each ASOC/SOF crew position to execute the Air Tasking Order. FY2026 funding will continue development of AI-based Reflex Agent Manager/Role Player and both the development and integration of WARHAWK into JTAGSS Command and Control Trainers to implement the Joint Air Ground Integration Center (JAGIC). Funds may be used to address emerging and short notice Diminishing Manufacturing Sources and Material Shortage (DMSMS) issues. DMS efforts to include removal of end-of-life software/hardware within simulators systems and move to a modular, common open system architecture that is sustainable and cyber-resilient. Implement requirements and standards defined under the Simulator Common Architecture Requirements and Standards initiative. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 0.000M was expended for$$, 4108000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207457F_675352$$, $$0207457F$$, $$675352$$, $$Guardian Angel RDT&E$$, 1758000, $$Guardian Angel (GA) is a Family of Systems (FoS) based in both human and equipment capabilities formulated to execute Air Force Personnel Recovery (PR) across the full spectrum of military operations. The GA FoS is employed by three distinct Air Force specialties: Pararescuemen (PJ), Combat Rescue Officer (CRO), and Survival, Evasion, Resistance, Escape (SERE) and is comprised of nine critical mission areas: Precision Aerial Insertion, Information Management, Force Application, Visual Augmentation, Maritime Recovery, Ground Mobility, Technical Rescue, Medical, and SERE. In order to stay aligned with with OSD Focus Area Command and Control (C2), logistics mobility (land/water), FY2026 funding will be used to obtain significant improvements in operational capability and develop items within the GA FoS to include but not limited to: Maritime Recovery (open ocean boat ), Ground Mobility, Technical Recovery, Precision Aerial Insertion (cargo & personnel parachutes), Medical (Simulators), Information Management, SERE, Visual Augmentation (night vision, augmented reality) and Force Protection. The GA weapon system development/Innovation activities also include studies, analysis, requirements development and developmental testing to support both current and future program planning and execution, quick-reaction capability prototypes/demonstrations to accelerate planning for technology transition, technology insertion and future acquisition programs. Funding will deliver enhanced capability for the dismounted GA Operators in terms of dramatic weight reduction, standardization of items across units, and increased mission effectiveness across the conflict spectrum. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 $0.443M was expended for civilian pay expenses in this program element, and in FY 2025 $0.361M is forecast for civilian pay expenses in this program element.$$, 1758000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207457F_676013$$, $$0207457F$$, $$676013$$, $$Equipment Modernization$$, 12038000, $$Air Force Special Warfare (AFSPECWAR) Tactical Air Control Party (TACP) Weapon System executes precision strike, integration, and all-domain command and control missions to meet Air Force power projection for the joint force's expanded maneuver. They do this by providing joint force air component commanders with a highly trained force that operates at the tactical edge in highly contested environments and complicates enemy decision-making processes. TACP Airmen plan, request, advise, and control joint fires and air power to meet multinational operations and supported Combatant commander's objectives. The purpose of Tactical Air Control Party - Modernization (TACP-M) programs are to provide TACPs with modernized voice, data, and video communications, including diverse waveforms and software, advanced targeting equipment, and enhanced battlefield awareness/management capabilities across all domains. Improved targeting and data communications capabilities improve kill chain timelines, defeat adversary systems through opening and closing kill webs, extended critical networks to the forward edge, and when required reduce the probability of fratricide or collateral damage. TACP-M programs support include addressing frequent TACP combat deployments that sometimes lead users to change equipment procurement priorities to support urgent operational needs and respond to evolving threat environments. TACP-M programs jointly develop and procure software and hardware with other AFSPECWAR programs to consolidate requirements that are common across the AFSPECWAR enterprise. This teaming arrangement helps standardize equipment, improves efficiency by consolidating acquisition efforts, enabling a common baseline, and reducing overall costs. TACP-M programs provide and modernize capabilities in the following five major areas: (1) Air Support Operations Center (ASOC)/Tactical Operational Center (TOC) systems; also known as TACP Command and Control and communications (C3) (used in static, mobile and maneuverable operations centers), (2) Vehicle Mounted Systems (used in tactical vehicles) and for On-The-Move and At-The-Halt operations, (3) Dismounted Systems (used by TACPs in wearable configurations), (4) Joint all-Domain Command and Control (JADC2) software, and (5) Support distributed and resilient ground-based command and control teams that leverage airpower within the Theater Air Control System. To ensure survivable and effective C3 capabilities, TACP needs to develop equipment capable of sensing (passive and active) enemy activity within the electromagnetic environment and deliver non-kinetic effects through ground-based jamming EMSO awareness, develop and integrate and a Wide Area Infrared System (WAIS) which will provide a 24/7 360 degree infrared imaging capability covering critical areas utilizing artificial intelligence for threat detection, High Capacity Beyond Line of Sight (BLOS) Baseband Backhaul (BB/BH) and other communications support equipment, advanced defined waveforms (Low Probability of Intercept/Low Probability of Detection (LPI/LPD)); network architecture to move data across elements & echelons and Small Unmanned Aircraft System (sUAS) for force protection and network extension. FY2026 funding will allow for the continued development of TACP Mission Software, WARHAWK and Special Warfare Assault Kit (SWAK)/Tactical Assault Kit (TAK) software Tactical Laser Communications capabilities, other JADC2 network enabling software applications and suites, EMSO and BLOS BB/BH. The CASS 1.4.5 program (to be renamed to "TACP Mission Software”) includes the WARHAWK and SWAK software programs modernizing the software used in Command, Control,$$, 12038000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207521F_673326$$, $$0207521F$$, $$673326$$, $$Precision Measurement$$, 2273000, $$This program develops, tests, and evaluates national and Air Force measurement standards (hardware) and calibration equipment in support of all Air Force programs and activities, including Precision Measurement Equipment Laboratories (PMELs) worldwide. Metrology research and development provides technology to support systems in all phases of development and acquisition, as well as Air Force R&D laboratories, test ranges, ground test facilities, and operational weapons systems support. Rapidly changing technology requires continuing research and development of measurement standards and calibration equipment to ensure modern weapon systems meet Air Force readiness objectives. This program addresses all metrology disciplines and includes the technology areas of laser, infrared, microwave, millimeter wave, optical, physical, mechanical, electrical, electronic, and ionizing radiation measurements. Metrology is a technical discipline devoted to the science of measurements and to the study and improvement of measurement technology. Measurements are the foundation of military system development, quality assurance, hardware conformance testing and system readiness tests. The integrity of these tests is assured through calibration and traceability assurance schemes. The capability to measure and calibrate must parallel the emergence of new technology, new ranges, and new capabilities of military systems. Lack of new measurement capability impedes or blocks the successful exploitation of new technologies, especially in the movement from development laboratory to production to deployment. R&D efforts are essential within the DoD to pace these requirements, otherwise, these same new systems will suffer time delays, excessive cost, and increased risk due to unreliable test results in all phases of development, production, deployment and operation. This program element may include necessary civilian pay expenses required to manage, execute and deliver Air Force Calibration capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605826F, 0605827F, 0605828F, 0605829F, 0605830F, 0605831F, 0605832F, 0605898F, and 0605833F. In FY24 $0K was expended for civilian pay expenses in this program element and in FY25 $175K is forecasted for civilian pay expenses in this program element. Program is managed by Air Force Materiel Command, Agile Combat Support Directorate, Air Force Metrology Division (WNM). This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                     Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0207521F / Air Force Calibration Programs Operational Systems Development$$, 2273000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207522F_640410$$, $$0207522F$$, $$640410$$, $$Tech Maturation & Risk$$, 15785000, $$The Airbase Air Defense Systems (ABADS) program element is the principal Air Force (AF) program to provide the ability to detect, track, identify, and defeat airborne threats to missions and assets. These threats include small-unmanned aircraft systems (sUAS), Rockets, Artillery and Mortars (RAM), and cruise missiles. These two efforts (Missile Defense (MD) and Counter-sUAS (C-sUAS)) aim to protect personnel, assets, and infrastructure vital to supporting the national security strategy. ABADS MD is designed as a configurable combination of Commercial Off the Shelf (COTS)/Government Off the Shelf (GOTS) sensor and Non-Kinetic Effector (NKE) technologies integrated with tailored Battle Management Command and Control (BMC2) subsystem that leverages GOTS products and Advanced Battle Management System (ABMS) Digital Infrastructure to provide adaptive, resilient, and dedicated air defense capability. The ABADS MD system is designed to operate independently or combine with other local and distributed capabilities to form a multi-layered defense-in-depth, improving airbase defense and airbase resiliency. ABADS MD FY2026 funding will support development efforts to operationalize the NKE following prototype transition from AFRL. Funding will also support and maintain a Government Development Security and Operations (DevSecOps) software pipeline, supporting software updates and prioritized capability upgrades. The Government DevSecOps pipeline will also support further alignment with the ABMS portfolio (Distributed Battle Management Node, Digital Infrastructure, and Cloud Based Command and Control). FY2026 funding also supports Director, Operational Test and Evaluation (DOT&E) oversight required test activities. The FY 2026 request was reduced by 0.015 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” The FY 2026 request for ABADS MD includes 5,041 thousand of discretionary and 15,000 thousand of mandatory (reconciliation) for a total of 20,041 thousand. The mandatory funds support ABADS MD development and integration activities in support of Golden Dome. Further information for this reconciliation request is provided in Section 20004 (Enhancement of Department of Defense Resources for Munitions and Defense Supply Chain Resiliency) of the Reconciliation Exhibit. ABADS Counter-small Unmanned Aircraft Systems (C-sUAS) specifically aims to counter the threats posed by the rapid proliferation of inexpensive yet highly capable systems, and the enemies who target US Service members, Allies, and Coalition partners. The ABADS C-sUAS program will continue to analyze evolving threats, evaluate new capabilities, and design an open system architecture that reduces life cycle cost and enables fielding to all 180+ AF installations. ABADS C-sUAS features a system of systems approach to integrate sensors and effectors into a robust Command and Control (C2) interface able to detect, track, identify, and defeat sUAS threats. The AF works closely with the DoD Joint C-sUAS Office (JCO) to align annual efforts. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                               Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0207522F / Airbase Air Defense Systems (ABADS) Component Development & Prototypes (ACD&P) ABADS C-sUAS FY2026 funding will further develop and test Command, Control, Communication, Computers, and Intelligence (C4I) systems to include follow-on of Medusa C2 System and focus on needed fixed and expeditionary site sense and defeat capability development. The Medusa C2 system supports Joint All-Domain Command & Control (JADC2) development and is required to employ electronic warfare capabilities, artificial intelligence, operator workload and task reduction capabilities, closed-loop training system for operator certification and proficiency, identification capabilities, and sensor fusion. Funding will support development and test of Medusa C2 software to further interoperability and incorporation within the ABMS architecture. It will continue electronic warfare upgrades, to include but not limited to new sensor and effector components, and add new Electronic Warfare skills which leverage current Ninja or future EW capabilities within Medusa C2 and other C2 systems. Funding will also continue efforts in alignment with the DoD's JCO, including cyber hardening of all new system changes, and support management of JCO funded Ninja development. Additionally, funding will be utilized to conduct studies, analysis, and evaluations of threats and capability gaps along with evaluation and streamlined acquisition of new capabilities. ABADS C-sUAS funding will also support innovation activities to include studies, analyses, requirements definition, and quick-reaction capability prototypes/ demonstrations to accelerate planning for technology transition, technology insertion and future acquisition programs. Funds will be used to further develop detection, tracking, ID, fusion and C2 technical solutions for a National Capital Region (NCR) C-sUAS system for protection of Presidential aviation assets and Common Operational Picture (COP). The NCR COP will include cloud-based infrastructure and system architectures. The FY 2026 cost of the ABADS C-sUAS Next Gen C2 Systems (CNGCS) Middle Tier of Acquisition effort is reflected in the budget request, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. The FY 2026 request was reduced by 2.356 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 0.000M was expended for civilian pay expenses in this program element, and in FY 2025 0.231M is forecasted for civilian pay expenses in this program element. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0207522F / Airbase Air Defense Systems (ABADS) Component Development & Prototypes (ACD&P)$$, 15785000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601103SF_610002$$, $$0601103SF$$, $$610002$$, $$University Research$$, 14569000, $$This program supports defense-related basic research in a wide range of scientific and engineering disciplines relevant to maintaining U.S. military technology superiority. Research topics include, but are not limited to, revolutionary and high priority technologies critical to the five core technical competencies of the United States Space Force: Space Security; Combat Power Projection; Space Mobility and Logistics; Information Mobility; and Space Domain Awareness. The program also enhances and promotes the education of U.S. scientists and engineers in disciplines critical to maintaining, advancing, and enabling future U.S. defense technologies. This program assists universities in establishing superior instrumentation capabilities needed to improve the quality of defense-related research and education. A fundamental component of this program is the recognition that future technologies and technology exploitations require highly coordinated and concerted multi- and interdisciplinary efforts. Efforts in this program have been coordinated through the Department of Defense Science and Technology Executive Committee process to harmonize efforts and eliminate duplication. This program is executed by the Air Force Research Laboratory (AFRL). AFRL is focused on high-impact, multi domain science and technology (S&T) solutions that propel innovation today and support the Air and Space Force in securing dominance in future operational environments. AFRL effectively aligns the Department of the Air Force (DAF) S&T enterprise and workforce towards the most consequential DAF priorities to accelerate the delivery of game-changing S&T. In order to manage, execute, and deliver science and technology capabilities, this program element may include: necessary civilian pay expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, administrative contractor services, etc. Funds in this program element may be used to investigate specified science advancements primarily targeted to challenges in the space domain and multi-domain research with space-domain application. The Air Force Research Laboratory (AFRL) utilizes 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories” to manage the workforce strength, structure, positions, and compensation without regard to any limitation on appointments, positions, or funding in a manner consistent with the budget. This program is in Budget Activity 1, Basic Research because this budget activity includes scientific study and experimentation directed toward increasing fundamental knowledge and understanding in those fields of the physical, engineering, environmental, and life sciences related to long-term national security needs. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 1: Basic PE 0601103SF / University Research Initiatives Research$$, 14569000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603748N_2937$$, $$0603748N$$, $$2937$$, $$Next Generation Fighter (F/A-XX)$$, 0, $$The details of this budget justification are classified, per Executive Order 13526, Sec 1.4 (a) and are submitted annually to Congress in the classified budget justification book.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207573F_674881$$, $$0207573F$$, $$674881$$, $$Prompt Diagnostics$$, 0, $$This is an amendment, prior verbiage had this funding pointing to National Technical Nuclear Forensics [NTNF]. The United States Nuclear Detonation [NUDET] Detection System [USNDS] is the system used for the collection, analysis, and evaluation of signatures from NUDETS in the Atmosphere or Space. This funding is to integrate the data from the seconds and third Space and Atmospheric Burst Reporting System [SABRS] sensors into the Integrated Correlation and Display System [ICADS] and to develop algorithms, codes, and tools necessary to enable detailed Subject Matter Expert analysis of SABRS data. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY23 $0 was expended for civilian pay expenses in this program element, and in FY24 $0 is forecasted for civilian pay expenses in this program element This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207590F_674037$$, $$0207590F$$, $$674037$$, $$SEEK EAGLE$$, 33707000, $$The Air Force SEEK EAGLE Office (AFSEO) is designated by the Assistant Secretary of the Air Force (Acquisition, Technology, and Logistics) as the center of expertise for aircraft-store compatibility activities and as the primary source of technical analysis and test support, as well as the central data repository, for the SEEK EAGLE process. The SEEK EAGLE process is a rigorous analysis of many factors to assure the safe and acceptable carriage and release (employment and jettison), safe escape, and ballistics accuracy of all stores on Air Force and foreign military sales aircraft. Thus, the AFSEO's mission as an accelerator is to ensure that every aircraft type is capable of employing the weapons and stores needed to meet Combatant Commander requirements, directly supporting the Secretary of the Air Force's (SECAF) Operational Imperatives (OI), and Cross-cutting Operational Enablers (COE). The Air Force operates a variety of combat and other aircraft that carry numerous and varied stores: bombs, missiles, rockets, fuel tanks, cargo pods, targeting pods, electronic countermeasures pods, etc. Stores are carried in many different loading combinations determined by operational and training scenarios, missions, tactics, and weapon development programs. Additionally, aircraft-store configuration (carriage and employment) requirements change as operational plans and tactics are updated and/or as new stores are developed and fielded. Aircraft program managers must provide SEEK EAGLE certifications for all aircraft-store configurations within their user-established carriage and employment parameters before they may be used for operations, test, or training. The AFSEO completes flight clearance and certification recommendations through any combination of engineering analysis, wind tunnel testing, modeling and simulation, and ground/flight test and evaluation. The SEEK EAGLE process encompasses eight engineering disciplines: Fit and Function, Flutter, Aircraft and Store Structural Integrity, Stability and Control, Electromagnetic Compatibility/Interference (EMC/EMI), Separations, Ballistics, and Safe Escape. In support of certification, the AFSEO recommends approximately 1000 aircraft-store combinations for flight each year through engineering analysis and testing. The AFSEO certification portfolio includes the Next Generation Air Dominance (NGAD) Family of Systems and B-21, as well as the following Mission Design Series aircraft: A-10, B-1, B-2, B-52, F-15C/D/E/EX, F-16, QF-16, F-22, F-35, KC-135, WC-130, MC-130H, HH-60W, MH-139A, MQ-9, T-7A, AT-6, and more. Integrated solutions for combat delivery mission planning problems are developed and provided to combat forces via Combat Weapons Delivery Software (CWDS) and Joint Safe Escape Analysis Solution (JSEAS) software. The SEEK EAGLE Office also works in coordination with the Air Force Safety Center to provide Hazards of Electromagnetic Radiation to Ordnance (HERO) analysis and certification recommendations for ordnance systems containing electro-explosive devices. Additionally, the AFSEO is responsible for incorporating new and emerging technologies into the SEEK EAGLE process to make certification more efficient in support of rapid acquisition timelines, as well as resourcing for the sustainment of a viable Air Force aircraft-store certification capability. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                PE 0207590F / Seek Eagle Operational Systems Development SEEK EAGLE funds are budgeted to support certification testing and analysis for new and inventory stores including, but not limited to: Small Diameter Bomb (SDB) I and II, Laser Joint Direct Attack Munitions (LJDAM), Joint Air-to-Surface Standoff Missile (JASSM), Long-Range Anti-Ship Missile (LRASM), Advanced Medium Range Air-to-Air Missile (AMRAAM), Miniature Air-Launched Decoy (MALD), BRU-57 (Smart Bomb Rack), BRU-61 (SDB Bomb Rack), Advanced Precision Kill Weapon System (APKWS), Sniper Targeting Pod with video data link, LITENING Targeting Pod with video data link, B61-12 nuclear free-fall weapon, penetrator warhead upgrades, practice bombs, electronic warfare pods, reconnaissance pods, and aircraft instrumentation pods. SEEK EAGLE funds also support certification of other inventory stores on Combat Air Forces (CAF) and Special Operations Command (SOCOM) aircraft. In addition, these funds further support capability development and weapons certification efforts required by Air Combat Command (ACC) to achieve Full Operational Capability (FOC) for the F-35A. Many of these weapons certification efforts are directly involved in SECAF OI-3, Moving Target Engagement, and all of them contribute to COE-1, Munitions. Additionally, many of the pods and other stores these funds support contribute directly to COE-2, Electromagnetic Spectrum. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24, 9.893M was obligated for civilian pay expenses in this program element, and 10.880M was forecasted for civilian pay expenses in FY25 in this program element. The FY26 request has been reduced by .034M for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 33707000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207605F_672888$$, $$0207605F$$, $$672888$$, $$Distributed Mission$$, 0, $$In FY2026, no requirement. In FY2025, no requirement. In FY2024: The Distributed Mission Operations Center (DMOC) provides comprehensive Live, Virtual, and Constructive (LVC) simulation capabilities which prepare warfighters to conduct Joint All-Domain Command & Control (JADC2) operations in air, land, sea, space, and cyber domains for theater-level, full spectrum combat training for Air Force, joint service, and coalition partners. The DMOC training capabilities reach over 40 geographically separated Live, Virtual, and Constructive (LVC) locations across 17 time zones representing such assets as real-world weapon systems, operator-in-the-loop, and constructive or computer-driven simulations. DMOC is responsible for development and integration of scenarios, models, and databases and the integration of participating sites into Virtual Flag (VF) and other Distributed Mission Operations (DMO) training events via numerous network connections, DMOC-developed interoperability tools, and controlled interfaces in support of Air Force, joint, and coalition warfighter readiness. In addition, activities include DMO technology and capability studies/analyses which support both current and future program planning and execution by: 1. Distributed Mission Operations Capability/Battlespace Systems Development: The DMOC upgrades and enhances the capabilities of various systems, tools, and simulators to incorporate emerging technology and training requirements into DMO events, such as Virtual Flag (VF) and VF: Coalition (VF:C), to enhance the quality of warfighter training. Activities include Environment Generator development, DMO Tool Development, and Simulator Enhancement. DMOC is in partnership with the US Naval Air Warfare Center-Aircraft Division (NAWCAD) to enhance the capabilities of the Next Generation Threat System (NGTS). The NGTS is the primary environment generator for both Blue and Red Air in DMOC White Force. DMO Tool development includes: a) DMOC Replay Tool (DRT), which facilitates a more complete mission review and debrief capability of the exercises as more sites and systems are added to events; b) enhancement & improvement of the Distributed Interactive Simulation (DIS) Filter and the Doctor-J (Dr. J) tools to enable tactical datalinks to be communicated and translated between disparate simulator and operationally fielded (i.e. live aircraft) communication formats; c) Development of Intelligence, Surveillance, and Reconnaissance (ISR)/Battle Damage Assessment (BDA) to improve damage state models used by intelligence analysts in exercises; and d) development of solutions for integrating Contested Degraded Operations Gateway (CDOG, geographical and Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:            PE 0207605F / Wargaming and Simulation Centers Operational Systems Development communications jamming) into DMO events; and simulator enhancement efforts to incorporate Mission Package standards upgrades into the Control and Reporting Center (CRC) Simulation Package (CSP) to allow a real-world system to be used as a simulator when needed in DMO events. 2. Assessment & Authorization (A&A)/Software Certification: The DMOC supports cybersecurity requirements definition, integration/test support, analysis, systems engineering support, A&A of core systems, and support software certification. The DMOC implements cybersecurity requirements and complies with the application of the Risk Management Framework (RMF) and Continuous Monitoring. Efforts include Cross-Domain Information Sharing / Multi-national Information Sharing (CDIS/ MNIS) ruleset development, load sharing, and testing; integration and testing of various newly developed / updated systems such as the DMOC Replay Tool, Dr. J, DIS Filter, and the DMOC Battlespace; support of Air Force Network Integration Center (AFNIC) software certification. 3. Distributed Training Sites & Systems Integration: DMOC integrates over 40 geographically separated LVC training locations and 50+ systems into LVC DMO training events such as VF and VF:C by resolving interoperability issues between disparate systems and networks so that all exercise participants can interact in the DMO environment. New sites and systems are incorporated into LVC DMO events each year based on higher headquarters and Combatant Commander's (CCDRs) emerging requirements. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Joint Training Center (JTC): Adds training and test capability to 5th generation operation readiness, scales up the Joint Simulation Environment (JSE), and increases operational training capability at Elmendorf AFB. This is not a new start. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207606F_642407$$, $$0207606F$$, $$642407$$, $$Joint Simulation$$, 260667000, $$Joint Simulation Environment (JSE) is the Air Force's synthetic solution for High-End Advanced Training, Tactics, and Testing (HEAT3). JSE supports operational plan rehearsals, large force exercises, and aircrew training events. This capability directly supports United States Air Force Warfare Center (USAFWC), United States Air Force Weapons School, Air Force Test Center (AFTC), Air Force Operational Test and Evaluation Center (AFOTEC), and augments platform training efforts that cannot be performed in open air. JSE encompasses, but is not limited to, lab facilities for development and experimentation, as well as multiple test and training locations, to include, but not limited to: Joint Integrated Test & Training Center Nellis AFB (JITTC-N), Digital Test & Training Range Nellis AFB (DTTR-N), Digital Test & Training Range Edwards AFB (DTTR-E), and future planned location JITTC-Joint Base Elmendorf-Richardson (JITTC-E). JSE Platform-In-A-Box (PIAB) Operational Flight Program (OFP) Based Simulator Development: Entails the study, evaluation, early experimentation, and development for platforms beyond the current/existing F-35 capability. Activities include analysis of OFPs against JSE software and interface standards, as well as common hardware standards enabling remote monitoring, updates, and security management. JSE Digital Test and Training Ranges (DTTR): Maintains and upgrades existing test capabilities, to include the continuation of installation, integration, and verification/ validation activities in support of fielded and future platforms and virtual air threats. Furthermore, the 445 Test Squadron at DTTR-E manages Developmental Test (DT) and Operational Test (OT) events, as well as cyber testing integration for the JSE Enterprise as part of their Lead Developmental Test Organization (LDTO) designation. JSE Core Environment Development/Integration: Continues to develop JSE foundational capabilities enabling further test, integration, and training. Activities include but are not limited to experimentation, development/enhancement of JSE connected systems, tools, services, hardware, and simulators to integrate new and existing digital entities (platforms, sensors, adversary & friendly weapons, ground & airborne threats), and common services including but not limited to weather effects, infrared (IR) models, cyber, and space. Funding may also be used to address Diminishing Manufacturing Sources (DMS) issues, obsolescence resolution and similar emerging requirements, as well as for overarching programmatic support. Funding for this exhibit is contained in PE 0207606F. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0207606F / Joint Simulation Environment (JSE) Component Development & Prototypes (ACD&P) This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, 0605898F. As this PE was established in FY 2025, FY 2024 civilian pay costs are not applicable, and in FY25 10.395M is forecasted for civilian pay expenses in this program element. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, 260667000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207611F_675273$$, $$0207611F$$, $$675273$$, $$Defense Readiness$$, 8880000, $$This package incorporates RDT&E funds to maintain constant readiness landscape changes, which entail software changes, new requirements, etc. to Air Force DRRS-S. DRRS-S is an OSD platform providing readiness reporting capabilities to the DoD. The DRRS-S mission is to establish a mission focused, capabilities based, common framework that provides the combatant commanders, military services, Joint Chiefs of Staff, and other key DoD users a data-driven environment and tools in which to evaluate, in near real-time, the readiness and capability of the U.S. Armed Forces to carry our assigned and potential tasks. These assigned and potential tasks sometimes drive software changes and development specifically for the Air Force which require RDT&E funding to achieve the ability to measure readiness. One example would be the development of Combat Wing. This drives a new assessment framework which needs to be developed within DRRS-S so commanders can measure the readiness of combat wings as a single capability, which are different from the way the Air Force currently assesses readiness. By not having the development ability with the RDT&E funding, readiness reporting will not meet the needs of Joint Staff, Congress, Commanders, or any end users of Air Force Readiness data. MODIFY THE DEFENSE READINESS REPORTING SYSTEM TO SUPPORT ENCHANCE RESOURCE REPORTING FOR COMBAT WINGS: Air Force modifications to force presentation and organization requires modifications new capabilities in DRRS to allow for presented forces to reflect meaningful resource and capability ratings that fully encompass the entirety of capability packages. This change will allow the AF to present fully capability packages with a single resource rating informed by supporting unit ratings. This will provide key decision makers with decision quality data reflecting the full capability package. This is in addition to the current functional unit structure that requires deeper cross referencing to account for the full capability package. The system will combine resource data from multiple units (where reasonable) to reflect combat unit readiness informed by combat support and combat service support limits. MODIFY THE DEFENSE READINESS REPORTING SYSTEM AIR FORCE INPUT TOOL TO STREAMLINE REPORTING: The Air Force Input Tool module of DRRS is the interface by which Air Force units report Readiness. This effort streamlines the input process with structured in-system guidance to increase data quality. This effort utilizes robust tools to summarize unit resources for assessors and direct both qualitative and quantitative inputs to generate, value and risk to assigned capabilities and missions. The end state provides robust qualified Readiness data that highlights resource impacts to specific capabilities. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                             Date: June 2025 Appropriation/Budget Activity                                                         R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                     PE 0207611F / Readiness Decision Support Enterprise Operational Systems Development MODIFY THE DEFENSE READINESS REPORTING SYSTEM AIR FORCE INPUT TOOL TO SUPPORT ENHANCED ANALYITCS: Updating the Air Force Input Tool to align reported resources to specific capability elements and support advanced analytics that reflect detailed data impact to specific resource shortfalls. Additionally, this effort will support ‘what if' reporting to provide AF leadership with preliminary evaluations given proposed Courses of Action (COA) options. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 8880000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207697F_675190$$, $$0207697F$$, $$675190$$, $$JFCOM Wargaming$$, 4399000, $$Funding supports the CSAF Title 10 wargaming efforts to test concepts, capabilities, programming choices, and plans using simulation and other techniques, otherwise known as wargaming. Based on the Department and Air Force direction, there is a concerted effort in these periods of fiscal restraint to reinvigorate, institutionalize, and systematize wargaming across the Department. This effort requires continued funding to maintain the level of effort to most effectively pursue an innovative strategy, avoid operational and technical surprise and make best use of limited resources. The Air Force continues to refine the wargame process and design to better integrate and synergize those efforts in support of the Air Force Strategy, Planning, Programming, Budget, and Execution (SPPBE) process. Specifically, in addition to maintaining a robust Title 10 Wargame series, Global Engagement, servicing Chief of Staff of the Air Force (CSAF) objectives. The HAF Wargaming Enterprise is executing on-call Wargaming in support of the AF/A5/7, the Agile series, along with quick-turning wargame support to the USAF Enterprise Capability Collaboration Team (ECCT) requirements, the Enterprise series, Plan Blue, and to service AF/A5/7 strategy and concept development objectives; all to better address the requirements of the Strategy, Planning, Programming, Budget, and Execution (SPPBE)process and cycles. Additionally, HAF Wargaming provides and coordinates Air Force representation at other Service and Joint wargames as they execute across the department. These efforts are providing decision support to senior Air Force leaders involving investment strategies and develop concepts to best employ U.S. forces in future conflicts. The Wargame Information Environment (WIE) is a continually evolving system that provides an array of services to game players which enables the accomplishment of game objectives. The backbone of the WIE is GameNet, a deployable, standalone, Local Area Network (LAN) with servers and laptops that host applications to support virtual battlespace collaboration, decision making, three-dimensional visualizations & mapping, and services. Behind these applications are cutting edge technologies and database architectures from both commercial off-the-shelf and government developed software that assures relevance to the wargame. The modeling, simulation, and analysis applications allow participants, adjudicators, and control team members to effectively and efficiently collaborate, make decisions, present those decisions, and execute moves within the wargame; documenting each step in the process. This information capture enables discovery during the wargame and permits postgame analysis. These findings inform portfolio rebalancing exercises, concept and strategy development, and very senior leader decision making. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2024 0 was expended for civilian pay expenses in this program element, and in FY2025 0 is forecasted for civilian pay expenses in this program element Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0207697F / Distributed Training and Exercises Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 4399000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0207701F_655012$$, $$0207701F$$, $$655012$$, $$Full Combat Mission Training$$, 12898000, $$Full Combat Mission Training (FCMT) supports Air Force Distributed Mission Operations (DMO), Live-Synthetic, Blended, and Joint Simulation Environment (JSE) integration. FCMT funding provides research in areas benefiting the DMO/Live Virtual Constructive (LVC) environment as a whole; provides research and development to facilitate integration of fielded and newly acquired Air Force owned training devices into DMO/LVC networks; enhances the quality of training for the systems added to the network; enables aircrews to network with LVC components to form the integrated DMO battlespace; links geographically distributed high-fidelity combat and combat support training devices including Command and Control and Intelligence, Surveillance, and Reconnaissance systems and develops, demonstrates, and inserts Multi- Level Security (MLS) capability. This capability enables warfighters to exercise and train at the operational and strategic levels of war as well as conduct networked unit- level training at home station. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $0.00M was expended for civilian pay expenses in this program element. FY 2025 $0.00M is forecasted for civilian pay expenses in this program element.$$, 12898000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0208006F_675302$$, $$0208006F$$, $$675302$$, $$Precision Aerial Delivery Systems$$, 2099000, $$Budget line 0208006F funds Airdrop Mission Planning/Joint Precision Airdrop System (JPADS). Airdrop Mission Planning/JPADS consists of hardware and software that serve as the primary mission planning system for all airdrop missions, enabling high-altitude logistical resupply and the delivery of diverse payloads. These payloads include kinetic effects, such as guided missiles capable of navigating to designated coordinates, and non-kinetic effects like sensors, communication nodes, and jammers, which rely on gravity for deployment. JPADS enhances operational efficiency, survivability, and lethality by enabling the safe and effective delivery of critical supplies and equipment to forces in the field, including from altitudes beyond the range of certain surface-to-air threats. JPADS is utilized by mobility aircraft, primarily the C-17 and C-130 platforms, for high and low-altitude airdrops. Consolidated Airdrop Tool (CAT) and other airdrop mission planning applications are key software for airdrop operations. Future initiatives include automating and enhancing airdrop planning with multi-stage airdrop, task saturation mitigation, and delivering palletized effects using Heavy Equipment Loading and Extraction airdrop. These initiatives utilize real-time data and acquisition of payload and delivery hardware systems (e.g. various delivery vehicles, modern parachute technologies, and various kinetic and non-kinetic effects) for prototyping, testing, evaluation, and demonstrations. FY2026 Airdrop efforts are focused on developing software/hardware capabilities for airdrop missions to include but not limited to: 1) high-altitude, precise, airdrop while mitigating surface-to-air threats; 2) improved single-pass airdrop capability to enhance survivability; 3) two stage payload delivery; 4) prototyping, testing, evaluation, and demonstration of palletized effects; 5) command and control of aerial delivery systems and palletized effects; and 6) supporting contested logistics aerial delivery (airdrop) in hostile or denied areas. These software modernization efforts integrate mobility forces in the Joint Long-Range Kill Chain while increasing aircraft and crew lethality and survivability.$$, 2099000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0208006F_675380$$, $$0208006F$$, $$675380$$, $$Mission Planning Systems (MPS)$$, 136646000, $$The Mission Planning System (MPS) develops software for aircraft mission planning, integrating the latest intelligence, weather, aircraft performance, and threat data into flight management systems enabling flight operations for Combat Air Forces (CAF), Mobility Air Forces (MAF), and Special Missions Air Combat Command (SMACC) aircraft, Collaborative Combat Aircraft (CCA), and training aircraft. MPS is required prior to any fixed or rotary wing aircraft sortie. The warfighter must be able to: 1) leverage mission data feedback to formulate plans with current data; 2) optimize and de-conflict flight routes with other aircraft; 3) review, print, and brief the plan; 4) download flight information to onboard aircraft avionics; 5) conduct dynamic/in-flight replanning, including collaboration and data sharing with mission partners and the Command and Control (C2) chain; and 6) quickly and seamlessly share post-mission data to inform planning for subsequent missions. Main efforts include Joint Mission Planning System (JMPS), JMPS Open Mission System (JOMS), and Theater Air Planning System of Systems (TAP-SoS). JMPS is a software and hardware configuration utilized by U.S. Air Force (USAF) and the U.S. Navy (USN) that focuses on pre-mission planning operations, connected and disconnected planning, and execution for all phases of mission planning operations. Mission Planning Modernization is a Software Acquisition Pathway program. Efforts, including JOMS, focus on connected and disconnected planning and execution for all phases of mission planning (pre-mission, in-flight, and post-mission planning). Software development is essential for real-time mission data C2 updates and collaboration with mission partners as well as dynamic mission replanning for evolving conditions and sharing post-mission data to inform follow on operations. Tools include Weapons Planning Software, Electronic Warfare (EW), Global Positioning System (GPS) crypto including GPS M-Code and weather. TAP-SoS enables integration and real-time data sharing with multiple C2 systems, including but not limited to Advanced Battle Management System (ABMS), Air Operations Centers, and Mobility Air Force C2 (MAFC2). Activities also include studies and analysis to support both current program planning and execution as well as future program planning. TAP-SoS continues and extends modernization by enabling seamless integration with the Department of the Air Force (DAF) BATTLE NETWORK (DBN). As the program shifts from JMPS upgrades activities to focus on modernization efforts, the program restructured in FY2024. MPS continues to upgrade JMPS to align with platform Operational Flight Program (OFP) requirements while developing and delivering modernized mission planning capability in JOMS and TAP-SoS. This restructure enables development to shift from platform centric to system centric mission planning utilizing modern software capabilities such as microservices and Software as a Service.$$, 136646000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0305172K_CA1$$, $$0305172K$$, $$CA1$$, $$Combined Advanced Applications$$, 5447000, $$The DISA Compartmented Enterprise Services Office (CESO) is charged with developing, implementing, and sustaining the DoD SAP IT Enterprise called Secure Web Services (SWS). As such, CESO offers a suite of web-enabled enterprise capabilities to DoD and Intelligence Community Special Access Program (SAP) organizations that enable secure communication and collaboration across the Services, Agencies, and the Fourth Estate. The majority of our current service offerings lie within the realm of Application and Desktop services. CESO’s SAP IT Enterprise Application and Desktop Services reside in CESO’s on-prem (Multi-Tenant Virtual Environment (MTVE)) and cloud-based (CESO Cloud Infrastructure (C2I)) infrastructures. Details of Combined Advanced Applications are classified and can be provided through appropriately classified channel.$$, 5447000, NULL, NULL, NULL, NULL, 158011000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0208007F_674550$$, $$0208007F$$, $$674550$$, $$Air Base Resiliency$$, 13711000, $$Tactical Deception is a Service program to provide a suite of technologies that will enable the USAF to minimize, distort, or create signatures. This includes technologies to confuse or mislead all major categories of adversary sensors. These capabilities can reduce confidence in adversary assessments, exhaust intelligence enterprises, and disrupt targeting cycles. In addition, these technologies and tactics techniques and procedures (TTPs) can be employed across the competition continuum for deterrence or advantage in conflict. Tac-D, CISR also supports all activities and costs needed to support the Air Force to further these types of development projects, as well as, required program support costs (PSC). This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, 0605898F, 0606398F. In FY24 $0 million was expended for civilian pay expenses in this program element, and in FY25 $200 thousand is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 13711000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0208030F_648030$$, $$0208030F$$, $$648030$$, $$Operational$$, 9865000, $$The Operational Weaponeering and Analysis (OWA) project provides mission critical classified weapons' effectiveness analysis and Modeling and Simulation (M&S) tools in direct support of the Air Combat Command (ACC) Targeting mission. The M&S Targeting tool capabilities are designed to meet both Air Force (AF) Master Plan and DoD National Defense Strategy objectives and LOEs. The program is integrating ACC and AFRL MAJCOM goals to establish a Digital Engineering and Transformation path to create a ‘pipeline' of capabilities that will support weapon and target requirements integration from R&D to Operational Warfighting within ACC, Combatant Commands (CCMDs), and other DoD Intelligence Agencies. OWA provides mission critical National Security Software (NSS) M&S software to meet instructions and directives found in CJCSI 3160 and 3170, as well as, AFI 14-401 and JP 3-60. M&S classified software tools are operationally critical to overall mission success and weapons employment. Weapons employment is not legally possible until a complete target and weapon analysis has been completed. The classified M&S software tools are in constant development to support evolving weapon phenomenology (conventional, directed energy, high power microwave, cyber, hypersonic, etc.) within the Weapons PEO and target modeling of a wide range of multi-domain targets, which includes structural, ground mobile, ships, and more. The Integrated Munitions Effects Analysis (IMEA) software is a classified mission critical program that provides Air Force Operational Warfighters with unique analytical capabilities. These unique capabilities are associated with Hard Deeply Buried Targets (HDBTs), Nuclear Weapons, and Weapons of Counter Mass Destruction (C- WMD) weapons employment. In addition, IMEA also analyzes national strategic sites facility defeat information with Nuclear and WMD weapons in support of Global Strike Command operational warfighter requirement. IMEA is also the software for Massive Ordinance Penetrator (MOP) and Massive Ordinance Air Blast (MOAB) lethality estimates in DoD. The Air Force Target and Effect Software (AFTES) provides an all-domain weapon and target capability to support Advanced Target Development and Intermediate Target Development within ACC and Joint environments. This classified software creates software that is digital, agile, and open. The tool is focused on integration of capabilities from ABMS into the JADC2 environment within a single open Modelling and Simulation (M&S) Engagement Framework to provide capabilities to the tactical edge. In addition, AFTES will draw it requirements from the ACC Agile Combat Employment (ACE) LOE to meet objectives laid out by the CSAF. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0208030F / War Reserve Materiel - Ammunition Component Development & Prototypes (ACD&P) In addition to operational support, IMEA and AFTES provides analytical reachback for both operational and weapon acquisition communities. OWA also aligns with Air Force Research Laboratory (AFRL) and Defense Threat Reduction Agency (DTRA) Research and Development (R&D) weapon lethality and effectiveness missions to create an R&D pipeline of capabilities all maintained in a single M&S software framework which allows the software to be easily developed, deployed, and maintained within the OWA Division. The AF assumed operational support and development of the IMEA program from the Defense Threat Reduction Agency in FY22. DTRA will continue to support Air Force with basic R&D research of new capabilities associated with HDBT, Nuclear, and WMD as defined by Memorandum of Agreement (MOA) between DTRA and the AF. OWA has become the operational transition partner for DTRA and AFRL to integrate and field all weapon and target R&D technology to AF and other Joint Environments. This program leverages Digital acquisition tenets of open, agile, and digital. Invests in analytical, information management, data management, digital environments, networks, facilities, and security infrastructure upgrades directly supporting development and sustainment of this program's capabilities, while leveraging DoD and DAF enterprise IT solutions. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY24 $.000 thousand was expended for civilian pay expenses in this program element, and in FY25 $.000 thousand is forecasted for civilian pay expenses in this program element. The FY 2026 request was reduced by $545 thousand for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, 9865000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0208036F_654910$$, $$0208036F$$, $$654910$$, $$Aeromedical Readiness$$, 0, $$Current projects in this program include Aeromedical Readiness (Project 654910). Aeromedical Readiness projects provide aerospace medical systems and treatment equipment to improve casualty care and meet worldwide warfighter medical operational requirements. Aeromedical Readiness provides key aeromedical devices, life-saving capabilities and quality of life technologies and equipment. This program enables the critical care of combat casualties by further developing and optimizing existing technologies for ground Expeditionary Medical Systems (EMEDS) and aeromedical evacuation systems. EMEDS and aeromedical evacuation systems provide the urgent care needed to treat deployed injured warfighters and return them to duty while in country, and to treat combat casualties that need to be safely transported to a stateside hospital for follow on treatment. The program also supports critical capabilities development in the multi-disciplinary areas for light-weight, durable, and rapidly deployable medical equipment to ensure the Air Force is poised to meet future medical readiness and operational requirements, to include but not limited to Spinal Immobilization Transport Device (SIT-D), Pathogen Detection Capability, Automated Vision Testing, Whole Blood Transport and other FDA approved medical treatment devices. This program supports projects ranging from research efforts to optimize human physiologic and cognitive performance for Air Combat Command, to development of patient isolation and transportation devices for Air Mobility Command that enable aeromedical evacuation of patients suffering with highly infectious diseases. In FY 2024, PE 0604617F, (Agile Combat Support), Project 654910, (Aeromedical Readiness) efforts were transferred to PE 0208036F, (Medical Counter-CBRN), Project 654910, (Aeromedical Readiness), in order to consolidate Combat Support medical readiness requirements under a single PE. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System        PE 0208036F / Medical C-CBRNE Programs Development & Demonstration (SDD)$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0208045K_T-40$$, $$0208045K$$, $$T-40$$, $$Major Range Test Facility$$, 70893000, $$The Joint Interoperability Test Command (JITC) is the only joint element of the Department of Defense’s (DoD) Major Range and Test Facility Base (MRTFB) that primarily performs Test and Evaluation (T&E) of Information Technology and National Security Systems (IT/NSS) in support of Command, Control, Communications, Computers and Intelligence (C4I). JITC is the DoD's only Joint Interoperability Certifier at the only Non-Service Operational Test Agency. Interoperability is vital to the DoD’s success as it allows forces, units and/or systems of military services, and U.S. partners to share data, information, materiel, and services required to operate collaboratively. Operational testing addresses critical issues of a system's effectiveness in combat-like environments. Additionally, operational testing provides decision makers an independent evaluation to better understand the risks and capabilities of a system’s effectiveness, suitability, and cyber- security before fielding to the warfighters. JITC’s T&E efforts determine the degree to which the DoD is fielding interoperable, operationally effective, suitable, and cyber survivable joint warfighting capabilities to achieve DoD’s goal of information superiority. JITC evaluates DoD system and capability conformance to applicable Military Standards and technical specifications and performs Cyber T&E of DoD IT and NSS (including Cloud services and Mobility). Collectively, JITC's Test, Evaluation, and Certification (TE&C) services support DISA's strategy to operate and secure the DISA portion of the DoD Information Network. JITC is responsible for: • Evaluating DoD IT/NSS for Joint/Coalition (involving two or more US military services and/or partner nations) interoperability to provide decision makers objective information on systems issues, risks and capabilities. • Issuing Joint Interoperability Certifications and Assessments to document system functionality and capability. • Conducting operational evaluations of production representative systems to determine how they perform in typical real-world scenarios. • Maintaining a federated IT infrastructure which provides a national test asset to DoD and other organizations as an MRTFB activity. • Providing interoperability mission support to warfighters to enable effective communication and operations between U.S. Military Services and other foreign nations. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Information Systems Agency                                                    Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:             PE 0208045K / C4I Interoperability RDT&E Management Support$$, 70893000, NULL, NULL, NULL, NULL, 120237000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0208053A_635$$, $$0208053A$$, $$635$$, $$Joint Tact Grd Station-P3I$$, NULL, $$JTAGS transitioned to US Space Force in Fiscal Year 2024 (FY2024). The Joint Tactical Ground Station (JTAGS) is a post-production, Acquisition Category (ACAT) III program. JTAGS provides missile warning message data for the Air and Missile Defense (AMD) architecture and improves performance for Integrated Air and Missile Defense Fire Control Systems/Composite Army Air and Missile Defense Brigades. JTAGS disseminates near real time warning, alerting, and cueing information on ballistic missile launches and other tactical events of interest throughout the theater using existing communication networks, providing critical support to Combatant Commanders in their Areas of Responsibility (AOR). Four OCONUS deployed JTAGS units, which are deployed in three theaters (United States Pacific Command (PACOM), United States Central Command (CENTCOM), United States European Command (EUCOM)), constitute DoD's only in-theater system providing space-based missile warning. The fifth CONUS system is used as an institutional trainer but is available as a deployable asset. JTAGS is designated as the in-theater element of the United States Strategic Command's Theater Event System (TES), supporting all Theater Missile Defense pillars, affording the shortest sensor-to-shooter connectivity. On 14 January 2016, the Army Acquisition Executive designated the JTAGS Pre- Planned Product Improvement (JTAGS P3I) program as a separate ACAT III modification program. The JTAGS Program Element (PE) supports development and testing of the JTAGS Block II Preplanned Product Improvements (P3I) program based on the JTAGS Operational Requirements Document (ORD), additive Joint Requirements Oversight Council - Memorandum (JROC-M) requirements, and the formal JTAGS Block II Capability Development Document (CDD) thresholds. P3I upgraded JTAGS to a Block II configuration for operation with the next generation of Space Based Infrared System (SBIRS) satellites, and improved warning tactical parameters and timeliness. The JTAGS Block II P3I program based on the 2009 JTAGS ORD is on contract as a two-phase development effort. JTAGS Block II P3I Phase 1 is complete. The final developmental efforts of JTAGS Block II P3I Phase 2 to achieve 2009 ORD requirements completed in FY2022. Follow-on Test and Evaluation (FOTE) completed in FY2022 with Materiel Release efforts to be conducted in FY2023. The Joint Tactical Ground Station (JTAGS) transitioned to US Space Force in FY2024. There is no funding requested in FY2026 in this PE.$$, NULL, NULL, NULL, NULL, NULL, 477000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0305206F_672002$$, $$0305206F$$, $$672002$$, $$Agile ISR$$, 8246000, $$The Agile ISR BPAC matures, develops, and deploys projects in support of current and future platform agnostic, non-proprietary, autonomous, multi-INT cross cueing ISR solutions based on DAF mission requirements in highly contested environments. This includes, but is not limited to, High Altitude Long Endurance (HALE) capability development, Detection Removal and Characterization Operations (DRACO), support and development of AgilePod, and other projects. Portions of the developmental efforts under Agile ISR are classified. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 0.000M was expended for civilian pay expenses in this program element, and in FY 2025 0.000M is forecast for civilian pay expenses in this program element.$$, 8246000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0208087F_674543$$, $$0208087F$$, $$674543$$, $$AF Offensive Cyber$$, 31197000, $$Distributed Cyber Warfare Operations (DCWO) consists of a portfolio of programs and projects that conduct Research, Development, Testing and Evaluation (RDT&E) leading to operations-ready offensive cyberspace capabilities. This includes the transition of efforts from laboratory, industry, and academia via studies, accelerated prototyping, and technology demonstrations. DCWO effectiveness comes from balancing acquisition related RDT&E efforts in three Air Force (AF) offensive cyber operations (OCO) mission threads (Off Network, Telephony Network, and the associated Infrastructure that propel the Off Network and Telephony Network mission threads) across three OCO-related subsystems and technical enablers (Platforms, Access, and Cyber Weapons) that enable products, services, and systems in the DCWO portfolio. The resulting DCWO capabilities provide cyber effects to Combatant Commanders and other offensive cyber customers to enable air superiority. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24 $1.995M was expended for civilian pay expenses in this program element, and in FY25 $2.046M is forecasted for civilian pay expenses in this program element. The FY 2026 request was reduced by $1.049 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                PE 0208087F / Distributed Cyber Warfare Operations Operational Systems Development$$, 31197000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0208088F_677820$$, $$0208088F$$, $$677820$$, $$Computer Security RDTE:$$, 7395000, $$The Firestarter program provides newly improved capabilities and technical transition opportunities for Cyber Defense and Information Assurance (IA) technologies and tools needed to defend Air Force (AF) Command, Control, Communications, Computer, and Intelligence (C4I) systems from cyber attacks, while ensuring recovery in the event of an attack. The emphasis of the program is directed toward defensive cyberspace capabilities; computer and network systems security; damage assessment and recovery; cyber threat recognition, attribution, and mitigation; and active response methodologies in response to evolving threats and changes to cyber environment. These areas of emphasis are realized through research and development, test and acquisition in the areas of proactive defense, defensive counter cyberspace, cyberspace intelligence, surveillance and reconnaissance & situational awareness, persistent network operations, as well as decision support, recovery, and digital forensics. Current AF systems, such as the Air Force Network (AFNet) Non-Classified Internet Protocol Router Network (NIPRNet) Gateways, Secret Internet Protocol Router Network (SIPRNet) Modernization program, and Host Based Security System leverage this technology to meet their information assurance and defensive cyberspace needs/requirements. Firestarter utilizes cyber and IA technology investments by United States Cyber Command (USCYBERCOM), the Defense Advanced Research Projects Agency (DARPA), the National Security Agency (NSA), Director of National Intelligence (DNI), Intelligence Advanced Research Projects Activity (IARPA), and the Department of Homeland Security (DHS), and various government research laboratories, to jump-start its development of solutions to existing AF cyber and IA requirements. This program supports AF Cyberspace strategic direction in support of Cyber Defense which provides capabilities to Sixteenth AF, as AF component to USCYBERCOM, Defense Information Systems Agency (DISA), National Security Agency (NSA), and other services to ensure Global Information Grid (GIG) cyber and IA requirements are being met. Activities performed include those designed to identify, analyze, test, rapidly acquire, and integrate emerging IA and cyber technology and defensive cyberspace weapons systems and capabilities into all regions of the GIG - terrestrial, airborne, and space systems. In addition, this effort will support implementation of Department of Defense (DoD) Enterprise-wide IA & Computer Network Defense (CND) Solutions Steering Group (ESSG) solutions. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24 $0.000M was expended for civilian pay expenses in this program element, and in FY25 $0.000M is forecasted for civilian pay expenses in this program element.$$, 7395000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0208088F_677821$$, $$0208088F$$, $$677821$$, $$Cyberspace Vulnerability$$, 0, $$Beginning in FY25, continuation of this work is described in Budget Program Activity Code (BPAC) 677824. Funding in this BPAC contributes to the development of software and related activities in support of the creation of the Integrated Defensive Cyberspace System (IDCS). The Cyberspace Vulnerability Assessment/Hunter (CVA/H) weapon system provides Air Forces Cyber (AFCYBER) and Combatant Commanders additional mobile precision in addition to currently fielded protection capabilities to identify, pursue, and mitigate cyberspace threats. The CVA/H weapon system performs defensive sorties world-wide via remote or on-site access. CVA/H executes Hunter missions on Air Force (AF) and Department of Defense (DoD) networks and systems. Hunter operations characterize and then eliminate threats for the purpose of mission assurance. The Hunter mission focuses on the capability to find, fix, track, target, engage, and assess (F2T2EA) the advanced persistent threat (APT). This effort funds development efforts to enhance command and control situational awareness and to expand the capability of the current weapon system to meet scope and scale of the USCYBERCOM directed Cyber Protection Teams (CPTs) and AF Mission Defense Teams (MDTs). Activity in this BPAC also supports development of enhancements to legacy AF Defensive Cyberspace Operations (DCO) weapon systems, as needed, to support current operations and facilitate the transition of legacy capabilities to the IDCS described more fully in BPAC 677824. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24 0.000M was expended for civilian pay expenses in this BPAC, and in FY25 0.000M is forecasted for civilian pay expenses in this BPAC.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0208088F_677822$$, $$0208088F$$, $$677822$$, $$Cyber Defense Analysis$$, 0, $$Beginning in FY25, continuation of this work is described in Budget Program Activity Code (BPAC) 677824. The Cyberspace Defense Analysis (CDA) weapon system conducts Defensive Cyberspace Operations (DCO) during peace time and contingency operations and network defense by monitoring, collecting, analyzing, and reporting sensitive information transiting or residing on the Air Force Network (AFNet). CDA assessments of non-secure telecommunications determine type and amount of sensitive and/or classified information that may have been disclosed to our adversaries and encompasses several mission subsets, including: Telephony Communications, Radio Frequency (RF) Communications, Email Communications, Internet based Capabilities (IbC), and Cyber Operations Risk Assessment (CORA). The CDA weapon system protects the AF's critical information such as Personally Identifiable Information (PII), Operations Security (OPSEC), and other sensitive information through passive monitoring and active Data Loss Protection (DLP). CDA shows its true capability in the force protection realm, OPSEC, DLP, etc. and helps ensure our adversaries are not provided early warning of our plans, capabilities, or limitations. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24 $0.000M was expended for civilian pay expenses in this program element, and in FY25 $0.000M is forecasted for civilian pay expenses in this program element.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0208088F_677823$$, $$0208088F$$, $$677823$$, $$AFCERT$$, 0, $$Beginning in FY25, continuation of this work is described in Budget Program Activity Code (BPAC) 677824. Funding in this BPAC contributes to the development of software and related activities in support of the creation of the Integrated Defensive Cyberspace System (IDCS). IDCS generates defensive cyberspace capabilities supported by active response methodologies as the main focus of our efforts (we utilize National Institute of Standards and Technology (NIST)-standardized actions, such as protecting and securing computer and network systems, detecting and assessing damage, defending while recognizing / attributing / mitigating cyber threats, and recovering systems and data) as the Department of the Air Force (DAF) seeks to keep pace with ever- evolving threats and changes to our operational [cyber] environment. IDCS benefits the DAF Total Force, including Active Duty (AD), Air National Guard (ANG), and Air Force Reserve Command (AFRC) Airmen by enabling rapid deployment of defensive cyber sensor capabilities while disrupting bad actors from exploiting critical vulnerabilities upon the initial discovery of adversarial action at the tactical edge, by utilizing both automated decision making (ADM) and human/machine teaming (HMT) with trained defensive cyber operators. IDCS will equip DAF operational units (predominantly Sixteenth Air Force (AFCYBER), 688th Cyber Wing Cyber Security Service Providers (CSSPs), and 67th Cyber Wing, Air Force Cyber Protection Teams (CPTs), in addition to Mission Defense Teams (MDTs) and network defenders) with capabilities required to sensor, monitor and protect DAF and ad- hoc mission networks (including networks utilized by Air Force Special Operations Command (AFSOC)), Industrial Control Systems (ICS), and Weapon Systems. IDCS supports both enterprise (fixed) and edge/mobile use cases. IDCS exists to sustain two major components: (1) common sensor platform, known as VOLTRN+; (2) situational awareness platform, known as Enterprise Logging Ingest & Cyber Situational Awareness Refinery (ELICSAR), acting as DAF's version of a Big Data Platform (BDP). IDCS components are comprised of 3 main parts: (A) Strategic Data Platform; (B) Strategic and Tactical Analytics; (C) Joint Situational Awareness Applications. Working together, IDCS enables AF DCO to host, integrate, and feed defensive-cyber-related data, which informs both operational and strategic analysis, contributing to enhanced situational awareness for senior leaders. IDCS addresses the lack of a synchronized, enterprise-level approach to mitigate cyberspace vulnerabilities related to mission performance and/or mission assurance. Failing to address capability gaps will hinder DAF's ability to project Air Power and dominate in a fight against near-peer adversaries. The increased request to Research, Development, Test and Evaluation (RDT&E) funding for this portfolio reflects the threats (identified with Secretary of the Air Force support) to Air Force Defensive Cyber Operations, specifically requiring sensor data and enhanced situational awareness to mobilize, deploy, and sustain forces. IDCS develops, sources, sustains, and provides common non-proprietary modular hardware (including commercial-off-the-shelf (COTS) solutions), hosting, an edge cloud-compute defensive cyber platform (with options for both standalone or cloud-connected software), and cloud-based containerized software needed to execute the Cyberspace Vulnerability Assessment/Hunter (CVA/H), Air Force Cyber Defense (ACD), and Cyber Defense Analysis (CDA) missions.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0305245D8Z_245$$, $$0305245D8Z$$, $$245$$, $$EW ENT EXP AND INNOV$$, 0, $$Classified.$$, 0, NULL, NULL, NULL, 0, 64002000, 2026) ON CONFLICT DO NOTHING;
