INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0305245D8Z_592$$, $$0305245D8Z$$, $$592$$, $$EW ENT EXP AND INNOV$$, NULL, $$Classified.$$, NULL, NULL, NULL, NULL, 0, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0305249F_675307$$, $$0305249F$$, $$675307$$, $$AF JWICS Enterprise$$, 21097000, $$The AF JWICS Enterprise PE provides funds for the modernization, development, procurement, and sustainment of the Air Forces SCI enterprise. ICAM - Identity, credentialing and Access Management (ICAM) includes the foundational identity elements that manage users, credentials, attributes, and the access risk based upon the sensitivity of the resources being protected. ICAM is foundational to Zero Trust and is not a single process or technology, but is a complex set of systems and services that operate under various policies and organizations. JTIM - Due to a database misalignment, a portion of JTIM funds have temporarily been programmed into this PE. As soon as we are capable of doing so, we intend on realigning these funds back to their original locations in the CAIS (27431F) PE. JTIM funds currently aligned in this PE still go to the intended OAC/MAJCOM (ACC) for execution and there will be no break in expenditures or capability due to this error. JTIM is a combined OUSD(I&S) and Joint Staff J2T effort to produce modern integrated cloud-based capability for the Joint Force targeting enterprise. These new capabilities will streamline the intelligence support to Services and Combatant Commands (CCMDs) into a federated intelligence-derived target production architecture. JTIM capabilities will unify the Defense Intelligence Enterprise (DIE) targeting workforce through the production management of thousands of high-value targets by providing timely and accurate aimpoints in the deployment of lethal and non-lethal effects. These capabilities will enhance the target intelligence data supporting targeteers and decision makers as well as providing multiple weaponeering solutions for each strike action along with improving the identification of critical elements needed for subsequent re-attack options. JTIM funds were incorrectly reprogrammed in FY26-30 and will be reprogrammed back to the CAIS PE (0207431F). IC-ITE - IC-ITE mission is enabling greater integration, information sharing, and safeguarding with the Intelligence Community (IC) by adopting IC standards, data, and technology frameworks, and using systems of common concerns for unmatched decision advantage. "This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In PY 0.00M was expended for civilian pay expenses in this program element, and in CY 0.00M is forecasted for civilian pay expenses in this program element.” Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0305249F / AF JWICS Enterprise Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 21097000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602183A_CW8$$, $$0602183A$$, $$CW8$$, $$Next Generation Aviation$$, NULL, $$This Project investigates Future Vertical Lift (FVL) and other Army and Department of Defense (DoD) advanced drive train technologies that increase performance and double current drivetrain life cycles while improving their reliability and maintainability. Research in this Project is fully coordinated with PE 0603043A (Air Platform Advanced Technology). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by Aviation & Missile Center (AvMC).$$, NULL, NULL, NULL, NULL, NULL, 1456000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0208088F_677824$$, $$0208088F$$, $$677824$$, $$677824 - Integrated Defensive$$, 87639000, $$Integrated Defensive Cyberspace System (IDCS) enhances the Department of Air Force (DAF) cyber infrastructure and supports operations within contested environments. The IDCS mission is to provide and maintain enterprise situational awareness of the DAF's cyber terrain within a contested environment to enable and support Cyber Forces response to evolving Cyber threats. The Air Force strategy previously involved three stand-alone programs that provided capabilities in a disparate fashion. IDCS delivers a comprehensive cyber defense architecture by integrating the three key mission sets with advanced sensors and data analytics. This provides commanders with critical risk assessments and enables proactive threat identification and neutralization on mission-critical networks. Integrated Defensive Cyberspace System (IDCS) is an integrated enterprise-level cybersecurity system that safeguards DAF computer, network, weapon, and control systems. It empowers operators to detect threats and assess their impact, allowing for quick deployment of defensive measures to thwart malicious actors from exploiting critical vulnerabilities. IDCS delivers the cybersecurity requirements of a variety of operational units, including the 16th AF, 688th Cyber Wing Cyber Security Service Providers (CSSPs), 67th Cyber Wing, AF Cyber Protection Teams (CPTs), Mission Defense Teams (MDTs), and network defenders. It equips these units with the tools necessary to protect DAF networks, Industrial Control Systems, and Weapon Systems. It supports both enterprise and edge/mobile cybersecurity defense use cases. IDCS provides capabilities to enable the following mission sets: Cyberspace Vulnerability Assessment/Hunter (CVA/H): The Hunter mission focuses on the capability to find, fix, track, target, engage, and assess (F2T2EA) the advanced persistent threat (APT). CVA/H provides capabilities to characterize and then eliminate threats for the purpose of mission assurance. CVA/H executes Hunter missions on Air Force (AF) and Department of Defense (DoD) networks and systems. Cyber Defense Analysis (CDA): The CDA mission conducts Defensive Cyberspace Operations (DCO) by monitoring, collecting, analyzing, and reporting sensitive information transiting or residing on the Air Force Network (AFNet). CDA assessments of non-secure telecommunications determine the type and amount of sensitive$$, 87639000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0208201F_660192$$, $$0208201F$$, $$660192$$, $$St System$$, 4985000, $$(U) The Offensive sUAS (O-sUAS) effort identifies requirements addressing capability gaps in the AF ability to rapidly generate a family of sUAS capable of executing Intelligence, Surveillance, and Reconnaissance (ISR), Electronic Warfare, and precision strike in permissive, contested, and denied environments. Funding supports operationalizing the AF UAS Strategy and force-present emerging systems, including exquisite, attributable, and expendable platforms, for collaborative operations within permissive, contested, and denied environments. O-sUAS funding also supports innovation activities to include studies, analyses, requirements definition, and quick-reaction capability prototypes/demonstrations to accelerate planning for technology transition, technology insertion and future acquisition programs such as but not limited to Small Business Innovation Research (SBIR) and Small Business Technology Transfer (STTR) programs. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, and 0606398F. In FY 2025 0.000 million was expended for civilian pay expenses in this program element, and in FY 2026 0.276 million is forecast for civilian pay expenses in this program element. Items requested in FY26 are representative but not limited to the system development and program support. Items developed during execution may change based on critical equipment needed to support current Air Force mission requirements. Due to the rapidly changing threat environment, the acquisition program manager has the authority to redirect funding as necessary to meet current slated and emerging requirements for operational units. O-sUAS funding also supports innovation activities to include studies, analyses, requirements definition, intelligence and data management activities, and quick-reaction capability prototypes/demonstrations to accelerate planning for technology transition, technology insertion and future acquisition programs. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E        PE 0208201F / Offensive small Unmanned Aircraft Systems (sUAS) Management Support$$, 4985000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0301025F_673280$$, $$0301025F$$, $$673280$$, $$Ceit01$$, 999000, $$Funds the research and development of AF Civil Engineer (CE) NexGen IT systems for all Total Force installations. The purpose for the funds are to develop/modernize NexGen IT, a Commercial-Off-The-Shelf (COTS) system; specifically to develop a Space Management/Utilization capability as well as new interfaces with other Civil Engineer data systems (i.e. Builder SMS). NexGen IT provides an integrated asset management system for the CE community with the capability to support cost accounting, Operations (Work Management and Material Control), Real Property, Project Management, and Energy Management. NexGen IT replaces several Legacy IT systems that lack the capability to meet present and future mission requirements and the ability to be compliant with Congressionally-mandated Financial Audit Improvement Readiness (FIAR). The Comprehensive Planning Platform (CPP) is a Civil Engineering Enterprise solution that enables installations and 2,800 users to make investment decisions based on asset management principles, strategic guidance, and data through a repeatable planning process. The platform digitally integrates Installation Development Plans (IDPs), Component Plans, & Asset Management Plans (AMPs) - strengthens installation planning & operationalizes asset management responsive to changes at the installation and enterprise by allowing for continuous updates. Funding is necessary to support migration activities from the current SharePoint Online (SPO) environment to Cloud-based servers, as well as support continued development of features necessary for the long-term build out of the CPP. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program element may include necessary emergent or unanticipated civilian pay expenses required to manage, execute, and deliver NexGen IT and CPP development/modernization for emergent or unanticipated weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0207479F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                  Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0301025F / GeoBase Operational Systems Development$$, 999000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0301113F_671931$$, $$0301113F$$, $$671931$$, $$TECH SURVEIL$$, 14749000, $$Mission Description: Provides funding to the Air Force owned DoD Cyber Crime Center to fund continued development and modifications of cybersecurity tools and activities to support DoD-wide military intelligence efforts to include CADO-IS (formerly CI-PED), Automated Data Obfuscation (ADO) formerly known as STORMSYSTEM, Encompasses specialized range of cyber defense services that support the 2023 National Cybersecurity Strategy with specific focus on protecting companies who do business with the DoD. DC3 lead development, integration, and deployment of network detection solutions that include scalable solutions; real- time alerting; detection/reporting of malicious cyber activity. Located on Defense Industrial Base (DIB) networks to detect data exfiltration or unauthorized access. Sensor program viewed as complementary and more advanced capabilities than legacy efforts (Service-specific sensors, in-house Intrusion Detect Systems, etc.), and DC3 conducts a Capabilities Based Assessment (CBA) for the Defense Forensic Evidence Networked Data Repository (DFENDR) which is a key component of the Law Enforcement Evidence Data Repository (LEEDR) program ongoing at Fort Eisenhower, GA. Activities include but are not limited to development of software/ hardware systems, integration and transition of lab-developed cyber capabilities, developmental testing, operational evaluation, manpower, studies, analysis, pilots, demonstrations, and risk reduction efforts to improve protection of critical technologies. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2025 $0 was expended for civilian pay expenses in this program element, and in FY2026 $0 is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0301113F / Cyber Security Intelligence Support Operational Systems Development$$, 14749000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601102A_AA8$$, $$0601102A$$, $$AA8$$, $$Sensing and Electromagnetics$$, 1342000, $$This Project conducts basic research on semiconductor materials, layered structures, and novel devices for optical sources, detectors, integrated optoelectronic circuits, and energy generation and storage devices. Efforts include multiscale modeling, material and structure growth and characterization, and novel device design and fabrication. The research has application to Soldier power, sensors, lower power communications, quantum networks; unattended sensor networks, including distributed sensor fusion; ground vehicle sensors and auxiliary power systems; alternative position, navigation, and timing (PNT) systems for Global Positioning System (GPS)- denied environments; and sensors and power for small unattended ground and air vehicles. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Army Research Laboratory (ARL) and Soldier Center (SC).$$, 1342000, NULL, NULL, NULL, NULL, 16083000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0301377F_675306$$, $$0301377F$$, $$675306$$, $$Analysis Enterprise$$, 1117000, $$Countering Advanced Conventional Weapons (CACW) investment is a Congressionally approved and OUSDI backed focused on improving Scientific and Technical Intelligence (S&TI) for the combined Defense Intelligence Enterprise (DIE) program through the accelerated creation of authoritative threat engineering analysis, weapon system models, and integrated simulation of top-priority threat scenarios. CACW's goal is to increase the overall analytic health of the DIE to meet S&TI analysis and threat Modeling and Simulation (M&S) weapons technical intelligence requirements against near peer threat competitors. CACW investments are a scalable, scenario- based approach to increase S&TI analysis and threat model development capacity across the DIE to close the intelligence gap on the understanding, characterization and impact of top priority threat systems and system-of-systems. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2024 3.868M was expended for civilian pay expenses in this program element, and in FY2025 5.818 is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 1117000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0301377N_3103$$, $$0301377N$$, $$3103$$, $$Intelligence Engineering$$, 16906000, $$The details of this program element are classified and are submitted annually to Congress in the classified budget justification books.$$, 16906000, NULL, NULL, NULL, NULL, 12341000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0301401F_3600$$, $$0301401F$$, $$3600$$, $$Research, Development, Test & Evaluation, Air Force / BA 7:$$, NULL, $$Cross Domain Tactical OPIR Processing delivers a mechanism providing reach-back support for battlespace awareness functions and manages the timely transfer of newly developed tools to operational users. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24 2.01 million was expended for civilian pay expenses in this program element, and in FY25 3.64 million is forecasted for civilian pay expenses in this program element. Efficiency - Workforce Optimization Reduces 3 civilian personnel full-time equivalents and funding to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." Efficiency-Contract Services Reduces contracts for $0.817 million in FY26 in contracts for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0301401F / AF Multi-Domain Non-Traditional ISR Battlespace Awareness Operational Systems Development$$, NULL, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0302015F_3600$$, $$0302015F$$, $$3600$$, $$Research, Development, Test & Evaluation, Air Force / BA 7:$$, NULL, $$The four (4) aircraft E-4B National Airborne Operations Center (NAOC) fleet satisfies the military need for an airborne operations center with communications capabilities permitting military and civilian leadership to monitor and control military and civil national assets during all phases of conflict (nuclear and non-nuclear) or natural disaster. The E-4B NAOC fleet also satisfies the military requirement to provide a highly survivable node of the National Military Command System (NMCS). This program's developmental efforts include, but are not limited to, upgrades and enhancements to aircraft structures, propulsion system, fuel system, environmental control system, electrical generation and distribution systems, flight safety and navigation systems (with their associated communications equipment), and the Systems Integration Lab. Modifications may enhance the aircraft's mission capabilities necessary for the E-4B fleet to execute its mission, to include but not limited to those necessary for the Senior Leadership Command, Control and Communications System (SLC3S), National Leadership Command Capability (NLCC), and Nuclear Command, Control, and Communications (NC3). Funds may also be used to explore and develop modifications, upgrades, and future systems required to meet evolving mission requirements. This budget supports the following developmental modifications and studies/projects currently underway or planned for accomplishment: - Survivable Super High Frequency (SSHF) will upgrade and replace portions of the E-4B's Jam-Resistant Secure Communications (JRSC) system to meet existing Presidential Policy Directive (PPD)-35 and National Security Presidential Directive (NSPD)-51/Homeland Security Presidential Directive (HSPD)-20 requirements and to ensure continued connectivity and interoperability as satellite and communications infrastructure evolves. Expected modifications include, but are not limited to, component and sub-system upgrades and replaces portions of the current Super High Frequency (SHF) system that are obsolete or near end of service life. A replacement to the SHF system is required as secure, survivable communications capability transitions from the Defense Satellite Communications System (DSCS). A risk-reduction study was completed in FY19 to further define the acquisition strategy of the SSHF program. The program will be acquired in 2 increments and each increment will be split into 2 installs to expedite fielding and reduce impact to Aircraft Availability. Increment 1A will upgrade the existing Ka-band system. Increment 1B will include technical solutions such as upgrading the existing modems and systems integration lab. Increment 2A will include new modem technology and common workstation. Increment 2B will include a new Ku-band system upgrades to the X-band system. Due to Air Force priorities, the X-band requirements will be deferred. - The E-4B Systems Integration Laboratory (SIL) program will develop a test environment configured to represent the mission systems of the E-4B with connectivity to mission networks and services. E-4B SIL started as the Test Accreditation Integration Lab (TAIL) 5 for development of the E-4B SSHF program. The E-4B SIL program will expand the capabilities of TAIL 5 beyond SSHF to include the other mission communication systems within the E-4B. The E-4B SIL is necessary to minimize Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0302015F / E-4B National Airborne Operations Center (NAOC) Operational Systems Development modernization and technical refresh schedules by reducing time on aircraft for install, test, ground connections/configurations, technical orders, redlines/rework, and training. Schedule reduction by the E-4B SIL will directly support increased Aircraft Availability (AA). The E-4B SIL will be developed in blocks begin with the Advanced Extremely High Frequency/Presidential National Voice Conferencing (AEHF/PNVC) Backbone being added to the existing SSHF baseline to provide the basic platform communications systems. The next block will incorporate the Mission Equipment Section (MES) systems to allow reproduction of necessary data to operate both the SIL and operational aircraft. The next blocks will continue to build out network and communication systems based their associated priorities and system dependencies. - Touchscreen Executive Phone - Airborne (TXP-A) - effort replaces the existing secure obsolete touch screen phones for senior national leaders to maintain multi-level security. The TXP-A will upgrade computing capabilities of the secure phone and durability of various components such as processors and touch screen displays. The replacement of the TXP-A phones will allow the NAOC to continue to meet Presidential Policy Directive (PPD)-35 requirements across the full spectrum of crisis. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 0.0M was expended for civilian pay expenses in this program element, and in FY 2025 0.0M is forecasted for civilian pay expenses in this program element. The FY 2026 cost of Middle Tier of Acquisition (MTA) effort E-4B is reflected in the budget request, including RDT&E and procurement of prototype units. The Department will certify Future Years Defense Program (FYDP) funding in a future budget submission This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
