INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601102A_AA1$$, $$0601102A$$, $$AA1$$, $$ILIR - AMC$$, 8340000, $$Work in this Project supports basic research at the Army Futures Command through the In-House Laboratory Independent Research (ILIR) program. Basic research lays the foundation for future developmental efforts by identifying fundamental principles governing various phenomena and appropriate pathways to exploit this knowledge. The ILIR program serves as a catalyst for major technology breakthroughs by providing laboratory directors flexibility in implementing novel research ideas and by nurturing promising young scientists and engineers and is used to attract and retain top doctoral degreed scientists and engineers. The ILIR program also provides a source of competitive funds for peer reviewed efforts at Army laboratories to stimulate high quality, innovative research with significant opportunity for payoff to Army warfighting capability. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Armaments Center (AC), Aviation and Missile Center (AvMC), Chemical Biological Center (CBC), Command, Control, Communication, Computers, Cyber, Intelligence, Surveillance and Reconnaissance Center (C5ISR), Ground Vehicle Systems Center (GVSC), and Soldier Center (SC).$$, 8340000, NULL, NULL, NULL, NULL, 11535000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601153N_1389$$, $$0601153N$$, $$1389$$, $$Electromagnetic Spectrum$$, 0, $$The Electromagnetic Spectrum research area conducts fundamental research in areas that utilize the electromagnetic spectrum to deliver operational capability to the warfighter. This research area focuses on new concepts that increase knowledge and develops advanced capabilities regarding sensing, atmospheric considerations, networking, quantum phenomena, electromagnetic warfare, and the innovative use of the electromagnetic spectrum to provide a significant warfighting advantage. Research efforts include: Research Platforms, Networking Sensing, Quantum Measurement Architectural Devices, Expeditionary Electromagnetic Spectrum and Electromagnetic Warfare.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601102A_AA2$$, $$0601102A$$, $$AA2$$, $$ILIR - SMDC$$, 1057000, $$Work in this Project supports basic research at the United States Army Space and Missile Defense Command - Technical Center (USASMDC-TC) through the In-House Laboratory Independent Research (ILIR) program. Basic research lays the foundation for future developmental efforts by identifying fundamental principles governing various phenomena and appropriate pathways to exploit this knowledge. The ILIR program serves as a catalyst for major technology breakthroughs by providing laboratory directors flexibility in implementing novel research ideas and by nurturing promising young scientists and engineers and is used to attract and retain top doctoral level scientists and engineers. The ILIR program also provides a source of competitive funds for peer reviewed efforts at Army laboratories to stimulate high quality, innovative research with significant opportunity for payoff to Army warfighting capability. Work in the Project provides a foundation for applied research initiatives at the Army laboratories and research, development, and engineering centers. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Research in this Project complements other Army Directed Energy efforts conducted under Program Element (PE) 0602150A (Air and Missile Defense Technology) Project DC1 (Next Generation Directed Energy Concept Development and Analysis) and Project HP1 (High Power Microwave Technology). Research is performed by the United States Army Space and Missile Defense Command - Technical Center (USASMDC-TC) in coordination with ASA(ALT) DASA R&T, AMD-CFT, Rapid Capabilities and Critical Technologies Office (RCCTO) as well as Program Executive Office (PEO) Missiles and Space (M&S).$$, 1057000, NULL, NULL, NULL, NULL, 1045000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601102A_AA3$$, $$0601102A$$, $$AA3$$, $$Single Investigator Basic Research$$, 106422000, $$This Project fosters extramural basic research to create and exploit new scientific discoveries and technology breakthroughs, primarily from universities, that will improve the Army's transformational capabilities. The Army maintains a strong peer-reviewed scientific research program through which leap-ahead technological solutions may be discovered, matured, and transitioned to overcome the technological barriers associated with next generation capabilities. Included are research efforts for increasing knowledge and understanding in fields related to long-term future force needs in the competency areas of Biological and Biotechnology Sciences; Electromagnetic Spectrum Sciences; Energy Sciences; Humans in Complex Systems; Mechanical Sciences; Military Information Systems; Network, Cyber, and Computational Sciences; Photonics, Electronics, and Quantum Sciences; Sciences of Extreme Materials; Terminal Effects; and Weapons Sciences. The breadth of this basic research program covers approximately 800 active, ongoing research grants and contracts with leading academic researchers and approximately 2,500 graduate students and 1,100 post- doctoral fellows yearly, supporting research at nearly 210 institutions in 50 states. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Project is performed by the Army Research Laboratory (ARL).$$, 106422000, NULL, NULL, NULL, NULL, 99224000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601102A_AA4$$, $$0601102A$$, $$AA4$$, $$Training and Human Science$$, 13630000, $$This Project focuses on research that improves Soldier-system performance in future force environments by looking at key phenomena underlying Soldier integration with intelligent technologies and autonomous agents. This Project researches optimal methods for information exchange between Soldiers and intelligent technologies including 1) human performance in automated, mixed-initiative (human control-machine control) environments; 2) visual scanning and target detection; 3) performance- related Soldier state changes; 4) integration across multiple sensory modalities; and 5) collaborative (team) and independent multi-task, multi-modal, multi-echelon Soldier-system performance - all cast against the influx of emerging intelligent technologies and autonomous systems. Technical solutions are being pursued in the areas of data generation and algorithm development in these emerging environments in order to update and improve our understanding of performance boundaries and requirements. These solutions include multi-disciplinary partnerships, metrics, simulation capabilities, and modeling tools for characterizing Soldier-system performance, and provide a shared conceptual and operational framework for militarily relevant research on critical aspects of human-agent teaming. In the area of translational neuroscience, research is carried out to examine leading edge methodologies and technologies to improve the measurement and classification of neural states and behavior in operationally-relevant environments; to examine the potential for application of neuroscience theories to autonomous systems to improve Soldier-system interactions; to model the relationship between brain structure and cognitive performance for understanding individual differences and injury; and to assess how neural pathways implicated in functional processing can be enhanced through dynamic system interface technologies for improving in- theatre performance and training. In the area of cybernetics, which is a scientific discipline that bridges the fields of control theory and communication theory for the study and modeling of behavior in complex systems, research is carried out to examine the complex human-system-environment relationships that define, constrain, and influence the interactions between Soldier and system. Research efforts are pursued to advance theory, models, and methodological approaches that capture the dynamic and multidimensional nature of human behavior, including the temporal dependencies inherent to human behavior, through an integrated program of research efforts focused on: novel cybernetic models of human multisensory integration and human-system communication; neuro-inspired, bio-inspired, and engineering approaches to computational algorithms for multisensory integration and multi-sensor fusion to enable enhanced and augmented Soldier perception in human-system interactions; new methodological approaches for the design of multisensory displays and human-system communications; and multisensory test bed platforms for examining experimental hypotheses driven by model predictions and proof-of-principle applications of identified algorithms and methods. This Project also investigates innovative theories, models, and methods to improve personnel assessment, training, and leader development, as well as provide a better understanding of individual, unit, and organizational behavior and performance within the context of complex organizational and operational environments. The research within these domains will enable advances in psychometrics to support the development of the next generation of psychological assessments for selection, classification, and assignment. The research also will target how to improve the assessment of difficult-to-measure skills and enable theoretical advances to inform and support the$$, 13630000, NULL, NULL, NULL, NULL, 20583000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601102A_AA5$$, $$0601102A$$, $$AA5$$, $$Biotechnology and Systems Biology$$, 8867000, $$This Project conducts fundamental research of biological systems and materials engineered for transformational Army capabilities. This Project focuses on technical core competencies including: Materials from Biology; Biological/Abiological Interfaces; Systems Biology; Computational Biology; Synthetic Biology, and how those competencies address Army needs to reduce logistics burden, increase situational awareness, and improve protection. Research will advance from manipulation of single microorganisms to designed microbial consortia for conversion of flexible feedstocks (indigenous and waste) into consistent products for energy and agile expedient manufacturing; advancing from the production of individual small molecules to gradient/precision/specialty materials for production of hierarchical and metamaterials for sensing and protection; and advance from laboratory use to ruggedized organisms and materials for field deployment enabling dynamic, responsive materials, advanced sensing, and materiel protection/denial. Further, understanding the state-of-the-art in genetic engineering and control of biological systems in military environments will allow for understanding the pacing synthetic biology threat to the future operating environment. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the Army Research Laboratory (ARL).$$, 8867000, NULL, NULL, NULL, NULL, 6499000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601102A_AA6$$, $$0601102A$$, $$AA6$$, $$Robotics and Mobile Energy$$, 10772000, $$This Project fosters basic research to expand the Army's capabilities in the area of propulsion, platform mechanics, and autonomous air and ground platforms. This includes research to enable the investigation of risk-based design methodologies and control algorithms for enduring operation of rotorcraft and ground vehicles, artificial intelligence, and novel mobility mechanics to enable robotic systems to serve as productive embodied teaming agents. This effort researches propulsion and alternative energy systems to increase the reliability, efficiency, and survivability of air and/or ground platforms. This Project also conducts research in support of advanced military vehicle technology with emphasis on sophisticated vehicle dynamics and simulation, vehicle-terrain interaction, vehicle control, and advanced track and suspension concepts. Advanced propulsion research will dramatically improve power density, performance, and thermal efficiency for advanced engines, transient heat transfer, high temperature materials, and thermodynamics. This Project also supports state-of-the-art simulation technologies to achieve a more fundamental understanding of advanced mobility concepts. The subject research is directed at unique, state-of-the-art phenomena in specific areas such as: non-linear ground vehicle control algorithms, using off-road terrain characteristics; and unique mobility approaches, using advanced analytical and experimental procedures. The work in this Project supports Program Element (PE) 0602148A (Future Vertical Lift Technology), PE 0602145A (Next Generation Combat Vehicle Technology), and PE 0601104A (University and Industry Rsch Ctrs). Work in this Project is performed by the Army Research Laboratory (ARL), Aviation and Missile Center (AvMC), and Ground Vehicle Systems Center (GVSC).$$, 10772000, NULL, NULL, NULL, NULL, 24774000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601102A_AA7$$, $$0601102A$$, $$AA7$$, $$Mechanics and Ballistics$$, 33957000, $$This Project conducts basic research in materials and ballistic science to create higher performing, lighter weight, lower cost materials and processes, discover new ways to store and release chemical energy from novel energetic materials, explore fundamental chemistry and physics controlling the launch and flight of gun- launched projectiles and missiles, and understand the interaction of these weapons with armored targets, including the high deformation rate behavior of materials and the mechanics of threat impact and penetration of armored targets. Research involves the study of new experimental capabilities to measure, characterize, and visualize complex phenomena with high temporal and spatial resolutions as well as the development of state-of-the-art computational models that provide predictive capabilities based on at-scale and cross-scale numerical frameworks that capture the relevant physical phenomena. Research in atmospheric science seeks an in-depth understanding of the complex atmospheric boundary layer associated with high-resolution meteorology, the transport, dispersion, optical properties, and characterization of chemical and biological aerosols, the propagation of full-spectrum electro-magnetic and acoustic energy and physics-based multi-scale models for electronic, optical, mechanical, and chemical materials. Efforts seek to explore methodologies and computational capabilities for the quantification of uncertainty in predictive modeling enabling risk-informed decision analysis multi-scale material models and environmental impacts on complex Army systems (manned and unmanned). This research also conducts research in chemistry and physics controlling ballistic propulsion and launch; creating aerodynamic forces on flight bodies to permit radical maneuver at high speeds, and high altitude glide and flight maneuver for increased range of gun launched projectiles. This research results in knowledge products that lead to new materials for armor and armaments, disruptive explosives and propellants, more accurate and non-lethal (NL)/lethal projectiles and missiles, omnisonic maneuver of projectiles, and advanced armors for increased survivability of Army combat systems. This research also funds efforts in the characterization of chemical and biochemical phenomena occurring at or near solid surfaces and interfaces; the interactions between chemical reactions and transport processes on surfaces; theory and modeling of processes at complex surfaces; and the synthesis and characterization of catalysts that function at the nanoscale. Investment in basic research centered on the surface science disciplines will enable growth of a knowledge base that will result in improved understanding of the interactions of complex materials in real world environments. Work in this Project supports key Army needs and provides the technical underpinnings for several PEs to include PE 0602145A (Next Generation Combat Vehicle Technology); PE 0602146A (Networks C3I Technology); PE 0602147A (Long Range Precision Fires Technology); PE 0602141A (Lethality Technology), and PE 0602143A (Soldier Lethality Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is completed by the Army Research Laboratory (ARL), Armaments Center (AC), Chemical Biological Center (CBC).$$, 33957000, NULL, NULL, NULL, NULL, 34416000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601153N_1390$$, $$0601153N$$, $$1390$$, $$Electronics$$, 0, $$The Electronics research area conducts basic research focused on increasing knowledge, developing advanced components and materials for electronics, communication systems, sensing devices, etc., to ensure the Naval warfighter can counter current and future threats. The research activities will focus on the following areas: - Nanoscale Computing Devices and Systems - Electronics and Sensors Technology - Expeditionary Electronics - Electronic Materials and Processes$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601102A_AA9$$, $$0601102A$$, $$AA9$$, $$Information and Networking$$, 30864000, $$This Project supports basic research to enable intelligent and survivable command, control, communication, computing, and intelligence (C4I) systems for the future force. As the combat force structure decreases and operates in more dispersed formations, information systems must be more robust, intelligent, interoperable, and survivable if the Army is to retain both information and maneuver dominance. This research addresses the areas of information assurance, signal processing for wireless battlefield communications, information extraction from multi-modal data human-agent naturalistic communication, and intelligent systems for C4I. Research will focus on understanding and solving inherent vulnerabilities associated with using standardized protocols and commercial technologies while addressing survivability in a unique hostile military environment that includes highly mobile nodes and infrastructure, bandwidth-constrained communications at the edge, resource-constrained sensor networks, diverse networks with dynamic topologies, high-level multi-path interference and fading, jamming and multi-access interference, levels of noise in speech signals and document images, and information warfare threats. These C4I technologies must accommodate heterogeneous security infrastructures, multi-service and multi-national interoperability, and information exchange/security mechanisms between multiple levels of security. The intelligent systems for C4I research focus on providing machine learning methods to overcome noisy, sparse, and heterogeneous data with artificial intelligence algorithms that can transfer learning from one domain to another. This foundational research will help identify highly relevant tactical events for mounted or dismounted commanders, leaders and Soldiers; improve the timeliness, quality, and effectiveness of actions; and speed the decision-making process of small teams operating in complex natural or urban terrain. Work in this Project supports key Army needs and provides the theoretical underpinnings for Program Element (PE) 0602146A (Network C3I Technology), PE 0602143A (Soldier Lethality Technology), and PE 0602145A (Next Generation Combat Vehicle Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Army Research Laboratory (ARL).$$, 30864000, NULL, NULL, NULL, NULL, 42894000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601102A_AB1$$, $$0601102A$$, $$AB1$$, $$Basic Res in infect Dis, Oper Med and$$, 2967000, $$This Project builds fundamental scientific knowledge contributing to the sustainment of United States Army scientific and technology information to solving military medical problems related to infectious diseases, operational medicine, and combat care. This Project provides the means to exploit scientific breakthroughs and avoid technological surprises, and fosters innovation in areas where there is little or no commercial investment due to limited markets (e.g., drugs and treatments for tropical diseases) and maintains laboratory capability to perform these functions. The work is consistent with the Under Secretary of Defense (Research and Engineering) science and technology focus areas and the Army Modernization Strategy. Work is performed at United States Army Research Institute of Environmental Medicine (USARIEM) and the United States Army Aeromedical Research Laboratory (USAARL).$$, 2967000, NULL, NULL, NULL, NULL, 4397000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601102A_AB2$$, $$0601102A$$, $$AB2$$, $$Protection, Maneuver, Geospatial,$$, 15702000, $$This Project advances fundamental science in areas of military engineering, biosciences, geospatial, and data sciences. The Project expands basic understanding of complex biological, chemical, geospatial, and material properties and processes at varying scales and time to support applied research and advanced technology development in the future. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work is performed by the United States (U.S.) Army Engineer Research and Development Center.$$, 15702000, NULL, NULL, NULL, NULL, 19109000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601102A_CH9$$, $$0601102A$$, $$CH9$$, $$Advancing Concepts and Technology$$, 3758000, $$This Project works across the Army Futures Command Combat Capabilities Development Command, with the Futures and Concepts Center, and the Directorate of Intelligence and Security to identify emerging and disruptive basic scientific research outcomes to translate, integrate, and ingrain research outcomes with Army Warfighting Concepts. Army Warfighting Concepts describe how the Army will fight in the far-term future and the Future Operational Environment contextualizes projected basic research in the deep future. Outcomes describe the projected future operational effects of science in the context of Army Concepts and the Future Operational Environment to enable informed decision making and mitigate risk for future Army capabilities. Advancing Concepts ensures Army Concepts are grounded by recent and anticipated discoveries in basic scientific research. Army basic research is use-inspired to address the future capability needs identified in the Army Concepts, and learning opportunities are created to advance Army Concepts and operationalize science for transformational overmatch. Technology Forecasting develops timely, objective, scientifically-grounded projections of scientific advances that hold promise to impact future operational capabilities for the Army. Emerging scientific areas are described and communicated across the Army Modernization Enterprise to inform Science and Technology decisions. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the Army Research Laboratory (ARL).$$, 3758000, NULL, NULL, NULL, NULL, 3782000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601102A_T14$$, $$0601102A$$, $$T14$$, $$BASIC RESEARCH INITIATIVES -$$, NULL, $$Congressional Interest Item funding provided for Defense Research Sciences. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy.$$, NULL, NULL, NULL, NULL, NULL, 38000000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601102F_613001$$, $$0601102F$$, $$613001$$, $$Physics and Electronics$$, 87303000, $$Basic research in the Physics and Electronics Project seeks to enable revolutionary advances and expand the fundamental knowledge supporting technologies critical to the future of the Department of the Air Force. Research prioritizes high-risk, high-reward, game-changing scientific breakthroughs essential for future leaps in warfighter system performance, functionality, reliability, and survivability while simultaneously reducing component and system power, size, mass, and life cycle costs. Major areas being investigated in this project are complex electronics and fundamental quantum processes; plasma physics and high energy density non-equilibrium processes; and lasers and optics, electromagnetics, communication, and signal processing. While the following specific efforts are the focus of the project, there is interest in exploring novel ideas that may bridge these major efforts as well as those in the other projects within this program.$$, 87303000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601102F_613002$$, $$0601102F$$, $$613002$$, $$Aerospace, Chemical and Material$$, 92045000, $$Basic research in the Aerospace, Chemical, and Materials Sciences Project seeks to enable revolutionary advances and expand the fundamental knowledge supporting technologies critical to the future of the Department of the Air Force. Research stresses high-risk, high-reward, game-changing scientific breakthroughs essential for future leaps in warfighter system performance, functionality, reliability, and survivability while simultaneously reducing component and system power, size, mass, and life cycle costs. Research topics include: aero-structure interactions and control; energy, power, and propulsion; complex materials and structures; and cross-disciplinary research reflecting the highly integrated nature of future weapon systems. While the following specific efforts are the focus of the project there is interest in exploring novel ideas that may bridge these major efforts as well as those in other projects within this program.$$, 92045000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601102F_613005$$, $$0601102F$$, $$613005$$, $$STEM Pipeline Development$$, 4892000, $$The major efforts in the Science, Technology, Engineering, and Mathematics (STEM) Pipeline Development Project are initiatives to support STEM education and outreach activities for kindergarten through 12th grade (K-12) students, and to support activities that encourage elementary, middle, and high-school youth to develop an interest in, and pursue, higher education and employment in the science, mathematics, and engineering career fields. These initiatives benefit the Department of the Air Force by cultivating a progressive pipeline of highly-trained and knowledgeable STEM professionals aimed at filling Department of the Air Force STEM workforce needs. This project seeks to cultivate STEM opportunities across the Department of the Air Force by supporting education and outreach activities that promote foundational knowledge building and experiential learning to inspire young students to pursue STEM-related career fields of critical importance to the Department of the Air Force.$$, 4892000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601102SF_610001$$, $$0601102SF$$, $$610001$$, $$Defense Research$$, 22270000, $$Defense Research Sciences consists of research activities in academia and industry along with research performed in the Department of the Air Force (DAF), including the Air Force Research Laboratory, Air Force Institute of Technology, and the United States Air Force Academy. This program supports basic broad-based scientific and engineering research in areas critical to the five core technical competencies of the United States Space Force: Space Security; Combat Power Projection; Space Mobility and Logistics; Information Mobility; and Space Domain Awareness, while simultaneously building capacity in academia and cultivating the Science, Technology, Engineering, and Mathematics (STEM) pipeline. All research areas are subject to long-range planning and technical review by both DAF and tri-Service scientific planning groups. Efforts in this program have been coordinated through the Department of Defense (DoD) Science and Technology (S&T) Executive Committee process to harmonize efforts and eliminate duplication. This program is executed by the Air Force Research Laboratory (AFRL). AFRL is focused on high-impact, multi-domain science and technology (S&T) solutions that propel innovation today and support the Air and Space Force in securing dominance in future operational environments. AFRL effectively aligns the Department of the Air Force (DAF) S&T enterprise and workforce towards the most consequential DAF priorities to accelerate the delivery of game-changing S&T. In order to manage, execute, and deliver science and technology capabilities, this program element may include necessary civilian pay expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, administrative contractor services, etc. Funds in this program element may be used to investigate specified science advancements primarily targeted to challenges in the space domain and multi-domain research with space-domain application. The FY 2026 request was increased by 0.921 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, Implementing the President's Department of Government Efficiency Cost Efficiency Initiative. The Air Force Research Laboratory (AFRL) utilizes 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories” to manage the workforce strength, structure, positions, and compensation without regard to any limitation on appointments, positions, or funding in a manner consistent with the budget. This program is in Budget Activity 1, Basic Research because this budget activity includes scientific study and experimentation directed toward increasing fundamental knowledge and understanding in those fields of the physical, engineering, environmental, and life sciences related to long-term national security needs. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 1: Basic PE 0601102SF / Defense Research Sciences Research$$, 22270000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601103A_AB3$$, $$0601103A$$, $$AB3$$, $$MURI/PECASE/DURIP$$, 78947000, $$This Project supports the Multidisciplinary University Research Initiative (MURI), the Defense University Research Instrumentation Program (DURIP), and the Presidential Early Career Awards for Scientists and Engineers (PECASE) program. The MURI program funds university based basic research in a wide range of scientific and engineering disciplines pertinent to maintaining land combat technology superiority. Army MURI efforts involve teams of researchers investigating high- priority, transformational topics that intersect more than one traditional technical discipline. For many complex problems, this multidisciplinary approach serves to accelerate research progress and expedite transition of results to application. The DURIP provides funds to acquire major research equipment to augment current, or devise new, research capabilities in support of Army transformational research. The PECASE program funds single-investigator research efforts performed by outstanding academic scientists and engineers early in their research careers. Work in this Project provides a foundation for applied research initiatives at the Army laboratories and centers. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the Army Research Laboratory (ARL).$$, 78947000, NULL, NULL, NULL, NULL, 72781000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601103F_615094$$, $$0601103F$$, $$615094$$, $$University Research$$, 94121000, $$This program supports defense-related basic research in a wide range of scientific and engineering disciplines relevant to maintaining U.S. military technological superiority. Research topics include, but are not limited to, transformational and high-priority technologies such as nanotechnology, sensor networks, artificial intelligence and information fusion, smart materials and structures, quantum materials and processes for sensing, communication and computing, efficient energy and power conversion, and high-energy materials for propulsion and control. The program also enhances and promotes the education of U.S. scientists and engineers in disciplines critical to maintaining, advancing, and enabling future U.S. defense technologies. For example, the National Defense Science and Engineering Graduate (NDSEG) program awards fellowships to train U.S. citizens in science and engineering disciplines of military importance under a joint tri-Service and Office of the Under Secretary of Defense for Research and Engineering competitive scholarship program. Finally, this program assists universities in establishing superior instrumentation capabilities needed to improve the quality of defense-related research and education. A fundamental component of this program is the recognition that future technologies and technology exploitations require highly coordinated and concerted multi- and interdisciplinary efforts. Efforts in this program have been coordinated through the Department of Defense Science and Technology Executive Committee process to harmonize efforts and eliminate duplication. This program is executed by the Air Force Research Laboratory (AFRL). AFRL is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. In order to manage, execute, and deliver S&T capabilities, this program element may include: necessary civilian expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, administrative contractor services, etc. Funds in this program element may be used to investigate specified science advancements in air, space and/or cyber domains. This program is in Budget Activity 1, Basic Research because this budget activity includes scientific study and experimentation directed toward increasing fundamental knowledge and understanding in those fields of the physical, engineering, environmental, and life sciences related to long-term national security needs. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 1: Basic       PE 0601103F / University Research Initiatives Research$$, 94121000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601103N_0000$$, $$0601103N$$, $$0000$$, $$University Research Initiatives$$, 0, $$The Office of Naval Research's (ONR) mission is to ensure the technological advantage of U.S. Naval forces. ONR fosters scientific research necessary for the discovery, development and delivery of new technologies. Often this research is done in partnership with academia. This program includes support for multidisciplinary basic research in a wide range of Naval relevant scientific and engineering disciplines that enables the U.S. Navy to maintain technological superiority and for the university research infrastructure to acquire the research instrumentation needed to maintain and improve the quality of university research important to the Navy. In order to provide greater transparency of Department of the Navy University Research Initiatives (URI) investments, funding has been transferred into new Projects within this PE (0601103N): - The Defense University Research Instrumentation Program (DURIP) project supports university research infrastructure essential to high quality, Navy-relevant research. This research instrumentation project complements Naval research objectives by supporting the purchase of high-cost research instrumentation that is necessary to carry out cutting-edge research. This research investment has been aligned to new Project 1100. - Multidisciplinary University Research Initiative (MURI) efforts involve teams of researchers investigating high priority topics and opportunities that intersect more than one traditional technical discipline. For many military problems, this multidisciplinary approach serves to stimulate innovation, accelerate research progress, and lay the foundation for transition of results into Naval applications. This investment has been aligned to new Project 1101. - The Presidential Early Career Awards (PECASE) project supports single-investigator research efforts performed by outstanding academic scientists and engineers early in their research careers. This project provides the knowledge base, scientific concepts, and technological advances for the maintenance of Naval power and national security. This investment has been aligned to new Project 1102. - The Minerva Research Initiative (MRI) is a partnership with the Office of the Secretary of Defense (OSD) to support basic social science and multi-disciplinary research aimed at improving national security and international stability. All research activities under the MRI project were moved to the Defense Research Sciences (DRS) PE 0601153N starting in FY 2024. - The ONR Graduate Student and Postdoctoral Research (GSPR) Fellow Support project supports the participation of graduate students and postdoctoral fellows in DON-related research. These graduate students and postdoctoral fellows will be the future leaders in areas of science, technology, engineering and mathematics (STEM) critical to DON, DOD and national security. This investment has been aligned to new Project 1103. Due to the number of efforts in this PE, the programs described herein are representative of the work included in this PE.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601103N_1100$$, $$0601103N$$, $$1100$$, $$Defense University Research$$, 16189000, $$Defense University Research Instrumentation Program (DURIP) funds are awarded to universities to purchase relatively high cost research instrumentation that is normally not provided for in single-investigator research grants. Individual grants may range from $50K to $3.0M. Proposals for DURIP awards are submitted to Defense Services (Army, Navy, Air Force, Space Force) in response to a public Funding Opportunity Announcement (FOA). Proposals received by the Office of Naval Research (ONR) are reviewed and all valid proposals received are prioritized. The Office of the Secretary of Defense (OSD) reviews, selects and announces all Depart of Defense (DoD) awardees. Universities awarded grants are required to purchase the instrumentation and take delivery before any billing occurs. DURIP awards provide one-year funding. For all DURIP awards proposals are required to be received, reviewed, prioritized, announced, initiated and completed within one fiscal year.$$, 16189000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601103N_1101$$, $$0601103N$$, $$1101$$, $$Multidisciplinary University Research$$, 51117000, $$The Multidisciplinary University Research Initiative (MURI) project is a Department of Defense (DoD) coordinated effort that supports high priority pure research topics. Each MURI topic is a five-year research grant addressing a challenging multidisciplinary scientific problem. MURI topics require collaboration among academic experts across disciplines from two or more universities to explore solutions to these cross-Service research challenges. The Office of the Undersecretary of Defense (OUSD) calls for new research topics annually, provides topic guidance, and approves new topics from each of the Defense Services. Office of Naval Research (ONR) MURI topics are selected based on Naval Science and Technology (S&T) priorities. Proposals for MURI research topics are submitted in response to a public Funding Opportunity Announcement (FOA) and all valid research proposals are evaluated by teams of technical experts. The Office of the Secretary of Defense (OSD) reviews all award nominations and announces selected awardees. Only US Universities and Research Institutions are eligible performers and the funding is provided through research grants. MURI projects make significant contributions to Navy and Department of Defense (DOD) objectives by accelerating research results through multi-university collaboration, a cross-fertilization of ideas, concepts and research approaches pursued. This collaborative research environment nurtured hastens the maturation of basic research concepts to applied applications and through the training of students in cross-disciplinary approaches to science and engineering research topics of priority interest to DoD.$$, 51117000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601104A_AB4$$, $$0601104A$$, $$AB4$$, $$Army Research Centers$$, 23314000, $$This project encompasses three types of Centers. The first is the Historically Black Colleges and Universities/Minority Institutions (HBCU/MI) Research Centers of Excellence which support the Army's research partnerships with HBCUs/MIs. The HBCU/MI Research Centers of Excellence were established as the next phase of what was previously known as the Partnered Research Initiative (PRI) Program that ended in Fiscal Year 2020. The focus of the HBCU/MI Research Centers of Excellence Program is to advance innovative basic research leading to potential technology development in areas of strategic importance to the Army by competitively selecting HBCU and MI research teams for grants or cooperative agreements. Awards have five-year periods of performance, with all supporting the Army's goal of broadening the performer base and diversifying the research ecosystem in the areas of information sciences, engineering, and physical sciences. The second is the University Affiliated Research Centers (UARCs). Army UARCs have been created to exploit opportunities to advance new capabilities through a sustained long-term multidisciplinary effort. The Institute for Soldier Nanotechnologies focuses on Soldier protection by emphasizing revolutionary materials research for advanced Soldier protection and survivability. The Institute for Collaborative Biotechnologies focuses on enabling network centric-technologies and broadening the Army's use of biotechnology for the development of bio-inspired materials, sensors, and information processing. The Institute for Creative Technologies is a partnership with academia and the entertainment and gaming industries to leverage innovative research and concepts for training and simulation. Examples of specific research of mutual interest to the entertainment industry and the Army are technologies for realistic immersion in synthetic environments, networked simulation, standards for interoperability, and tools for creating simulated environments. The third is the Army Centers of Excellence (COEs). The COEs focus on expanding the frontiers of knowledge in research areas where the Army has enduring needs and couples state-of-the-art research programs at academic institutions with broad-based graduate education programs to increase the supply of scientists and engineers in automotive and rotary wing technology. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this project is completed by the Army Research Laboratory (ARL), Aviation and Missile Center (AvMC), and Ground Vehicle Systems Center (GVSC).$$, 23314000, NULL, NULL, NULL, NULL, 24522000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601104A_AB7$$, $$0601104A$$, $$AB7$$, $$Army Collaborative Research and$$, 29659000, $$This project supports the Army Collaborative Research Alliances (CRAs) and Collaborative Technology Alliances (CTAs). CRAs and CTAs are partnerships between Army laboratories and centers, private industry, and academia that focus on the rapid transition of innovative technologies to the Warfighter to enable the Army's Future Force. The collaboration between industry, academia, and the government is a key element of the alliance concept as each member brings with it a distinctly different approach to research. Academia is known for its cutting-edge innovation; the industrial partners are able to leverage existing research results for transition and to deal with technology bottlenecks; and the Army researchers keep the program oriented toward solving complex Army technology problems. This approach enables an Alliance to bring together world class research and development talent and focus it on Army-specific technology objectives for application to Army needs. The topics covered by CRAs and CTAs include cyber security (funded in PE 0601121A / Cyber Collaborative Research Alliance), the internet of battlefield things, distributed and collaborative intelligent systems technology, neuroergonomics and neuroscience, advanced materials, exploitation of quantum effects, semiconductor modeling, convergent manufacturing, autonomous maneuver and machine learning and artificial intelligence. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this project is performed by the Army Research Laboratory (ARL).$$, 29659000, NULL, NULL, NULL, NULL, 58118000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601104A_AB8$$, $$0601104A$$, $$AB8$$, $$Army Educational Outreach Program$$, 12666000, $$This project supports science, technology, engineering, and mathematics (STEM) activities that encourage elementary/middle/high school and undergraduate youths to develop an interest in and pursue education in the STEM fields to support the Army, and the nation's growing dependence on STEM skills. These activities are coordinated within the Army Educational Outreach Program (AEOP) that links and networks appropriate components to derive the best synergies to present the Army to a larger pool of technical talent and to provide students with Army-unique practical experiences at Army laboratories, centers, and institutes and expose them to Department of Defense (DoD) careers. AEOP increases interest and involvement of students and teachers across the nation in STEM, including military affiliated communities, through exposure to Army sponsored research, education, competitions, internships, and practical experiences. This project utilizes Army STEM assets to contribute to a STEM literate citizenry as well as enhances the national pool of science and engineering personnel that in turn supports defense industry and Army laboratory and research, development, and engineering center needs. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy.$$, 12666000, NULL, NULL, NULL, NULL, 11889000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601104A_AC6$$, $$0601104A$$, $$AC6$$, $$International Science and Technology$$, 3752000, $$This project funds: 1) the Army Combat Capabilities Development Command (DEVCOM) International Technology Centers (ITCs), and 2) the Foreign Technology (and Science) Assessment Support (FTAS) program. The ITCs seek to discover highly promising basic research from the universities of foreign partners and awards seed funding to discoveries that support the United States Army's Science and Technology (S&T) strategy. The ten ITCs located in North America, South America, Asia, and Europe support the Army's goals of providing the best technology in the world to our Warfighters by leveraging the international S&T investments of international partners, thereby increasing our ability to use limited S&T funds on promising research opportunities. The ITCs will identify and assess international technology programs, 'technology finds', to assess their potential impact on the Army's S&T investment strategy and modernization priorities. These 'technology finds' are submitted to various Army S&T organizations for assessment and consideration to determine their suitability for investment. Highly promising research will be awarded seed funding through a grant, contract, or cooperative agreement. The FTAS program also builds upon the 'technology finds' submitted by the ITCs. In some cases, the find is truly unique and may well meet an Army requirement or potentially support ongoing Army S&T investments or modernization priorities. In such cases, the FTAS program can provide initial resources (seed money) to determine the appropriateness of these technology areas identified as having potential relevance to the Army. These efforts will provide information useful in making early assessments of the technology's potential contributions to the Army's S&T strategy and modernization priorities The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this project is performed by the U.S. Army Combat Capabilities Development Command (DEVCOM) Headquarters Forward Elements.$$, 3752000, NULL, NULL, NULL, NULL, 7343000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601104A_J13$$, $$0601104A$$, $$J13$$, $$UNIVERSITY AND INDUSTRY$$, NULL, $$Congressional Interest Item funding provided for University and Industry Initiatives. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy.$$, NULL, NULL, NULL, NULL, NULL, 16000000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601153N_1391$$, $$0601153N$$, $$1391$$, $$Full Spectrum Cyber$$, 0, $$The Full Spectrum Cyber research area addresses a number of research topics to include, but not limited to, advanced/emerging and theoretical implications of advanced networking architectures, neural networks, artificial intelligence (AI), machine learning (ML), secure software algorithms, autonomous operating agents/ systems, vulnerability analysis, use of intelligent agents, cryptographic computing, defenses against cyber-attacks, threat modeling, privacy-enhancing technologies, covert and encrypted communications, reconfigurable system design, quantum sensors, etc. Basic research activities within this area include: - Complex Software Systems and Cybersecurity - Expeditionary Cyber - Networks and Communications - Science of Artificial Intelligence$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601108D8Z_108$$, $$0601108D8Z$$, $$108$$, $$High Energy Laser$$, 16817000, $$This program is executed via the Joint Directed Energy Transition Office (JDETO) in alignment with the Department of Defense Directed Energy Roadmap, as well as other strategic guidance. Section 219 of the 2017 National Defense Authorization Act designated a senior official for directed energy and redesignated a legacy office as the JDETO with reporting to the senior official. Currently, the Principal Director for Directed Energy serves as this senior official and updates the Department of Defense Directed Energy Roadmap on an annual basis. The goal of this program, in turn, is to support the Department’s initiatives in directed energy to build a sustainable and long-term advantage, in addition to a resilient Joint force and defense ecosystem. This program funds basic research in directed energy to enable game-changing high energy laser and high power microwave technologies. These efforts provide fundamental scientific knowledge to support future Department of Defense directed energy weapon systems. In practice, directed energy weapon systems have many potential advantages, including speed-of-light time-to-target, high precision, low incremental cost per kill, and a magazine that is recharged through on-board, fuel-based power and thermal management systems that reduce logistics requirements in contrast to stocks of munitions or warheads. As a result, directed energy weapon systems have the potential to perform a wide variety of military missions. Activities conducted under this program are generally chosen for their potential to grow the directed energy workforce with next-generation scientists and engineers. This program is part of an overall Department of Defense strategy in Joint directed energy basic research. Efforts within this program will leverage multi-disciplinary university research institutes (both domestic and international) to stimulate student interest in directed energy and encourage research in topics related to high energy laser and high power microwave technologies. This program builds upon other investments in directed energy basic research by the Services and Agencies to harmonize Department efforts and eliminate duplication. In support, efforts in this program have been coordinated with the Department of Defense Directed Energy and Non-Lethal Weapons Science and Technology Community of Interest. This program is executed via a technical program within the JDETO referred to as the Directed Energy Center of Excellence Program, which enables (1) basic research in directed energy technology that supports workforce development with university partners and (2) international collaboration between universities in the United States and partner countries. Note that (1) and (2) are in alignment with the near-, mid-, and long-term goals of Department of Defense Directed Energy Roadmap and encourage transition. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                              Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 1: Basic PE 0601108D8Z / High Energy Laser Research Initiatives Research$$, 16817000, NULL, NULL, NULL, NULL, 40497000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601110D8Z_010$$, $$0601110D8Z$$, $$010$$, $$Basic Research Initiatives$$, 16551000, $$The Basic Research Initiatives Project supports oversight of basic research throughout the Department, as well as initiatives and pilot programs, in order to create conditions for defense basic research investments to produce high-payoff, transformative scientific breakthroughs for the Department. The project supports the five Basic Research Office (BRO) strategic goals: (1) support the technology priorities set by the Department of Defense (OSD); (2) coordinate and conduct oversight of DoD-wide basic research programs; (3) improve the science and engineering workforce via tailored programs and public outreach; (4) enhance university-industry and university-government collaboration; and (5) engage with the academic research community and international partners. This Project includes Strategic Support for Basic Research (SSBR), which sustains the operations of the BRO and creates conditions for research policies and initiatives to be formulated and instantiated. It also includes several pilot programs and initiatives, including the Defense Established Program to Stimulate Competitive Research (DEPSCoR), international research collaboration, and cross-agency joint programs.$$, 16551000, NULL, NULL, NULL, NULL, 42931000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601110D8Z_016$$, $$0601110D8Z$$, $$016$$, $$Minerva Research Initiative$$, 17199000, $$The Minerva Research Initiative supported social science research aimed at improving our basic understanding of security, broadly defined. All supported projects were university-based and unclassified. The goal was to improve DoD’s basic understanding of the social, cultural, behavioral, and political forces that shape regions of the world of strategic importance to the U.S.$$, 17199000, NULL, NULL, NULL, NULL, 17143000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601110D8Z_060$$, $$0601110D8Z$$, $$060$$, $$Vannevar Bush Faculty Fellowship$$, 48514000, $$The Vannevar Bush Faculty Fellowship (VBFF) program supports world-class researchers in scientific areas of critical importance to the DoD and ensures the cultivation of exceptional talent. Fellows’ research spans a broad set of emerging scientific areas with transformative potential, including quantum information science, novel engineered materials, cognitive neuroscience and human-machine interfaces, engineering biology, applied and computational mathematics, networks, machine learning and artificial intelligence, manufacturing science, and others. The prestigious research program delivers the most innovative and transformational scientific ideas of relevance to the DoD, from the top scientists in the Nation. The program fosters close connections between academia and the defense science and engineering (S&E) enterprise, a primary goal of Strategic Support for Basic Research (SSBR) efforts. Fellows provide the Department the deep scientific expertise from today’s leading research universities and collaborate with defense scientists and engineers. This program actively engages and coordinates basic research across the Department. The project includes support for the Laboratory-University Collaboration Initiative (LUCI) program, which is designed to team scientists in the DoD laboratories with top academic researchers from the programs sponsored or overseen by the Office of the Secretary of Defense (in particular, the VBFF fellows), in order to collaboratively perform research on a topic of their choice and explore early adoption of the scientific discoveries for military applications, platforms and systems, operations, and strategic roadmaps. Three-year grants allow a deep exchange of ideas between academic and DoD research communities, bring the most recent scientific breakthroughs closer to DoD relevance, and greatly expand the skills and knowledge of the S&E workforce within the laboratories. The project also supports the Bush Fellows Research Study Team (BRFST) program, designed to allow selected leaders in the academic research community to engage with the DoD at high levels, including briefings from MAJCOMs and site visits to military installations. This program brings deeper understanding of military operations and strategic vision to selected US academic researchers, in order to enhance the creation of out-of-the-box, innovative solutions and the growth of intellectual talent attuned to DoD mission needs. Extension of this program will enhance relevance of university-based research to the military mission.$$, 48514000, NULL, NULL, NULL, NULL, 30444000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601117E_MED-01$$, $$0601117E$$, $$MED-01$$, $$BASIC OPERATIONAL$$, 0, $$The Basic Operational Medical Science Program Element (PE) will explore and develop basic research in medical-related information and technology leading to fundamental discoveries, tools, and applications critical to overcoming DoD challenges. This PE will address the Department's identified need for warfighter medical care related to prevention and treatment of infectious disease, real-time healthcare interventions of acute and chronic illness and injury, and interventions for improved warfighter resilience and performance against operational stressors. This PE also supports innovation and robust transition planning in the technology cycle by working with entrepreneurs to increase the likelihood that DARPA-funded technologies take root in the U.S. and provide new capabilities for national defense. Beginning in FY 2026, efforts in this PE will be funded in PE 0601122E, Emerging Opportunities.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601120D8Z_120$$, $$0601120D8Z$$, $$120$$, $$National Defense Education$$, 146010000, $$This program supports the Department's strategy to Build Sustainable and Long-Term Advantage and Cultivate the Workforce that the DoD needs. The National Defense Education Program (NDEP) supports the National Defense Science & Technology Strategy in ensuring the foundations for research and development have the workforce it needs now and into the future, through investments at every level of education. NDEP: (1) Fosters and enhances the Department of Defense’s (DoD) ability to develop and access high-quality science, technology, engineering, and mathematics (STEM) talent vital to national defense; (2) Is executed by the Office of the Under Secretary of Defense for Research and Engineering (OUSD(R&E)); (3) Aligns to the Federal STEM Strategy, and addresses critical STEM education and talent development challenges across the PreK-20 education continuum through evidence-based approaches; (4) Activities align with the Department’s vision of a diverse STEM talent pool readily accessible to serve our Nation and evolve the Department’s competitive edge; (5) Activities engage in assessment and evaluation practices as outlined by the Office of Management and Budget and the Government Accountability Office; and (6) Aligns to the DoD STEM Strategic Plan in support of the National Defense Strategy and the DoD science and technology (S&T) critical technology areas. NDEP is part of the broader Department-wide effort under DoD STEM, which works collectively with partners from academia, industry non-profit organizations, defense research laboratories and engineering centers, and other government entities to: (1) build strong foundations for STEM literacy; (2) increase inclusion, diversity, and equity in STEM; and (3) prepare the STEM workforce of the future. NDEP activities provide authentic learning experiences through a variety of education and outreach initiatives in the form of scholarships, internships, enrichment activities, project/research-based competitions, and mentorships through strategic partnerships. The NDEP programs span across all age groups, including Pre- kindergarten through twelfth grade (PreK-12) students and teachers, and postsecondary, undergraduate, and graduate students. The NDEP’s portfolio includes: the Science, Mathematics, and Research for Transformation (SMART) scholarship-for-service program; STEM Education and Outreach (E&O) efforts including the Defense STEM Education Consortium (DSEC); and specific Congressionally directed programs, to include the Manufacturing Engineering Education Program (MEEP) per 10 U.S. Code 4843 and broader NDEP funding opportunities in STEM education and workforce development. The SMART Program enables the Department to transform its STEM workforce while addressing near-term workforce demands. Per 10 U.S. Code 4093, the SMART program awards highly competitive scholarships to undergraduate and graduate students in any of the 24 STEM academic disciplines critical to national security, and Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                  Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 1: Basic PE 0601120D8Z / National Defense Education Program (NDEP) Research hires the students, upon graduation, into DoD's civilian workforce. As part of the SMART experience, scholars engage in internships that allow for relevant hands-on research and work experiences in DoD facilities and international partner research institutions, thereby enhancing their educational experience. The SMART program ensures the Department has a steady infusion of high-quality technical talent, prepared in areas of critical importance, and ready to apply their technical knowledge, skills, and abilities to fulfill the DoD mission. Through an annual competitive SEED grant, SMART offers transitioning Ph.D. scholars an opportunity to establish a foundational research and engineering effort in their area of expertise aligned with a DoD mission or critical technology area and supporting their development into subject matter experts. Additionally, per FY 2021 NDAA Sec. 250, SMART also offers a competitive funding opportunity through the Creative Research & Engineering Advancing Technical Equity in STEM (CREATES) Grant to expand and enhance connections and opportunities between the SMART program, SMART scholars, SMART sponsoring facilities, and students and faculty at Historically Black Colleges and Universities (HBCU), Minority Institutions (MI), Minority Service Institutions (MSI), Tribal Colleges and Universities (TCU) and Women’s Colleges (WC). Since its inception in FY 2005, SMART has awarded approximately 5,200 scholarships to students pursuing undergraduate and graduate STEM degrees. To date, over 3,400 scholars have completed their academic pursuit and transitioned into DoD employment. More than 1,300 scholars are currently pursuing their SMART-funded degrees. Over 2,000 participants have successfully completed the program through their DoD Service commitment. NDEP’s STEM E&O activities will continue to engage military-connected students in collaboration with the Department of Defense Education Activity (DoDEA), external partners, and other stakeholders to support the preparation of dependents of members of the armed forces for careers in STEM as enacted under 10 U.S. Code 2192(b). Additionally, where feasible, NDEP activities will also support the Supporting Veterans in STEM Careers Act, enacted in FY 2020. Per 10 U.S. Code 2192, NDEP’s STEM E&O activities support a cohesive and coordinated approach by providing a continuum of preK to career opportunities for students, educators (formal and informal), administrators, and schools, especially for military-connected students. The primary effort under NDEP STEM E&O is the Defense STEM Education Consortium (DSEC), which is a consortium-model approach, leveraging a collaborative ecosystem of partners that aims to develop America’s STEM workforce of the future ready to support the national security mission and the Warfighter. The DSEC is a multi-year investment through a cooperative agreement award comprised of a consortium of program partners that have a national reach, as well as regionally focused activities leveraging evidence-based approaches. In FY2025, about 40% of SMART Scholarship recipients previously participated in preK-12 programs such as those funded under DSEC. DSEC is designed to evolve over time, enabling the Department and the consortium the flexibility to bring in new strategic partners to address emerging issues in STEM education and talent development, and to align to DoD’s priorities. The Biotechnology Education and Workforce Development (BIOTECH) efforts will be consolidated into the STEM E&O beginning in FY 2026 and establishes new educational programs that align with biotechnology priorities through competitive grants and internal call for proposals. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                   Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 1: Basic PE 0601120D8Z / National Defense Education Program (NDEP) Research$$, 146010000, NULL, NULL, NULL, NULL, 168539000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601153N_1392$$, $$0601153N$$, $$1392$$, $$Human Systems$$, 0, $$Humans are at the core of every current and foreseeable Naval mission, whether they are assessing, coordinating and communicating decisions and actions across and within command echelons, planning and directing missions, controlling, managing or supervising systems in support of a mission, or directly executing the mission. The ability to select, train, sustain, maintain, and improve innate human competencies extends the warfighter's ability to meet current and anticipated needs. Creating synergies between warfighters and their technologies positions naval forces to quickly pivot to meet and dominate future challenges. The basic research in this project will lead to the development of future capabilities for maintaining, sustaining, and enhancing a warfighter's performance across a range of missions and operational environments throughout their career. The science and resulting technologies enable streamlined talent management, enhance cognitive and physical performance, and augment warfighter-machine teaming for greater operational effectiveness.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601121A_CB5$$, $$0601121A$$, $$CB5$$, $$Cyber Collaborative Research$$, 5463000, $$This Project fosters cyber research, performed by a competitively selected consortium, formed to advance the theoretical foundations of cyber science in the context of Army networks. This work consists of academia, industry, and government researchers working jointly to develop a fundamental understanding of cyber phenomena so that fundamental laws, theories, and theoretically grounded and empirically validated models can be applied to a broad range of Army domains, applications, and environments. This research focuses on three interrelated cyber aspects and is conducted using a trans-disciplinary approach that takes into account the human element of the network. The three aspects of cyber that are addressed are: 1) adaptive reasoning for deception, 2) anticipating, detecting, and analyzing malicious activities, and 3) agile cyber maneuver to thwart and defeat malicious activities. The overarching goals are to significantly decrease the adversary's return on investment when considering cyber-attack on Army networks and minimizing the impact on Army network performance. This research creates a framework that effectively integrates the knowledge of cyber assets and potential adversary capabilities and approaches and provides defense mechanisms that dynamically adjust to changes related to mission, assets, vulnerability state, and defense mechanisms. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the Army Research Laboratory (ARL).$$, 5463000, NULL, NULL, NULL, NULL, 5459000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0601122E_EMR-01$$, $$0601122E$$, $$EMR-01$$, $$MATH AND$$, 194578000, $$The efforts described in this Program Element (PE) address the Basic Research associated with the Emerging Opportunities Program that provides the technical foundation for long-term National Security enhancement through the discovery of new phenomena and the exploration of the potential of such phenomena for Defense applications. This PE supports the scientific study and experimentation that is the basis for more advanced knowledge and understanding in quantum, electronic, mathematical, information, computer, materials, and medical sciences. This PE also supports innovation and robust transition planning in the technology cycle by working with entrepreneurs to increase the likelihood that DARPA funded technologies take root in the U.S. and provide new capabilities for national defense. The Math and Computer Sciences project supports scientific study and experimentation on new mathematical and computational algorithms, models, and mechanisms in support of long-term national security objectives. Modern information technologies, both classical and quantum, and analytic technologies, enable important new military capabilities and drive the productivity gains essential to U.S. economic competitiveness. Conversely, new classes of threats require the creation of fundamentally new mathematical and computational approaches to enhance the software-intensive systems upon which our society depends. The basic research conducted under the Math and Computer Sciences project will produce breakthroughs that enable new capabilities for national and homeland security. The Disruptive Microtechnologies Sciences project supports investigations into materials, devices, and architectures that will enable dramatic improvements versus the current state-of-the-art. This includes developing technology to enable fundamentally new ways of creating useful circuits to enable the next generation of microtechnologies. Areas of focus include photonic circuits that harness the power of light at the chip-scale, quantum circuits that take advantage of the unique properties that quantum offers versus classical computing and sensing, and organic circuits that integrate organic molecules into microtechnologies. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                                            Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 1: Basic PE 0601122E / EMERGING OPPORTUNITIES Research The Materials Sciences project provides the fundamental research that underpins the design, development, assembly, and optimization of advanced materials, devices, and systems for DoD applications in areas such as design and simulation of novel materials and structures, energetics, complex hybrid systems, and advanced metrology. The Basic Operational Medical Science project will explore and develop basic research in medical-related information and technology leading to fundamental discoveries, tools, and applications critical to overcoming DoD challenges. This project will address the Department's identified warfighter medical care related to prevention and treatment of infectious disease, real-time healthcare interventions of acute and chronic illness and injury, and interventions for improved warfighter resilience and performance against operational stressors. The Emerging Opportunities Support project contains non-headquarters management costs in support of DARPA functions and activities across the entire Emerging Opportunities PE. These costs include: DARPA classified and unclassified network support and equipment; contractor support; classified program security; building security; commercial transition services that increase the likelihood that DARPA-funded technologies remain in the U.S. and provide new capabilities for national defense; DARPA outreach to universities and industry; external contracting, financial and support fees; Program Manager Intragovernmental Personnel Act (IPA) Funding; Program Managers from other Government Agencies; and similar operating expenses. Agency support is allocated on a pro-rata basis across the Agency's BA1, BA2 and BA3 PEs and, therefore, fluctuates per PE by fiscal year based on the total Agency budget in that fiscal year. Prior to FY 2026, efforts in this PE were funded in PE 0601101E, Defense Research Sciences, and PE 0601117E, Basic Operational Medical Science.$$, 194578000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
