INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602134A_CD2$$, $$0602134A$$, $$CD2$$, $$Counter Improvised-Threat Advanced$$, 6174000, $$This Project investigates novel methods for detecting and defeating existing and emerging improvised explosive devices (IED) and their potential application against other explosive hazard threats. This Project is executed by the Army Futures Command (AFC) in coordination with the Under Secretary of Defense for Research and Engineering (USD(R&E)) and the Defense Threat Reduction Agency (DTRA). Work in this Project is fully coordinated with Program Element (PE) 0603134A (Counter Improvised Threat Simulation) / Project CD3 (Counter Improvised Threat Simulation). The cited work is consistent with the USD/R&E priority focus areas and the Army Modernization Strategy. Work in this Project is executed by the U.S. Army Combat Capabilities Development Command (DEVCOM) in coordination with the Under Secretary of Defense for Research and Engineering (USD(R&E)).$$, 6174000, NULL, NULL, NULL, NULL, 6014000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602026E_EFF-01$$, $$0602026E$$, $$EFF-01$$, $$EFFECTS$$, 19143000, $$The efforts described in this Program Element (PE) address the Applied Research associated with the examination and evaluation of emerging technologies and system concepts that employ either physical or non-physical means to degrade or deny targeted adversary capabilities. This PE also supports innovation and robust transition planning in the technology cycle by working with entrepreneurs to increase the likelihood that DARPA funded technologies take root in the U.S. and provide new capabilities for national defense. The Effects project will examine and evaluate emerging technologies and system concepts that employ physical or non-physical means to degrade or deny targeted adversary capabilities. The feasibility of achieving potential improvements, in terms of resources, schedule, and technological risk, is also evaluated. The results from these studies and initiatives are used, in part, to formulate future prototype development programs or refocus ongoing work. Topics for this thrust include: methods of defeating enemy anti-aircraft attacks; munition technologies to increase precision, range, endurance, and hard or soft-kill weapons for a variety of mission sets; digital design methodologies that are compatible with surged production. The Effects Support project contains non-headquarters management costs in support of DARPA functions and activities across the entire Effects PE. These costs include: DARPA classified and unclassified network support and equipment; contractor support; classified program security; building security; commercial transition services that increase the likelihood that DARPA-funded technologies remain in the U.S. and provide new capabilities for national defense; DARPA outreach to universities and industry; external contracting, financial and support fees; Program Manager Intragovernmental Personnel Act (IPA) Funding; Program Managers from other Government Agencies; and similar operating expenses. Agency support is allocated on a pro-rata basis across the Agency's BA1, BA2 and BA3 PEs and, therefore, fluctuates per PE by fiscal year based on the total Agency budget in that fiscal year. Prior to FY 2026, efforts in this PE were funded in PE 0602716E, Electronics Technology. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                                      Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:         PE 0602026E / EFFECTS Applied Research$$, 19143000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602026E_EFF-07$$, $$0602026E$$, $$EFF-07$$, $$EFFECTS SUPPORT$$, 1132000, $$The efforts described in this Program Element (PE) address the Applied Research associated with the examination and evaluation of emerging technologies and system concepts that employ either physical or non-physical means to degrade or deny targeted adversary capabilities. This PE also supports innovation and robust transition planning in the technology cycle by working with entrepreneurs to increase the likelihood that DARPA funded technologies take root in the U.S. and provide new capabilities for national defense. The Effects project will examine and evaluate emerging technologies and system concepts that employ physical or non-physical means to degrade or deny targeted adversary capabilities. The feasibility of achieving potential improvements, in terms of resources, schedule, and technological risk, is also evaluated. The results from these studies and initiatives are used, in part, to formulate future prototype development programs or refocus ongoing work. Topics for this thrust include: methods of defeating enemy anti-aircraft attacks; munition technologies to increase precision, range, endurance, and hard or soft-kill weapons for a variety of mission sets; digital design methodologies that are compatible with surged production. The Effects Support project contains non-headquarters management costs in support of DARPA functions and activities across the entire Effects PE. These costs include: DARPA classified and unclassified network support and equipment; contractor support; classified program security; building security; commercial transition services that increase the likelihood that DARPA-funded technologies remain in the U.S. and provide new capabilities for national defense; DARPA outreach to universities and industry; external contracting, financial and support fees; Program Manager Intragovernmental Personnel Act (IPA) Funding; Program Managers from other Government Agencies; and similar operating expenses. Agency support is allocated on a pro-rata basis across the Agency's BA1, BA2 and BA3 PEs and, therefore, fluctuates per PE by fiscal year based on the total Agency budget in that fiscal year. Prior to FY 2026, efforts in this PE were funded in PE 0602716E, Electronics Technology. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                                      Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:         PE 0602026E / EFFECTS Applied Research$$, 1132000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602102F_624347$$, $$0602102F$$, $$624347$$, $$Materials for Structures,$$, 59700000, $$This project develops and transitions materials and processing technologies to enhance the affordability, maintainability, and performance of current and future Air Force weapon systems. A key focus is affordable, lightweight materials for aircraft, spacecraft, missiles, and propulsion systems. These materials include metals, polymers, ceramics, metallic and nonmetallic composites, and hybrid materials, designed to improve the structural and performance of existing systems and to address future system needs. Key features of the materials and structures being developed are that they have improved ablation and oxidation resistance, structural integrity, thermal management capabilities, and strength to weight ratios. These attributes enable expanded mission capability for missile and aircraft systems. New processes are developed to provide more affordable solutions while maintaining the performance of fielded and future operational systems. To maintain the performance of fielded systems, the project develops alternative or replacement materials that address obsolescence challenges. The project develops advanced processing methods to enable adaptive manufacturing of aerospace materials.$$, 59700000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602102F_624348$$, $$0602102F$$, $$624348$$, $$Materials for Electronics, Optics,$$, 41402000, $$This project develops materials technologies for the Department of the Air Force's Intelligence, Surveillance, and Reconnaissance (ISR), situational awareness, and specialty coatings for aerospace platforms and munitions. This includes sensors for microwave, short, mid, and long-wave infrared (SWIR, MWIR, LWIR) detection and countermeasures devices used for targeting, electronic warfare, and active aircraft protection. Electronic and optical materials are being developed to enable surveillance and situational awareness with faster operating speeds, greater tunability, higher power output, improved thermal management (including higher operating temperatures), greater sensitivity, and extended dynamic range. This project develops materials for protection of aircrews, sensors, and aerospace structures from directed energy threats without impairing mission effectiveness. Nanostructured and biological materials are being developed for aerospace structures, munitions, aerospace vehicle subsystems, and personnel.$$, 41402000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602102F_624349$$, $$0602102F$$, $$624349$$, $$Materials Technology for$$, 46320000, $$This project develops materials and processing technologies to support operational Department of the Air Force mission areas by providing the ability to inspect the quality of delivered systems, transition more reliable and maintainable materials, establish a capability to detect and characterize performance threatening defects, characterize materials processes and properties necessary for materials transition, and provide quick reaction support and failure analysis to the operational commands and repair centers. Repair techniques and nondestructive inspection/evaluation (NDI/E) methods are developed that are needed for metallic and non-metallic structures, coatings, corrosion control processes, and to support integration of composite structures for aerospace systems. Various NDI/E methods are essential to ensure optimum quality in the design and production of aircraft, propulsion, and missile systems. These NDI/E methods are also essential to monitor and detect the onset of any service-initiated damage and/or deterioration due to aging of operational systems.$$, 46320000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602148A_BZ7$$, $$0602148A$$, $$BZ7$$, $$Future Vertical Lift Medical$$, 6921000, $$This Project involves research to prevent injury and performance degradation in Aviators, Unmanned Arial System (UAS) Operators and other Warfighters in training and operations; refines risk assessment and performance models based on operational stressors, e.g., sleep deprivation, work load, fatigue; and delivers biomedical-based spinal injury criteria and assessment methodologies. This research provides medical information important to the design and operational use of future vertical lift aircraft, and when appropriate, ground vehicles. The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy.$$, 6921000, NULL, NULL, NULL, NULL, 7624000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602114N_0000$$, $$0602114N$$, $$0000$$, $$Power Proj Applied Research$$, 30635000, $$In an Artificial Intelligence (AI) enabled maritime battlespace, the ability to fight at the speed of light will determine the outcome. The effective defense against threats increasingly beyond human speed, will enable U.S. naval forces to outthink, outmaneuver and outfight adversaries. This Program Element (PE) supports both advanced technology research and near to mid-term transition opportunities. The advanced research focus is primarily on Directed Energy, High Speed Weapon Propulsion, Electro-Optic/Infrared (EO/IR) Sensor Technologies, and Naval Precision Strike Decision Tools and Planning. The goal of this research is to develop technologies and capabilities that enable Directed Energy (DE) weapons as well as defense against adversary DE systems; the development of vehicle and propulsion technology for high-speed weapons operating from Mach 3 and beyond; investment in the areas of Electro Optic/Infrared devices and advanced sensors; and technologies that provide the navy of the future the ability to quickly locate, target, and strike critical targets in the maritime environment and ashore.$$, 30635000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602115E_BT-01$$, $$0602115E$$, $$BT-01$$, $$BIOMEDICAL$$, 0, $$The Biomedical Technology Program Element (PE) focuses on applied research for medical related technologies that will maintain warfighter health and performance before, during, or after operations. Successful technologies within this Program Element will maintain warfighter health against emerging threats through novel biothreat detection, rapid medical countermeasure identification and development, and distributed production of effective therapeutics. In-theater, warfighter health will be maintained through the development of field-relevant technologies such as reliable and accessible critical medical resources, novel detection and protection capabilities for traumatic brain injury, and rapid, effective triage of battlefield injuries. Technologies are also being developed to provide new capabilities for warfighter recovery from sustained injury including, but not limited, to spinal cord injury. Additionally, this PE will improve warfighter readiness by characterizing and assaying physical and cognitive performance to drive data-driven awareness. This PE also supports innovation and robust transition planning in the technology cycle by working with entrepreneurs to increase the likelihood that DARPA-funded technologies take root in the U.S. and provide new capabilities for national defense. Beginning in FY 2026, efforts in this PE will be funded in PE 0602024E, Warfighting Performance.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602123N_0000$$, $$0602123N$$, $$0000$$, $$Force Protection Applied Res$$, 125699000, $$This project addresses applied research associated with providing the capability of Platform and Force Protection for the U.S. Navy. It supports the development of technologies associated with all naval platforms (surface, subsurface, terrestrial, and air) and the protection of those platforms. Research is focused on providing technologically superior defense of naval assets and delivering warfighting capabilities at reduced total ownership costs for surface and subsurface platforms through investments in applied research in Power, Energy, Propulsion, Engineering, and Design. This project develops technologies for reducing detectable signatures, while enhancing the mission effectiveness of naval platforms (surface, subsurface, terrestrial, and air) through improvements in platform range, responsiveness, survivability, observability, readiness, safety and life cycle cost. The project addresses technology development that provides substantial performance improvements in energetic material systems and subsystems, while addressing safety, reliability, and affordability concerns. This project is broken out into five primary areas of study: Aircraft Technology, Fleet Force Protection and Defense Against Undersea Threats, Advanced Energetics, Surface Ship and Submarine Hull Mechanical & Electrical (HM&E), and Naval Research Enterprise/Innovation Operations.$$, 125699000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602123N_3270$$, $$0602123N$$, $$3270$$, $$Sec. 2912 Operational Energy$$, 0, $$This project addresses applied research associated with providing the capability of Platform and Force Protection for the U.S. Navy. It supports the development of technologies associated with all naval platforms (surface, subsurface, terrestrial, and air). Research is focused on providing technologically superior defense of naval assets and delivering warfighting capabilities at reduced total ownership costs for surface and subsurface platforms through investments in applied research in Power and Energy,$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602123N_9999$$, $$0602123N$$, $$9999$$, $$Congressional Adds$$, 0, $$Congressional add projects not included in other efforts.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602128D8Z_231$$, $$0602128D8Z$$, $$231$$, $$Promotion and Protection Strategies$$, 3166000, $$The Promotion and Protection Strategies program executes activities providing visibility, fostering partnerships, incentivizing industry transition partners, and supporting developmental network that serves as a nucleus of the defense industrial base for biotechnology. The program centralizes transition planning efforts for the Distributed Bioindustrial Manufacturing Program (DBIMP) by coordinating the Acquisition (e.g., Program Executive Officers, Program Managers, technology warrant officers, etc.), Policy, and Research and Engineering communities, including the Tri-Service Biotechnology for a Resilient Supply Chain (T-BRSC) program. The programs plans for transition of non-pharmaceutical biomanufactured materials and chemicals by integrating innovative biomanufactured products into DoD’s systems and platforms through holistic acquisition and investment strategies. Promotion and Protection Strategies presents the Department’s first coordinated effort to centralize acquisition efforts for biotechnology. By providing visibility, fostering partnerships across DoD, and incentivizing industry transition partners, the program will support a developmental network in which new technologies are not only pushed to higher budget activities from lower ones, but where personnel and industry partners at higher budget activities pull on technologies being developed at lower ones. This will serve as the nucleus of a defense industrial base for biotechnology that delivers innovative biomanufactured products into DoD’s systems and platforms. This directly supports the rebuilding of our military by providing capabilities matched with the threat, reviving our defense industrial base, and rapidly fielding emerging technologies. It also reestablishes deterrence by providing capabilities closer to the threat or other logistically advantageous locations. Activities focus on efforts to supply DoD priority systems with critical chemicals and materials in support of production of material including munitions, hypersonics, and UASs, as well as point-of- need biomanufacturing in the INDOPACOM theater. Promotion and Protection Strategies executes landscape and subject matter assessments to facilitate transition, align acquisition, policy, and research and engineering communities, to inform The Promotion and Protection Strategies program executes activities providing visibility, fostering partnerships, incentivizing industry transition partners, and supporting a developmental network that serves as a nucleus of the defense industrial base for biotechnology. The program centralizes transition planning efforts for the Distributed Bioindustrial Manufacturing Program (DBIMP) by coordinating the Acquisition (e.g., Program Executive Officers, Program Managers, technology warrant officers, etc.), Policy, and Research and Engineering communities, including the Tri-Service Biotechnology for a Resilient Supply Chain (T-BRSC) program. The program plans for transition of non-pharmaceutical biomanufactured materials and chemicals by integrating innovative biomanufactured products into DoD’s systems and platforms through holistic acquisition and investment strategies. Promotion and Protection Strategies represents the Department’s first coordinated effort to centralize acquisition efforts for biotechnology. By providing visibility, fostering partnerships across DoD, and incentivizing industry transition partners, the program will support a developmental network in which new technologies are not$$, 3166000, NULL, NULL, NULL, NULL, 3155000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602131M_2958$$, $$0602131M$$, $$2958$$, $$Cyberspace Activities$$, 5306000, $$This Project activity provides freedom of maneuver and influence in the cyber-electronic warfare domain while simultaneously denying the same to the adversary and protecting critical command systems. Technologies are being developed using a multi-disciplinary approach that combines radio frequency electronics, digital signal processing, computer engineering, software engineering, machine learning and data science to support Naval Expeditionary Forces operating with size, weight, and power constrained equipment in denied, degraded, intermittent, or limited (DDIL) communications environments. Areas of applied research include distributed precision time, predictive software defined radio architectures, coordinated cyber and spectrum maneuver to mitigate detection and exploitation, tactical cyber visualization, discovering and mapping networks in dense urban environments, contextual awareness and blind channel characterization.$$, 5306000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602131M_3001$$, $$0602131M$$, $$3001$$, $$Marine Corps Landing Force Tech$$, 40391000, $$This project funds applied research; technology assessment, road mapping, and concept development; and less technologically mature projects within the Future Naval Capability (FNC) process as means to inform, enhance, enable, and invent future concepts and capabilities with new Science and Technology (S&T). This project is organized into ten activities, the core of which is represented by the eight Expeditionary Warfighting Capability Areas.$$, 40391000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602135A_A31$$, $$0602135A$$, $$A31$$, $$Counter Small Unmanned Aircraft Sys$$, 12618000, $$This Project investigates, designs, and develops novel capabilities that aid in the detection, tracking, identification, mitigation, and/or defeat of small unmanned aerial systems (sUAS) groups 1-3. Designs and develops interceptor capabilities to deliver physical effects that enable faster intercept, greater standoff ranges, increased magazine depth, survivability, affordability, and/or decrease in size, weight, and power requirements. Provides capabilities to track and predict UAS flight paths, airspace situational awareness, and/or location of UAS operators to increase defeat and force protection capabilities. Develops algorithms to enable threat prioritization, airspace control, coordinated response, and resource management of C-SUAS capabilities. Develops technical solutions to defeat sUAS capabilities, including target acquisition, navigation, and control, in addition to identifying and exploiting weaknesses in sUAS system design and operation The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Aviation & Missile Center (AvMC).$$, 12618000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602141A_AH6$$, $$0602141A$$, $$AH6$$, $$Disruptive Energetics and Propulsion$$, 5019000, $$This project investigates, models, and assesses energetic material and propulsion technologies to validate novel concepts such as maximizing total energy density and power delivered on target. This Project also optimizes propellant grains for increased range and altering gun configurations to increase energy on target in order to exploit the controllable/scalable energy release required for improving effectiveness and reducing vulnerability of future gun/missile systems. Work in this project complements Program Element (PE) 0601102A (Defense Research Sciences) / Project AA7 (Mechanics and Ballistics), PE 0602141A (Lethality Technology) / Project AH7 (Lethality and Scalable Effects Technologies), PE 0602141A (Lethality Technology) / Project AH8 (Lethality Materials and Processes Technology), and PE 0602144A (Ground Technology) / Project BL1 (Materials and Manufacturing Research Technology) The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this project is performed by the Army Research Laboratory (ARL).$$, 5019000, NULL, NULL, NULL, NULL, 8656000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602141A_AH7$$, $$0602141A$$, $$AH7$$, $$Lethal and Scalable Effects$$, NULL, $$Work in this project designs, determines, and assesses technology options for scaling warhead lethality and providing extreme efficiency for highly effective, simultaneous mixed/multi target defeat and collateral damage. This Project will also design and assess scalable structure defeat to mitigate collateral damage for disruptive urban Warfighting. Work in this project complements project AH6 (Disruptive Energetics and Propulsion Technologies) within this PE and builds upon disruptive energetic and ballistic sciences research in PE 0601102A (Defense Research Sciences) / project AA7 (Mechanics and Ballistics). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this project is performed by the Army Research Laboratory (ARL).$$, NULL, NULL, NULL, NULL, NULL, 1517000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602141A_AH8$$, $$0602141A$$, $$AH8$$, $$Lethality Materials and Processes$$, NULL, $$Work in this project designs, determines, and assesses innovative materials solutions aimed at achieving leap ahead increases in lethality and weapons effectiveness through improvements in weight and volume efficiency, lethal effects, and sustainability of military systems. This research complements Program Element (PE) 0602141A (Lethality Technology) / Project AH6 (Disruptive Energetics and Propulsion Technology) and Project AH7 (Lethal and Scalable Effects Technologies), and PE 0602147A (Long Range Precision Fires Technology) / AH4 (Precision and Cooperative Weapons in a Denied Environment) and builds upon and ballistic sciences research in PE 0601102A (Defense Research Sciences) / Project AA7 (Mechanics and Ballistics). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this project is performed by the Army Research Laboratory (ARL).$$, NULL, NULL, NULL, NULL, NULL, 1899000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602141A_AH9$$, $$0602141A$$, $$AH9$$, $$Advanced Warheads Technology$$, 27597000, $$This project explores multiple pathways to enhance lethal efforts for future warheads against emerging peer/near peer target sets and investigates synergistic effects of novel micro warheads using advanced materials. This project investigates innovative energetic materials and novel processing techniques for the next generation of explosives and propulsion applications to enable an increase in range, lethality, and utility of munitions. It also directly supports Army Modernization Priorities through researching and developing energetic (propellant) technologies and processes for increased performance, expanded operation temperature bounds, and improved safety and environmental compliance of missile systems. Work in this project complements Program Element (PE) 0602145A (Next Generation Combat Vehicle Technology) / Project BK5 (Adv Direct In-Direct Armament Sys (ADIDAS) Tech) and PE 0603464A (Long Range Precision Fires Advanced Technology) / Project CE9 (Armaments Advanced Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this project is performed by the Armaments Center.$$, 27597000, NULL, NULL, NULL, NULL, 23501000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602141A_BS6$$, $$0602141A$$, $$BS6$$, $$Lethality Technology (CA)$$, NULL, $$Congressional Interest Item funding provided for Lethality Technology. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy.$$, NULL, NULL, NULL, NULL, NULL, 68000000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602141A_CF7$$, $$0602141A$$, $$CF7$$, $$Solid-state Laser Concepts and$$, 7841000, $$This project provides the research and development of advanced solid-state laser materials and architectures to support the Army Directed Energy Strategy for laser- based directed energy (DE) weapons. This project investigates advanced laser technologies based on unconventional solid-state laser concepts and designs, scalable and intelligent power modules, and advanced thermal management systems for the development of less complex, low size, weight, and power (SWaP) Army DE weapons and tactical lasers with much improved capabilities. Work in this project complements Program Element (PE) 0603466A (Air and Missile Defense Technology) / Project CV6 (Optimized High Energy Laser Source Adv Tech) The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this project is performed by the Army Research Laboratory (ARL).$$, 7841000, NULL, NULL, NULL, NULL, 8986000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602183A_DC2$$, $$0602183A$$, $$DC2$$, $$High Performance Computing for$$, 1405000, $$This Project investigates and validates aeromechanics modeling and simulation tools for Future Vertical Lift (FVL) and other Army and DoD aviation systems and platforms. Research efforts in this Project are also applicable to the family of FVL manned and unmanned platforms. Work in this Project is fully coordinated with Program Element (PE) 0603043A (Air Platform Advanced Technology) / Project DC3 (HPC for Army Aviation Concepts). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by Aviation & Missile Center (AvMC).$$, 1405000, NULL, NULL, NULL, NULL, 1246000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602141A_CF8$$, $$0602141A$$, $$CF8$$, $$Terminal Effects Against Critical$$, 5138000, $$This Project designs and develops engineering tools and high-fidelity modeling and simulation capabilities for materials and structural response to predict and enhance weapons performance to ensure lethality against structures and critical assets. Through dynamic impact experiments for a broad range of velocities against conventional and advanced structural materials, this project develops engineering tools and technologies to rapidly evaluate and predict weapon performance. Computational chemistry will be utilized to explore potential prediction and optimization pathways of high-energy density material formulations. Work in this Project complements Program Element (PE) 0603116A (Lethality Advanced Technology) / Project CH5 (Terminal Effects Against Critical Targets Adv Tech). The work cited is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the United States Engineer Research and Development Center Geotechnical and Structures Laboratory.$$, 5138000, NULL, NULL, NULL, NULL, 2138000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602141A_CG4$$, $$0602141A$$, $$CG4$$, $$Advanced Radar Concepts and$$, 10588000, $$This project conducts experiments on single crystal diamond and diamond hetero-structure semiconductor materials, layered structures, and novel devices for Diamond Electronics and integrated photonics structures and devices for Radar, Communications, and improved Size, Weight, and Power (SWaP) Department of Defense systems. Efforts include multiscale modeling, material and structure growth and characterization, and novel device design and fabrication as well as two-dimensional (2-D) electronics for bio-inspired neuromorphic sensors, processors, and memory. This research has application to radars, communication systems, electronic warfare, directed energy, electronics for hypersonic systems, radiation hard systems, quantum sensing, and others. This project directly supports Air and Missile Defense modernization priority capabilities by investigating essential component technologies for insertion into Multi-Mission Army Radar systems. This project addresses the challenges of integrating new materials into Silicon Complementary Metal Oxide Semiconductor (CMOS) processing flows, and electronics reliability including protection against unintended adversarial use of state-of-the-art semiconductor materials, devices, and systems for Air and Missile Defense in contested environments. Work in this project complements Program Element (PE) 0603466A (Air and Missile Defense Advanced Technology) Project AD6 (Next Generation Fires Radar Advanced Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this project is performed by the Army Research Laboratory (ARL) and Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Center.$$, 10588000, NULL, NULL, NULL, NULL, 5471000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602141A_CI1$$, $$0602141A$$, $$CI1$$, $$Advanced Armaments Lethality$$, NULL, $$This project designs and develops novel armament systems concepts and enabling technologies in weapons, munitions, and fire control, in order to advance range and accuracy capabilities. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this project is performed by the Armaments Center (AC).$$, NULL, NULL, NULL, NULL, NULL, 1636000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602141A_CIA$$, $$0602141A$$, $$CIA$$, $$Applied Armaments Tech for$$, 8000, $$This project investigates technologies that holistically maximize armament performance, minimize target engagement timelines, reduce crew workloads, enhance responsiveness and enable collaborative lethal effectiveness on target across distributed platforms & missions. This project researches cross caliber weapon, munition & fire-control technologies to enhance Remote Weapon Systems (RWS) responsiveness and single or combined platform lethality in Multi-Domain Operations (MDO) environments. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this project supports the Next Generation Combat Vehicle Army Modernization Priority. Work in this project is performed by the Armaments Center.$$, 8000, NULL, NULL, NULL, NULL, 2442000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602141A_CIB$$, $$0602141A$$, $$CIB$$, $$Sensor to Shooter (STS) Applied$$, NULL, $$This project designs and develops advanced algorithms for sensor to shooter decision aids and incorporates predictive tools and permissive airspace capabilities to reduce the sensor to shooter timeline and effects execution. Investigate technologies for enabling multi-sensor fusion for collaborative tracking of multi-theater threat tracks to enable tactical target engagement and counter fires across threat flight timeline. Work in this project complements Program Element (PE) 0603116A (Lethality Advanced Technology) / Project CID (Sensor to Shooter (STS) Advanced Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this project supports Next Generation Combat Vehicle, Tactical Network, Future Vertical Lift, and Long-Range Precision Fires Army Modernization Priorities. Work in this project is performed by the Armaments Center, Command, Control, Communication, Computers, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Center, and United States Army Space and Missile Defense Technical Center.$$, NULL, NULL, NULL, NULL, NULL, 4022000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602141A_CIC$$, $$0602141A$$, $$CIC$$, $$Fire Control Lethality Technology$$, 1472000, $$Work in this project researches, investigates and develops concepts for common open architecture fire control systems to maximize distributed armament systems performance. Researches fire control architecture framework and protocols utilizing artificial intelligence and machine learning to minimize target engagement timelines, reduce cognitive processes, and enable collaborative lethal effectiveness on target across weapon platforms. Develops modular fire control concepts enabling safe, lethal, and agile integration of current systems to engage emerging threats and decrease system vulnerabilities for maximize performance and combined arms effects. Work in this project complements Program Element (PE) 0602141A Lethality Technology/ Applied Armaments Tech for Distributed Lethality, PE 0603462A Next Generation Combat Vehicle Advanced Technology/ Next Generation Intelligent Fire Control, and PE 0602183A Air Platform Applied Research/ Airborne Threat Defeat The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this project is performed by the Armaments Center.$$, 1472000, NULL, NULL, NULL, NULL, 1409000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602143A_AZ2$$, $$0602143A$$, $$AZ2$$, $$Body Armor & Integrated Headborne$$, 4739000, $$This Project investigates and develops materials for Soldier-borne protective equipment, such as body armor and combat helmets, to increase protection from ballistic, blast, and blunt impact threats. This Project also investigates and executes systematic studies to design and develop materials, devices, systems and methods that enable the identification of protective solutions against ballistic, blast and directed energy threats. Included are investigations of emerging technologies, novel materials, and test methods and integration of personal armor, combat helmets, hearing protection, eyewear, and other personal protective equipment items. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by Soldier Center (SC).$$, 4739000, NULL, NULL, NULL, NULL, 6321000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602141A_CJ1$$, $$0602141A$$, $$CJ1$$, $$Lethality Enabling University Applied$$, 3566000, $$The project leverages research and technological innovations from academia, of lethal directed energy, laser diagnostics and accelerated design of future hypersonics, deep learning (DL) guidance tools, novel materials, and emerging technologies of importance to the Army, by accelerating research and conducting experiments focused on getting technology to the warfighter more quickly. This project performs discovery research efforts to focus more on mid to far-term Army modernization priorities while also maintaining delivery of near-term technologies critical to the Long Range Precision Fires and Air and Missile Defense. This project focuses on employment of research technologies originating from extramural applied research in academia pertaining to lethal directed energy, laser diagnostics, future hypersonic glide body and scramjet propulsor design, DL guidance tools, novel materials, and expansion of the Ballistic, Aero-Optics and Materials (BAM) range applied to lethality. This effort conducts applied research and development leading to potential emerging technologies in areas of importance to the Army in directed energy, future hypersonic glide body design, DL and novel materials, etc., by bringing competitively selected universities with research and development teams into technical alliances. Work in this project complements Program Element (PE) 0602141A (Lethality Technology) / Project CZ9 (Foundational Hypersonic Weapons Research), PE 0602150A (Air and Missile Defense Technology) / Project DC1 (Next Generation DE Concept Development & Analysis), PE 0603116A (Lethality Advanced Technology) / Project CG2 (Lethality Enabling University Adv Development), and PE 0603464A (Long Range Precision Fires Advanced Technology) / Project BY2 (Advanced Hypersonic Technology). The work cited is consistent with Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this project is performed by the Army Research Laboratory (ARL).$$, 3566000, NULL, NULL, NULL, NULL, 5384000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602141A_CJ7$$, $$0602141A$$, $$CJ7$$, $$Future Air Defense Missile Enabling$$, 4289000, $$This project investigates, develops, and evaluates critical missile technologies and components necessary for advanced lethal capability in support of future/mid to far term affordable short range air defense interceptor capability to defeat Cruise Missile (CM), Rotary Wing (RW), Tactical / Lethal Unmanned Aerial System (UAS), and Fixed Wing (FW) threats. This effort designs and develops technologies to provide advanced materials, seekers, guidance and control, and propulsion for reduced size weight and power and cost for Maneuver Short Range Air Defense (MSHORAD), Short Range Air Defense (SHORAD), and Lower Tier essential to maintain overmatch against mid-/far-term threats. This project will investigate, identify and develop advanced radar concepts, technologies and signal processing algorithms to enable multi- mission radar functions and expanded threat capability. This project supports Air and Missile Defense Modernization priority efforts. Work in this project complements Program Element (PE) 0602147A (Long Range Precision Fires Technology) / Project AF3 (Extended Range Propulsion Technology) and Project AF8 (Affordable Extended Range Precision Technology), PE 0602150A (Air and Missile Defense Technology) / Project SU1 (Counter Small Unmanned Aircraft Sys (C-sUAS) Tech), and PE 0603466A (Air and Missile Defense Advanced Technology) / Project SU2 (Counter Small Unmanned Aircraft Sys (C-sUAS) Adv). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this project is performed by the Aviation & Missile Center (AvMC).$$, 4289000, NULL, NULL, NULL, NULL, 2259000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602141A_CZ9$$, $$0602141A$$, $$CZ9$$, $$Foundational Hypersonic Weapons$$, 11205000, $$This project investigates foundational problems associated with high-speed weapons and informs the future strategic fires echelon of Long-Range Precision Fires (LRPF) capabilities. This Project funds the research of material science subjects such as extreme thermal loading and aero-thermodynamics and control technologies for high- speed vehicles which may encounter high mechanical loads at launch. Work in this project complements Program Element (PE) 0601102A (Defense Research Sciences) / Project AA7 (Mechanics and Ballistics) and PE 0602141A (Lethality Technology) / Project AH6 (Disruptive Energetics and Propulsion Technologies), Project AH7 (Lethal and Scalable Effects Technologies), and Project AH8 (Lethality Materials and Processes Technology), PE 0602144A (Ground Technology) / Project BL1 (Materials and Manufacturing Research Technology), and PE 0602145A (Next Generation Combat Vehicle) / Project BI4 (Materials Application and Integration Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this project is performed by the Army Research Laboratory (ARL) and the United States Army Space and Missile Defense Command, Technical Center.$$, 11205000, NULL, NULL, NULL, NULL, 8055000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602141A_DN6$$, $$0602141A$$, $$DN6$$, $$Science of Massed Responsive Fires$$, 20434000, $$This project supports research on munitions, kinetic and non-kinetic payloads, and weapons in energetics, propulsion, flight, guidance, warheads, guns, material science, and electromagnetic device packages and sensors. This project also supports research in novel energetic materials and energetic monomer/polymer synthesis, composable design science, models for gun wear and erosion, and the development of algorithms, frameworks, and toolsets for cost-effective collaborative autonomous delivery of weapons. Electronic (e.g., jamming, spoofing) and kinetic (e.g., intercept) counters that disrupt nodes of defeat are within adversary reach. Enablers delivered in this research project provide entirely new approaches of dynamically adapting multi-functional systems of weapon systems (beyond improvements to field/air defense and cannon/missile artillery) and the means to physically realize this capability at relevant speed and size scales in collapsed formations to defeat complex, rapidly changing threats at depth. Work in this project complements Program Element (PE) PE 0601102A (Defense Research Sciences) / Project AA7 (Mechanics and Ballistics), PE 0602141A (Lethality Technology) / Project AH6 (Disruptive Energetics and Propulsion Technologies), and PE 0602141A (Lethality Technology) / Project CZ9 (Foundational Hypersonic Weapons Research). This Project transitions to PE 0602141A (Lethality Technology) / Project AH9 (Advanced Warheads Technology), PE 0602147A (Long Range Precision Fires Technology) / Project AG4 (Extended Range Artillery Munition Suite Technology), PE 0602141A (Lethality Technology) / Project CI1 (Advanced Armaments Lethality Technology), PE 0602141A (Lethality Technology) / Project CIA (Applied Armaments Tech for Distributed Lethality), PE 0602147A (Long Range Precision Fires Technology) / Project AF8 (Affordable Extended Range Precision Technology), PE 0603464A (Long Range Precision Fires Advanced Technology) / Project CZ8 (PrSM Modular Payload Advanced Development), and PE 0603464A (Long Range Precision Fires Advanced Technology) / Project BY2 (Advanced Hypersonics Technology). The cited work is consistent with Under Secretary of Defense for Research and Engineering Science and Technology priority focus areas and the Army Modernization Strategy. Work in this project is performed by Army Research Laboratory (ARL).$$, 20434000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602142A_BS1$$, $$0602142A$$, $$BS1$$, $$Army Applied Research$$, NULL, $$The Army Applied Research budget line includes systematic application of knowledge toward the production of useful materials, devices and systems or methods including the design, development and improvement of science and technology for Army applications. Efforts in this budget line include studies, investigations and non-system specific technology efforts leading to bread-board hardware or proof of principle analysis.$$, NULL, NULL, NULL, NULL, NULL, 38072000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602143A_AY6$$, $$0602143A$$, $$AY6$$, $$Soldier Squad Small Arms$$, 3229000, $$This Project investigates individual and crew-served weapon designs and technologies that enhance the fighting capabilities and survivability of the dismounted Warfighter in support of all of the Services. In addition, it conceives and advances weapon concepts based on innovative ballistic and advanced incapacitation technologies that will enhance the defeat of hard and soft infantry targets at extended ranges based upon the Joint Service Small Arms Technology Development Strategy (JSATDS). The Project will continue to support technology needs from all Services to include the Next Generation Family of Weapons. In addition, this Project will develop the technology/weapons concepts that will upgrade medium and heavy support weapons at echelons. Finally, this Project will perform research directed toward non-kinetic modalities to incapacitate combatants. Work in this Project supports key Army needs and leverages the technical research of several Program Elements (PEs) to include PE 0601102A (Defense Research Sciences) / Project AA7 (Mechanics and Ballistics), PE 0603118A (Soldier Lethality Advanced Technology), and PE 0602141A (Lethality Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Armaments Center (AC) and Army Research Laboratory (ARL).$$, 3229000, NULL, NULL, NULL, NULL, 10018000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602143A_AZ5$$, $$0602143A$$, $$AZ5$$, $$Soldier Protection Technology -$$, 8321000, $$This Project investigates and develops Soldier protection methodologies, which includes the materials, methods, and models that enable design and integration of emerging material technologies into lightweight, flexible and modular Soldier equipment to protect against the range of existing and emerging battlefield threats for head, torso, and extremity protection. Specific research thrusts include the development of materials and mechanisms to enhance ballistic protection; computational models and associated laboratory experiments to provide a fundamental understanding of material properties and failure mechanisms, as well as correlation to ballistic/ blast/blunt impact performance of Soldier personal protective equipment (PPE) and improved fibers, composite, and ceramic materials. Specific technologies support experimental helmets that reduce impact and blast loading to the head, Soldier torso protection systems to increase protection from ballistic and blunt impacts, and novel fibers and fabrics that provide additional survivability mechanisms. Work in this Project supports key Army needs and is fully coordinated with several PEs to include PE 0602143A (Soldier Lethality Technology) and 0603118A (Soldier Lethality Advanced Technology); and leverages the technical research of several PEs to include PE 0601102A (Defense Research Sciences) / Project AA7 (Mechanics and Ballistics) and 0602144A (Ground Technology) / Project BL1 (Materials and Manufacturing Research Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Army Research Laboratory (ARL).$$, 8321000, NULL, NULL, NULL, NULL, 10198000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602143A_BB4$$, $$0602143A$$, $$BB4$$, $$Dismounted Soldier Survivability$$, 4786000, $$This Project investigates fibers, textiles, components, and materials focused on enhancing Soldier survivability from combat threats (flame and thermal, blast and ballistic, multispectral sensor, and laser threats) and environmental threats (e.g., cold, heat, wet, vector, antimicrobial, etc.) to increase operational effectiveness while decreasing the Soldier's physical and cognitive burden. The results from this Project will transition knowledge, materials, subcomponents and methods to Advanced Technology Development efforts in support of enhancing Soldier Lethality by providing protective material solutions focused on the aspects of dismounted movement and maneuver operations of the Army. This Project develops and applies validation methods that enable systematic studies of human systems integration principles and practices to protective equipment materials and designs to advance the understanding of trade-offs between protection, lethality, and mobility. Work in this Project supports key Army needs and leverages/complements the technical research of several Program Elements (PEs) to include PE 0601102A (Defense Research Sciences), PE 0602143A (Soldier Lethality Technology) / Project AZ5 (Soldier Protection Technology - Vulnerability), and PE 0603118A Soldier Lethality Advanced Technology / Project BB3 (Dismounted Soldier Survivability Equip/Tech Integ). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Soldier Center (SC).$$, 4786000, NULL, NULL, NULL, NULL, 4838000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602143A_BC2$$, $$0602143A$$, $$BC2$$, $$Next Gen Mobility & Lethality Tech for$$, 5623000, $$This Project investigates the means to monitor, assess, predict and optimize/enhance Soldier/small unit and decision-making and shoot and move performance. In addition, it will provide design guidance for individual and mission specific equipment (e.g., individual protection, small arms, load carriage, information portrayal etc.) and quantitative impacts on Soldier l and small unit performance in the Future Operating Environment. Research conducted focuses on translating mission-essential tasks to define and measures of human Soldier performance in the trade space of mobility, survivability, and lethality. These measures of human performance will inform predictive algorithms, human based modeling and simulation, and assessment tools that enable Soldier performance trade space analysis for acquisition, training, and doctrine. These data and algorithms will allow the Army to determine the impact of new capabilities on Soldier and small unit performance and effectiveness, understand deficiencies in performance and investigate novel strategies to optimize and enhance performance. This Project also complements and is fully coordinated with work performed across Army, Navy, and Air Force under the Human Systems Community of Interest: Protection, Sustainment, and Warfighter Performance. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Soldier Center (SC).$$, 5623000, NULL, NULL, NULL, NULL, 6726000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602143A_BC7$$, $$0602143A$$, $$BC7$$, $$Training Technology (Other than STE)$$, 20772000, $$This Project funds research into technologies and their applications that can inform and/or enhance the Army's live, virtual, and constructive training systems. This Project conducts research in immersive virtual, mixed, and augmented reality (AR) environments that stimulate human senses (e.g., sight, sound, and touch) and also conducts laboratory experiments to understand how users interface with the technology in order to improve the realism of simulation environments and therefore create enhanced immersion and more effective training systems. Models and simulations are designed are developed to allow realistic, fair fight engagements across all training environments and training devices, to include the cyberspace domain. Included in the investigations of this Project are also medical training systems (e.g., part- task trainers and physiological modeling). Work in this Project supports key Army needs and complements efforts in Program Element (PE) 0603118A (Soldier Lethality Advanced Technology) / Project BC8 (Training Advanced Technology (Other than STE)). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Soldier Center (SC) and the Institute for Creative Technologies (ICT) University Affiliated Research Center (UARC).$$, 20772000, NULL, NULL, NULL, NULL, 32616000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602143A_BD1$$, $$0602143A$$, $$BD1$$, $$Adv Soldier Sensors/Displays Tech for$$, 17062000, $$This Project designs and develops low power, next generation modular sensor and display components for detection and identification of both threats and friendlies in all environments to increase situational awareness, decrease fratricide, and enable Soldiers to respond more quickly for greater lethality. This Project complements s work done in Program Element (PE) 0603118A (Soldier Lethality Advanced Technology) / BC9 (Adv Soldier Sensors/Displays AdvTech for Dismounts). Work in this Project is performed by the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Center.$$, 17062000, NULL, NULL, NULL, NULL, 16253000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602183A_DE2$$, $$0602183A$$, $$DE2$$, $$Airborne Threat Defeat$$, 1879000, $$Airborne Threat Defeat addresses the need to engage and disorient guided threats. Work in this Project complements Program Element (PE) 0603465A (Future Vertical Lift Advanced Technology) / Project CA8 (Adv Rotocraft Armaments Protection Sys). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Armaments Center (AC).$$, 1879000, NULL, NULL, NULL, NULL, 5583000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602143A_BD6$$, $$0602143A$$, $$BD6$$, $$Soldier Sys Interfaces/Integration-$$, 299000, $$This Project investigates, designs, and validates advanced technologies and algorithms for enhancing dismounted Soldier deployed robotics and autonomous systems used to improve the Small Unit's situational awareness, survivability, and lethality. Technologies to be investigated may include: algorithms for dismounted robotic systems to enable autonomous navigation, automated object recognition, persistent surveillance, launch and recovery from vehicles, networked lethality, manned- unmanned teaming, and collaborative behaviors; and advanced user interfaces to optimize human-robotic interaction during dismounted operations. These advanced technologies will enable Squad and Platoon level autonomous reconnaissance using robotic systems to minimize the operator's dedicated control of the systems and reduce their cognitive burden, thus allowing Soldiers to be more lethal and survivable. Work in this Project supports key Army needs and leverages the technical research of several Program Elements (PEs) / Projects to include PE 0603118A (Soldier Lethality Technology) / Project BD7 (Soldier Sys Interfaces/Integration-Sensor Tech) and Project BC9 (Advanced Soldier Sensors/Displays Advanced Technology for Dismounts). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Soldier Center (SC).$$, 299000, NULL, NULL, NULL, NULL, 301000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602143A_BD8$$, $$0602143A$$, $$BD8$$, $$Soldier & Sm Unit Tactical Energy$$, NULL, $$This Project conducts applied research and development on materials and component level power and energy technologies in the areas of energy storage, power generation, alternative energy, and intelligent power distribution and thermal management designs that support Command, Control, Communications, Computers, Intelligence, Surveillance and Reconnaissance (C4ISR) and Soldier power needs to include next generation squad weapons and advanced optical devices and sensors. Enables future Soldier lethality and mobility for longer mission durations at lighter weights to provide enhanced lethality and tactical overmatch of adversaries, and to reduce the burden on the Soldier. This Project support key Army needs and complements the technical research of Program Element 0602184 (Soldier Applied Research) / Project CO1 (Soldier Power and Energy Concepts) and Program Element 0603118A (Soldier Lethality Advanced Technology) / BD9 (Soldier & Sm Unit Tactical Energy AdvTech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Army Research Laboratory (ARL) and Command, Control, Communication, Computers, Cyber, Intelligence, Surveillance and Reconnaissance Center (C5ISR) Center.$$, NULL, NULL, NULL, NULL, NULL, 6911000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602143A_BE3$$, $$0602143A$$, $$BE3$$, $$Joint Service Combat Feeding$$, 4276000, $$This Project investigates and develops nutrient compositions and stabilization techniques to maximize the Warfighter's physical and cognitive performance on the battlefield, investigates technologies to enhance detection and identification capabilities of chemical and biological threats in foods, and develops innovative ration and field feeding technologies to reduce resupply requirements for the multi-domain battlefield. The Army serves as the Executive Agent for this Department of Defense (DoD) program, with oversight and coordination provided by the DoD Combat Feeding Research and Engineering Board. Work in this Program Element (PE) is related to and fully coordinated with PE 0602787A (Medical Technology) / Project MK4 (Warfighter Health Applied Research Technology) to develop technologies and concepts; Army Additive Manufacturing Community of Practice to enable customization, increase readiness, and improve sustainment due to fabrication of end-use items at point of need; Defense Threat Reduction Agency to maximize protection of rations from contamination; Defense Health Agency (DHA) to transition and develop materiel solutions in the microbiome technical areas; and the Defense Health Agency (DHA) Joint Program Committee-5, which seeks to develop effective nutritional countermeasures against stressors and to maximize health, performance, and well-being. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Soldier Center (SC).$$, 4276000, NULL, NULL, NULL, NULL, 4074000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602143A_BP9$$, $$0602143A$$, $$BP9$$, $$Soldier Lethality Technologies (CA)$$, NULL, $$This Project is for congressional increases that support applied research in support of Soldier Lethality, where the Soldier and Squad are treated as an integrated combat platform.$$, NULL, NULL, NULL, NULL, NULL, 107800000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602143A_BR9$$, $$0602143A$$, $$BR9$$, $$Personnel & Airdrop Safety$$, 3563000, $$This Project funds the research and investigation of component technologies to enhance cargo and personnel airdrop capabilities for global precision delivery, rapid deployment, and insertion for force projection into hostile regions. Areas of emphasis include parachute technologies, parachutist injury reduction, precision offset aerial delivery, soft landing technologies, and airdrop simulation. Technologies support the Soldier Lethality Army Modernization Priority. New operational concepts call for increased precision of personnel and cargo in austere environments in which small units are dispersed and logistical supply is limited. The Army requires enhanced payload extraction and other increased capabilities to support the airdrop requirement for current and future vehicles exceeding aircraft payload weight capacity. Work in this Project supports key Army needs and complements the technical research of several Program Elements (PEs) to include PE 0601102A (Defense Research Sciences), PE 0602143A (Soldier Lethality Technology) / Project BD6 (Soldier Sys Interfaces/ Integration- Sensor Tech), and PE 060311SA (Soldier Lethality Advanced Technology) / Project BE5 (Personnel & Airdrop Safety Advanced Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Soldier Center (SC).$$, 3563000, NULL, NULL, NULL, NULL, 3028000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602144A_BK7$$, $$0602144A$$, $$BK7$$, $$Robotics for Engineer Operations$$, 3477000, $$This research investigates and develops standoff robotic capabilities to reduce Soldier/Combat Engineer risks and fatalities while conducting activities essential to shaping the environment. It will close the gaps between commercial construction equipment and the requirements of the future Engineer Force to support maneuver, movement, and sustainment. This research will develop the capability to generate a near real-time site model with appropriate engineering details to allow unmanned system shaping of the environment through physical interaction (e.g., push, pull, lift, or dig). This effort will also develop the requisite mission planner and task execution controller that accepts input from the user and provides suggestions and feedback based on updates to the site model, reporting from hardware agents, and resource allocation logic. The end state goal is the development of beyond line of sight teleoperation and semiautonomous capabilities allowing Engineer robotic support to match pace in future combat environments. This effort will support the development, testing, and evaluation of prototypical robotic Combat Engineer equipment. This Project develops modeling and simulation tools that represent realistic states for Engineer robotic operations and develops and assesses semi-autonomous and autonomous construction equipment technologies needed for remote control Engineer operations. Work in this Project complements Program Element (PE) 0603119A (Ground Advanced Technology) / Project BK8 (Robotics for Engineer Operations Advanced Technology). The work cited is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas. Work in this Project is coordinated with Program Element (PE) 0603462A (Next Generation Combat Vehicle Advanced Technology). Work in this Project is performed by the United States Army Engineer Research and Development Center Construction Engineering Research Laboratory, Information Technology Laboratory, and Geotechnical and Structures Laboratory.$$, 3477000, NULL, NULL, NULL, NULL, 6399000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602144A_BL1$$, $$0602144A$$, $$BL1$$, $$Materials and Manufacturing$$, 5787000, $$This Project links materials research, manufacturing processes, and design to enable high quality additive manufacturing products for Army applications through the development of high-performance feedstock materials (polymers, metals, and ceramics), physics-based process models, and in-situ process monitoring. Integration of these tools with process models enables real-time control and manipulation of material structure and properties to produce three-dimensional hybrid electronics packaging, power and energy sources and converters and new materials/structures for protection. The goal of this work is to develop robust physics-based models to optimize material properties, structures, and manufacturing processes for Army applications in protection, maneuver, power, sensing, and signature management necessary to rapidly respond to emerging and unknown threats in a battlefield environment. This work is done in coordination with Program Element (PE) 0602145A (Next Generation Combat Vehicle Technology), 0602143A (Soldier Lethality Technology) and 0603118A (Soldier Lethality Advanced Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas. Work in this Project is performed by the Army Research Laboratory (ARL)$$, 5787000, NULL, NULL, NULL, NULL, 4310000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602144A_BL2$$, $$0602144A$$, $$BL2$$, $$Explosives Forensics Technology$$, 1002000, $$This Project investigates and develops sensor technology for the trace detection of military explosives, homemade explosives (HME), and solid chemical hazards found on contaminated surfaces. This project pursues research in signatures and algorithms required to provide improved trace analysis of chemical hazards to enable integration and augmentation into chemical and explosive detection equipment for the warfighter. Work in this Project compliments Program Element (PE) 0603119A (Ground Advanced Technology) / Project BL3 (Explosives Forensics Advanced Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Chemical Biological Center (CBC).$$, 1002000, NULL, NULL, NULL, NULL, 1645000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602144A_BL5$$, $$0602144A$$, $$BL5$$, $$Expedient Passive Protection$$, 4156000, $$This Project designs and develops rapidly deployable passive protective solutions; methodologies for intuitive decision support; and tactics, techniques, and procedures to increase the survivability of personnel, critical assets, and facilities from a range of threats. Through experimental and computational investigation and design, this project develops force protection technologies for complex and contested environments. This Project also develops expedient solutions and methodologies for decision support for protection against a range of threats, to include improvised, conventional, and emerging weapons such as ballistic missiles. Work in this Project complements Program Element (PE) 0603119A (Ground Advanced Technology) / Project BL6 (Expedient Passive Protection Advanced Technology). The work cited is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project supports the Army Science and Technology Ground Portfolio. Work in this Project is performed by the United States (US) Army Engineer Research and Development Center Geotechnical and Structures Laboratory.$$, 4156000, NULL, NULL, NULL, NULL, 2934000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602144A_BL7$$, $$0602144A$$, $$BL7$$, $$Power Projection in A2AD$$, 4103000, $$This Project designs and develops remote assessment technologies to determine entry and maneuver corridors, develops site selection tools and decision support technologies for climatic regions in all season conditions including aviation site selection tools, enhanced automated route reconnaissance technologies, mobility models for extreme temperatures, and road capacity assessment technologies. These technologies reduce reliance on manned on-site reconnaissance for projection platform assessments and provide all season capacity predictions to ensure air and ground battlespace entry and maneuver. This Project also designs and develops material solutions to repair, rebuild and construct infrastructure required for movement and maneuver in highly contested, complex operational environments such as Anti- Access/Area Denial (A2/AD). Work in this PE complements PE 0603119A (Ground Advanced Technology) / Project BL8 (Power Projection in A2AD Environments Adv Tech). The work cited is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas. Work in this Project is performed by the United States Army Engineer Research and Development Center Geotechnical and Structures Laboratory.$$, 4103000, NULL, NULL, NULL, NULL, 2908000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602144A_BL9$$, $$0602144A$$, $$BL9$$, $$Protection from Advanced Weapon$$, 4778000, $$This Project designs and develops structural hardening, high-performance computing capabilities, and force protection technologies to enhance survivability of personnel and critical assets. This project investigates and develops advanced materials for protection against blast, fragmentation, and penetration through physical experiments and modeling and simulation. Additionally, this project investigates, designs, and develops passive protection technologies and protective design criteria to mitigate attack from emerging advanced threats. Work in this Program Element (PE) complements PE 0603119A (Ground Advanced Technology) / Project BM1 (Protection from Advanced Weapon Effects Adv Tech). The work cited is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas. Work in this Project is performed by the United States Army Engineer Research and Development Center Geotechnical and Structures Laboratory.$$, 4778000, NULL, NULL, NULL, NULL, 5211000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602144A_BN8$$, $$0602144A$$, $$BN8$$, $$Ground Technology Materials(CA)$$, NULL, $$Congressional Interest Item funding provided for Ground Technology Materials. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy.$$, NULL, NULL, NULL, NULL, NULL, 207500000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602144A_CG6$$, $$0602144A$$, $$CG6$$, $$Ground Vehicle Power and Energy$$, NULL, $$This Project investigates and develops advanced power and energy technologies for combat ground vehicles that are necessary for parallel hybrid, series hybrid, and all- electric vehicle systems. This Project investigates, designs, and develops electric conversion technologies to reduce size and weight of military vehicles while increasing performance and capabilities to support current and future mission loads and provide improved military vehicle mobility. Work in this Project is coordinated with PE 0602145A (Next Generation Combat Vehicle Technology) / PE 0603462A (Next Generation Combat Vehicle Advanced Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas. Work in this Project is performed by the Army Research Laboratory (ARL) and Data and Analysis Center (DAC).$$, NULL, NULL, NULL, NULL, NULL, 2580000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602201F_622404$$, $$0602201F$$, $$622404$$, $$Aeromechanics$$, 0, $$This project develops aerodynamic configurations of a broad range of revolutionary, affordable aerospace vehicles. It matures and applies modeling and numerical simulation methods for fast and affordable aerodynamics prediction and integrates and demonstrates multi-disciplinary advances in airframe, propulsion, weapon, and air vehicle control integration. In FY 2025, the entirety of PE 0602201F, Aerospace Vehicle Technologies, Project 622404 Aeromechanics, was transferred to PE 0602203F, Aerospace Propulsion, Project 622401 Structures for increased integration between airframe, flight control, propulsion, electrical, power and thermal management.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602144A_CG7$$, $$0602144A$$, $$CG7$$, $$Ground Protection Concepts and$$, 9859000, $$This Project investigates advanced materials and mechanisms to defeat the most common and most dangerous threats that are expected to be encountered by our ground forces in near-, mid-, and far-term. This Project also designs and develops experimental and computational tools and techniques (high resolution instrumentation to observe impact events, theories, and algorithms to explain these phenomena and numerical implementation of these algorithms) for the development of mass- efficient armor mechanisms. This project designs and develops armor mechanisms that will be integrated to create multi-threat armor technologies and form the building blocks for Adaptive and Cooperative Protection Technologies in the Advanced Concepts for Active Defense Project (Program Element (PE) 0602145A Next Generation Combat Vehicle Technology). Additionally, research will focus on subcomponent/component models to predict performance of early concepts and the means to assess effectiveness on ground platforms. The Project will balance designs and developments of active threat defeat measures with the necessary advanced passive and reactive components that will ultimately provide for full system solutions which meet the requirements of current and next generation ground tactical and combat vehicles. This Project is coordinated with and transitions to Projects in PE 0603462A (Next Generation Combat Vehicle Advanced Technology), PE 0602145A (Next Generation Combat Vehicle Technology), and builds upon weapon target interaction research in PE 0601102A (Defense Research Sciences) / Project AA7 (Mechanics and Ballistics). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas. Work in this Project is performed by the Army Research Laboratory (ARL).$$, 9859000, NULL, NULL, NULL, NULL, 10473000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602144A_CG8$$, $$0602144A$$, $$CG8$$, $$Human Autonomy Teaming$$, NULL, $$This Project performs applied research for capabilities that support teams of Soldier and Artificial Intelligence (AI)-enabled systems to execute missions in complex, dynamic, multi-domain operations environments. Centered on ground vehicle mission planning and operations, this Project is focused on core technologies to enable Soldiers and AI-enabled systems to function as a team, to perform at high levels, and to adapt to adversarial actions and new mission requirements. This Project will enable future Soldiers with AI-enabled systems to perform complex missions with increasingly sophisticated technologies, and in increasingly complex, dynamic, sociotechnical environments. The applied research will provide the fundamental technologies to enable scalable Soldier-AI teams and team-centered dynamic tasking to effectively utilize the full capabilities of team and technologies. The research will include considerations to reduce data requirements for AI adaptation, increasing appropriate Soldier trust and use of technology, and ensuring ethical behavior by teams of Soldier and AI-enabled systems. The capabilities created by this research will lead to increased overall Soldier-AI team mission performance, improved Soldier-centric situation awareness technologies, and units that can effectively integrate within a multi-domain battlefield. Work in this Project is coordinated with PE 0602145A (Next Generation Combat Vehicle Technology), PE 0603462A (Next Generation Combat Vehicle Advanced Technology) and PE 0602143A (Soldier Lethality Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project supports the Army Science and Technology Ground and Next Generation Combat Vehicle portfolios. Work in this Project is performed by the Army Research Laboratory (ARL).$$, NULL, NULL, NULL, NULL, NULL, 9170000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602144A_CI2$$, $$0602144A$$, $$CI2$$, $$Ground Enabling University Applied$$, NULL, $$The Project leverages applied research from academia, in the focus areas of ground autonomy, Artificial Intelligence/Machine Learning (AI/ML) and robotics, occupant/ vehicle survivability and other ground platform technologies of importance to the Army. This Project performs discovery research efforts to focus more on mid to far- term Army modernization priorities while also maintaining delivery of near-term technologies critical to the next generation combat vehicles. This Project focuses on employment of research technologies originating from extramural applied research in academia pertaining to navigation/routing, autonomous robotic vehicles with the use of artificial intelligence and machine learning as applied to ground mobility and maneuver, and other innovative ground enabling applied research technologies. This effort conducts applied research and development leading to potential emerging technologies in areas of strategic importance to the Army in autonomy, robotics and AI/ML, protection of both platform and occupant, and other ground platform technologies in propulsion, survivability, powertrain, etc., by bringing competitively selected Universities with research and development teams into Technical Alliances. Work in this Project complements Program Element (PE) 0603119A (Ground Advanced Technology), PE 0602145A (Next Generation Combat Vehicle Technology) and PE 0603462A (Next Generation Combat Vehicle Advanced Technology). The work cited is consistent with Under Secretary of Defense for Research and Engineering priority focus areas. Work in this Project is performed by the Army Research Laboratory (ARL).$$, NULL, NULL, NULL, NULL, NULL, 3763000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602144A_CV3$$, $$0602144A$$, $$CV3$$, $$Engineer Enablers Maneuver, LOG, &$$, 4166000, $$This effort designs and develops decision support capabilities to modernize the Army's logistics planning. The project will research planning of logistics resupply via distributed supply routes through complex terrain and environmental conditions within a contested environment, while also improving the efficiency of logistics planning, enabling planners to develop and compare courses of action, and simulate logistics activities using complex algorithms. This effort links the engineer applications into a geospatial framework and enables planners to better understand the dynamic scenario development providing a simple and clear critical vulnerabilities assessment, easy visual comparison of inventories available, supply needs within the battlespace, and the logistics options to mitigate potential issues. Work in this Project complements Program Element (PE) 0603119A (Ground Advanced Technology) / Project CV5 (Engineer Enablers Maneuver, LOG, & Sustainment Adv). The work cited is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas. Work is performed at the United States Army Engineer Research and Development Center Geotechnical and Structures Laboratory, Coastal and Hydraulics Laboratory, Environmental Laboratory, Geotechnical Research Laboratory, Cold Regions Research and Engineering Laboratory, Construction Engineering Research Laboratory, and Information Technology Laboratory.$$, 4166000, NULL, NULL, NULL, NULL, 2115000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602303E_IT-03$$, $$0602303E$$, $$IT-03$$, $$CYBER SECURITY$$, 0, $$The efforts described in this Program Element (PE) address the Applied Research associated with the Information and Communications Technology Program that is directed toward the application of advanced, innovative computing systems and communications technologies. This PE also supports innovation and robust transition planning in the technology cycle by working with entrepreneurs to increase the likelihood that DARPA funded technologies take root in the U.S. and provide new capabilities for national defense. The High Productivity, High-Performance Responsive Architectures project focuses on developing the computer hardware and associated software technologies required for future computationally- and data-intensive national security applications. Powerful new approaches are needed to manage the rapid growth in available sensor data, to leverage advances in machine learning, artificial intelligence, and quantum computing, and to maintain the security of DoD information systems. The project therefore aims not only to create new computing platforms to include quantum technology, but also to efficiently extract information out of large and chaotic data sets with embedded and low-size, weight, and power systems. Advances in these areas will allow for DoD electronic systems to collaboratively manage scarce resources, such as the electromagnetic spectrum, and to adapt to new requirements and situations. Further, the resulting technologies, by being accessible to a wide range of application developers, will support new, sustainable computing systems for a broad spectrum of scientific and engineering applications. The Cyber Security project is developing the computing, networking, and cyber security technologies required to protect DoD, U.S. Government, and U.S. civilian information, information infrastructure, cyber-physical and embedded systems, critical infrastructure, and other computation-intensive mission-critical systems. Information technologies enable important existing and new military capabilities, and drive the productivity gains essential to U.S. industry. Meanwhile, cyber threats grow in sophistication and number, and put sensitive data, classified computer programs, mission-critical information systems, and U.S. economic competitiveness at risk. The technologies developed in this project will enhance the resilience of information systems to current and emerging cyber threats, enable broad situational awareness of the cyber domain, and provide the basis for accurate, calibrated, and safe cyber response. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                                          Date: June 2025 Appropriation/Budget Activity                                                        R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:                 PE 0602303E / INFORMATION & COMMUNICATIONS TECHNOLOGY Applied Research The Artificial Intelligence and Human-Machine Symbiosis project develops technologies to enable machines to function not only as tools that facilitate human action, but also as trustworthy partners to human operators. Of particular interest are systems that can understand human language, extract information, and reliably categorize content contained in diverse media; answer questions, reach conclusions, and propose explanations; and learn, reason, and apply knowledge gained through experience to respond intelligently to new and unforeseen events. Enabling computing systems with such human-like intelligence is now of critical importance because the tempo of military operations in emerging domains exceeds that at which unaided humans can orient, understand, and act. The technologies developed in this project will enable warfighters to make better decisions in complex, time-critical, battlefield environments; intelligence analysts to make sense of massive, incomplete, and contradictory information; software developers and certifiers to design, implement, evaluate, and accredit cyber-physical systems and other complex software-reliant systems with greater efficiency and confidence; and unmanned systems and semi-autonomous agents to perform critical missions in contested physical and virtual environments safely and reliably. Beginning in FY 2026, efforts in this PE will be funded in PE 0602025E, Making, Maintaining, Supply Chain and Logistics.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602303E_IT-04$$, $$0602303E$$, $$IT-04$$, $$ARTIFICIAL$$, 0, $$The efforts described in this Program Element (PE) address the Applied Research associated with the Information and Communications Technology Program that is directed toward the application of advanced, innovative computing systems and communications technologies. This PE also supports innovation and robust transition planning in the technology cycle by working with entrepreneurs to increase the likelihood that DARPA funded technologies take root in the U.S. and provide new capabilities for national defense. The High Productivity, High-Performance Responsive Architectures project focuses on developing the computer hardware and associated software technologies required for future computationally- and data-intensive national security applications. Powerful new approaches are needed to manage the rapid growth in available sensor data, to leverage advances in machine learning, artificial intelligence, and quantum computing, and to maintain the security of DoD information systems. The project therefore aims not only to create new computing platforms to include quantum technology, but also to efficiently extract information out of large and chaotic data sets with embedded and low-size, weight, and power systems. Advances in these areas will allow for DoD electronic systems to collaboratively manage scarce resources, such as the electromagnetic spectrum, and to adapt to new requirements and situations. Further, the resulting technologies, by being accessible to a wide range of application developers, will support new, sustainable computing systems for a broad spectrum of scientific and engineering applications. The Cyber Security project is developing the computing, networking, and cyber security technologies required to protect DoD, U.S. Government, and U.S. civilian information, information infrastructure, cyber-physical and embedded systems, critical infrastructure, and other computation-intensive mission-critical systems. Information technologies enable important existing and new military capabilities, and drive the productivity gains essential to U.S. industry. Meanwhile, cyber threats grow in sophistication and number, and put sensitive data, classified computer programs, mission-critical information systems, and U.S. economic competitiveness at risk. The technologies developed in this project will enhance the resilience of information systems to current and emerging cyber threats, enable broad situational awareness of the cyber domain, and provide the basis for accurate, calibrated, and safe cyber response. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                                          Date: June 2025 Appropriation/Budget Activity                                                        R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:                 PE 0602303E / INFORMATION & COMMUNICATIONS TECHNOLOGY Applied Research The Artificial Intelligence and Human-Machine Symbiosis project develops technologies to enable machines to function not only as tools that facilitate human action, but also as trustworthy partners to human operators. Of particular interest are systems that can understand human language, extract information, and reliably categorize content contained in diverse media; answer questions, reach conclusions, and propose explanations; and learn, reason, and apply knowledge gained through experience to respond intelligently to new and unforeseen events. Enabling computing systems with such human-like intelligence is now of critical importance because the tempo of military operations in emerging domains exceeds that at which unaided humans can orient, understand, and act. The technologies developed in this project will enable warfighters to make better decisions in complex, time-critical, battlefield environments; intelligence analysts to make sense of massive, incomplete, and contradictory information; software developers and certifiers to design, implement, evaluate, and accredit cyber-physical systems and other complex software-reliant systems with greater efficiency and confidence; and unmanned systems and semi-autonomous agents to perform critical missions in contested physical and virtual environments safely and reliably. Beginning in FY 2026, efforts in this PE will be funded in PE 0602025E, Making, Maintaining, Supply Chain and Logistics.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602144A_DA1$$, $$0602144A$$, $$DA1$$, $$SAFR Alternatives for Readiness$$, 6251000, $$This Project will develop safer alternative technologies that enable Army readiness, support supply chain resilience, improve Soldier and worker safety and reduce environmental impacts, including reduction of greenhouse gas emissions. The Project investigates alternatives for cross-cutting materials, undergoing or threatened by regulatory scrutiny, found in ground vehicles and all other types of Army weapon systems. Research areas of focus include alloys, ceramics, composites, textiles, maintenance fluids, propellants, explosives, and pyrotechnics. This work addresses increasing threats to readiness associated with carcinogenic, toxic, and restricted materials such as lead, beryllium, perchlorates, volatile organic compounds and per- and polyfluoroalkyl substances (PFAS) (forever chemicals), which can diminish Soldier and community health, restrict training and interrupt critical maintenance activities. Future liabilities and risks are characterized early in the life cycle of material development to ensure truly sustainable alternatives. This Project also investigates, develops and designs technologies to allow Soldiers to rapidly prioritize risk for PFAS to enable informed, timely and cost-effective solutions. This Project complements and transitions technologies to Program Element (PE) 0603119A (Ground Advanced Technology) / Project DA2 (SAFR Alternatives for Readiness Advanced Tech). Work in this Project is performed by the Army Research Laboratory (ARL); the Armaments Center (AC); the Aviation and Missile Center (AvMC); the Soldier Center (SC); the Ground Vehicle Systems Center (GVSC); and the U.S. Army Corps of Engineers (USACE) Engineer Research and Development Center (ERDC).$$, 6251000, NULL, NULL, NULL, NULL, 4982000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602144A_DG1$$, $$0602144A$$, $$DG1$$, $$Development of Obscurants$$, 2661000, $$This project will investigate and evaluate obscurants (i.e., materials) and obscurant technologies that are designed to degrade threat force surveillance sensors and defeat the enemy's target acquisition devices, missile guidance, and directed energy weapons. This project investigates advanced, infra-red, and multi-spectral obscurant materials that will provide effective, safe, and efficient screening of deployed units and platforms. Work in this project compliments Program Element (PE) 0602144A (Ground Technology) / Project DG2 (Advanced Development of Obscurants). The cited work is consistent with the Under Secretary of Defense Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the Chemical Biological Center (CBC).$$, 2661000, NULL, NULL, NULL, NULL, 2673000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602144A_DI7$$, $$0602144A$$, $$DI7$$, $$Environmental Security Resilience$$, 10102000, $$This Project matures and demonstrates capabilities to support Army Environmental Security, providing decisions and support tools for critical mission environments to address natural resource impediments, man-made stressors, extreme weather, and environmental engineering challenges that impact mission, infrastructure, training activities, deployment staging or present security concerns to operations. Project capabilities span the functional domains of strategic support area management, emergency preparedness, surge capacity, environmental impact on operations, and analysis of future operational environment and environmental threats. This effort will provide new material solutions, models and decision support tools for operational planning and infrastructure management. Work in this Project complements Program Element (PE) 0602144A (DI7) / Project (Environmental Security Resilience Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the United States Army Engineer Research and Development Center Environmental Laboratory, Construction Research Engineering Laboratory, and the Cold Regions Research and Engineering Laboratory.$$, 10102000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602145A_BF3$$, $$0602145A$$, $$BF3$$, $$Combat Vehicle Robotics Tech$$, NULL, $$This Project designs, develops, and evaluates a variety of innovative technologies that enable scalable integration of multi-domain robotic and autonomous system capabilities teamed within Army formations supporting all combat warfighting functions (close combat, reconnaissance, targeting and acquisition, etc.). This Project focus areas include autonomous architecture, autonomous behaviors and perception, and soldier machine integration. Autonomous Behaviors efforts focus on enhancing the performance of autonomy such as obstacle detection and avoidance. Soldier Machine integration efforts focus on design and development of technologies to become more efficient and effective for a robotic operator to complete missions on government owned software. This work is this Project is done in coordination with Program Element (PE) 0603462A (Next Generation Combat Vehicle Advanced Technology) / Project BF4 (Combat Vehicle Robotics). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas. Work in this Project is performed by Ground Vehicle System Center (GVSC).$$, NULL, NULL, NULL, NULL, NULL, 15950000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602145A_BF6$$, $$0602145A$$, $$BF6$$, $$Crew Augmentation and Optimization$$, NULL, $$This project designs capabilities for reduced vehicle crew sizes to successfully operate a larger number of closed-hatch manned and remote unmanned vehicles in a complex multi-domain operations environment. This project will enable future crews to perform missions with increasingly sophisticated technologies, and in increasingly complex, dynamic socio-technical environments. The applied research will provide the fundamental technologies to enable integrated performance improved learning - Warfighter Machine Interfaces (WMIs) that are scalable to multiple crew hardware and functional configurations; reconfigurable frameworks and simulation for concept experimentation and exploration; and team-centered dynamic tasking by machine intelligence to effectively utilize full capabilities of crew and technologies. The research will generate Soldier-informed data, reports, and analysis to support operational use in future vehicles through Soldier experimentation and assessment of technical concepts in simulation and in-field WMIs. The capabilities created by this research will increase overall crew and team performance; improved Soldier safety due to fewer Soldier per vehicle, closed-hatch operations, and improved standoff from effective control; and vehicles that can effectively conduct multiple domain operations. Work in this project complements Program Element (PE) 0603462A (Next Generation Combat Vehicle Advanced Technology) and PE 0602143A (Soldier Lethality Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas. Work in this project is performed by the Ground Vehicle System Center (GVSC) and the Army Research Laboratory (ARL).$$, NULL, NULL, NULL, NULL, NULL, 10997000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602750N_1394$$, $$0602750N$$, $$1394$$, $$Manufacturing$$, 6816000, $$This project develops and matures technologies that enable superior warfighting capabilities for surface and sub-surface naval platforms, undersea weapons and countermeasures, and Marine Corps technologies to a point where they can be proposed and continued as Future Naval Capabilities in program element (PE) 0603673N, Future Naval Capabilities Advanced Technology Development.$$, 6816000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602145A_BF8$$, $$0602145A$$, $$BF8$$, $$Artificial Intelligence & Machine$$, 1049000, $$This project develops and characterizes artificial intelligence and machine learning software and algorithms to team with soldiers in support of fully autonomous maneuver of the Next Generation Combat Vehicle (NGCV) and other autonomous systems, both physical and non-embodied. Efforts develop capabilities for NGCV and other autonomous agents that increase autonomy, unburdening the soldier operator, with a high degree of survivability and lethality in a highly contested environment. This work also investigates power distribution and conversion technologies to provide compact, efficient, and high-power capabilities for electrical and electro- mechanical loads supporting both mobile and stationary unmanned platforms. Research enables combat vehicles to rapidly learn, adapt, and reason faster than the adversary; accomplish missions in contested, austere and congested environments, characterized by lack of structure, adversarial actions, and minimal a priori knowledge; and provide force reduction through self-learning vehicles that can operate in complex militarily relevant environments. This project also matures emerging research leading to potential technology development in areas of strategic importance to the Army by bringing competitively selected Universities with research teams into Technical Alliances. The cited work is consistent with Under Secretary of Defense for Research and Engineering priority focus areas.$$, 1049000, NULL, NULL, NULL, NULL, 16908000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602145A_BF9$$, $$0602145A$$, $$BF9$$, $$Sensors for Autonomous Operations$$, 23207000, $$This project designs and develops modular and adaptive sensor components, novel embedded processing approaches, innovative threat cueing solutions and novel multi-function sensor payloads integrated with novel signal image processing techniques to provide improved manned and unmanned ground vehicle situational understanding in all environments. This project will also investigate and develop techniques to detect maneuver obstacles, to include explosive hazards, tank ditches, and concrete blockades. This research is coordinated with Program Element (PE) 0603462A (Next Generation Combat Vehicle Advanced Technology), PE 0603118A (Soldier Lethality Advanced Technology), PE 0602143A (Soldier Lethality Technology), PE 0602148A (Future Vertical Lift Technology) and PE 0603465A (Future Vertical Lift Advanced Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas. Work in this project is performed by the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Center.$$, 23207000, NULL, NULL, NULL, NULL, 25327000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602145A_BG2$$, $$0602145A$$, $$BG2$$, $$Modeling and Simulation for MUMT$$, NULL, $$This project develops Modeling and Simulation (M&S) tools and technologies to assess and improve freedom of movement for ground forces and supports vehicle developers by addressing challenges for robotic and ground vehicles. Through investigation and design, this project develops obstacle detection and classification algorithms for dynamic mobility hazards in urban and complex environments. This project develops tools to evaluate system performance reducing the need for physical testing including: real-time mobility decision support tools, vehicle-terrain interactive models for autonomous convoy operations, simulation tools for vehicle mobility in highly altered terrain, and M&S tools for predicting the performance of autonomous vehicles in a wide variety of weather and terrain conditions. These M&S technologies can be integrated across Army vehicle platforms as required. Work in this project complements Program Element (PE) 0603462A (Next Generation Combat Vehicle Advanced Technology) / Project BG3 (Modeling and Simulation for MUMT Advanced Tech). The work cited is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas. Work in this project is performed by the Geotechnical and Structures Laboratory.$$, NULL, NULL, NULL, NULL, NULL, 5511000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602145A_BG6$$, $$0602145A$$, $$BG6$$, $$Advanced Concepts for Active$$, 29047000, $$This project funds research for advanced materials and mechanisms to defeat the most common and most dangerous threats that are expected to be encountered by our ground forces in the near, mid and far term. Work conducted in this project will result in concepts for Adaptive and Cooperative Protection of ground combat vehicles. Additionally, research will focus on subcomponent/component models to predict performance of early concepts and the means to evaluate effectiveness on ground platforms. The project will balance developments of active threat defeat measures with the necessary advanced passive and active components to provide solutions which will help meet the requirements of current and next generation ground tactical and combat vehicles. This project is coordinated with and transitions to Program Element (PE) 0603462A (Next Generation Combat Vehicle Advanced Technology) and builds upon weapon target interaction research in PE 0602144A (Ground Technology) and PE 0601102A (Defense Research Sciences) / Project AA7 (Mechanics and Ballistics). The cited work is consistent with Under Secretary of Defense for Research and Engineering priority focus areas. Work in this project is performed by the Army Research Laboratory (ARL), Command, Control, Communication, Computers, Cyber, Intelligence, Surveillance and Reconnaissance Center (C5ISR), Data and Analysis Center (DAC), and Ground Vehicle Systems Center (GVSC).$$, 29047000, NULL, NULL, NULL, NULL, 32444000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602145A_BH5$$, $$0602145A$$, $$BH5$$, $$Platform Electrification and Mobility$$, NULL, $$This project researches and develops advanced power and energy technologies for tactical and combat ground vehicles that are necessary for parallel or series hybrid- electric drive. Research energy storage, distribution and battlefield charging technologies to enable future plug-in hybrid-electric drive and all electric tactical vehicle systems. This project researches and develops advanced power and energy technologies for combat ground vehicles that are necessary for parallel hybrid, series hybrid and all- electric vehicle systems. Work in this project complements PE 0603462A (Next Generation Combat Vehicle Advanced Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas. Work in this project is performed by the Ground Vehicle System Center (GVSC)$$, NULL, NULL, NULL, NULL, NULL, 11857000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602145A_BK5$$, $$0602145A$$, $$BK5$$, $$Adv Direct In-Direct Armament Sys$$, 8525000, $$This project matures and conducts experiments on component technologies for large caliber direct fire light-weight armament systems that will exceed the current capability of 120mm direct fire and be optimized for future operational environment with cross-domain engagement capability. This project also researches large caliber direct fire munitions to project overwhelming lethality while ensuring maneuver forces remains mobile and sustainable during close-combat engagements at extended ranges. Research in this project is related to and fully integrated with the efforts funded in Program Element (PE) 0603462A (Next Generation Combat Vehicle Advanced Technology) / Project BK6 (Advanced Technology Direct In Direct Armament Sys (ADIDAS) Advanced Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas. Research in this project is performed by the Armaments Center (AC) and Army Research Laboratory (ARL).$$, 8525000, NULL, NULL, NULL, NULL, 10654000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602145A_BP5$$, $$0602145A$$, $$BP5$$, $$Ground Vehicle Technology (CA)$$, NULL, $$Congressional Interest Item funding provided for Ground Vehicle Technology. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas.$$, NULL, NULL, NULL, NULL, NULL, 94700000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602145A_BI2$$, $$0602145A$$, $$BI2$$, $$Sensor Protection Technology$$, 4237000, $$This project investigates, designs, and develops techniques for masking friendly force capabilities and intentions. The project pursues technologies to reduce the susceptibility of sensor systems to detection and targeting by threat forces, as well as to inform the development of next generation signature reduction schemas. This project also designs, investigates, fabricates, evaluates and characterizes advanced sensor protection technologies, components, and concepts that will enable the future soldier to see and operate through a laser directed energy weapon attack. Both active and passive protection technologies will be investigated to protect Army sensors that operate in the visible, short-wave infrared, mid-wave infrared, and long-wave infrared spectra from battlefield laser threats. Areas of research include passive optical limiters such as nonlinear organic dyes, semiconductors, and meta-materials, as well as fast active switches and tunable filters. Technologies investigated include novel optics designs combined with signal processing, spectral filtering, and threat sensing algorithms. Work in this project is coordinated with Program Element (PE) 0603462A (Next Generation Combat Vehicle Advanced Technology), PE 0603118A (Soldier Lethality Advanced Technology), PE 0603465A (Future Vertical Lift Advanced Technology), and PE 0602143A (Soldier Lethality Technology) The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas. Work in this project is performed by the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Center$$, 4237000, NULL, NULL, NULL, NULL, 5428000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602145A_BI4$$, $$0602145A$$, $$BI4$$, $$Materials Application and Integration$$, NULL, $$This project designs, develops, fabricates and evaluates a variety of materials (e.g. metals, ceramics, polymers and composites) to enable more survivable, lighter weight vehicle armor, chemical and biological protection, armaments and electronics for the next generation combat vehicle. Research focuses on unique and /or novel materials properties, developing physics-based models, materials characterization techniques, non-destructive testing methods and advanced fabrication/processing methodologies to transition candidate solutions for maturity, scale-up, and integration into systems. This project also continues the Advanced Vehicle Power Technology Alliance between the Department of Energy and the Army with a focus on materials, providing an emphasis on developing advanced technologies that enable military ground vehicles to become significantly more energy efficient. The alliance is chartered to accelerate the conceptualization and transition into deployment of inventive and creative energy-saving concepts that the Nation needs to achieve energy security. This project matures and integrates lightweight materials and joining technologies in support of lighter military vehicles which are more fuel-efficient and expeditionary with superior mobility and protection of both vehicles and occupants. Work in this project leverages research from Program Element (PE) 0601102A (Defense Research Sciences) / Project AA7 (Mechanics and Ballistics) and 0602144A (Ground Technology) / Project BL1 (Materials and Manufacturing Research Technology). This work is also coordinated with PE 0603462A (Next Generation Combat Vehicle Advanced Technology). The cited work is consistent with Under Secretary of Defense for Research and Engineering priority focus areas. Work in this project is performed by the Army Research Laboratory (ARL).$$, NULL, NULL, NULL, NULL, NULL, 7441000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602145A_BJ2$$, $$0602145A$$, $$BJ2$$, $$Tactical and Navigation Lasers$$, 5482000, $$This project designs and develops novel laser sensor technologies which provide improved maneuver, lethality, and survivability capabilities via manned and autonomous navigation, adversary sensor threat detection, and target detection and designation in all environments. It will deliver novel laser technologies which will provide low size, weight, and power (SWaP) laser sources and receivers for optical augmentation detection systems; and compact Laser Detection and Ranging (LADAR) sources for situational awareness and air and ground vehicle operations and navigation in all environments. This project is a critical enabler for autonomous operations in environments where other imaging technologies are not sufficient. This project is coordinated with Program Element (PE) 0603462A (Next Generation Combat Vehicle Advanced Technology), PE 0603118A (Soldier Lethality Advanced Technology), PE 0603465A (Future Vertical Lift Advanced Technology), and PE 0602143A (Soldier Lethality Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas. Work in this project is performed by the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Center.$$, 5482000, NULL, NULL, NULL, NULL, 5708000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602145A_BK2$$, $$0602145A$$, $$BK2$$, $$Virtual Prototyping Technology$$, NULL, $$This project designs and analyzes novel NGCV system level ground vehicle concepts by integrating advanced mobility, survivability, lethality, sensing and electrical/ electronic technologies to address emerging and future advanced threats. This project provides system level ground vehicle design concepts and performance analysis, assesses cost and performance trades, and provides real-time soldier feedback on technology performance for the Army's NGCVs. Technologies to be evaluated include high efficiency advanced powertrains, power generation, vehicle electrification, active protection systems, active blast, advanced lethality and robotic control and autonomy technologies. The NGCV virtual prototypes include Virtual Soldier Operational Experiments (VSOE) with System Integration Labs (SILs) to give warfighters an understanding into how behaviors and tactics change given emerging operation concepts based on new technologies and capabilities. Future integration of VSOEs with software and hardware SILs with realistic interfaces and utilizing mixed reality technology will provide higher fidelity Soldier evaluations, without the time and cost associated with physical prototypes. The virtual prototyping results provide critical inputs to the Army's NGCV program by providing independent technical and operational performance results for the Army's next generation of ground combat vehicles while reducing risk and accelerating transition to physical prototypes. Work in this project is coordinated with Program Element (PE) 0603462A (Next Generation Combat Vehicle Advanced Technology) / Project BF4 (Combat Vehicle Robotics Adv Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas. Work in this project is performed by the Ground Vehicle System Center (GVSC).$$, NULL, NULL, NULL, NULL, NULL, 5410000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602146A_AP5$$, $$0602146A$$, $$AP5$$, $$Electronic Warfare Technology$$, NULL, $$This Project investigates emerging technologies related to Electronic Warfare (EW) applications, non-kinetic survivability/lethality, and emerging concepts of employment in the increasingly contested and congested electromagnetic environment, with the goal of enhancing the survivability/lethality of Army platforms through Electronic Attack (EA), electronic warfare support (ES), and Electronic Protection (EP) with high operational realism for current and future threats being implemented at multiple scales. Work in this Project complements Program Element (PE) 0603463A (Network C3I Advanced Technology) / Project AO7 (EW for Maneuver Operations (EMO) Adv Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Army Research Laboratory (ARL) and Data and Analysis Center (DAC).$$, NULL, NULL, NULL, NULL, NULL, 5334000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602146A_AM6$$, $$0602146A$$, $$AM6$$, $$Modular RF Communications$$, 1191000, $$This Project investigates and develops techniques, methods, and standards for automation and intelligence to optimally broadcast data among available radio frequency (RF) and networking technologies. This Project adds resiliency to the network through diversity and automation techniques to make automated network decisions (e.g., automated Primary, Alternate, Contingency, and Emergency (PACE)) for the tactical Army to maintain operation in continually changing environments. Work in this Project complements Program Element (PE) 0603463A (Network C3I Advanced Technology) / Project AM7 (Modular RF Communications Advanced Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center.$$, 1191000, NULL, NULL, NULL, NULL, 5803000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602146A_AM8$$, $$0602146A$$, $$AM8$$, $$Protected SATCOM Technology$$, 3489000, $$This Project investigates resiliency of Wideband Satellite Communications (SATCOM) in contested and congested electromagnetic environments. Wideband SATCOM is the primary high-bandwidth Beyond Line of Sight (BLOS) communications used by the tactical Army. This Project designs and develops technologies and components, such as interference cancellation, to increase availability and reliability of Wideband SATCOM in spectrum-challenged environments. Work in this Project complements Program Element (PE) 0603463A (Network C3I Advanced Technology) / Project AM9 (Protected SATCOM Advanced Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by Command, Control, Computer, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center.$$, 3489000, NULL, NULL, NULL, NULL, 4358000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602146A_AN3$$, $$0602146A$$, $$AN3$$, $$Non Traditional Waveforms$$, 7446000, $$This Project investigates non-traditional protocols and technologies to provide spectrally efficient, high bandwidth, low latency, lower spectrum footprint, and/or anti-jam capabilities to tactical networks. This Project develops network resiliency for the dismounted and vehicular units through science &and technology investigation. Work in this Project complements Program Element (PE) 0603463A (Network C3I Advanced Technology) / Project AN4 (Non-Traditional Waveforms Advanced Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center.$$, 7446000, NULL, NULL, NULL, NULL, 10661000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602146A_AN7$$, $$0602146A$$, $$AN7$$, $$COE - Every Receiver is a Sensor$$, NULL, $$This Project investigates, designs, and codes advanced automated exploitation and fusion analysis tools, applications, and software services that harvest, correlate and fuse tactical receiver sources with new and emerging data sources to improve understanding of the threat picture and more efficiently support near-real time Situational Understanding of the battlefield. This project investigates deep sensing capabilities to detect emitters in a dense electromagnetic environment. Work in this Project complements Program Element (PE) 0603463A (Network C3I Advanced Technology) / Project AN8 (COE - Every Receiver is a Sensor Advanced Tech) and PE 0602146A (Network C3I Technology) / Project AN9 (UNT - Every Receiver is a Sensor Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center.$$, NULL, NULL, NULL, NULL, NULL, 997000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602146A_AN9$$, $$0602146A$$, $$AN9$$, $$UNT - Every Receiver is a Sensor$$, 8898000, $$This Project develops algorithms that enable every communication receiver in the tactical environment to operate as a sensor while maintaining the systems' original networking capability. It matures standards and protocols to expand the Cyber-Electromagnetic Activity (CEMA) situational understanding. This Project investigates resource management approaches to increase simultaneity within resource constrained environments. It extends the Army's deep sensing capability by improving simultaneous functionality, leveraging all potential sensing assets within the area of operations and supporting real time feedback of mission effectiveness. This project helps the Army pace global electromagnetic spectrum technology advancements by designing and developing critical near peer signals intelligence (SIGINT) capabilities designed for the Army's size, weight, and power (SWaP)-constrained tactical edge. Work in this Project complements Program Element (PE) 0603463A (Network C3I Advanced Technology) / Project AO1 (UNT - Every Receiver is a Sensor Advanced Tech) and PE 0602146A (Network C3I Technology) / Project AN7 (COE - Every Receiver is a Sensor Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center.$$, 8898000, NULL, NULL, NULL, NULL, 2073000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602146A_AO4$$, $$0602146A$$, $$AO4$$, $$Energy Efficient Devices Technology$$, NULL, $$This Project addresses sustainment operations by unburdening the Soldier and reducing logistics requirements (e.g., fewer batteries) for communications, computing, and sensing. The objective is to investigate the underlying energy efficiency of supply and demand for Soldier-portable and distributed sensor electronics to enable the dismounted Soldier to maintain communications, freedom of movement, and increase mission duration. The majority of the electronics power used by the dismounted Soldier and by distributed electronics is attributable to radio frequency (RF) communications. In addition, freedom of movement and action during sustained and high tempo operations requires seamless battery recharging. To address these challenges, energy efficient electronics research includes RF and optoelectronic circuits, devices, materials and wireless power (and data) transfer. Work in this Project complements Program Element (PE) 0602146A (Network C3I Technology) / Project AN3 (Non-Traditional Waveforms Technology), PE 0602143A (Soldier Lethality Technology) / Project BD8 (Soldier & Sm Unit Tactical Energy Tech), and PE 0601102A (Defense Research Sciences) / Project AA9 (Information and Networking). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Army Research Laboratory (ARL).$$, NULL, NULL, NULL, NULL, NULL, 4469000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602148A_AL8$$, $$0602148A$$, $$AL8$$, $$Holistic Situational Awareness and$$, 2399000, $$This Project focuses on modeling and simulation of pilotage and decision aiding system technology that allows for carefree operations in complex and hostile environments. Work in this Project is fully coordinated with PE 0603465A (Future Vertical Lift Advanced Technology Development) / Project AL9 (Holistic Sit Awareness and Dec Making Adv Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology focus areas and the Army modernization strategy. Work in this Project is performed by Aviation & Missile Center (AvMC).$$, 2399000, NULL, NULL, NULL, NULL, 967000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602146A_AQ2$$, $$0602146A$$, $$AQ2$$, $$EW Techniques Technology$$, NULL, $$This Project develops countermeasures against adversarial counter-fire systems that obscure and create distractive blue force locations. This Project will develop and mature distributed, coordinated electromagnetic warfare (EW) capabilities designed to extend effective range, reduce blue transmitter susceptibility to localization, and introduce errors in adversary intelligence, surveillance and reconnaissance (ISR) systems to facilitate maneuver within multi-domain operations (MDO). Work in this Project complements Program Element (PE) 0603463A (Network C3I Advanced Technology) / Project AO7 (EW for Maneuver Operations (EMO) Adv Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center.$$, NULL, NULL, NULL, NULL, NULL, 521000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602146A_AQ7$$, $$0602146A$$, $$AQ7$$, $$High Tempo Data Driven Decision$$, 2316000, $$This Project investigates and develops data driven decision tools that increase operational tempo and allow commanders to dominate decision spaces over adversaries. The tools will provide the commander with contextually relevant data and adaptive decision models. Information and recommendations will be made and disseminated to commander and staff in a cognitively appropriate manner. Work in this Project complements Program Element (PE) 0603463A Network C3I Advanced Technology / Project AQ8 (High Tempo Data Driven Decision Tools Adv Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center.$$, 2316000, NULL, NULL, NULL, NULL, 1258000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602146A_AT7$$, $$0602146A$$, $$AT7$$, $$Network-Enabled GeoSpatial-GEOINT$$, 2760000, $$This Project investigates and develops an integrated capability to rapidly share mission critical 3-dimensional (3D) information that supports planning and execution at the Soldier level. This will be achieved through the maturation of next-generation geospatial analytical models for 3D complex urban environment data, delivering enriched understanding of dynamic Operational Environments and distributed to a tactical Common Operating Environment. This Project will result in improved situational awareness and autonomy at low echelons, contributing to increased maneuver and mobility during manned and unmanned teaming operations. Work in this Project complements Program Element (PE) 0603463A (Network C3I Advanced Technology) / Project AT8 (Network-Enabled GeoSpatial and GEOINT Services AdvTech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the United States Army Engineer Research and Development Center Geospatial Research Laboratory, Cold Regions Research and Engineering Laboratory, and Information Technology Laboratory.$$, 2760000, NULL, NULL, NULL, NULL, 2462000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602146A_AT9$$, $$0602146A$$, $$AT9$$, $$Tactical GeoSpatial Information$$, 2951000, $$This Project investigates and develops next generation geospatial analytical tools for 3-dimensional complex environments for low echelon and tactical edge exploitation. Research focuses on improving geospatial and Geospatial Intelligence (GEOINT) aspects of situational awareness in the complex environments by exploiting new data sources, automating analytical tasks, and testing new collection technologies, including interiors of infrastructure. Research develops capabilities to enhance/ update provisioned (baseline) standard, sharable, geospatial foundation (SSGF) data through automated analytics on multi-sourced spatial data resulting in streamlined, enhanced high fidelity terrain analysis products. Reducing data gaps and processing timelines will greatly increase Soldier situational awareness and support faster decision making in complex terrain. Work in this Project complements Program Element (PE) 0603463A (Network C3I Advanced Technology) / Project AU1 (Tactical GeoSpatial Information Capabilities ATech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the United States Army Engineer Research and Development Center Geospatial Research Laboratory.$$, 2951000, NULL, NULL, NULL, NULL, 2618000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602146A_AV5$$, $$0602146A$$, $$AV5$$, $$Protective Technologies$$, 4844000, $$This Project designs and develops Anti-Tamper tools, devices, and techniques to protect acquisition program systems' Critical Program Information (CPI) from continually evolving adversarial reverse engineering/exploitation threats due to battlefield loss and foreign sale. Loss of CPI will impact the ability of these systems to maintain US overmatch capabilities. Research in this Project complements Program Element (PE) 0603042A (C3I Advanced Technology) / Project DI6 (Anti-Tamper Advanced Tech Development) The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Aviation & Missile Center (AvMC).$$, 4844000, NULL, NULL, NULL, NULL, 6356000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602146A_AV9$$, $$0602146A$$, $$AV9$$, $$Advanced PNT for GPS Independent$$, 7952000, $$This Project develops technologies that will enable precise and assured Positioning, Navigation, and Timing (PNT) in Global Positioning System (GPS)-denied environments by addressing the PNT's toughest Scenario - Scenario 4 (no available GPS signal during the mission duration) with a goal of enabling Soldier missions of up to seven days in a GPS denied environment. This is achieved by researching advanced quantum timing circuits, advanced inertial measurement unit (IMU) components, multi-sensor modalities, perception techniques, geo-location data, vision aided navigation sensors, and available radio frequency (RF) signals. This work also addresses the PNT Scenario 1 (GPS operations that start well and have degraded GPS signals throughout the mission duration) through Scenario 3 (GPS operations that have bad or limited availability of GPS signals throughout the entire mission). This is achieved by investigating the ability to transmit jam- resistant, precision timing synchronized signals using optical fibers, free-space using lasers, and in the RF domain using innovative RF antenna concepts to extend the reach of Soldier compatible capabilities in heavily contested GPS environments. Work in this Project complements Program Element (PE) 0603463A (Network C3I Advanced Technology) / Project AW6 (Modular GPS Independent Sensors Advanced Tech) and Program Element (PE) 0602146A (Network C3I Technology) / Project AW5 (Modular GPS Independent Sensors Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Army Research Laboratory (ARL).$$, 7952000, NULL, NULL, NULL, NULL, 8993000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602148A_BP7$$, $$0602148A$$, $$BP7$$, $$Future Vertical Lift Air Platform Tech$$, NULL, $$Congressional Interest Item funding provided for Future Vertical Lift Platform Technology. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy.$$, NULL, NULL, NULL, NULL, NULL, 33500000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602146A_AW1$$, $$0602146A$$, $$AW1$$, $$Autonomous Navigation Technology$$, NULL, $$This Project investigates use of sensors on the platform and available navigation signals to the localization and decision making of Robotic/Autonomous Systems. Additionally, it examines the use of machine learning algorithms for cooperative navigation to aid in a Positioning, Navigation and Timing (PNT) solution. This will enable the user to achieve operational overmatch in a Global Positioning System (GPS) impeded environment as well as enhanced navigation (reducing dependence on GPS) through challenging terrains. This project investigates and develops techniques and algorithms to provide assured access to PNT in degraded electromagnetic (jamming), space, or cyber environments and notify Soldiers, Systems, and Platforms when PNT cannot be trusted for mission duration. This project seeks to study and develop an innovative, adaptive Navigation Warfare (NAVWAR) electronic attack (EA) capability, both jamming and spoofing, utilizing cooperative platforms to deny adversaries the ability to utilize GNSS receivers, reducing their overall mission effectiveness. The cooperative platforms can defeat advanced Global Navigation Satellite System (GNSS) capabilities, including controlled reception pattern antennas (CRPAs), by creating a diverse and adaptive jamming geometry. Cooperative platforms can leverage their distributed environmental situational awareness to establish and transmit spoofing solutions. Work in this Project complements Program Element (PE) 0603463A (Network C3I Advanced Technology) / Project AV8 (Navigation Warfare (NAVWAR) Advanced Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the United States Army Space and Missile Defense Technical Center and Command, Control, Computer, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center.$$, NULL, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602146A_AW5$$, $$0602146A$$, $$AW5$$, $$Modular GPS Independent Sensors$$, NULL, $$This Project performs research and development of modular Global Positioning System (GPS)-independent sensors and an open architecture sensor fusion core enabling simple, plug-and-play sensor modules that can be tailored for any platform based on mission needs and requirements. This Project investigates the design of a single receiver that integrates multiple commercial and military signal sources to provide Position Navigation and Timing (PNT) solution effective in contested environments. Work in this Project complements Program Element (PE) 0603463A (Network C3I Advanced Technology) / Project AW6 (Modular GPS Independent Sensors Advanced Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center.$$, NULL, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602146A_BP2$$, $$0602146A$$, $$BP2$$, $$Sensor and Electronic Network$$, NULL, $$Congressional Interest Item funding provided for Sensor and Electronic Network Initiatives. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy.$$, NULL, NULL, NULL, NULL, NULL, 62000000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602146A_CG3$$, $$0602146A$$, $$CG3$$, $$Assured PNT Communications$$, 1767000, $$This Project designs and develops technologies for Space-enabled, High Altitude (HA) and Counter-Surveillance and Reconnaissance (C-SR) applications to support Army tactical ground forces. The Project focuses on advancing technology discovery and development in key research areas that support Army's access to space-based capabilities, C-SR, quantum science communications and sensing, multi-function and multi-mission applications. This Project supports Tactical Land Component Forces access to Space-enabled and C-SR capabilities for force projection and maneuver through persistent and deep sensing. Work in this Project complements Program Element (PE) 0603463A (Network C3I Advanced Technology) / Project CJ8 (Assured PNT Communications Advanced Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the United States Army Space and Missile Defense Technical Center.$$, 1767000, NULL, NULL, NULL, NULL, 5494000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602146A_CI3$$, $$0602146A$$, $$CI3$$, $$Mobile and Survivable Command Post$$, NULL, $$This Project develops and investigates emerging communications, tactical cloud, distributed computing, power management and storage, and shielding materials necessary to improve Command Post (CP) survivability and effectiveness for near-peer Multi-Domain Operations (MDO) engagements. Work in this Project complements Program Element (PE) 0603463A (Network C3I Advanced Technology) / Project CI7 (Mobile and Survivable Command Post (MASCP) Adv Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology focus areas and the Army Modernization Strategy. Work in this Project is performed by the Command, Control, Communication, Computers, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Center and Soldier Center (SC).$$, NULL, NULL, NULL, NULL, NULL, 3170000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602146A_CU6$$, $$0602146A$$, $$CU6$$, $$Adaptive Information Mediation and$$, 11884000, $$This Project develops techniques to accelerate decision-making at lower echelons where data, information systems (IS), and Soldiers are distributed across complex and hostile environments. With robust multi-modal distributed information analytics and adaptive information mediation, decision makers can share understanding across echelons through a cross-reality information interaction. Research focuses on operational issues and gaps concerning decision uncertainty, at-the-edge situational awareness/understanding, and secure low-Size, Weight, and Power (SWAP) IS that support converged capabilities. These capabilities are critical in overcoming limitations in traditional uni-modal machine learning architectures that depend on extensive training data and stove-piped Command and Control systems that cannot provide a shared, adaptive common operating picture across echelons. Work in this Project complements Program Element (PE) 0603462 (Next Generation Combat Vehicle Advanced Technology) / Project BF4 (Combat Vehicle Robotics Adv Tech) and Program Element (PE) 0603463 (Network C3I Advanced Technology) / Project AQ8 (High Tempo Data Driven Decision Tools Adv Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology focus areas and the Army modernization strategy. Work in this Project is performed by the Army Research Laboratory (ARL).$$, 11884000, NULL, NULL, NULL, NULL, 6962000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602146A_CV4$$, $$0602146A$$, $$CV4$$, $$Pathfinder 3D Applied Technology$$, 1031000, $$This Project investigates and develops a geospatial rapid position and navigation solution in Global Positioning System (GPS) degraded and denied environments. Research focuses on using onboard sensors and high-resolution digital terrain geospatial alternative solution based upon Visual Three-Dimensional (3-D) Terrain Referencing and Navigation (VTRAN). This Project will result in the linkage of air and ground assets integrating sensory and (One World Terrain and Reference) geospatial data within the modular GPS Independent Sensors architecture. This Project provides critical alternatives to maneuver forces for position and navigation in a multi-domain operational environment. Work in this Project complements Program Element (PE) 0603463A (Network C3I Advanced Technology) / Project DB6 (Pathfinder 3D Adv Technology). The work cited is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the United States Army Engineer Research and Development Center Geospatial Research Laboratory.$$, 1031000, NULL, NULL, NULL, NULL, 2014000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602147A_AF3$$, $$0602147A$$, $$AF3$$, $$Extended Range Propulsion$$, 2797000, $$This Project directly supports Long Range Precision Fires Modernization Priority capabilities by designing, fabricating, and investigating missile enabling propulsion technologies to enable range extension and/or block speed improvement for long range applications; and enables improvement in High Performance Propellants (HPP) via gains in energy density and burn rate control. Work in this Project complements Program Element (PE) 0602147A (Long Range Precision Fires Technology) / Project AF8 (Affordable Extended Range Precision Tech) and Program Element (PE) 0603464A (Long Range Precision Fires Advanced Technology) / Project AF2 (Long Range Maneuverable Fires (LRMF) Advanced Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Aviation & Missile Center (AvMC).$$, 2797000, NULL, NULL, NULL, NULL, 10956000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602147A_AF8$$, $$0602147A$$, $$AF8$$, $$Affordable Extended Range Precision$$, 8878000, $$This Project directly supports Long Range Precision Fires (LRPF) Modernization Priority capabilities by investigating the design and fabrication of components and subsystems critical to produce affordable extended range precision missiles as well as critical component technologies including advanced propulsion, seekers/sensors, fire control, datalink, guidance, navigation and controls, airframes, survivability techniques and technologies, and additional high payoff areas. Work in this Project complements Program Element (PE) 0602147A (Long Range Precision Fires Technology) / AF1 (Long Range Maneuverable Fires (LRMF) Technology) / AF3 (Extended Range Propulsion Tech) and PE 0603464A (Long Range Precision Fires Advanced Technology) / AF2 (Long Range Maneuverable Fires (LRMF) Advanced Tech); and PE 0603464A (Long Range Precision Fires Advanced Technology) / BY2 (Advanced Hypersonic Technology) The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Research in this Project is performed by the Aviation & Missile Center (AvMC).$$, 8878000, NULL, NULL, NULL, NULL, 9692000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602147A_AG4$$, $$0602147A$$, $$AG4$$, $$Extended Range Artillery Munition$$, 9865000, $$This Project directly supports Long Range Precision Fires Modernization Priority capabilities by investigating critical enabling component technologies and designing high precision terminal guidance in denied environments, capable of surviving high gun shock loads, at extended ranges, and automated cannon artillery technologies to increase operational tempo and unburden the soldier. The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Armaments Center.$$, 9865000, NULL, NULL, NULL, NULL, 1310000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602147A_AH4$$, $$0602147A$$, $$AH4$$, $$Precision and Coop Weapons in a$$, NULL, $$This Project investigates technologies to deliver accurate fires from extended ranges in denied environments and informs future close- and deep-range Long Range Precision Fires (LRPF) capabilities (e.g., Extended Range Cannon Artillery, Precision Strike Missile). Work in this Project research technologies for navigation of munitions without Global Positioning System (GPS) and flying munitions to much greater distances against advanced threat Area Denial Assets by delivering navigation technology for multiple munitions with complementary sensors and maneuverability technology for munitions with enhanced lift and control characteristics. Work in this Project complements PE 0602141A (Lethality Technology) / Project AH6 (Disruptive Energetics and Propulsion Technologies), Project AH7 (Lethal and Scalable Effects Technologies), and Project AH8 (Lethality Materials and Processes Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the Army Research Laboratory (ARL).$$, NULL, NULL, NULL, NULL, NULL, 8903000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602147A_BN5$$, $$0602147A$$, $$BN5$$, $$Fuze and Power for Munitions$$, 2731000, $$This Project directly supports Long Range Precision Fires Modernization Priority capabilities by investigating critical component technologies and designs capable to enable advanced lethality and scalable warheads for future munitions as well as exploring new power technologies for extended run time and extended range munitions. The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Research in this Project is performed by the Armaments Center.$$, 2731000, NULL, NULL, NULL, NULL, 3293000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602147A_BO9$$, $$0602147A$$, $$BO9$$, $$WEAPONS & MUNITIONS TECH$$, NULL, $$Congressional Interest Item funding provided for Weapons and Munitions Tech Program Initiative. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy.$$, NULL, NULL, NULL, NULL, NULL, 62000000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602147A_DM6$$, $$0602147A$$, $$DM6$$, $$Cannon Fires Automation Research$$, 1473000, $$This project develops new technologies to enhance tactical cannon fires capabilities for future operational environments requiring cross-domain engagements across distributed formations. Designs, develops, and conducts experiments on component technologies for unmanned, optionally manned, and autonomous indirect fires armaments system and subsystem tasks. Designs, develops, and conducts experiments on cannon technologies to achieve automated / autonomous indirect fires across platforms and missions. Investigates remote and autonomous command and control for indirect fires systems to enable technology insertion, commonality, and optimized performance across multiple Fires functions and formations. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is completed by the Armaments Center (AC).$$, 1473000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602148A_AK9$$, $$0602148A$$, $$AK9$$, $$Adv Teaming for Tactical Aviation$$, NULL, $$This Project investigates and develops subsystem and component level technologies that enable advanced teaming behaviors for mixed platform formations in combined arms operations. Primary component technologies to develop are in the areas of resilient autonomy algorithms, team-based communications and situational awareness management, decision aiding for weapons systems engagement, autonomous terrain and collision avoidance, and human autonomy interface design. Work in this Project is fully coordinated with Program Element (PE) 0603465A (Future Vertical Lift Advanced Technology) / Project AL1 (Adv Teaming for Tactical Aviation Oper Adv Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology focus areas and the Army modernization strategy. Work in this Project is performed by the Aviation & Missile Center (AvMC), and the Command, Control, Communication, Computers, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Center.$$, NULL, NULL, NULL, NULL, NULL, 14863000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602750N_1395$$, $$0602750N$$, $$1395$$, $$Materials$$, 0, $$This project develops and matures technologies that enable superior warfighting capabilities for surface and sub-surface naval platforms, undersea weapons and countermeasures, and Marine Corps technologies to a point where they can be proposed and continued as Future Naval Capabilities in program element (PE) 0603673N, Future Naval Capabilities Advanced Technology Development.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602148A_CC3$$, $$0602148A$$, $$CC3$$, $$FVL Radar Technologies$$, 3401000, $$This Project develops underlying technologies applicable to next generation airborne radars used for detection, tracking and precision targeting, navigation and fire control for multiple modalities. It develops fully automated target recognition for radar, advanced processing techniques, distributed radar sensing and sensor coordination methods needed for targeting-quality detect, identify, locate and report (DILR) capabilities from airborne platforms. Efforts improve radar survivability and lethality across the Aviation ecosystem, speed target prosecution timelines for actionable information on the battlefield and provide the Warfighter with persistent DILR enabling day/night/all-weather sensing in congested/contested Multi-Domain Operations (MDO) environments. Work in this Project is fully coordinated with Program Element (PE) 0603465A (Future Vertical Lift Advanced Technology) / Project CC4 (FVL Radar Advanced Technologies). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by Command, Control, Communication, Computers, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Center.$$, 3401000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602148A_CH2$$, $$0602148A$$, $$CH2$$, $$Air Launched Effects Technology$$, NULL, $$This Project utilizes improved analytic modeling to investigate the effects that potential unmanned system capabilities could have on air vehicle design considerations and operational concepts. This Project improves government capability to design and assess novel Unmanned Aircraft System (UAS) concepts. This Project also develops and investigates the ability to launch a UAS from a manned or unmanned future vertical lift aircraft at tactical altitudes and to control the same after launch from nearby Future Vertical Lift (FVL) aircraft, as well as development of the associated payloads (recon, battle damage assessment, targeting, comms, decoy). This Project will assess the enabled capabilities and determine their relevance to current Army Aviation engagement and survivability portfolios. Work in this Project is fully coordinated with Program Element (PE) 0603465A (Future Vertical Lift Advanced Technology) / Project AK8 (Air Launched Effects Advanced Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology focus areas and the Army modernization strategy. Work in this Project is performed by Aviation and Missile Center (AvMC).$$, NULL, NULL, NULL, NULL, NULL, 4204000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602148A_CH3$$, $$0602148A$$, $$CH3$$, $$Holistic Team Survivability$$, 3490000, $$This Project will investigate and design advanced survivability technologies to develop a holistic team-based solution that delivers advanced sensing and electronic warfare (EW) effects across a family of aircraft to optimally penetrate and survive in the anti-access/area denial (A2AD) environment. This Project will take an integrated team-based system of systems survivability approach through a purpose-driven mix of improved survivability situational awareness, signature management, vulnerability reduction, enhanced platform survivability against directed energy munitions, route and maneuver optimization, expendables, advanced sensors, and electro-optics (EO) & radio frequency (RF) jamming for existing and future air platforms. This Project will also provide advanced teaming algorithms for survivability. This Project develops and evaluates multi layered survivability concepts and supporting technologies for increased survivability of Future Vertical Lift (FVL) Family of Systems (FVL FoS) in an advanced and evolving integrated air defense systems environment. Work in this Project is fully coordinated with Program Element (PE) 0603465A (Future Vertical Lift Advanced Technology) / Project CG1 (Holistic Team Survivability Adv Tech). The cited research is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology focus areas and the Army modernization strategy. Work in this Project is performed by Aviation & Missile Center (AvMC) and Command, Control, Communication, Computers, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Center.$$, 3490000, NULL, NULL, NULL, NULL, 10904000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602148A_CH4$$, $$0602148A$$, $$CH4$$, $$Power & Thermal Management for$$, NULL, $$This Project directly supports Future Vertical Lift (FVL) Modernization Priority capabilities by investigating and developing power and thermal management technologies to provide significantly higher electrical power capability to FVL aircraft while addressing consequential size, weight, and thermal issues. This Project provides power capability for advanced electric aeromechanical effectors, advanced mission systems algorithms for route planning and teaming, and advanced electronic warfare devices. This also Project investigates emerging electrical power generation and distribution, energy storage, and thermal management technologies needed for future Command, Control, Communications, Computers, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) and survivability equipment for application to FVL and other Army platforms. Enables significantly increased aircraft electrical power capability for advanced electric aeromechanical effectors, advanced mission systems to include algorithms for route planning and teaming, and for advanced electronic warfare devices while minimizing size and weight. Work in this Project is fully coordinated with Program Element (PE) 0603465A (Future Vertical Lift Advanced Technology) / Project CH7 (Power & Thermal Management for FVL Adv Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology focus areas and the Army modernization strategy. Work in this Project is performed by Aviation & Missile Center (AvMC) and Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Center.$$, NULL, NULL, NULL, NULL, NULL, 8481000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602148A_CI4$$, $$0602148A$$, $$CI4$$, $$Adaptive Avionics Technologies$$, 3604000, $$This Project will Build on Modular Open Systems Approach (MOSA) successes to enable future aviation mission systems to proactively exploit emerging innovation from multiple technological domains, employing continuous development and continuous deployment by researching and developing advanced avionics integration techniques and optimized processing management. Work in this Project is fully coordinated with Program Element (PE) 0603465A (Future Vertical Lift Advanced Technology) / Project CI8 (Adaptive Avionics Advanced Technologies). The cited work is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology focus areas and the Army modernization strategy. Work in this Project is performed by Aviation & Missile Center (AvMC).$$, 3604000, NULL, NULL, NULL, NULL, 982000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602180A_DM7$$, $$0602180A$$, $$DM7$$, $$Counter AI App Rsch$$, 1496000, $$This Project designs and develops mechanisms for the implementation of trusted artificial intelligence and machine learning (AI/ML) for processing, detecting, identifying, and reacting to potentially adverse effects on AI/ML capabilities. It provides recommendations for countering adversarial AI/ML, improving algorithms, and ensuring resilience in complex and contested environments. Effective use of Counter-AI to secure response mechanisms for the identification and detection of adversarial AI/ML is critical to address threats in a rapidly evolving environment. These technologies will produce an AI solution that rapidly adjusts AI/ML algorithms to disregard and stop malicious attempts to corrupt Army AI/ML tools. The cited work is consistent with Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the Artificial Intelligence Integration Center (AI2C).$$, 1496000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602148A_CI5$$, $$0602148A$$, $$CI5$$, $$High Speed Maneuverable Missile$$, 605000, $$The Project investigates, designs, and evaluates missile component technologies compatible with Future Vertical Lift (FVL) and Future Unmanned Aircraft Systems (FUAS) aviation platforms and ground platforms in a Multi-Domain Battle/Cross-domain Maneuver operational environment. Efforts provide technologies to support a smaller, faster, maneuverable missile capable of long-range non-line-of-sight attack in contested/degraded environments. Technology development increases aviation and ground lethality and platform survivability by increasing missile standoff range, speed, and maneuverability, a faster rate of fire, shorter times of flight, and multi- threat lethal effects. Enables cross domain applications for aviation and ground vehicle platforms, including handoff capability, to engage threats in dead zones, and to operate in contested environments. Work in this Project is fully coordinated with Program Element (PE) 0603465A (Future Vertical Lift Advanced Technology), Project CK2 (High Speed Maneuverable Missile Adv Tech). The cited research is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology focus areas and the Army modernization strategy. Work in this project is performed by Aviation and Missile Center (AvMC).$$, 605000, NULL, NULL, NULL, NULL, 23325000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602150A_AE2$$, $$0602150A$$, $$AE2$$, $$Unconventional Countermeasures-$$, 2694000, $$This Project designs and develops technologies to deter tactical surveillance and targeting by adversarial area denial systems and munitions. The Project investigates methods to increase survivability of critical assets against precision-guided near-peer advanced weapons threats, investigates and develops tonedown methods for signature management, and computationally develops novel countermeasures. This Project also develops a suite of high-fidelity, physics-based modeling and simulation tools for the design and development of unconventional countermeasures and survivability enhancers applicable to a wide range of operating environments. Work in this Project complements Program Element (PE) 0603466A (Air and Missile Defense Advanced Technology) / Project AE3 (Unconventional Countermeasures- Survivability ATech). The work cited is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the United States Army Engineer Research and Development Center Geotechnical and Structures Laboratory.$$, 2694000, NULL, NULL, NULL, NULL, 3361000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602150A_BN6$$, $$0602150A$$, $$BN6$$, $$Advanced Weapons Components$$, NULL, $$Congressional Interest Item funding provided for Advanced Weapon Components. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy.$$, NULL, NULL, NULL, NULL, NULL, 70500000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602150A_CV7$$, $$0602150A$$, $$CV7$$, $$High Energy Laser Direct Diode Apl$$, 2382000, $$This Project designs and develops single mode diode emitters to increase output power to 100 Watts with >60% electrical-to-optical efficiency and packaging for an array of emitters. This Project will leverage industry and National Labs research to overcome gain limitations in the semi-conductor gain region. This Project also funds research necessary to make significant improvements to the size, weight, and power (SWaP) of laser subsystems. Research in this Project complements other Army Directed Energy efforts conducted under (PE) 0602150A (Air and Missile Defense Technology)/Project DC1 (Next Generation Directed Energy Concept Development and Analysis) and PE 0603466A (Air and Missile Defense Advanced Technology)/Project CV6 (Optimized High Energy Laser Source Advanced Technology). The cited research is consistent with the Army's modernization programs, the Under Secretary of Defense for Research and Engineering priority focus areas, the Army Modernization Strategy, and supports the Army's future capability opportunities for leap-ahead technology for Directed Energy. Research is performed by the United States Army Space and Missile Defense Command - Technical Center (USASMDC-TC) in coordination with RCCTO.$$, 2382000, NULL, NULL, NULL, NULL, 1440000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602150A_CV8$$, $$0602150A$$, $$CV8$$, $$Vulnerability Modules for Multi-$$, 7230000, $$This Project will design and develop High Energy Laser (HEL) Vulnerability Modules (VM), engagement tactics data and kill signatures for targeting Unmanned Aerial Systems, Cruise Missiles, and Rotary Wing threats for future HEL weapon systems. VM development includes Smart VM development to enable real time threat feature detection and targeting. Smart VMs enable optimized aimpoint selection across a large range of current and future threat targets, increasing the HEL Weapon Systems lethality. Research in this Project complements other Army Directed Energy efforts conducted under (PE) 0602150A (Air and Missile Defense Technology)/Project DC1 (Next Generation Directed Energy Concept Development and Analysis. The cited research is consistent with the Army's modernization programs, the Under Secretary of Defense for Research and Engineering priority focus areas, the Army Modernization Strategy, and supports the Army's future capability opportunities for leap-ahead technology for Directed Energy. Research is performed by the United States Army Space and Missile Defense Command - Technical Center (USASMDC-TC) in coordination with RCCTO and PEO Missiles and Space/PM Shield.$$, 7230000, NULL, NULL, NULL, NULL, 8659000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602150A_DA9$$, $$0602150A$$, $$DA9$$, $$Radar Survivability through Dis$$, 995000, $$This project investigates and develops critical radar capability enhancements to defeat advanced Air and Missile threats and protect Army maneuver forces and critical assets. Radar enhancements are required for advanced Electronic Protection (EP) techniques against advanced jammers, electronic Combat Identification (CID), and resource optimization across the threat spectrum while retaining 360 degree coverage capability. Technology development includes providing capabilities for: dispersed multi-static operation, classifying/tracking emerging threats and high-volume threats; adaptive digital beam forming to enable resource efficiency, performance in a dynamic clutter environment and enhanced survivability in a contested battlespace; and multi-modal tracking and additional discrimination models to support diverse and emerging threats, such as swarms and guided munitions. Enhanced development for the state-of-the-art scalable, digital array radar testbed to include advanced algorithms, transmitted power, antenna gain, detection range and angle accuracy/resolution upgrades to the existing/new radar front/back ends will allow greater performance characterization for Multi-mission Army Radar systems supporting Multi-domain Operations (MDO). This research complements Program Element (PE) 0602141A (Lethality Technology) / Project CG4 (Advanced Radar Concepts); PE 0602148A (Future Vertical Lift Technology) / Project CC3 (FVL Radar Technology); and PE 0601102A (Defense Research Sciences) / Project AA8 (Foundational Distributed Radar); and PE0602141A (Lethality Technology) / Project CJ7 (Future Air Defense Missile Enabling Technology) and PE 0603466A (Air and Missile Defense Advanced Technology) / Project DB3 (Radar Survivability through Dis Sensing Adv Tech)); and PE 0602275A (Electronic Warfare Applied Research)/ Project A70 (Sensor Electronic Support Tech); and PE 0603275A (Electronic Warfare Advance d Technology) / Project A78 (Sensor Electronic Support Adv Tech) The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Aviation & Missile Center (AvMC).$$, 995000, NULL, NULL, NULL, NULL, 4531000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602183A_CW6$$, $$0602183A$$, $$CW6$$, $$Future UAS Propulsion Technology$$, NULL, $$This Project designs and assesses advanced engine and power system component technologies to support the goals of multi-fuel capability, reduced fuel consumption, and reduced engine size, weight, and cost in current and Future Unmanned Aircraft Systems (FUAS). Work in this Project is fully coordinated with Program Element (PE) 0602148A (Future Vertical Lift Technology) / Project CH4 (Power & Thermal Management for FVL Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology focus areas and the Army Modernization Strategy. Work in this Project is performed by Army Research Laboratory (ARL).$$, NULL, NULL, NULL, NULL, NULL, 3430000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602150A_DC1$$, $$0602150A$$, $$DC1$$, $$Next Generation DE Concept$$, 6686000, $$This Project researches and investigates technologies that will enable next generation directed energy weapons to operate more efficiently and defend against challenging evolving threats. Research areas investigated include lethality effectiveness, adaptive optics, beam control, laser sources, algorithms, and analyses for applications that will enable an improved layered defense capability. This Project determines critical activities to enable next generation directed energy technical innovations. Work in this Project complements (PE) 0602150A (Air and Missile Defense Technology)/Projects CV7 (High Energy Laser Direct Diode Applied Technology), CV8 (Vulnerability Modules for Multi-Domain Operations) and DE3 (Advanced Beam Control Component Development for Counter-Cruise Missile) and PE 0603466A (Air and Missile Defense Advanced Technology)/Projects CV6 (Optimized High Energy Laser Source Advanced Technology) and IB1 (Integrated Beam Control Systems Demonstration for Counter-Cruise Missile). The cited research is consistent with the Army's modernization programs, the Under Secretary of Defense for Research and Engineering priority focus areas, the Army Modernization Strategy, and supports the Army's future capability opportunities for leap-ahead technology for Directed Energy. Research is performed by the United States Army Space and Missile Defense Command - Technical Center (USASMDC-TC).$$, 6686000, NULL, NULL, NULL, NULL, 6309000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602150A_DE3$$, $$0602150A$$, $$DE3$$, $$Adv Beam Control Component$$, 5505000, $$This project researches and develops advanced beam control technologies to enable new sensors, illuminators, deformable mirrors, wavefront sensors (WFS), optical components, and acquisition and tracking concepts. Design and develop an advanced large-aperture off-axis beam expander, incorporating innovative, cost-saving component research. Develop algorithms for WFS and laser-quality tracking. This effort will increase effective range for multi-domain missions, including counter-cruise missile operations. Work in this Project complements (PE) 0602150A (Air and Missile Defense Technology)/Project DC1 (Next Generation Directed Energy Concept Development and Analysis) and PE 0603466A (Air and Missile Defense Advanced Technology)/Project IB1 (Integrated Beam Control Systems Demonstration for Counter-Cruise Missile). The cited research is consistent with the Army's modernization programs, the Under Secretary of Defense for Research and Engineering priority focus areas, the Army Modernization Strategy, and supports the Army's future capability opportunities for leap-ahead technology for Directed Energy. Research is performed by the United States Army Space and Missile Defense Command - Technical Center (USASMDC-TC) in coordination with RCCTO.$$, 5505000, NULL, NULL, NULL, NULL, 7984000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602150A_HP1$$, $$0602150A$$, $$HP1$$, $$High Power Microwave Technology$$, 500000, $$This Project will design and develop High Power Microwave (HPM) Vulnerability Data, engagement tactics data and kill signatures for targeting Unmanned Aerial Systems, Cruise Missiles, and Precision Guided Munition (PGM) threats for future HPM weapon systems. It will also develop additional HPM capabilities unique to the Army needs including antennas, sources, and other HPM system components. Data developed will be incorporated to enable real time threat detection and targeting, increasing the lethality of the HPM weapon systems through optimizing waveform selection. Research in this Project complements other Army Directed Energy efforts conducted for IFPC-HPM, PE 0604019A / Expanded Mission Area Missile (EMAM). The cited research is consistent with the Army's modernization programs, the Under Secretary of Defense for Research and Engineering priority focus areas, the Army Modernization Strategy, and supports the Army's future capability opportunities for leap-ahead technology for Directed Energy. Research is performed by the United States Army Space and Missile Defense Command - Technical Center (USASMDC-TC) in coordination with RCCTO and PEO Missiles and Space.$$, 500000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602150A_SU1$$, $$0602150A$$, $$SU1$$, $$Counter Small Unmanned Aircraft Sys$$, NULL, $$This Project investigates, designs and develops novel Counter-small Unmanned Aircraft System (C-sUAS) kinetic missile interceptor capabilities. Project will transition technologies for increased range, reduce reaction time, increase lethality, improve reliability, reduce reload time for fixed site and mobile C-sUAS configurations. Provides maneuver forces a quick-response, high speed, long-range kinetic interceptor capabilities against Group 3 small Unmanned Aircraft Systems (sUAS) that operate at higher altitudes with greater standoff ranges for Multi-Domain Operations (MDO). Designs and develops small, lightweight, and low-cost missile interceptor technologies for increased magazine depth (stowed kills) to enable brigade/maneuver force kinetic defeat of numerous sUAS at short range. Provides deeper magazine against sUAS threats with versatile employment options at a low cost, and maneuver forces increased freedom of movement and protection during large scale combat operations. This project supports Air and Missile Defense Modernization priority efforts. Work in this project complements Program Element (PE) 0602141A (Lethality Technology) / Project CJ7 (Future Air and Missile Defense Enabling Technology); PE 0602147A (Long Range Precision Fires Technology / Project AF8 (Affordable Extended Range Precision Technology); and PE 0603464A (Air and Missile Defense Advanced Technology) / Project SU2 (Counter s-UAS Advanced Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Aviation & Missile Center (AvMC).$$, NULL, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602180A_CL2$$, $$0602180A$$, $$CL2$$, $$AI Enhanced Intel Operations$$, 2818000, $$This Project will design and develop technologies to augment human intelligence analysts with artificial intelligence (AI) and machine learning (ML)-enabled decision support, workflow automation, and recommendation tools to modernize how the Intelligence Warfighting Function supports Multi-Domain Operations and Joint All Domain Command and Control (JADC2). This Project will mature technologies that will enable intelligence organizations to conduct synchronized, proactive intelligence operations, therefore optimizing team performance. Work in this project complements Program Element (PE) 0603040A (Artificial Intelligence and Machine Learning Advanced Technologies) / Project CL1 (AI Enhanced Intel Operations Advanced Technologies). The cited work is consistent with Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the Artificial Intelligence Integration Center (AI2C).$$, 2818000, NULL, NULL, NULL, NULL, 2453000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602183A_CW7$$, $$0602183A$$, $$CW7$$, $$High Speed and Efficient VTOL$$, 1572000, $$This Project designs and develops material component technologies and dynamic models to enable future generation capabilities for Future Vertical Lift (FVL) platforms. This Project is focused on improving range, payload, and endurance performance as well as reliability and maintainability metrics. The outcomes from the efforts within this Project will be applicable to the Family of Future Vertical Lift manned and unmanned platforms. Work in this Project is fully coordinated with Program Element (PE) 0602183A (Air Platform Applied Research) / Project CW8 (Next Generation Aviation Transmission Apl Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology focus areas and the Army Modernization Strategy. Work in this Project is performed by Army Research Laboratory (ARL).$$, 1572000, NULL, NULL, NULL, NULL, 1522000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602180A_CL7$$, $$0602180A$$, $$CL7$$, $$ATR Using Multiple Cooperative$$, 2629000, $$This Project will design and develop Artificial Intelligence (AI) and Machine Learning (ML) algorithms that leverage a team of air and ground sensors to autonomously navigate and collaborate through shared perception of the optical, thermal, and electromagnetic spectrums to find, identify, geo-locate, and track targets during reconnaissance missions. These technologies will produce prototype implementations of novel autonomy and detection algorithms to be run on teams of air and ground sensors, as well as an appropriate interface to task and observe feedback from autonomous sensors. Work in this Project complements Program Element (PE) 0603040A (Artificial Intelligence and Machine Learning Advanced Technologies) / Project CL6 (ATR Using Multiple Cooperative Sensors Adv Technologies) The cited work is consistent with Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the Artificial Intelligence Integration Center (AI2C).$$, 2629000, NULL, NULL, NULL, NULL, 7938000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602180A_CN7$$, $$0602180A$$, $$CN7$$, $$Predictive Maintenance Applied$$, 1265000, $$This Project designs and develops artificial intelligence (AI) and machine learning (ML) tools and capabilities to predict and analyze maintenance status for emerging and legacy aviation and ground platforms. Investigates techniques to extract data from maintenance databases and platform sensors and make inferences of missing data via virtual simulations. Will investigate maintenance concepts that employ AI data capture and integrate AI tools into enterprise resource planning for military aviation and ground vehicles. Will determine platforms of focus and prioritize by cost and value to Army missions. Each platform will be sequentially investigated at the appropriate component (i.e. engine health) and fleet level. Will determine appropriate technologies and capabilities needed to construct a robust Army-wide predicative maintenance platform that will accelerate the pace of innovation for this problem set. Will validate and inform requirements and technical architectures for modernization efforts of next generation aviation and ground systems both manned and unmanned. These technologies will produce concepts for a digitized maintenance environment that provides real-time decision-making support tools to maintainers and commanders by producing a warfighter optimized front end with an enterprise aggregated back end. Work in this project complements Program Element (PE) 0603040A (Artificial Intelligence and Machine Learning Advanced Technologies) / Project CN6 (Predictive Maintenance Advanced Technology). The cited work is consistent with Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the Artificial Intelligence Integration Center (AI2C).$$, 1265000, NULL, NULL, NULL, NULL, 5810000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602180A_DA5$$, $$0602180A$$, $$DA5$$, $$AI Enabled Talent Management$$, 312000, $$This Project designs, develops, and validates applied behavioral and social science research to enhance the Soldier Lifecycle (e.g., selection, assignment, training, and leader development) and human relations (e.g., unit cohesion). This Project will design and develop new personnel measures and methods that more fully assess potential and predict performance, behavior, attitudes, and resilience. These technologies also provide innovative and effective Force Integration methods to optimize individual and team performance to ensure the Army can meet mission requirements in uncertain and complex environments. This Project designs and develops new performance measures and metrics for individuals and units, designs innovative training methods, and conducts scientific assessments to inform Human Capital policy and programs. This Project will also investigate non-materiel solutions to help the Army adjust to changes in force size and structure, a variety of mission demands and contexts, challenges in human relations, and budgetary constraints. These technologies will produce tools that can measure and assess the skills of individual Soldiers and units' readiness to meet mission requirements. Work in this Project complements Program Element (PE) 0603007A (Manpower, Personnel and Training Advanced Technology) / Project 792 (Personnel Performance & Training). The cited work is consistent with Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Research in this Project supports the Army Science and Technology Ground Portfolio. Work in this Project is performed by the Artificial Intelligence Integration Center (AI2C).$$, 312000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602180A_DA6$$, $$0602180A$$, $$DA6$$, $$AI-Enabled Command and$$, 4976000, $$This Project designs and develops solutions that enable Artificial Intelligence (AI)-Enabled Command and Coordination. Additionally, project investigates and matures technologies required to enable commanders and their staff to synchronize and converge all elements of available combat power to achieve multi-domain effects. Technology maturation includes the development and testing of algorithms, models, software, hardware, and interfaces required to support the command of Army forces, coordination of Army operations, execution of the operations process, and establishing necessary Command and Control (C2) systems. Work in this Project complements Program Element (PE) 0603040A (Artificial Intelligence and Machine Learning Advanced Technologies) / Project DA7 (AI-Enabled Command and Coordination Adv Tech). The cited work is consistent with Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the Artificial Intelligence Integration Center (AI2C).$$, 4976000, NULL, NULL, NULL, NULL, 3146000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602180A_DB9$$, $$0602180A$$, $$DB9$$, $$Army AI Integration Center Apl$$, NULL, $$Congressional Interest Item funding provided for Army AI Integration Center Applied Research. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy.$$, NULL, NULL, NULL, NULL, NULL, 3000000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602180A_DE8$$, $$0602180A$$, $$DE8$$, $$AI Development Environment Applied$$, NULL, $$This effort investigates cloud-native architectures, orchestration technologies, and collaboration techniques to support current and future Artificial Intelligence (AI) model development and machine learning operations (MLOps) tasks across a globally distributed workforce. Research will increase the effectiveness and efficiency of development platforms, decrease model development costs, optimize shared resources, and reduce the time required to integrate new AI capabilities into software products. This effort will provide the AI enabled Army of the future with low cost, rapid analytic and AI/ML solutions at the edge and enable accelerated algorithm development for faster delivery to the field. Less expensive AI/ML development by leveraging shared resources. These technologies will mature software components to improve the speed of development of AI models. Work in this project complements Program Element (PE) 0603040A (Artificial Intelligence and Machine Learning Advanced Technologies) / Project DE9 (AI Development Environment Advanced Technology). The cited work is consistent with Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the Artificial Intelligence Integration Center (AI2C).$$, NULL, NULL, NULL, NULL, NULL, 1355000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602180A_DM8$$, $$0602180A$$, $$DM8$$, $$AI Enabled Contested Logistics Spt$$, 249000, $$This Project designs and develops AI-enabled contested logistics tools for warfighters using all platforms (legacy and future) at all echelons, from the maintenance area to the lowest tactical level. This project investigates data from programs of record and determines additional data streams required to build a complete picture of logistics operations in a contested environment. Contested logistics data will investigate the required maintenance data, operations information, and personnel data to increase unit readiness and reduce decision making timelines and predict unit readiness based on historical operations. These technologies will design a suite of applications uniquely tailored to the end-user that will actively expand machine learning capabilities across the force with regards to the contested logistics domain. Work in this project complements Program Element (PE) 0603040A / Artificial Intelligence and Machine Learning Advanced Technologies / CN6 / Predictive Maintenance Advanced Technology. The cited work is consistent with Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the Artificial Intelligence Integration Center (AI2C).$$, 249000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602181A_CM7$$, $$0602181A$$, $$CM7$$, $$Collaborative Convergence Applied$$, NULL, $$This Project supports research required to oppose adversary technologies in the threat based early operational environment. Focus is on those technologies that will aid in reducing the sensors to shooters timelines. This is accomplished using Artificial Intelligence (AI) algorithm decision agent design architectures, advanced methods for processing data, and improved AI performance. Additionally, this Project will research technologies and solutions necessary to enable mission command in multi-domain operations. The project will accelerate emerging research to achieve sensor to shooter dominance. Work in this Project complements Program Element (PE) 0603041A (All Domain Convergence Advanced Technology), PE 0602146A (Network C3I Technology) and PE 0603463 (Network C3I Advanced Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the Army Research Laboratory (ARL).$$, NULL, NULL, NULL, NULL, NULL, 13775000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602182A_CN4$$, $$0602182A$$, $$CN4$$, $$Network Enabling University Applied$$, 2261000, $$The Project leverages applied research from academia, in the focus areas of intelligent networks, self-sensing/self-healing networks, network security, air and ground vehicle teaming and alternatives to Global Positioning System (GPS). This Project will focus on research that supports mid-to-long term tactical Command, Control, Communications and Intelligence (C3I) capabilities (e.g. networking, cyber, electronic warfare, Positioning, Navigation and Timing (PNT), Predictive Intelligence Networks (PIN), space, persistent surveillance). This Project also focuses on bringing competitively selected Universities with research and development teams into Technical Alliances that will investigate and develop technologies originating from applied research in academia pertaining to intelligent networks, self-sensing/self- healing networks, and network security and artificial intelligence/machine (AI/ML) learning as applied to C3I, and other innovative communication as well as alternatives to GPS, leading to potential emerging technologies in areas of strategic importance to the Army in secure and intelligent communication and networking. Work in this Project complements Program Element (PE) 0603042A (C3I Advanced Technology) / Project CN3 (Network Enabling University Adv Development). The work cited is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Army Research Laboratory (ARL).$$, 2261000, NULL, NULL, NULL, NULL, 2577000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602182A_CN5$$, $$0602182A$$, $$CN5$$, $$Network Vuln/Effectiveness Assess$$, 2000, $$This Project develops analytical methodologies and capabilities to characterize hardware and software that enable Electromagnetic Warfare (EW) and Cyber capabilities to assess operations of Army Network and communication platforms and dismounts, while maintaining freedom to maneuver, communicate, and sense. This Project also develops a holistic cross-domain analysis and assessment methodology for network and communication technologies faced with advanced Cyber Electromagnetic Activity (CEMA). These investigations are critical to identifying vulnerabilities of United States systems and technologies so that network and network-enabled systems can be hardened as early as possible in development cycle. Work in this Project complements Program Element (PE) 0602146A (Network C3I Technology) / Project AN3 (Non- Traditional Waveforms Technology), PE 0602213A (C3I Applied Cyber) / Project 2CY (Information Trust Technology), PE 0602213A (C3I Applied Cyber) / Project CY6 (Autonomous Cyber Technology), PE, 0602146A (Network C3I Technology) / Project CI3 (Mobile and Survivable Command Post (MASCP) Tech), PE 0603457A (C3I Cyber Advanced Development) / Project 8CY (Information Trust Advanced Technology), PE 0603463A (Network C3I Advanced Technology) / Project AN4 (Non-Traditional Waveforms Advanced Technology), PE 0603457A (C3I Cyber Advanced Development) / Project 6CY (Autonomous Cyber Advanced Technology), PE 0603463A (Network C3I Advanced Technology) / Project AM7 (Modular RF Communications Advanced Technology), and PE 0603463A (Network C3I Advanced Technology) / Project CI7 (Mobile and Survivable Command Post (MASCP) Adv Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by Combat Capabilities Development Command (DEVCOM) Analysis Center (DAC).$$, 2000, NULL, NULL, NULL, NULL, 4378000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602182A_CT4$$, $$0602182A$$, $$CT4$$, $$C3I Applied Research (CA)$$, NULL, $$Congressional Interest Item funding provided for C3I Applied Research. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy.$$, NULL, NULL, NULL, NULL, NULL, 2000000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602182A_CW2$$, $$0602182A$$, $$CW2$$, $$Exploitation of Atmospheric Impacts$$, NULL, $$This Project enables identification and exploitation of how atmospheric phenomena impact windows of superiority for Army capabilities by developing technologies that characterize, predict, and efficiently express atmospheric impacts in future operating environments. New sensing technologies and algorithms enable heterogeneous sensor networks to extract critical environmental information optimizing performance and reducing the need for dedicated meteorological sensors. Novel physics-based models, empirical parameterizations, and machine learning applications extrapolate this environmental information both spatially and temporally. Uncertainty-aware decision support tools leverage this situational awareness to efficiently express atmospheric effects on friendly and threat weapons systems, sensors, and operations at the point of need and across multiple domains. This information can be exploited by autonomous and human decision makers for mission planning and execution; battlefield visualization; reconnaissance, surveillance, and target acquisition; route planning to maximize stealth and efficiency; long-range precision fires; and modeling of environmental impacts for combat simulations and war games. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Army Research Laboratory (ARL).$$, NULL, NULL, NULL, NULL, NULL, 1459000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602182A_CX3$$, $$0602182A$$, $$CX3$$, $$Intelligent Env Battlefield Awareness$$, 2553000, $$This Project investigates, develops, and designs technologies to allow Soldiers to maneuver faster in dynamic environments as informed by physical, geological, and biological constraints. This Project enhances visualization tools for mission planning through delivering web modules/software tools which contain crucial geochemical resources and advanced knowledge of geo-environmental infrastructure for mission planners. These technologies provide situational awareness for multi-source intelligence, particularly in anti-access/area denied (A2/AD) operational environments. Work in this Project complements Program Element (PE) 0603042A (C3I Advanced Technology (Adv Tech)) / Project CX7 (Intelligent Env Battlefield Awareness Adv Tech). The work cited is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed at the United States Army Engineer Research and Development Center Environmental Laboratory, Geospatial Research Laboratory, Information Technology Laboratory, Cold Regions Research and Engineering Laboratory, Construction Research Engineering Laboratory, and Geotechnical and Structures Laboratory.$$, 2553000, NULL, NULL, NULL, NULL, 2121000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602182A_CX4$$, $$0602182A$$, $$CX4$$, $$Persistent Geophysical Sensing-$$, 3133000, $$This Project designs and develops algorithms, hardware, and software components to provide passive, persistent, non-line-of-sight, multi-modal sensing capable of providing fused battlefield intelligence for increased situational awareness in a dynamic operational environment. These technologies provide near-real-time data collection, processing, and alerting on evolving cross-domain threats including strategic and tactical fires, air and ground platforms, as well as critical transportation infrastructure (bridges) and explosive events with applications for deep sensing. Work in this Project complements Program Element (PE) 0603042A (C3I Advanced Technology) / Project CX8 (Persistent Geophysical Sensing-Infrasound Adv Tech). The work cited is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work is performed by the United States Army Engineer Research and Development Center Geotechnical and Structures Laboratory, Coastal and Hydraulics Laboratory, Construction Engineering Research Laboratory, Cold Regions Research and Engineering Laboratory, Environmental Laboratory, and Information Technology Laboratory.$$, 3133000, NULL, NULL, NULL, NULL, 2482000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602182A_CX5$$, $$0602182A$$, $$CX5$$, $$Sensing in Contested Environments$$, NULL, $$This Project characterizes through direct or inferential methods the identification of non-weaponized biological hazards posed to Soldiers in operational environments by advancing sensor technologies and software modules that will detect and characterize hazards within confined environments. This research provides Soldiers the capability to understand biological hazards present in subterranean environments and take necessary steps to mitigate or avoid these threats. Work in this Project complements Program Element (PE) 0603042A (C3I Advanced Technology) / Project CX9 (Sensing in Contested Environments Advanced (Adv) Technologies). The work cited is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed at the United States Army Engineer Research and Development Center Environmental Laboratory.$$, NULL, NULL, NULL, NULL, NULL, 990000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602182A_CX6$$, $$0602182A$$, $$CX6$$, $$Subterranean Detection and$$, 1132000, $$This Project designs and develops an integrated suite of tunnel detection, subterranean monitoring solutions, and vulnerability assessment technologies to detect, identify, and monitor subterranean threat activities in urban environments through advanced sensing and rapid analysis capabilities. This Project also develops and investigates enhanced technologies to detect tunnels and tunneling activity in complex and varied environments. This research is critical to provide greater situational awareness of the subterranean domain and enhanced survivability for the Soldier. Work in this Project complements Program Element (PE) 0603042A (C3I Advanced Technology) / Project CZ5 (Subterranean Detection and Monitoring Adv Tech). The work cited is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the United States Army Engineer Research and Development Center Geotechnical and Structures Laboratory, Construction Engineering Research Laboratory, Coastal and Hydraulics Laboratory and Cold Regions Research and Engineering Laboratory.$$, 1132000, NULL, NULL, NULL, NULL, 1626000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602182A_CZ6$$, $$0602182A$$, $$CZ6$$, $$Assured PNT Enabling Applied$$, 1672000, $$Assured Positioning Navigation and Timing (APNT) Enabling Technologies project investigates and develops technologies for Space-enabled, Deep Sensing, Counter Surveillance and Reconnaissance (C-SR) and High Altitude applications for Army tactical ground forces. Focus areas include but are not limited to modeling and simulation for C-SR and Deep Sensing technologies, investigate the utilization of space data for Army tactical applications, and developing actionable PNT situational awareness information. Work in this Project complements Program Element (PE) 0603463A (Network C3I Advanced Technology) / Project CJ8 (Assured PNT Communications Advanced Tech). The research cited is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the United States Army Space and Missile Defense Technical Center.$$, 1672000, NULL, NULL, NULL, NULL, 3225000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602182A_CZ7$$, $$0602182A$$, $$CZ7$$, $$Convergent CEMA Technical Effects$$, NULL, $$This Project investigates, designs, and develops hardware and software to enable cyber and radio frequency (RF) technical effects along with inconspicuous Cyber Electromagnetic Activity (CEMA) and network operations of Army platforms and dismounts, while maintaining freedom to maneuver, communicate, and sense. This research will investigate and develop methods to protect blue platforms from adversarial detection and attack. This research is critical to counter near-peer adversary ability to geo-locate and put indirect fires onto blue force positions. Work in this Project complements Program Element (PE) 0602146A (Network C3I Technology) / Project AM6 (Non Modular RF Communications Technology) and Project AN3 (Non Traditional Waveforms Technology), Program Element (PE) 0602213A (C3I Applied Cyber) / Project CI6 (Network Obscuration and Deception Tech) and Project CY6 (Autonomous Cyber Technology), Program Element (PE) 0603457A (C3I Cyber Advanced Development) / Project 6CY (Autonomous Cyber Advanced Technology), and Program Element (PE) 0603463A (Network C3I Advanced Technology) / Project AM7 (Modular RF Communications Advanced Technology) and Project AN4 (Non Traditional Waveforms Advanced Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Army Research Laboratory (ARL).$$, NULL, NULL, NULL, NULL, NULL, 5272000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602750N_1396$$, $$0602750N$$, $$1396$$, $$Naval Engineering$$, 12020000, $$This project develops and matures technologies that enable superior warfighting capabilities for surface and sub-surface naval platforms, undersea weapons and countermeasures, and Marine Corps technologies to a point where they can be proposed and continued as Future Naval Capabilities in program element (PE) 0603673N, Future Naval Capabilities Advanced Technology Development.$$, 12020000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602182A_DA8$$, $$0602182A$$, $$DA8$$, $$Quantum PNT & Radio Frequency$$, 5228000, $$This Project will investigate quantum sensing approaches for positioning, navigation, timing (PNT), and field sensing. The focus is to improve the accuracy and resiliency of both Army PNT capabilities independent of Global Positioning System (GPS) to include situational awareness, for electromagnetic signals across the entire frequency spectrum. The payoff of this work will be the development of sensing capabilities and approaches that are beyond classical limits enabling a new paradigm of systems that are more secure, resilient, and precise. Work in this Project complements Program Element (PE) 0603463A (Network C3I Advanced Technology) / Project AW6 (Modular GPS Independent Sensors Advanced Tech) and Program Element (PE) 0602146A (Network C3I Technology) / Project AW5 (Modular GPS Independent Sensors Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by Army Research Laboratory (ARL).$$, 5228000, NULL, NULL, NULL, NULL, 2517000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602182A_DB4$$, $$0602182A$$, $$DB4$$, $$Enabling Long Standoff 3D (ELS3D)$$, 492000, $$This Project investigates and develops a low size, weight, and power (SWAP) laser transmitter, processing algorithms and calibration models tailored for higher resolution 3D data collections over larger areas from longer stand-off for mapping, Intelligence Surveillance and Reconnaissance (ISR) and targeting. Long standoff airborne collection of high-resolution quick turnaround 3D data is vital for mission planning, target detection and identification, fire control, autonomous navigation, kinetic targeting, and battle damage assessment. Existing light detection and ranging (LIDAR) systems are limited to short standoff and/or near-nadir collection, limiting their use against near-peer adversaries and restricting the provision of 3D data. The payoff will enable long standoff airborne collection of high-resolution quick turnaround 3D data through the development LIDAR subsystems and processing algorithms. Work in this Project complements Program Element (PE) 0603042A (C3I Advanced Technology) / Project DB5 (Enabling Long Standoff 3D Adv Tech). The work cited is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the United States Army Engineer Research and Development Center Geospatial Research Laboratory, and Geotechnical and Structures Laboratory.$$, 492000, NULL, NULL, NULL, NULL, 1983000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602182A_DE6$$, $$0602182A$$, $$DE6$$, $$Understanding Environment as a$$, NULL, $$This Project designs and advances mission planning software enabling the Soldier to identify, track, and plan for industrial or commercial chemical/environmental threats. Software modules will increase capability of mission based planning technologies providing new operational routing options for mission execution with environmental threat overlays. Work in this Project complements Program Element (PE) 0603042A (C3I Advanced Technology) / Project DE7 (Understanding the Environment as a Threat Adv Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the United States Army Engineer Research and Development Center Environmental Laboratory, Geospatial Research Laboratory, and Information Technology Laboratory.$$, NULL, NULL, NULL, NULL, NULL, 1005000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602182A_DM9$$, $$0602182A$$, $$DM9$$, $$Distributed Multi-Agent Reasoning$$, 5844000, $$This Project supports research on distributed Artificial Intelligence (AI) reasoning networks and data fusion techniques to provide an overall assessment of multi-domain tactical Windows of Opportunities to assess if windows are opening-closing-degrading-enhancing for tactical operations. This effort will research the properties of Windows of Opportunity such as scope, resilience, uncertainties, vulnerabilities, and superiority in order to enable air and ground agents to autonomously identify and assess multi-domain Windows of Opportunity for fast exploitation while being resilient to adversarial disruptions and deceptions. Work in this Project complements Program Element (PE) 0603463A (Network C3I Advanced Technology) / Project AQ8 (High Tempo Data Driven Decision Tools Adv Tech), PE 0603463A (Network C3I Advanced Technology) / Project AM7 (Modular RF Communication Advanced Technology), and PE 0603457 (C3I Cyber Advanced Development) / Project 6CY (Autonomous Cyber Advanced Technology). The cited research is consistent with Under Secretary of Defense for Research and Engineering Science and Technology priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the Army Research Laboratory (ARL).$$, 5844000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602183A_CL5$$, $$0602183A$$, $$CL5$$, $$Air Platform Enabling University$$, NULL, $$This Project focuses on applied research originating from extramural applied research in academia pertaining to navigation/routing, autonomous robotic vehicles, artificial intelligence and machine learning as applied to aerial mobility and maneuver, holistic survivability, teaming, integrated mission systems, air-launched effects, and other innovative air enabling applied research technologies that will accelerate the Army modernization in next generation aerial vehicles. This Project will perform discovery research efforts to focus more on mid to far-term Army modernization priorities while also maintaining delivery of near-term technologies fundamental to the modernization priorities. This Project conducts applied research and development leading to all the potential emerging technologies in areas of strategic importance to Army Aviation in artificial intelligence / machine learning (AI/ML), autonomous teaming systems, survivability, aeromechanics, advanced vertical take-off and landing(VTOL) design & concepts, flight dynamics, vibration & noise control, propulsion, human factor engineering and structures & materials, etc., by bringing competitively selected Universities with research and development teams into Technical Alliances. The Project will also continuously experiment with methods to identify, demonstrate and transition novel technology from entities that might not otherwise collaborate with the Department of Defense (DoD), with the end goal of accelerating the adoption of cutting-edge applied research technology for the warfighter in the Army aviation portfolio. Work in this Project complements Program Element (PE) 0602148A (Future Vertical Lift Technology), PE 0603465A (Future Vertical Lift Advanced Technology Development), PE 0603043A (Air Platform Advanced Technology) and PE 0602144A (Ground Technology). The work cited is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Army Research Laboratory (ARL).$$, NULL, NULL, NULL, NULL, NULL, 507000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602183A_CL8$$, $$0602183A$$, $$CL8$$, $$Aviation Teaming Autonomy Concepts$$, NULL, $$This Project establishes multi-level simulations, physics-based models, and artificial intelligence/machine learning (AI/ML) algorithms and methods to inform and advance capabilities for heterogeneous advanced teaming concepts to support operations in complex and peer contested environments. This Project focuses on advancing innovations to enable concepts and technology for deep sensing and effects, complex mobility and maneuver for Unmanned Aircraft Systems (UAS) (and small UAS), and adaptive behaviors to optimize formation performance. Innovative solutions, knowledge, and understanding generated from this effort informs Program Element (PE) 0602148A Future Vertical Lift Technology / Project AK9 (Adv Teaming for Tactical Aviation Operations Tech). Work in this Project is fully coordinated with PE 0602148A (Future Vertical Lift Technology) and PE 0603465A (Future Vertical Lift Advanced Technology Development) / Project AL1 (Adv Teaming for Tactical Aviation Oper Adv Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology focus areas and the Army modernization strategy. Work in this Project is performed by Army Research Laboratory (ARL).$$, NULL, NULL, NULL, NULL, NULL, 3090000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602183A_CN1$$, $$0602183A$$, $$CN1$$, $$Disruptive Countermeasure Concepts$$, 7146000, $$This Project investigates advanced technologies to reduce Future Vertical Lift (FVL) platform susceptibility and vulnerability to damage from guided and unguided threats, as well as technologies to defeat small arms, rocket, and missile threats. This Project performs research and develops innovative detect and defeat technologies against next -generation threats to the FVL. Areas of research include new laser materials and designs for in-band, low size, weight, power, and cost (SWaP-C) precision laser soft-kill countermeasures operating in the mid- and long-wave infrared, lethality effects of ultrashort pulsed lasers, and sensitive radio frequency (SeRF) detection modality for use as aircraft survivability equipment (ASE). In addition, this Project will also perform research and development on the use of remotely-deployed, passive multi-modal sensors to localize threat ground vehicles and discriminate decoys. Research in this Project is fully coordinated with Program Element (PE) 0602146A (Network C3I Technology) / Project AN7 (COE - Every Receiver is a Sensor Technology), PE 0602148A (Future Vertical Lift Technology) / Project CH3 (Holistic Team Survivability Technology), PE 0603463A (Network C3I Advanced Technology) / Project AN8 (COE - Every Receiver is a Sensor Advanced Tech), and PE 0603465A (Future Vertical Lift Advanced Technology) / Project AL1 (Adv Teaming for Tactical Aviation Oper Adv Tech). The cited research is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology focus areas and the Army modernization strategy. Work in this Project is performed by Army Research Laboratory (ARL).$$, 7146000, NULL, NULL, NULL, NULL, 8980000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602183A_CT5$$, $$0602183A$$, $$CT5$$, $$Air Platform Applied Research (CA)$$, NULL, $$Congressional Interest Item funding provided for Air Platform Applied Research The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy.$$, NULL, NULL, NULL, NULL, NULL, 6500000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602183A_CU7$$, $$0602183A$$, $$CU7$$, $$Control & Autonomy for Tactical$$, 8298000, $$This Project will develop and flight-validate new approaches and tools applicable to advanced high-speed configurations being considered for Future Vertical Lift (FVL) and transition to industry to ensure that FVL aircraft meet Army requirements. Work in this Project may also address and be applied to the needs of other Army and specific Department of Defense (DoD) aviation systems. Research in this Project is fully coordinated with Program Element (PE) 0603043A (Air Platform Advanced Technology) / Project CV1 (Control & Autonomy for Tactical Superiority Adv). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by Aviation & Missile Center (AvMC).$$, 8298000, NULL, NULL, NULL, NULL, 4621000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602183A_CU8$$, $$0602183A$$, $$CU8$$, $$Structures Tech for Enduring Efficient$$, 1494000, $$This Project will ensure critical structures technologies providing improved weight efficiency, fatigue tolerance, parasitic weight avoidance, and integration / synergy opportunities will transition to Advanced Technology Development tasks to later provide Future Vertical Lift (FVL) Project Management Offices and Original Equipment Manufacturers mission performance benefit in terms of range/payload, survivability, sustainment, and operational availability. Research in this Project may also address and be applied to the needs of other Army and specific DoD aviation systems. Research in this Project is fully coordinated with Program Element (PE) 0603043A (Air Platform Advanced Technology) / Project CV2 (Structures Platform Int Resilience & Efficiency). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by Aviation & Missile Center (AvMC).$$, 1494000, NULL, NULL, NULL, NULL, 1620000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602183A_CU9$$, $$0602183A$$, $$CU9$$, $$Systems Design Technology$$, 7180000, $$This Project will leverage large datasets and advances in multi-disciplinary optimization techniques, incorporate higher fidelity analysis, and machine learning techniques to improve predictions of emerging aviation requirements and system complexity. Research in this Project is fully coordinated with Program Element (PE) 0603043A (Air Platform Advanced Technology). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by Aviation & Missile Center (AvMC).$$, 7180000, NULL, NULL, NULL, NULL, 3020000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602183A_CW3$$, $$0602183A$$, $$CW3$$, $$Advanced Rotors Applied Technology$$, 1548000, $$This Project investigates Future Vertical Lift (FVL) and other Army and Department of Defense (DoD) aviation systems technologies that mature high speed and highly efficient rotor and hub system designs. Research in this Project is fully coordinated with PE 0603043A (Air Platform Advanced Technology) / Project CX1 (Advanced Rotors Advanced Tech). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by Aviation & Missile Center (AvMC).$$, 1548000, NULL, NULL, NULL, NULL, 2519000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602183A_CW4$$, $$0602183A$$, $$CW4$$, $$Air Vehicle Structures and Dynamics$$, 4082000, $$This Project develops modeling tools, methodologies, and experimental platforms needed to research aircraft including small uncrewed systems, traditional crewed Future Vertical Lift (FVL) platforms, and Launched Effects (LE). Research in this project focuses on low noise and aero elastically stable rotor technologies, reconfigurable and multi-mission aircraft, simulation, and advanced flight controls. This research enables high speed flight, longer range and endurance, increased maneuverability, and lower noise signatures from handheld to full-scale crewed platforms. Research in this project is also applicable to the family of FVL manned and unmanned platforms. Research in this Project is fully coordinated with Program Element (PE) 0603465A (Future Vertical Lift Advanced Technology Development). The cited research is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology focus areas and the Army modernization strategy. Research in this Project is performed by Army Research Laboratory (ARL).$$, 4082000, NULL, NULL, NULL, NULL, 2931000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602183A_CW5$$, $$0602183A$$, $$CW5$$, $$Experimental and Computational$$, 10301000, $$This Project investigates new high fidelity computational methods to simulate aerodynamic effects and test methods of emerging rotorcraft lift technologies that could be incorporated into Future Vertical Lift (FVL) designs and other Army and Department of Defense (DoD) aviation systems. Research in this Project is fully coordinated with PE 0603043A (Air Platform Advanced Technology). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by Aviation & Missile Center (AvMC).$$, 10301000, NULL, NULL, NULL, NULL, 6586000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602750N_1398$$, $$0602750N$$, $$1398$$, $$Ocean Atmosphere and Space$$, 0, $$This activity invests in the research related to the ability to conduct military operations in expeditionary and maritime environments is support of naval expeditionary forces. This can include antisubmarine warfare in the littorals and maritime choke points, mine warfare and explosive hazard defeat applications, and remote sensing. Research may span system studies, system architecture development, and component and/or breadboard validation in laboratory environments.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602183A_DK1$$, $$0602183A$$, $$DK1$$, $$Air Vehicle Integrated & Alternative$$, 8400000, $$This project enhances Army aviation mission capability and addresses operational energy and environmental challenges. Includes the development, maturation, and system design of technologies including advanced engines, hybrid and electric systems, power and control allocation, propulsive power delivery, electric actuation, structures, and other technologies that enhance performance, efficiency or are critical to implementation. Work in this Project is fully coordinated with Program Element (PE) 0603043A (Air Platform Advanced Technology) / Project DK2 (Air Vehicle Improvements & Advanced Tech (AVIATe)). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Aviation & Missile Center (AvMC).$$, 8400000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602184A_CK9$$, $$0602184A$$, $$CK9$$, $$Advancing Concepts and Technology$$, 3027000, $$This Project works across the Army Futures Command Combat Capabilities Development Command (DEVCOM), with the Futures & Concepts Center (FCC), and the Directorate of Intelligence and Security to explore current and future emerging and disruptive applied scientific research to translate, integrate, and ingrain applied research outcomes with the Army. Warfighting Concepts to describe how the Army will fight in the mid and far-term future while the Future Operational Environment contextualizes projected applied research outcomes in the deep future. Applied research outcomes describe the projected future operational effects of science in the context of Army concepts and probable operational capabilities to mitigate risk for future Army capabilities and enable informed decision making across the Army Modernization Enterprise. This Project ensures Army Concepts are grounded by recent and anticipated advances in applied scientific research, Army applied research is capability use-inspired to deliver the right future capability identified in the Army Concepts, and learning opportunities are created to advance Army Concepts and operationalize science for transformational overmatch. This Project also performs long-range technology forecasts and trend analysis, informed by the threat and the predicted future state of technology, of Army-relevant applied research topics to enable informed decision making for the near-, mid-, and far-terms. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Research in this Project is performed by the Army Research Laboratory (ARL).$$, 3027000, NULL, NULL, NULL, NULL, 2575000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602184A_CN2$$, $$0602184A$$, $$CN2$$, $$Intelligent Weapons Concepts and$$, 4452000, $$This Project focuses on far-term, overarching lethality technologies by investigating techniques for Soldiers to guide the in-field adaptation of intelligent small arms technologies to respond to changing mission requirements, novel environments, and adversarial actions. Research areas include cognition-centric displays to ensure Soldiers maintain appropriate situational awareness in augmented reality (AR) environments, opportunistic shooter sensing, and interactive machine learning techniques to ensure small arms technologies can adapt to changing situations quickly and with reduced data requirements as compared to non-human guided machine learning and Artificial Intelligence (AI). The results of this Project will enhance operational performance of individuals and teams of Soldiers in the future operational environment through novel weapon and human-agent interaction technologies. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Army Research Laboratory (ARL).$$, 4452000, NULL, NULL, NULL, NULL, 4409000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602184A_CN9$$, $$0602184A$$, $$CN9$$, $$Soldier Enabling University Applied$$, NULL, $$This Project investigates technologies from academia that will improve capabilities and systems to advance Soldier and Squad lethality-overmatch and Soldier performance. This Project funds collaborative, enduring applied extramural university-based research and brings together competitively selected universities with Army research teams into Technical Alliances. This Project will determine discovery solutions and inform capabilities development for mid- to far-term Army modernization priorities while also maintaining delivery of near-term technologies fundamental to the modernization priorities. The technical scope of this Project includes the investigation and design of overarching Soldier-centric technologies including, human systems integration, robotics, synthetic environments for training, advanced materials, power management, energy, Warfighter endurance, and computational technologies. This Project conducts applied research for potential emerging technologies in areas of strategic importance to the Army in Soldier capabilities related to increased protection, performance, agility, situational awareness, and lethality. This Project will also continuously strive to engage and collaborate with entities that might not otherwise collaborate with the Department of Defense (DoD) to identify and determine novel Soldier-centric technologies for accelerating the adoption of emerging technologies for the Warfighter in the Army Soldier portfolio. Work in this Project complements Program Element (PE) 0603044A (Soldier Advanced Technology) / Project CN8 (Soldier Enabling University Advanced Development) The work cited is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the Army Research Laboratory (ARL).$$, NULL, NULL, NULL, NULL, NULL, 18000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602184A_CO1$$, $$0602184A$$, $$CO1$$, $$Soldier Power And Energy Concepts$$, NULL, $$This Project conducts applied research to improve safe, compact, efficient, rugged, lightweight, and energy dense power sources for increased capabilities for the mounted and dismounted force. This Project also investigates materials, processes, and component level energy storage and conversion technologies that enable tactical overmatch and reduce the physical and cognitive burden on Soldiers. Research will focus on safe electrochemical energy storage, high specific energy storage and conversion, novel materials and processing for energy and power, and new cell designs that address the power needs of future capabilities including advanced sensors, communications systems, and electronic Warfighting capabilities. Enabling and emerging technologies are supported in this Project to address future Soldier power needs necessary for increased lethality, increased mobility, and longer mission durations at reduced physical burden to the Soldier in the future operating environment. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Research in this Project is performed by the Army Research Laboratory (ARL).$$, NULL, NULL, NULL, NULL, NULL, 4350000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603041A_DA4$$, $$0603041A$$, $$DA4$$, $$All Domain Convergence Engineering$$, NULL, $$This Project enables critical engineering and architecture support to all Army modernization priorities as the Army pursues convergence. Full development of mature system and system of systems level architectures ensure objective and data-driven analyses can be performed on new Army technologies and modernization efforts. Development of digital engineering products for new Army technologies currently under development enable digital analyses and assessments to be performed rapidly and repeatedly prior to full scale field tests like Project Convergence. The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy.$$, NULL, NULL, NULL, NULL, NULL, 8000000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602184A_CV9$$, $$0602184A$$, $$CV9$$, $$Technical-SAVVY Soldier Applied$$, 3744000, $$This Project conducts applied research a technologically fluent force. This research will develop models of technological fluency (TF) (TF Modeling), methods and measures to assess and develop the technological fluency of Soldiers across a career (TF Personnel Assessments), and technologies to maximize technological fluency resilience and performance in Soldiers and units (Maximizing TF). TF is defined as the ability of Soldiers and units to use and rapidly adapt new and intelligent technologies without formal training on these technologies, and it will be a decisive factor in a future operating environment in which Soldiers and squads are teamed with increasingly sophisticated and evolving technologies. Soldiers and leaders in specialty areas (e.g., Cyber and Emerging Tech) and General Purpose Forces will require increased technological aptitudes and skills to adapt emerging technologies to evolving mission sets and avoid being overmatched by Artificial Intelligence (AI)- enabled "smart" technologies. This Project supports key Army needs and will coordinate with and/or leverage findings of several Program Elements (PEs) to include PE 0602785A (Manpower, Personnel and Training Technology), 0602143A (Soldier Lethality Technology), and 0602145A (Next Generation Combat Vehicle Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Army Research Laboratory (ARL) and the Army Research Institute (ARI) for Behavioral and Social Sciences.$$, 3744000, NULL, NULL, NULL, NULL, 2772000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602184A_CW9$$, $$0602184A$$, $$CW9$$, $$Syn Bio for Reactive-Resp Matls-$$, 6023000, $$This Project designs and investigates materials through the application of biotechnology and synthetic biology advances to develop material capabilities that respond and/or can adapt to a wide range of external stimuli and biological processes. Research into innovative materials that are capable of sensing, responding, and adapting to a broad spectrum of environmental variables will be conducted. This Project will explore new biology-based methods for controlled synthesis and assembly to create multi-functional materials and advanced composites as well as develop materials that are able to self-monitor, self-heal, and self-sustain. This Project also focuses on developing models, materials characterization techniques, non-destructive testing methods, and advanced fabrication and processing methodologies as well as the identification of unique material properties. The cited research is consistent with the Undersecretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Research in this Project is performed by the Army Research Laboratory (ARL).$$, 6023000, NULL, NULL, NULL, NULL, 3498000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602184A_DN1$$, $$0602184A$$, $$DN1$$, $$Directed Energy Biological Effects$$, 659000, $$This Project is a multi-disciplinary effort to investigate, determine characterize, mitigate, and validate emerging anti-personnel energy field threats. This Project designs and develops sensors, sources, and instrumentation to understand the molecular to organismal level of energy field impacts that produce neurocognitive and motor deficits. This effort will also investigate vulnerabilities and exploitable biophysical mechanisms which can be used to design, construct, and characterize tunable sources for laboratory use and future transition. Work in this Project complements Program Element (PE) 0601102A (Defense Research Sciences) / Project AA5 (Biotechnology and Systems Biology). The cited research is consistent with Under Secretary of Defense for Research and Engineering Science and Technology priority focus areas and the Army modernization strategy. Work in this Project is performed by Army Research Laboratory (ARL).$$, 659000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602184A_DN2$$, $$0602184A$$, $$DN2$$, $$Joint Service Small Arms Enabling$$, 7692000, $$This Project investigates individual and crew-served armament component design (weapon, munition, and fire control) and technologies that enable increased lethality and survivability of the dismounted Warfighter across all the Joint Services. This Project investigates and designs engineering solutions to reduce the blast overpressure field for the M3 Carl Gustaf. Work in this Project complements Program Element (PE) 0603044A (Soldier Advanced Technology) / Project DN4 (Joint Service Small Arms Adv Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is completed by the Armaments Center (AC).$$, 7692000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602184A_DO1$$, $$0602184A$$, $$DO1$$, $$Modernized Composites &$$, 2000000, $$This Project investigates manufacturing sciences and advanced automation through additive, subtractive, and digital manufacturing sciences of novel composite materials for use in both existing and future DoD-wide systems. This Project develops novel composite materials to deliver advanced structural materials with improved durability, functionality and performance, to support broad applications across the future operational environment and DoD. Focus will be on properties required for understanding operation in contested environments. The Project will use unique contract and collaborative approaches to accelerate transitions into and from university programs. Work in this Project complements Program Element (PE) 0603044A (Soldier Advanced Technology) / Project DO2 (Modernized Composites & Manufacturing Adv Dev). The cited work is consistent with the Under Secretary of Defense for Research and Engineering Advanced Materials Critical Technology Area and the Army Modernization Strategy. Work in this Project is performed by DEVCOM Soldier Center.$$, 2000000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602201F_622401$$, $$0602201F$$, $$622401$$, $$Structures$$, 0, $$This project develops advanced structures concepts to exploit new materials and fabrication processes and investigates new concepts and design techniques. New structural concepts include low cost design and fabrication techniques, incorporating subsystem hardware items and adaptive mechanisms into the aerospace structures and/or skin of the platform. In FY 2025, the entirety of PE 0602201F, Aerospace Vehicle Technologies, Project 622401 Structures, was transferred to PE 0602203F, Aerospace Propulsion, Project 622401 Structures for increased integration between airframe, flight control, propulsion, electrical, power and thermal management.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602201F_622403$$, $$0602201F$$, $$622403$$, $$Flight Controls and Pilot-Vehicle$$, 0, $$This project develops technologies that enable maximum affordable capability from manned, remotely-piloted, and autonomous aerospace vehicles. Advanced control, automation, and autonomy technologies are developed for maximum vehicle performance throughout the flight envelope and simulated in full-scale, surrogate, and virtual environments. Resulting technologies contribute significantly towards the development of reliable autonomous or remotely piloted air vehicles, hypersonic aircraft, and extended-life legacy aircraft. In FY 2025, the entirety of PE 0602201F, Aerospace Vehicle Technologies, Project 622403 Flight Controls and Pilot-Vehicle Interface, was transferred to PE 0602203F, Aerospace Propulsion, Project 622403 Flight Controls and Pilot-Vehicle Interface for increased integration between airframe, flight control, propulsion, electrical, power and thermal management.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602201F_622405$$, $$0602201F$$, $$622405$$, $$High Speed Systems Technology$$, 0, $$This effort investigates, analyzes, and develops high speed/hypersonic aerospace vehicle technologies. Advanced high temperature structures concepts are explored and developed to exploit new materials, fabrication processes, and design techniques. Advanced aerodynamic vehicle configurations are developed and analyzed through simulations, experiments, and multi-disciplinary analyses. Advanced subsystem, integration and analysis technologies are developed and simulated for hypersonic vehicles. These technologies will enable future high speed weapons and platforms; intelligence, surveillance, and reconnaissance systems; and space access vehicles. In FY 2025, the entirety of PE 0602201F, Aerospace Vehicle Technologies, Project 622405 High Speed Systems Technology, was transferred to PE 0602203F, Aerospace Propulsion, Project 622405 High Speed Systems Technology for increased integration between airframe, flight control, propulsion, electrical, power and thermal management.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602201F_625172$$, $$0602201F$$, $$625172$$, $$NUCLEAR SYSTEM$$, 0, $$This project provides sustaining science and technology to preserve nuclear deterrence for future generations, develops complimentary projects to inform future systems, establishing inter-agency partnerships for Modeling & Simulation and test platforms, and coordinates with existing programs for next generation strategic systems development and test platforms.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602202F_620200$$, $$0602202F$$, $$620200$$, $$Enterprise Transformational Appld$$, 0, $$This program element develops multidisciplinary applied research efforts to accelerate the technology pipeline of transformational capabilities by reducing risk and maturing the technology so it can transition in support of larger advanced technology development capability investments. These activities are selected to enable solutions to the DAFs highest priorities to include Operational Imperatives and Critical Technology Areas. The Explore effort engages traditional & nontraditional industry, government laboratories and academia through 12-24 month feasibility studies and demonstrations. The Seedlings for Disruptive Capabilities Program (SDCP) facilitates AFRL cross-disciplinary applied research to provide leap-ahead, high risk technology development. Modeling, simulation, and analyses activities will continue to explore transformational research analytic technologies to enable validated positions and provide a solid foundation with emphasis to predict future outcomes and technology needs, as well as looking for more seedlings to feed the transformational capability pipeline. Continue to advance future workforce development programs and broadening partnerships to deepen and expand the scientific and technology enterprise. Applied research efforts span a broad spectrum of activities, and established processes allow agility and flexibility to meet higher demand signals.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602202F_621123$$, $$0602202F$$, $$621123$$, $$Learning and Operational$$, 21292000, $$This project enables warfighter decision superiority by advancing the science and technology of human multi-sensory perception, learning, information processing, and action. Research is conducted in two focus areas: learning and operational training, and digital models of cognition. Digital Models of Cognition focuses on holistic models that work at understanding and prediction of mission effectiveness to maximize training effectiveness as well as to make human cognitive models available for other modeling, simulation, and analysis. Learning and operational training improves learning and understanding by linking evolving technology with understanding of how warfighters assimilate information and abilities. This project looks to establish a persistent, global experimentation, test, and training ecosystem that supports personalized, proficiency-based readiness for warfighters in joint all-domain operations, including work that supports Air Education and Training Command's undergraduate pilot training programs, Air Combat Command's fighter community, Air Force (AF) combat casualty care and enroute medical operations, human-machine teams executing Command, Control, Communications and Battle Management tasks, the development of Multi-Capable Airmen for maintenance and operations support, and the growing needs of the Unit States Space Force for space domain and cislunar operations. Using digital modeling, advancements will take into account human perception, cognition, and action in system development, wargaming, and operational planning, to support the development of human digital twins that can be integrated into AF Modeling and Simulation capabilities for training, and prediction of cognitive load and fatigue for maximum endurance operations in support of Air Mobility Command and Air Combat Command operational mission requirements.$$, 21292000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602202F_625328$$, $$0602202F$$, $$625328$$, $$Biosciences Performance$$, 33093000, $$This project conducts bioengineering and biotechnology research to optimize, safe-guard, and restore the performance of the multi-domain Airman in all environments. Research is focused in the areas of 1) Applied Cognitive Neurosciences: technologies to sustain, augment, and recover operator performance; 2) Biotechnology for Performance: research in systems biology, synthetic biology, and risk assessment; 3) Performance Sensing and Assessment: technologies to sense and forecast operator state based on physiological, molecular, and environmental signatures related to mission performance; and 4) Performance Impact of Flight: elucidate how air environments affect processes of life and the ability to maintain physiological equilibrium and develop countermeasures and technologies to sustain, enhance, and restore operator performance. In FY 2025 this Project 625328 changed its name from "Human Dynamics Evaluation" to "Biosciences Performance".$$, 33093000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602202F_625329$$, $$0602202F$$, $$625329$$, $$Warfighter Interfaces and Teaming$$, 46105000, $$This project conducts research to achieve warfighter decision superiority across air, space, and cyber domains through research on advanced human-machine interfaces, joint-cognitive systems decision-making, and distributed and collaborative teaming and communication enhancements. Research provides advanced warfighter Command and Control interface technology, team collaboration tools, intelligent decision aids, and agile communications management. Research is conducted in two focus areas: human-machine interactions, and distributed teaming and communication. Human-machine interactions focuses on achieving decision superiority by optimizing human engagement with increasingly complex, highly automated, and Artificial Intelligence-enabled combat and combat support systems. Distributed teaming and communication focuses on research technology and methods to enhance the formation, assessment, and performance of distributed teams of warfighters as well as human-machine teams executing combat. Human Machine Teaming technology is critical to optimally integrating Airmen and Guardians with the increasingly technological & networked battlespace to achieve and maintain resilient decision superiority and defeat adversaries. In FY 2025 this Project 625329 changed name from "Sensory Evaluation and Decision Science to "Warfighter Interfaces and Teaming".$$, 46105000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602202F_627757$$, $$0602202F$$, $$627757$$, $$Bioeffects$$, 33438000, $$This project conducts applied research on the effects of human exposure to electromagnetic energy (direct current to radio frequency to optical, scalable directed energy weapons, and other novel weapons). The project conducts laboratory experiments to provide fundamental knowledge of mechanisms of interaction of directed energy with molecules, cells, tissues, organs, and whole organisms in support of military directed energy systems. This research addresses mechanisms of interactions through fundamental physical principles, biological responses, and physiological outcomes. Research focus areas include novel directed energy bioeffects and mechanisms and directed energy modeling, simulation, and analysis. This research enhances combat survivability and systems effectiveness through technologies that enable deployed forces to counter optical threats and exploit optical systems for offensive applications. In addition, basic biological investigations into the mechanisms associated with high peak power and high average power radio frequency exposure allow for the exploitation of directed energy systems for offensive capabilities while protecting the warfighter from adversarial use of radio frequency technologies. Novel directed energy bioeffects mechanisms research examines the physical, physiological, behavioral, and neural interactions of electromagnetic energy with tissues to understand dose-response effects as well as reveal the means to cause or prevent a specific effect. This work assures valid assessments of real-world concerns and manages the risks associated with technological surprise. The project includes laboratory experiments to understand the mechanistic and behavioral effects of novel weapon incidents to Airmen and Guardians and to understand the effects of protection strategies on Airman and Guardian performance. Directed energy modeling, simulation, and analysis research focuses on new software components that represent and optimize concepts of novel system employment from the Airman and Guardian standpoint. These components are matured for future transition and application for engagement-to-mission level simulations in which directed energy weapons are employed.$$, 33438000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602203F_622401$$, $$0602203F$$, $$622401$$, $$Structures$$, 74989000, $$This project performs technology development to advance aerodynamic and structural systems of the aerospace vehicle to address Department of the Air Force capability needs and anticipated future capability needs. Requisite technology area competencies in design, analysis, synthesis, and validation, work in synergy with design integration of other aerospace vehicle systems to define and provide technology gap solutions. FY 2026 change - 622401 "Structures” project is retitled "Aerodynamics and Structures Technology”. In FY 2025, the entirety of PE 0602201F, Aerospace Vehicle Technologies, Project 622401 Structures and Project 622404 Aeromechanics, were transferred to PE 0602203F, Aerospace Propulsion, Project 622401 Structures (FY2026 Structures project retitled Aerodynamics and Structures Technology). This is an administrative realignment to provide increased enhanced project transparency and not a new start.$$, 74989000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602203F_622403$$, $$0602203F$$, $$622403$$, $$Flight Controls and Pilot-Vehicle$$, 76072000, $$This project is dedicated to advancing technologies for manned, remotely piloted, and autonomous aerospace vehicles, with a focus on achieving maximum performance and affordability. The development of advanced control, automation, and autonomy technologies is a key aspect, aiming to deliver safe and efficient vehicle operation and mission execution through the use of digital engineering, flight experimentation, and evaluation. These efforts contribute significantly to the development of reliable autonomous collaborative platforms, high-speed aircraft, and operational aircraft. Furthermore, the project encompasses the design of integrated electrical and thermal management components, controls, and systems for military aerospace applications, ensuring that the power and thermal needs of future aerospace capabilities can be met. By developing controls and system integration technologies, the project also ensures the interoperability of aircraft, power, thermal, engine, and other systems and subsystems, ultimately supporting the development of electrical power and thermal management components, controls, and systems suitable for various aircraft platforms, including autonomous collaborative platforms and future aircraft, while addressing reliability, maintainability, affordability, and supportability. FY 2026 Changes: • Due to administrative transfer of work and funding ($38.640 million) from 623145, Aerospace Power Technology project to 622403, Aerospace Power & Flight Control Technology project for system level thrusts versus component level thrusts to enable acceleration of integrated system capabilities and capture realistic representation of work. • 622403 "Flight Controls and Pilot-Vehicle Interface” project is retitled "Aerospace Power & Flight Control Technology”. FY 2025, the entirety of PE 0602201F, Aerospace Vehicle Technologies, Project 622403 Flight Controls and Pilot-Vehicle Interface, was transferred to PE 0602203F, Aerospace Propulsion, Project 622403 Flight Controls and Pilot-Vehicle Interface. This is an administrative realignment to provide increased enhanced project transparency and not a new start$$, 76072000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602203F_622405$$, $$0602203F$$, $$622405$$, $$High Speed Systems Technology$$, 55234000, $$This project investigates, analyzes, and develops applied technologies that enable future multi-Mach, responsive high-speed/hypersonic weapons and platforms (vehicles) via modeling, simulation and analysis (MS&A), and ground and flight tests. The extreme conditions high-speed/hypersonic weapons or platforms are subjected to manifest as complex multi-disciplinary technical challenges, namely: durability, broad operability from Mach 0 to Mach 5+ (multi-Mach operability), vehicle-level integrated power and thermal management, and integration of mission systems. The development of technical solutions to these multi-disciplinary challenges at the subsystem level, and the subsequent integration of them at the system level, is critical to reduce the risk and time required to transition technologies into operational systems. Digital material management is utilized to develop and deliver an integrated digital environment (IDE) to assess technology, evaluate its impacts, and make capability-focused investment decisions. FY 2026 change - due to administrative transfer of work and funding ($18.430 million) from 623012 Advanced Propulsion Technology project to 622405 High Speed Systems Technology project for system level thrusts versus component level to enable acceleration of integrated system capabilities and capture realistic representation of work. In FY 2025, the entirety of PE 0602201F, Aerospace Vehicle Technologies, Project 622405 High Speed Systems Technology, was transferred to PE 0602203F, Aerospace Propulsion, Project 622405 High Speed Systems Technology. This is an administrative realignment to provide increased enhanced project transparency and not a new start.$$, 55234000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602203F_623012$$, $$0602203F$$, $$623012$$, $$Advanced Propulsion Technology$$, 0, $$This project develops combined/advanced cycle air breathing high-speed and hypersonic propulsion technologies to provide revolutionary propulsion options for the Air Force. These new engine technologies will enable future high-speed/hypersonic weapons and aircraft concepts. The primary focus is on hydrocarbon-fueled engines capable of operating over a broad range of flight Mach numbers. Efforts include modeling, simulations, and proof of concept demonstrations of critical components; advanced component development; and ground-based demonstrations. FY 2026 change - due to administrative transfer of work and funding (18.430 million) from 623012 Advanced Propulsion Technology project to 622405 High Speed Systems Technology project for system level thrusts versus component level to enable acceleration of integrated system capabilities and capture realistic representation of work.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602203F_623048$$, $$0602203F$$, $$623048$$, $$Combustion and Mechanical$$, 0, $$This project evaluates lubricants, for advanced turbine engines, and combined cycle engines with emphasis on low cost and high-speed applications. In FY 2025, Lubricant Technologies effort in this project will transfer to Program 0602203F, Aerospace Propulsion, Project 623066, Turbine Engine Technology, to align resources to Aerospace Systems Core Technical Competencies.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602203F_623066$$, $$0602203F$$, $$623066$$, $$Turbine Engine Technology$$, 71804000, $$This project develops air breathing engine technology to address military specific needs for manned systems, autonomous vehicles, and munition applications. Technology development includes Mission Optimized Air Breathing Propulsion Technology Development and Revolutionary Propulsion Technology Development by utilizing military utility and physics-based analysis. FY 2026 change - due to administrative transfer of work and funding to system level thrusts versus component level to enable acceleration of integrated system capabilities and capture realistic representation of work. In FY 2025, Lubricant Technologies efforts transferred from PE 0602203F, Aerospace Propulsion, Project 623048, Combustion and Mechanical Systems, to 623066 Turbine Engine Technology project, to align resources to Aerospace Systems priorities.$$, 71804000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602203F_623145$$, $$0602203F$$, $$623145$$, $$Aerospace Power Technology$$, 0, $$This project develops integrated electrical and thermal management components, controls and systems for military aerospace applications. Power component technologies are developed to increase reliability, maintainability, commonality, affordability, and supportability of aircraft and flight line equipment. Research is conducted in energy storage and hybrid power system technologies to enable special purpose applications. Electrical power and thermal management technologies enable future military power and thermal needs. Controls and system integration technologies ensure the interoperability of aircraft, power, thermal, engine and other systems and subsystems. This project supports development of electrical power and thermal management components, controls and systems suitable for applications to legacy and future aircraft platforms including strike and mobility concepts. Lightweight power systems suitable for other aerospace applications are also developed. FY 2026 change - due to administrative transfer of work and funding ($38.640 million) from 623145 Aerospace Power Technology Project to 622403, Aerospace Power & Flight Control Technology project for system level thrusts versus component level to enable acceleration of integrated system capabilities and capture realistic representation of work.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602203F_625171$$, $$0602203F$$, $$625171$$, $$Missile Rocket Propulsion$$, 34426000, $$This project develops rocket propulsion technologies for the design, development, and fabrication of strategic systems (including solid boost/missile motors, post boost control, aging and surveillance efforts), and tactical missiles. Analytical and experimental areas of emphasis are propellants, propellant management, combustion, rocket material applications, model-based system engineering, digital design of manufacture and test, test stand live-fire testing, and technology for sustainment of strategic systems. This project develops the next generation of physics-based Modeling, Simulation, and Analysis (MS&A) tools for rapid and agile missile propulsion design, analysis, and production, as well as the digital engineering concepts to manage the entire process of design, test, and validation of solid rocket motors through live-fire tests. All efforts in this project contribute to the sustainment of the rocket propulsion industry, providing rocket propulsion technology for the entire DoD. All efforts are reviewed by a DoD level steering committee yearly for relevance to DoD missions.$$, 34426000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602203F_625330$$, $$0602203F$$, $$625330$$, $$Aerospace Fuel Technology$$, 8534000, $$This project evaluates fuels for advanced turbine engines, scramjets, detonation, and combined cycle engines. This project also considers fuel related concepts that can increase turbine engine operational reliability, durability, mission flexibility, energy efficiency, and performance while reducing weight, fuel consumption, and cost of ownership. Applications include autonomous collaborative platforms, munitions, and high-speed systems (to include hypersonics). Research areas of emphasis include evaluations of fuel properties and characteristics of traditional, specialty, and alternative fuels developed from unconventional sources.$$, 8534000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602204F_622002$$, $$0602204F$$, $$622002$$, $$Electronic Component Technology$$, 53672000, $$This project focuses on electronics and optoelectronics technologies that generate, control, receive, and process electromagnetic spectrum for aerospace sensor and electronic warfare applications. The enabling technologies developed under this project will be used for intelligence, surveillance, reconnaissance, electromagnetic warfare, battlespace access, and precision engagement capabilities. The technologies developed include exploratory electronic and optoelectronic devices, components, microsystems, and subsystems. This project also assesses designs, develops, fabricates, and demonstrates the associated technologies for integrating combinations of these component technologies. The project develops and demonstrates significantly smaller size, lower weight, lower cost, lower power dissipation, higher reliability, trustworthiness, and improved performance components. The device and subsystem technology developments under this project are military unique; they are based on Department of the Air Force and other Department of Defense weapon systems requirements in the areas of radar, communications, electromagnetic warfare, positioning, navigation, timing, and smart weapons.$$, 53672000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602204F_622003$$, $$0602204F$$, $$622003$$, $$EO Sensors & Countermeasures$$, 0, $$This project develops advanced electro-optical aerospace sensor technologies for a variety of offensive and defensive applications. The sensor technologies under development cover the ultraviolet through the infrared portion of the spectrum. Technical efforts include improvements in system integration, digital processing, analysis tools, and sensor architectures. One of the project's goals is to improve electro-optical and related technologies for the detection, tracking, and identification of non- cooperative and difficult targets, such as those obscured by camouflage or operating at significant range. This project also develops the passive and active sensors and algorithms needed to enable precision targeting in challenging operating environments as well as advanced electro-optical threat warning and countermeasures technologies. These technologies are critical to future aerospace surveillance and targeting.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602204F_622005$$, $$0602204F$$, $$622005$$, $$Cyber Technology$$, 0, $$This project focuses on technologies for enabling agile and resilient Air Force mission systems. This project improves our understanding of cyber vulnerabilities of mission systems by investigating the fundamental nature of those vulnerabilities including: how they come about, how they can be discovered, how they can be quantified and categorized, how they can be exploited, and how they can be removed or mitigated to secure the system. This project develops adaptable and resilient hardware/software for real-time avionics cyber-attack pattern recognition and develops a protection system with the capability for autonomous learning, adaptation, and self-protection. This project investigates open architecture concepts and technologies to deliver capability flexibility to Department of the Air Force mission systems. These technologies are matured via integrated capability demonstrations.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602204F_624920$$, $$0602204F$$, $$624920$$, $$Electronic Warfare Technology$$, 38103000, $$This project develops and assesses affordable, reliable, all weather radio frequency countermeasure concepts for aerospace applications covering the range of radio frequency sensors including communications, navigation, intelligence, surveillance and reconnaissance (ISR), and radar, both active and passive, across the air, land, sea, space and cyber domains. It develops and evaluates technology for electronic warfare, integrated radar and electronic warfare systems, and electro-optical/ infrared seeker defeat. This project develops the radio frequency warning and countermeasure technology for advanced electronic warfare and information operations applications. The project also explores technologies to maintain a military advantage in positioning, navigation and timing integrity, accuracy, and resiliency as well as on aircraft mission assurance - the protection of airborne platforms, manned and unmanned, in contested environments. The ultimate goal of the project is to ensure unrestricted access to the airspace and the electromagnetic spectrum in contested and congested environments.$$, 38103000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602204F_626095$$, $$0602204F$$, $$626095$$, $$Sensor Fusion Technology$$, 40933000, $$This project develops foundational and applied technologies required for closed-loop autonomous sensing employing multiple information domains, diverse sensor phenomena, and multiple platform types to provide intelligence, surveillance, and reconnaissance, target recognition, situational awareness and battlespace visualization, fire control, and battle damage assessment capabilities against a wide variety of air and ground based targets engaged in multitudes of behaviors in a broad range of operational environments. This project conducts exploratory and applied investigations to determine technology feasibility and estimate operational capability constraints associated with missions in future contested and highly contested operating environments, using cooperative and non-cooperative sensing sources. This project develops techniques to automate multi-sensor exploitation and information processing which leverage data fusion, adaptive signal processing, sensor and platform orchestration, and by leveraging artificial intelligence / machine learning research communities. This project develops concepts and algorithms for efficient processing at the edge, parallel processing, distributed processing, and high-performance computing in sensor data processing and synthetic data generation.$$, 40933000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602204F_627622$$, $$0602204F$$, $$627622$$, $$RF Sensors and Countermeasures$$, 66412000, $$This project develops and assesses affordable, reliable all weather radio frequency sensing and countermeasure concepts for aerospace applications covering the range of radio frequency sensors including communications, navigation, intelligence, surveillance and reconnaissance, and radar, both active and passive, across multiple domains. This project also develops and evaluates technology for intelligence, surveillance and reconnaissance sensors, fire control radars, electromagnetic warfare, integrated radar and electromagnetic warfare systems, and offensive information operations systems. It emphasizes the detection and tracking of surface and airborne targets with radio frequency signatures that are difficult to detect due to reduced radar cross sections, concealment and camouflage measures, severe clutter, or heavy jamming. Techniques exploited include the use of multiple radio frequency phenomenologies, multi-dimensional adaptive processing, advanced waveforms and knowledge-aided processing techniques. It also develops advanced electro-optical aerospace sensor technologies for a variety of offensive and defensive applications. The sensor technologies under development cover the ultraviolet through the infrared portion of the spectrum. Technical efforts include improvements in system integration, digital processing, analysis tools, and sensor architectures. One of the project's goals is to improve electro-optical and related technologies for the detection, tracking, and identification of noncooperative and difficult targets, such as those obscured by camouflage or operating at significant range. This project also develops the passive and active sensors and algorithms needed to enable precision targeting in challenging operating environments as well as advanced electro-optical threat warning and countermeasures technologies. The project also explores technologies to maintain a military advantage in positioning, navigation and timing integrity, accuracy, and resiliency. This project also develops concepts to counter threats to our aerospace systems. It develops and evaluates technology for electromagnetic warfare, integrated radar and electromagnetic warfare systems, and electro-optical/infrared seeker defeat.$$, 66412000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602212F_3600$$, $$0602212F$$, $$3600$$, $$Research, Development, Test & Evaluation, Air Force / BA 2: Applied$$, NULL, $$Implementation of 10 U.S.C. Section 2363, amendment to PL 110-417, 10 U.S.C. Section 2358 and 10 U.S.C. 2805(d)(1)(B), to fund: innovative basic and applied research conducted at the defense laboratory and supports military missions; development programs supporting the transition of technologies developed by the defense laboratory into operational use; workforce development activities improving the capacity of the defense laboratory to recruit and retain personnel with necessary scientific and engineering expertise that support military missions; and the repair or minor military construction of the laboratory infrastructure and equipment. The Air Force is dependent on technological advances in response to emerging threats and to maintain a competitive advantage. Air Force has a comprehensive and deliberative planning process to identify and fund research that is expected to have the greatest benefit to the Air Force and the warfighter. 10 U.S.C. Section 2363 provides the Commander of the Air Force Research Laboratory (AFRL), in consultation with the Air Force Science and Technology (S&T) Executive, a degree of flexibility to rapidly exploit scientific breakthroughs or respond to emerging threats, to include developing a skilled workforce and necessary infrastructure. This flexibility increases the rate of innovation and accelerates the development and fielding of needed military capabilities to address current and future problems. The Air Force has established PE 0602212F, where the 10 U.S.C. Section 2363 funds are internally reprogrammed to this program element in the year of execution after receipt of the appropriation. This allows increased transparency to Congress on 10 U.S.C. Section 2363 funding and additional execution flexibility for 10 U.S.C. Section 2363 activities to cross all technology areas. This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied        PE 0602212F / Defense Laboratories R&D Projects (10 U.S.C, Sec 2358) Research$$, NULL, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602212F_622030$$, $$0602212F$$, $$622030$$, $$Defense Lab R&D$$, 0, $$Implementation of 10 U.S.C. Section 2363, amendment to PL 110-417, 10 U.S.C. Section 2358 and 10 U.S.C. 2805(d)(1)(B), to fund: innovative basic and applied research conducted at the defense laboratory and supports military missions; development programs supporting the transition of technologies developed by the defense laboratory into operational use; workforce development activities improving the capacity of the defense laboratory to recruit and retain personnel with necessary scientific and engineering expertise that support military missions; and the repair or minor military construction of the laboratory infrastructure and equipment. The Air Force is dependent on technological advances in response to emerging threats and to maintain a competitive advantage. Air Force has a comprehensive and deliberative planning process to identify and fund research that is expected to have the greatest benefit to the Air Force and the warfighter. 10 U.S.C. Section 2363 provides the Commander of the Air Force Research Laboratory (AFRL), in consultation with the Air Force Science and Technology (S&T) Executive, a degree of flexibility to rapidly exploit scientific breakthroughs or respond to emerging threats, to include developing a skilled workforce and necessary infrastructure. This flexibility increases the rate of innovation and accelerates the development and fielding of needed military capabilities to address current and future problems. The Air Force has established PE 0602212F, where the 10 U.S.C. Section 2363 funds are internally reprogrammed to this program element in the year of execution after receipt of the appropriation. This allows increased transparency to Congress on 10 U.S.C. Section 2363 funding and additional execution flexibility for 10 U.S.C. Section 2363 activities to cross all technology areas. This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied        PE 0602212F / Defense Laboratories R&D Projects (10 U.S.C, Sec 2358) Research$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602213A_2CY$$, $$0602213A$$, $$2CY$$, $$Information Trust Technology$$, 4716000, $$This Project develops defensive cyber technology to ensure that data traversing the network remains verified and has not been modified through unauthorized means. Project enhances system access without affecting personnel authentication processes, enhances awareness of user actions and intent within the network, and maintains information provenance from originator to consumer. It will also integrate zero trust principles where access to resources is granted based on continuous risk assessments. Work in this Project complements Program Element (PE) 0603457A (C3I Cyber Advanced Development) / Project 8CY (Information Trust Advanced Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center.$$, 4716000, NULL, NULL, NULL, NULL, 6026000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603342D8Z_483$$, $$0603342D8Z$$, $$483$$, $$Innovation with academia$$, 0, $$DIU increases the Department's access to commercial technologies and talent, with the ultimate goal of fielding technology at a pace that effectively deters our adversaries and helps ensure victory if we are forced to fight. Consistent with the Administration's 2026 interim National Defense Strategy and the National Defense Science and Technology Strategy, this new era of competition requires technological superiority to ensure the United States’ ability to project power, maintain international norms and rule of law, provide credible deterrence, and prevail in conflict.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602213A_3CY$$, $$0602213A$$, $$3CY$$, $$Network Access and Effects$$, NULL, $$This Project investigates computer assisted/automated methodologies to expedite technology development for Offensive Cyber Operations (OCO)/Radio Frequency (RF) Enabled operations. This includes identification of non-traditional access and effect vectors across diverse and evolving adversary targets of interest to enable the commander freedom of maneuver and non-kinetic firing options. This Project will expedite OCO/RF enabled operational developers, planners and operators time to readiness when navigating the complexity of near-peer engagements. This Project investigates the application of machine learning technologies to assist in capability development and mission execution processes with respect to Offensive Cyber Operations (OCO)/Radio Frequency (RF) Enabled capabilities. Work in this Project complements Program Element (PE) 0603457A (C3I Cyber Advanced Development) / Project 9CY (Network Access and Effects Advanced Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by Command, Control, Computer, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center.$$, NULL, NULL, NULL, NULL, NULL, 8538000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602213A_CY6$$, $$0602213A$$, $$CY6$$, $$Autonomous Cyber Technology$$, NULL, $$This Project investigates and applies robust cyber security techniques and applications to advanced communications and networking devices, software, algorithms and protocols utilized within wireless tactical networks to protect against nation state level cyber effects and maintain Warfighter confidence in network information, resources, identities and mission partners by hardening the blue force attack surface. Work in this Project complements Program Element (PE) 0603457A (C3I Cyber Advanced Development) / Project 6CY (Autonomous Cyber Advanced Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Army Research Laboratory (ARL) and Command, Control, Computer, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center.$$, NULL, NULL, NULL, NULL, NULL, 6100000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602230D8Z_230$$, $$0602230D8Z$$, $$230$$, $$Defense Technology Innovation$$, 46261000, $$The Defense Technology Innovation (Beyond 5G) effort builds upon the technology foundation that underpins fifth-generation / future generation (5G/FutureG) cellular network systems as a basis to create the next generation of wireless cellular network and security technologies for military applications. Working in concert with other U.S. Government science and technology agencies, Beyond 5G is successfully conducting applied research to adopt, adapt, advance, and integrate technologies to create asymmetric advantages. Our approach is to replace cost-prohibitive, single-function stovepipes that limit the force from fully executing the Combined Joint All- Domain Command and Control (CJADC2) concepts of tomorrow.$$, 46261000, NULL, NULL, NULL, NULL, 35528000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602234D8Z_534$$, $$0602234D8Z$$, $$534$$, $$Lincoln Laboratory$$, 10603000, $$This project supports the long-term strategic technology capabilities within the DoD in established and emerging mission areas. Each year, MIT LL in coordination with the Office of the Under Secretary of Defense for Research and Engineering (OUSD(R&E)) reviews and selects projects focusing on addressing technology gaps in critical problems facing national security. Factors considered in the selection include ability to accelerate development, have impact, and provide innovation in the DoD critical technology areas. Selection of projects derives from an annual, highly selective proposal process in which demand for funding exceeds supply by nearly a factor of three. Successful projects often result in advanced capabilities that lead to further sponsored-program development. The Lincoln Laboratory (LL) research areas that comprise this overall research and development portfolio are described below. Core-technology areas: • Advanced Devices emphasizes the development of devices and subsystems utilizing microelectronic, photonic, biological, and chemical technologies to enable new approaches to DoD systems. Efforts include technologies for high power Radio Frequency (RF) devices; multi-function, highly integrated lasers; fast and sensitive imagers; and mechanical microsystems for autonomous systems. • Optical Systems and Technology focuses on developing optical technologies for visible, infrared, and wide band spectroscopic sensing as well as communications systems. The efforts include high energy lasers; scalable focal plane imaging technology; photonic integrated circuits; optical system prototypes; and associated phenomenology measurements. • Information, Computation and Exploitation Sciences develops novel architectures, tools, and techniques for the processing, fusion, interpretation, computation, and exploitation of multi-sensor, multi-intelligence data. Efforts include innovative hardware and software technologies for graph processors and cloud computing; artificial intelligence (AI) and graph algorithms for analytics, including deep learning algorithms; multi-intelligence analytics, including open-source data processing techniques; and human-machine interfacing and automation technologies to enhance warfighter effectiveness and ability to work with advanced computing systems.$$, 10603000, NULL, NULL, NULL, NULL, 88978000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602234D8Z_815$$, $$0602234D8Z$$, $$815$$, $$Cyber Security, Science and$$, 876000, $$The Cyber Security, Science and Engineering research project focuses on the development of technologies and new techniques for the protection of systems against cyber- attack and exploitation. Efforts include research into technologies for cyber situational awareness, command and control; technology to improve resilience of systems to cyber-attack; and technologies for system exploitation research. The Cyber Security, Science and Engineering research project, 815, supports innovative research that addresses critical national security problems in cyber. The project funds innovations that directly lead to the development of new system concepts, technologies, and algorithms in support of DoD missions. Funding supports high-risk, high-payoff research, which provides unique and specialized capabilities for the current and emerging needs of the Department.$$, 876000, NULL, NULL, NULL, NULL, 7125000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602235N_0000$$, $$0602235N$$, $$0000$$, $$Common Picture Applied Research$$, 55246000, $$Activities and efforts in this program examine concepts and technologies that enable the transformation to network centric warfare. Network centric capabilities rely on information to connect assets and provide timely and accurate understanding of the environment. The mission area requirements for rapid, accurate decision- making; dynamic, efficient, mission-focused communications and networks; and pervasive and persistent sensing drive network centric Science and Technology S&T investments. The activities described in this Program Element (PE) address future Navy and Marine Corps capabilities needed to maintain maritime superiority and ensure national security. They are based on input from Naval Research Enterprise (NRE) stakeholders (including the Naval enterprises, the combatant commands, the Office of the Chief of Naval Operations, and Headquarters Marine Corps) and are designed to exploit breakthroughs in science and technology in order to deliver maximum warfighting benefit to our sailors and marines. These efforts are aligned with shared priorities throughout the whole of RDT&E in order to quickly advance new capabilities from discovery to deployment across the warfighting domains.$$, 55246000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602788F_625315$$, $$0602788F$$, $$625315$$, $$C4I Dominance Technology$$, 115649000, $$This project executes mission-driven applied research to advance the critical technologies supporting Command, Control, Communications, Computers, and Intelligence (C4I), a core enabler of operational effectiveness across the Department of the Air Force (DAF). Activities under this project accelerate the development of next- generation capabilities to ensure time-dominant decision-making, enable synchronized multi-domain operations, and provide reliable, cyber-secure communications in contested environments. Additionally, these efforts advance high-speed computing and data analytics to support real-time intelligence processing and information fusion, which are essential to operational readiness and the successful implementation of Combined Joint All-Domain Command and Control (CJADC2).$$, 115649000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602236N_0000$$, $$0602236N$$, $$0000$$, $$Warfighter Sustainment Applied Res$$, 74264000, $$U.S. Sailors and Marines are key to mission success. This Program element (PE) supports research that advances artificial intelligence (AI) enabled decision aides, autonomy, human-machine teaming, augmented performance, command and control and protective equipment to ensure they outthink, outperform and outfight adversaries in a complex, maritime environment. This PE also supports developments in biocentric and advanced materials technologies to provide new options to enhance performance of warfighters and their platforms. This Program conducts applied research to address Warfighter protection and performance concerns, including efforts that focus on advanced Naval materials, biocentric technologies, decision support, intelligent and autonomous systems, human performance optimization, training and education technologies, social and cultural science, and biomedical technologies. This PE also supports the Office of Naval Research (ONR) Global mission to serve as the preeminent external facilitator for the Naval Research Enterprise. This is accomplished by establishing quality, relevant connections between the international research and development community, Naval fleet/forces, DOD, other US Government agencies and international partners.$$, 74264000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602236N_9999$$, $$0602236N$$, $$9999$$, $$Congressional Adds$$, 0, $$Congressional add projects not included in other efforts.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602251D8Z_227$$, $$0602251D8Z$$, $$227$$, $$Applied Research for the$$, 53983000, $$The Applied Research for the Advancement of Science and Technology (S&T) Priorities program was established to implement Department-wide technology development portfolios and foster tri-Service research areas of common interest within cross-cutting S&T efforts. The program has three investment areas:(1) three- year applied research projects selected by the S&T Executive Committee (EXCOM); (2) two-year technology projects nominated by the S&T Communities of Interest (CoIs) to address technology gaps or opportunities; and (3) technology assessment and study support to the CoIs. The execution of the ARAP Program by the Office of the Secretary of Defense and the support it provides to the CoIs inspires and ensures joint strategic S&T oversight and multi-Service, multi-agency collaboration and coordination.The Applied Research for the Advancement of Science and Technology (S&T) Priorities (ARAP) Program directly supports the National Defense Strategy and aligns with DoD critical science and technology priorities, strengthening broadly applicable technical capabilities and fostering emerging technologies within the Department of Defense laboratories to enhance warfighter advantages. By funding foundational enabling technologies, the ARAP Program facilitates the design, development, advancement and transition of early-stage technologies and novel ideas, translating promising research into solutions for critical military needs that directly improve situational awareness through advanced sensors, enhanced lethality with precision weaponry, and more effective communication and coordination. Continuous infusion of new technology ensures our forces maintain a decisive edge and have the flexibility needed to adapt to diverse and rapidly changing operational environments. Furthermore, the ARAP Program fosters increased collaboration and partnership among science and engineering teams of subject matter experts across the DoD enterprise, providing funding to recruit top national talent from universities, and bolsters the in-house scientific and technical research capabilities of DoD laboratories, ultimately accelerating the delivery of advanced capabilities to our warfighters. The ARAP Program funds the activities of the DoD Reliance 21 collaborative framework. This framework’s core strength lies in its strategic planning and the DoD Science & Technology (S&T) Executive Committee’s (EXCOM) robust leadership, comprised of senior-level executives from across the Department. The S&T EXCOM ensures coordinated resource allocation by convening regularly to align resources and proactively address emerging challenges. For example, the S&T EXCOM recently awarded funding to accelerate the development of long-range strike capabilities that pushes the boundaries of several technological domains in response to evolving battlefield threats, and strategically prioritized investments in Quantum technology to enhance decision-making speed. This leadership is powered by a robust ecosystem of 16 S&T Communities of Interest (COIs). These COIs, spanning cross-cutting topics like advanced materials, cyber warfare, biomedical and biotech, energy and power, warfighter and space platforms, and other critical technology areas, maintain a global perspective on technological advancements. They strategically guide investment through detailed technology roadmaps that inform and identify candidate ARAP projects, ensuring resources are directed towards the most promising and impactful areas. The Applied Research for the Advancement of Science and Technology (S&T) Priorities program strategically implements and executes Department-wide technology development portfolios, ensuring the timely availability of emerging capabilities that will transition and enhance the effectiveness of both near- and far-term weapon systems. Collaboration across multiple technical and technology areas is essential for increasingly complex modern weapons systems development. For example, a next-generation fighter jet might require advancements in materials science, artificial intelligence, sensor technology, propulsion, and cyber security. Progress in one$$, 53983000, NULL, NULL, NULL, NULL, 60877000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602271N_0000$$, $$0602271N$$, $$0000$$, $$Electromagnetic Systems Applied$$, 79929000, $$Freedom of maneuver on a global scale for U.S. naval forces depends upon assured access to the electromagnetic spectrum and the ability to deny adversary exploitation. Electromagnetic technologies must fluidly deliver communication, surveillance electronic warfare and digital integration to understand, shape and defend the battlespace. This project addresses technology opportunities associated with Naval platforms for new capabilities in Electro-Optic and Infrared (EO/IR) Sensors, Surveillance, Electronic Warfare, Navigation, Solid State Electronics, Vacuum Electronics Power Amplifiers, and Nanoelectronics. The project supports development of technologies to enable capabilities in Missile Defense, Directed Energy, Platform Protection, Time Critical Strike, and Information Distribution. This project directly supports the Department of Defense Joint Warfighter Plan and the Defense Technology Area Plans. Activities and efforts within this program have attributes that focus on enhancing the affordability of warfighting systems. The program also provides for technology efforts to maintain proactive connectivity and collaboration between Department Of the Navy (DON) Science and Technology (S&T) and Joint, Navy, and Marine Corps commands worldwide. Due to the number of efforts in this Program Element (PE), the programs described herein are representative of the work included in this PE.$$, 79929000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602271N_9999$$, $$0602271N$$, $$9999$$, $$Congressional Adds$$, 0, $$Congressional Interest Items not included in other Projects.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602275A_A63$$, $$0602275A$$, $$A63$$, $$Sensor to Shooter (STS) Applied$$, 7022000, $$This project designs and develops advanced algorithms and architectures for armaments fire control systems for C-sUAS engagements. These capabilities will provide C-sUAS mobility, increased stowed kills vs sUAS threats, and increased protection for maneuver units. This project develops unit common C-sUAS capabilities for maneuver formations. Work in this project complements PE 0603275A (Electronic Warfare Advanced Technology) / A72 (Sensor to Shooter (STS) Advanced Technology). The cited work is consistent with Secretary of Defense Memorandum, Army Transformation and Acquisition reform. Work in this project supports Air and Missile Defense, Soldier Lethality, and Long-Range Precision Fires Army Modernization Priorities. Work in this project is performed by the Armaments Center, Command, Control, Communication, Computers, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Center, and United States Army Space and Missile Defense Technical Center.$$, 7022000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602275A_A64$$, $$0602275A$$, $$A64$$, $$Autonomous Navigation Technology$$, 2832000, $$This project seeks to develop innovative and adaptive Navigation Warfare (NAVWAR) electromagnetic attack (EA) capabilities to deny adversaries the ability to utilize Global Navigation Satellite System (GNSS) receivers. This project will leverage software defined EA hardware to agilely deny an increasingly evolving threat's ability to geolocate and navigate, greatly reducing the mission effectiveness of adversary autonomous and manned platforms. These cooperative NAVWAR EA systems and platforms can defeat advanced Global Navigation Satellite System (GNSS) and platform-based capabilities. Work in this project complements Program Element (PE) 0603275A (Electronic Warfare Advanced Technology) / Project A74 (Navigation Warfare (NAVWAR) Advanced Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this project is performed by the United States Army Space and Missile Defense Technical Center and Command, Control, Computer, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center.$$, 2832000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602275A_A65$$, $$0602275A$$, $$A65$$, $$Modular GPS Independent Sensors$$, 6807000, $$This project investigates and develops Assured and Resilient Position, Navigation and Timing (PNT) technologies that mitigate the impacts of adversary Electromagnetic Warfare attacks. This Project performs research and development of Electromagnetic Protection (EP) to Global Positioning System (GPS)-independent sensors using open architectures, sensor fusion, plug-and-play sensor modules that can be tailored for any platform based on mission needs and requirements. This Project will develop modular PNT sensor and fusion capabilities to enable the Army to continuously transform in contact, adding new PNT modalities, signals and EP, maintaining the critical ability of Soldiers and platforms to navigate in a rapidly evolving threat space. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this project is performed by the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center.$$, 6807000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602275A_A66$$, $$0602275A$$, $$A66$$, $$CEMA Sensing Technology$$, 2097000, $$This project develops algorithms, techniques, and methodologies to passively and actively sense the electromagnetic spectrum (EMS) associated with all types of adversarial cyber and electromagnetic activities (CEMA) to gain situational awareness, detect threats, and enable effective response. This project investigates resource management approaches to enable simultaneous RF operations within resource constrained environments. It extends the Army's deep sensing capability by improving simultaneous functionality, leveraging all potential sensing assets within the area of operations and supporting real time feedback of mission effectiveness. Work in this project complements Program Element (PE) 0603275A (Electronic Warfare Advanced Technology) / Project A76 (CEMA Sensing Advanced Technology) The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this project is performed by the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center.$$, 2097000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602275A_A67$$, $$0602275A$$, $$A67$$, $$Electronic Warfare Technology$$, 8633000, $$This project investigates and develops cutting-edge technologies for Electronic Warfare (EW) applications, non-kinetic survivability/lethality, and emerging concepts of employment in the increasingly contested and congested electromagnetic environment. The goal is to enhance the survivability/lethality of Army platforms through Electronic Attack (EA), Electronic Support (ES), and Electronic Protection (EP) with high operational realism for current and future operational environments. Work in this project complements Program Element (PE) 0603275A (Electronic Warfare Advanced Technology) / Project A77 (EW for Maneuver Operations (EMO) Adv Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this project is performed by the Army Research Laboratory (ARL) and Data and Analysis Center (DAC).$$, 8633000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602275A_A68$$, $$0602275A$$, $$A68$$, $$EW Techniques Technology$$, 5192000, $$This project develops countermeasures against adversarial counter-fire systems that obscure and create distractive blue force locations. This project will research and develop distributed, coordinated electromagnetic warfare (EW) capabilities designed to extend effective range, reduce blue transmitter susceptibility to localization, and introduce errors in adversary intelligence, surveillance and reconnaissance (ISR) systems to facilitate maneuver within multi-domain operations (MDO). Work in this project complements Program Element (PE) 0603275A (Electronic Warfare Advanced Technology) / Project A77 (EW for Maneuver Operations (EMO) Adv Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this project is performed by the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center.$$, 5192000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602275A_A69$$, $$0602275A$$, $$A69$$, $$EW Tech for Protection Against$$, 7109000, $$This project will investigate and design advanced survivability technologies to develop a team-based solution that delivers advanced sensing and electronic warfare (EW) effects across a family of aircraft to optimally penetrate and survive in the anti-access/area denial (A2AD) environment. This project will take an integrated team- based system of systems survivability approach through a purpose-driven mix of improved survivability situational awareness, signature management, vulnerability reduction, enhanced platform survivability against directed energy munitions, route and maneuver optimization, expendables, advanced sensors, and electro-optics (EO) & radio frequency (RF) jamming for existing and future air platforms. This Project will also provide advanced teaming algorithms for survivability. This Project develops and evaluates multi layered survivability concepts and supporting technologies for increased survivability of Future Vertical Lift (FVL) Family of Systems (FoS) in an advanced and evolving integrated air defense systems environment. The cited research is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology focus areas and the Army modernization strategy. Work in this project is performed by Aviation & Missile Center (AvMC) and Command, Control, Communication, Computers, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Center.$$, 7109000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602275A_A70$$, $$0602275A$$, $$A70$$, $$Sensor Electronic Support Tech$$, 1266000, $$This project investigates and develops critical radar capability enhancements to defeat advanced Air and Missile threats and protect Army maneuver forces and critical assets. Radar enhancements are required for advanced Electronic Protection (EP) techniques against advanced jammers, electronic Combat Identification (CID), and resource optimization across the threat spectrum while retaining 360 degree coverage capability. This research complements Program Element (PE) 0601275A (Electronic Warfare Basic Research) / Project A61 (Sensing and Electromagnetics) and PE 0603275A (Electronic Warfare Advanced Technology) / Project A78 (Radar Survivability through Dis Sensing Adv Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this project is performed by the Aviation & Missile Center (AvMC).$$, 1266000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602275A_A71$$, $$0602275A$$, $$A71$$, $$Network Vuln/Effectiveness Assess$$, 4457000, $$This project develops analytical methodologies and tools to characterize hardware and software that enable Electromagnetic Warfare (EW) and Cyber capabilities to assess operations of Army Network and communication platforms and dismounts, while maintaining freedom to maneuver, communicate, and sense. This Project also develops a holistic cross-domain analysis and assessment methodology for network and communication technologies faced with advanced Cyber Electromagnetic Activity (CEMA). These investigations are critical to identifying vulnerabilities of United States systems and technologies so that network and network- enabled systems can be hardened as early as possible in development cycle. Work in this project complements Program Element (PE) 0602276A (Electronic Warfare Cyber Applied Research) / Project A79 (Autonomous Cyber Technology) and PE 0603276A (Electronic Warfare Cyber Advanced Technology) / Project A80 (Autonomous Cyber Advanced Technology), The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this project is performed by Combat Capabilities Development Command (DEVCOM) Analysis Center (DAC).$$, 4457000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602276A_A79$$, $$0602276A$$, $$A79$$, $$Autonomous Cyber Technology$$, 17102000, $$This project investigates and applies robust cyber security techniques and applications to advanced communications and networking devices, software, algorithms and protocols utilized within wireless tactical networks to protect against nation state level Cyber and Electromagnetic Activities (CEMA) and maintain Warfighter confidence in network information, resources, identities and mission partners by hardening the blue force attack surface. This project investigates RF-enabled cyber approaches to Disrupt, Deny, Degrade, Destroy and Manipulate (D4M) adversary C2ISR systems and capabilities. Furthermore, in full alignment with ARCYBER "reprogrammability" efforts, this project will also focus on establishing new methodologies for the development of EW / OCO effects that are more readily implemented, upgradable and portable across different Army platforms. Work in this project complements Program Element (PE) 0603276A (Electronic Warfare Cyber Advanced Technology) / Project A80 (Autonomous Cyber Advanced Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this project is performed by the Army Research Laboratory (ARL) and Command, Control, Computer, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center.$$, 17102000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602298F_622520$$, $$0602298F$$, $$622520$$, $$Science and Technology$$, 10813000, $$The Air Force Research Laboratory (AFRL) is a global technical enterprise, boasting some of the best and brightest leaders in the world. It provides revolutionary, relevant, and responsive science and technology (S&T) to the Warfighter. AFRL's mission is to lead the discovery, development, and integration of affordable warfighting technologies for the global air, space, and cyberspace force.$$, 10813000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602303E_IT-02$$, $$0602303E$$, $$IT-02$$, $$HIGH PRODUCTIVITY,$$, 0, $$The efforts described in this Program Element (PE) address the Applied Research associated with the Information and Communications Technology Program that is directed toward the application of advanced, innovative computing systems and communications technologies. This PE also supports innovation and robust transition planning in the technology cycle by working with entrepreneurs to increase the likelihood that DARPA funded technologies take root in the U.S. and provide new capabilities for national defense. The High Productivity, High-Performance Responsive Architectures project focuses on developing the computer hardware and associated software technologies required for future computationally- and data-intensive national security applications. Powerful new approaches are needed to manage the rapid growth in available sensor data, to leverage advances in machine learning, artificial intelligence, and quantum computing, and to maintain the security of DoD information systems. The project therefore aims not only to create new computing platforms to include quantum technology, but also to efficiently extract information out of large and chaotic data sets with embedded and low-size, weight, and power systems. Advances in these areas will allow for DoD electronic systems to collaboratively manage scarce resources, such as the electromagnetic spectrum, and to adapt to new requirements and situations. Further, the resulting technologies, by being accessible to a wide range of application developers, will support new, sustainable computing systems for a broad spectrum of scientific and engineering applications. The Cyber Security project is developing the computing, networking, and cyber security technologies required to protect DoD, U.S. Government, and U.S. civilian information, information infrastructure, cyber-physical and embedded systems, critical infrastructure, and other computation-intensive mission-critical systems. Information technologies enable important existing and new military capabilities, and drive the productivity gains essential to U.S. industry. Meanwhile, cyber threats grow in sophistication and number, and put sensitive data, classified computer programs, mission-critical information systems, and U.S. economic competitiveness at risk. The technologies developed in this project will enhance the resilience of information systems to current and emerging cyber threats, enable broad situational awareness of the cyber domain, and provide the basis for accurate, calibrated, and safe cyber response. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                                          Date: June 2025 Appropriation/Budget Activity                                                        R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:                 PE 0602303E / INFORMATION & COMMUNICATIONS TECHNOLOGY Applied Research The Artificial Intelligence and Human-Machine Symbiosis project develops technologies to enable machines to function not only as tools that facilitate human action, but also as trustworthy partners to human operators. Of particular interest are systems that can understand human language, extract information, and reliably categorize content contained in diverse media; answer questions, reach conclusions, and propose explanations; and learn, reason, and apply knowledge gained through experience to respond intelligently to new and unforeseen events. Enabling computing systems with such human-like intelligence is now of critical importance because the tempo of military operations in emerging domains exceeds that at which unaided humans can orient, understand, and act. The technologies developed in this project will enable warfighters to make better decisions in complex, time-critical, battlefield environments; intelligence analysts to make sense of massive, incomplete, and contradictory information; software developers and certifiers to design, implement, evaluate, and accredit cyber-physical systems and other complex software-reliant systems with greater efficiency and confidence; and unmanned systems and semi-autonomous agents to perform critical missions in contested physical and virtual environments safely and reliably. Beginning in FY 2026, efforts in this PE will be funded in PE 0602025E, Making, Maintaining, Supply Chain and Logistics.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602336F_623360$$, $$0602336F$$, $$623360$$, $$Technology Exploration$$, 4969000, $$The Air Force Research Laboratory (AFRL) is focused on high-impact, multi-domain science and technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Forces to win the future fight. The AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. The Nuclear Delivery Systems Technology Exploration program establishes the foundational computational tools necessary to conduct nuclear forensics, perform potential strategic surveillance, and predict future nuclear re-entry system environmental effects and responses. Program activities aid investigations and analyses of national strategic and nuclear deterrence operations; foreign low yield or evasive underground nuclear tests; and multi-physics algorithms to accurately simulate untested environmental effects and responses in support of nuclear reentry systems development activities in Program Element 0603273F (Science & Technology for Nuclear Reentry Systems). This program provides applied Science & Technology to reestablish nuclear deterrence operations by reestablishing specialized expertise and modernizing the infrastructure and technologies necessary to address, and respond to, current and emerging multi-peer-contested nuclear environments. This program further supports the requisite DAF Science & Engineering mission enabling civilian workforce with the necessary technical competencies to develop, manage, and deliver Science & Technology capabilities. The use of program funds in this Program Element is aligned with the civilian pay expenses budgeted for in the following program elements: 1206601SF, 0601102F, 0602020F, 0602102F, 0602202F, 0602203F, 0602204F, 0602298F, 0602602F, 0602605F, 0602788F, and 0603680F. In FY 2026, $1.615 million is budgeted in this program for 8 direct Full-Time Equivalent civilians. The Air Force Research Laboratory references statutory language under 10 USC 4091 ("Authorities for certain positions at Science & Technology reinvention laboratories”) to manage the workforce strength, structure, positions, and compensation. This program element may include necessary expenses to support operation and maintenance activities to manage, execute, and deliver science and technology capabilities. This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 2: Applied      PE 0602336F / Nuclear Delivery Systems Tech Exploration Research$$, 4969000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602345A_A41$$, $$0602345A$$, $$A41$$, $$Adv Teaming for Tactical Aviation$$, 11996000, $$This Project investigates and develops subsystem and component level technologies that enable advanced teaming behaviors for mixed platform formations in combined arms operations. Primary component technologies to develop are in the areas of resilient autonomy algorithms, team-based communications and situational awareness management, decision aiding for weapons systems engagement, autonomous terrain and collision avoidance, and human autonomy interface design. The cited work is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology focus areas and the Army modernization strategy. Work in this Project is performed by the Aviation & Missile Center (AvMC), and the Command, Control, Communication, Computers, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Center.$$, 11996000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602345A_A42$$, $$0602345A$$, $$A42$$, $$Air Launched Effects Technology$$, 3677000, $$This Project utilizes improved analytic modeling to investigate the effects that potential unmanned system capabilities could have on air vehicle design considerations and operational concepts. This Project improves government capability to design and assess novel Unmanned Aircraft System (UAS) concepts. This Project also develops and investigates the ability to launch a UAS from Army manned or unmanned aircraft at tactical altitudes and from manned or unmanned ground platforms and to control the same after launch from nearby air and ground assets, as well as development of the associated payloads (recon, battle damage assessment, targeting, comms, decoy). This Project will assess the enabled capabilities and determine their relevance to current Army Aviation engagement and survivability portfolios. Work in this Project is fully coordinated with Program Element (PE) 0603345A (Unmanned Aerial Systems Launched Effects Advanced Technology Development) / Project A45 (Air Launched Effects Advanced Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology focus areas and the Army modernization strategy. Work in this Project is performed by Aviation and Missile Center (AvMC).$$, 3677000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602345A_A43$$, $$0602345A$$, $$A43$$, $$Aviation Teaming Autonomy Concepts$$, 2735000, $$This Project establishes agile research in multi-level simulations, physics-based models, and artificial intelligence/machine learning (AI/ML) algorithms and methods to inform and advance capabilities for heterogeneous advanced teaming concepts to support operations in complex and peer contested environments. This Project focuses on advancing innovations to enable concepts and technology for deep sensing and effects, complex mobility and maneuver for Unmanned Aircraft Systems (UAS) (and small UAS), and adaptive behaviors to optimize formation performance. This Project focuses on agile and adaptable reconfiguration of teams of multiple autonomous assets for strategic maneuvering, targeting, striking, and long-range precision navigation efforts in adversarial environments. Work in this Project is fully coordinated with PE 0602345A (Unmanned Aerial Systems Launched Effects Applied Research) / Project A41 (Adv Teaming for Tactical Aviation Operations Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology focus areas and the Army modernization strategy. Work in this Project is performed by Army Research Laboratory (ARL).$$, 2735000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602386A_CP6$$, $$0602386A$$, $$CP6$$, $$Foundational Biotechnology Design$$, 7203000, $$This Project works collaboratively with Joint Service partners to investigate and determine novel biotechnology methods and processes to establish a domestic resilient supply chain for defense needs. Applied research designs and conducts experiments on bio-derived, bio-functionalized, and bio-manufactured materials and biosynthetic precursors. Efforts under this Project investigate and validate models for design of defense applications. Areas of focus may include reclamation or sequestration of rare Earth/critical elements in the defense supply chain and drop-in replacements for currently employed military materials. Work in this Project compliments Program Element (PE) 0603386A (Biotechnology for Materials - Advanced Research) / CP7 (Biotechnology Demonstration and Evaluation). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy.$$, 7203000, NULL, NULL, NULL, NULL, 16060000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602386A_SM1$$, $$0602386A$$, $$SM1$$, $$Scale-Up Microbial Products for$$, 1006000, $$This project develops biomanufacturing capabilities of mission-critical materials for military use. This project enables the Army to achieve Multi-Domain Operations by securing the supply chain and bridging the gap between laboratory-scale material production and large-scale manufacturing for mission-critical materials. This cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the Chemical Biological Center (CBC). Project SM1/Scale-Up Microbial Products for Biomanufacturing is a new start in FY 2025 within PE 0602386A / Biotechnology for Materials - Applied Research.$$, 1006000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602435N_0000$$, $$0602435N$$, $$0000$$, $$Ocean Wrfghtg Env Applied Res$$, 81270000, $$This project provides the foundational environmental knowledge for undersea, surface and air-based warfighting technologies and effective operations anywhere on the globe, as well as the operation of unattended sensors and unmanned air, surface and underwater vehicles. This project includes the Navy contribution to broader federal research such as the National Oceanographic Partnership Program (NOPP), efforts aimed at understanding and predicting the impacts of underwater sound on Marine Mammals, and efforts to improve extended range environmental prediction through coupled Earth system models. Major efforts of this project are devoted to gaining real-time knowledge of the Battlespace Environment (BSE), understanding the variability between processes in the world's ocean, atmosphere and coastal regions, and providing the on-scene commander with the capability to exploit the environment to tactical, operational, and strategic advantage. Research results are transitioned to the Fleet Numerical Meteorology and Oceanography Center and to the Naval Oceanographic Office where they are used to provide timely information about the natural environment for all fleet operations. Efforts include ocean and atmospheric analysis and prediction for real-time description of the operational environment from near space to the sub-seafloor, shallow water acoustics, sensors for undersea surveillance and weapon systems, and influences of the natural environment on Mine Countermeasures, Naval Mining, Anti-Submarine Warfare (ASW), Information Warfare, and Naval Special Warfare systems.$$, 81270000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602435N_9999$$, $$0602435N$$, $$9999$$, $$Congressional Adds$$, 0, $$Congressional Interest Items not included in other Projects.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602602F_622068$$, $$0602602F$$, $$622068$$, $$Advanced Guidance Technology$$, 63172000, $$This project investigates, develops, and evaluates conventional munitions guidance technologies to establish technical feasibility and military utility of innovative munition seekers, weapon aerodynamics, navigation and control, and guidance subsystem integration/simulation. Project payoffs include adverse-weather, Global Positioning System (GPS)-degraded and Global Positioning System-denied, networked, and autonomous precision munition guidance capability; increased number of kills per sortie; increased aerospace vehicle survivability; improved weapon reliability and affordability; and improved weapon survivability and effectiveness.$$, 63172000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602602F_622502$$, $$0602602F$$, $$622502$$, $$Ordnance Technology$$, 61930000, $$This project investigates, develops, and evaluates conventional ordnance technologies to establish technical feasibility and military utility for advanced explosives, fuzes, warheads, sub-munitions, and weapon airframes, carriage, and dispensing. The project also assesses the lethality and effectiveness of current and planned conventional weapons technology programs and assesses target vulnerability. The payoffs include improved storage capability and transportation safety of fully assembled weapons, improved warhead and fuze effectiveness, improved sub-munitions dispensing, low-cost airframe/subsystem components and structures, and reduced aerospace vehicle and weapon drag.$$, 61930000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602605F_624866$$, $$0602605F$$, $$624866$$, $$Lasers & Imaging Technology$$, 0, $$This project explores the technical feasibility of high power lasers, including beam control, for applications such as aircraft protection, force protection, and precision engagement from the Department of the Air Force platforms. This project investigates the effects of laser weapons on a wide range of systems and components as well as producing, modifying, validating and applying Directed Energy and non-Directed Energy concept development and assessment tools to determine which technology solutions to pursue.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602605F_624867$$, $$0602605F$$, $$624867$$, $$Advanced Weapons & Survivability$$, 43436000, $$This project conducts research in high power electromagnetics (HPEM), which can include high power microwaves (HPM), plasmas, particle beams, and millimeter waves and other unconventional, innovative weapon technologies, to satisfy Department of the Air Force requirements in the following areas: counter-adversary unmanned aerial systems (c-UAS), counter-adversary intelligence/surveillance/reconnaissance (c-ISR), counter-adversary missiles (c-Missile) and counter-adversary electronics (c-Electronic) for high-value airborne asset (HVAA) protection, and point defense. This project conducts research to advance the state-of-the-art of HPM sources, antennas, and novel directed energy applications by investigating the effects of HPM weapons on a wide range of systems and components. This project conducts physics-level numerical simulations, modeling, and analysis to inform science and technology investments and for assessing the military utility of HPM systems. This project includes but is not limited to high power microwaves, plasmas, particle beams, and millimeter waves. Technologies developed under this project feed directly into HPM technology demonstrations to graduate the technology to higher technology readiness level (TRL) under PE 0603605F (Advanced Weapons Technology), project 633152 (High Power Microwave Development and Integration).$$, 43436000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602605F_625173$$, $$0602605F$$, $$625173$$, $$Laser Technology$$, 48895000, $$This project conducts research to advance the state-of-the-art in continuous wave (CW) and pulsed laser sources, optical beam combination techniques, optical beam control technologies, optical beam propagation methodologies, lethality enhancement techniques via laser effect testing, and the integration of these technologies into laboratory-level system demonstration packages for Air Force applications such as counter-adversary unmanned aerial systems (c-UAS), counter-adversary intelligence/ surveillance/reconnaissance (c-ISR), and counter-adversary missiles (c-Missile) for high value airborne asset (HVAA) protection, and point defense. This project conducts modeling, simulation, and analysis to guide science and technology investments and for assessing the military utility of the technologies being developed. Technologies developed under this project feed directly into laser system technology demonstrations to graduate the technology to a higher technology readiness level (TRL) under PE 0603605F (Advanced Weapons Technology), 633151 (High Power Solid State Laser Technology).$$, 48895000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602651M_0000$$, $$0602651M$$, $$0000$$, $$JT Non-Lethal Wpns Applied Res$$, 7300000, $$This project funds the applied research, study, assessment, and demonstration of technologies that could provide a non-lethal capability or target effect. Investment areas include applied research related to: non-lethal directed energy weapons (lasers, millimeter wave and high power microwave) for counter-personnel and counter- materiel missions; non-lethal acoustic and optical technologies; advanced non-lethal materials (including materials for vehicle/vessel stopping and counter-facility applications); associated human effects and effectiveness for new non-lethal stimuli; injury potential and effectiveness of directed energy, electric stun, ocular, and acoustic based non-lethal technologies; and developing models of crowd behavior and dynamics.$$, 7300000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602668D8Z_003$$, $$0602668D8Z$$, $$003$$, $$Cyber Applied Research$$, 17988000, $$This Program Element supports the Department's Interim National Defense Strategic Guidance priorities to Defend the U.S. Homeland including America’s skies and borders, and Deterring China in the Indo-Pacific. It does so by developing cyber capabilities that integrate functionally with electromagnetic spectrum operations to increase readiness and deterrence, particularly in priority areas such as USINDOPACOM. This PE explores technical and scientific concepts to overcome challenges in the Joint Warfighting Environment with cyber effects and integrated non-kinetic options through applied research for an asymmetric advantage across all domains (maritime, land, air, cyberspace, and space). It applies the Joint Publication (JP) 3-0 principles of Mass, Maneuver, and Unity of Command to achieve specific outcomes with minimal collateral damage and unforeseen consequences for integrated non-kinetic effects development Efforts are focused to support the Joint Warfighting Environment through intended cyber effects execution without perturbing the unintended kinetic and non-kinetic entities through disruptive integration of cyberspace operations with electromagnetic spectrum operations (EMSO) and sensing. The PE accelerates cyber S&T capability development to directly address INDSG priorities to defend the homeland and deter aggression/prepared to prevail in U.S. Indo-Pacific Command (USINDOPACOM) area of responsibility against China. Adversaries are increasingly leveraging asymmetric tactics in the Joint Warfighting Environment. The Department of Defense (DoD) needs to evolve its approach to warfare, integrating cyber and non-kinetic effects to maintain a decisive advantage across all domains. The Non-Kinetic Advantage (NKA) project is a collaborative effort aimed at revolutionizing how the Joint Force employs non-kinetic capabilities. By focusing on four key pillars – Protect, Process, Visualize, and Align & Shape – NKA will deliver a decisive advantage in the information battlespace. Payoff: NKA will enable the Joint Force to conduct faster, more effective operations across all domains, even in contested environments. Will provide Asymmetric Advantage by mastering the information battlespace, NKA will provide a decisive edge against adversaries, deterring aggression and ensuring US dominance. Will enable Rapid Decision Making by NKA empowering commanders with the information and tools needed to make rapid, well-informed decisions in complex, dynamic environments.$$, 17988000, NULL, NULL, NULL, NULL, 90173000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602668D8Z_007$$, $$0602668D8Z$$, $$007$$, $$Pacific Intelligence and Innovation$$, 0, $$Congressional Add: Pacific Intelligence and Innovation Initiatives (P3I)$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602668D8Z_712$$, $$0602668D8Z$$, $$712$$, $$Academic Cyber Institute VICEROY$$, 0, $$Congressional Add: Academic Cyber Institute$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602668D8Z_714$$, $$0602668D8Z$$, $$714$$, $$Semiconductor Supply Chain$$, 0, $$Congressional Add: Semiconductor Supply Chain Cyber Security Research$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602669D8Z_825$$, $$0602669D8Z$$, $$825$$, $$Microelectronics Research Maturation-$$, 0, $$This project focuses on the applied research activities of the Commons including the early research and development of new microelectronics materials, processes, devices, and architectural designs. It seeks to answer how new models, science, and technology can be leveraged to create a different manufacturing paradigm based on proven process tools in agile microelectronics fabrication facilities (fabs). The project also supports the establishment of the Commons Hubs, which will be networks of regional capabilities organized in collaboration with the Commons Consortium Manager (CM) to address DOD and commercial needs and requirements. The Hubs may include existing facilities augmented to enhance intrinsic specializations in emerging areas of microelectronics. Each Hub will concentrate on one of six technical areas including: Secure Edge Computing, 5G/6G Technology, Artificial Intelligence Hardware, Quantum Technology, Electromagnetic Warfare, and Commercial Leap Ahead Technologies. Core Facilities (i.e., fabs) are integral parts of the Hubs network that will provide key fabrication capabilities that are required to demonstrate prototypes with the volume and characteristics required to ensure reduced risk for full manufacturing production. This effort also includes early workforce development activities through the Commons network. Activities may span K-12, undergraduate, graduate and continuing education and may include, for example, establishment of PhD internships and post-doc training at Hub facilities and internships with Hub members.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602675D8Z_046$$, $$0602675D8Z$$, $$046$$, $$Providing Research and End-user$$, 0, $$This program will leverage and integrate expertise from operational end users, physical climate scientists and models, tools, and datasets, and social scientists with deep understanding of designated regional and local communities to anticipate and respond more quickly and precisely to climate and environmental change risks and opportunities. The program aims to explore how specific environmental and social indicators might inform strategic reviews to adapt warfighter training and planning in anticipation of climate global trends. The research program will build upon the products of the 6.1 Minerva Research Initiative (program element 0601110D8Z) with a focus on end-user defined mission, geographic, and timescale priorities to forecast local and regional climate and environmental change effects, assess and predict likely societal impacts and responses, and ultimately provide operations planners technically-relevant and operationally precise scenarios to incorporate into Contingency Plans (CONPLANs) and Operational Plans (OPLANs) and Intelligence, Surveillance, and Reconnaissance (ISR) requirements related to climate change.$$, 0, NULL, NULL, NULL, NULL, 3854000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602702E_TT-03$$, $$0602702E$$, $$TT-03$$, $$NAVAL WARFARE$$, 0, $$The efforts described in this Program Element (PE) address the Applied Research associated with the Tactical Technology Program that supports the advancement of concepts and technologies to enhance the next generation of tactical systems. This PE funds a number of projects in the areas of Naval Warfare, Advanced Land Systems, Aeronautics and Space Technology and Information Analytics Technology. This PE also supports innovation and robust transition planning in the technology cycle by working with entrepreneurs to increase the likelihood that DARPA-funded technologies take root in the U.S. and provide new capabilities for national defense. The Naval Warfare Technology project develops advanced technologies for application to a broad range of naval requirements. Enabling and novel technologies include concepts for expanding the envelope of operational naval capabilities to include the entire sea column such as improved situational awareness over large maritime environments, ship self-defense techniques, novel underwater propulsion modalities, high speed underwater vessels, improved techniques for underwater object detection and discrimination, long endurance unmanned surface vehicles, methods and techniques for servicing assets throughout the sea column, and high bandwidth communications. This project will also examine methods and architectures for distributing maritime operations to enable a more agile, survivable, and cost-effective fleet. The Advanced Land Systems Technology project is developing technologies for enhancing U.S. military effectiveness and survivability in operations ranging from traditional threats to military operations against irregular forces that can employ disruptive or catastrophic capabilities, or disrupt stabilization operations, including competing in underground spaces. Programs in this project will break the relative symmetry of land combat to give U.S. forces a decided advantage in the current and future ground battlefield. The emphasis is on developing affordable technologies that reduce reliance on consolidated forward-operating bases and required lines of communication, and provide small units and individual warfighters with hyper-mobility and hyper-lethality. This project will develop methods and technologies to expand the maneuver trade space to include the vertical dimension, including subterranean environments, as well as underground spaces. It will leverage advances in artificial intelligence to enable integrated manned-unmanned operations and decrease warfighter exposure through the use of autonomous agents. Aeronautics and Space Technology efforts will address high payoff opportunities that dramatically reduce costs associated with advanced aeronautical and space systems and/or provide revolutionary new system capabilities for satisfying current and projected military mission requirements. This includes advanced technology Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                                           Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:              PE 0602702E / TACTICAL TECHNOLOGY Applied Research studies of revolutionary propulsion, vehicle, and launch concepts, sophisticated fabrication methods, and examination of novel materials and enabling technologies for aeronautics and space system applications. Studies that also fundamentally change the calculus of battle including consideration of a mix of assets, platforms that are potentially disposable or with limited lifespans, and autonomous integration of space and air platforms in the tactical battlespace are included. The Information Analytics Technology project develops technology for analyzing data and information arising from: 1) intelligence networks; 2) open sources, social and broadcast media, and other external sources; 3) sensors and signal/image processors; and 4) collection platforms and weapon systems. Technical challenges include processing huge volumes of diverse, incomplete, and uncertain data in tactically-relevant timeframes, and countering the information operations of sophisticated adversaries who seek to deceive, degrade, deny, and disrupt the U.S. information enterprise. Benefits sought include a deeper understanding of the evolving operational environment tailored to the needs of commanders at every echelon; an enhanced capability to plan, monitor, and control diverse military operations ranging from stabilization and information operations to combat engagements; and increased efficiency of core military functions such as national and homeland security, warfighter protection, and defense support of law enforcement and civil authorities. Beginning in FY 2026, efforts in this PE will be funded in PE 0602023E, Access and Awareness.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
