INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602715E_MBT-01$$, $$0602715E$$, $$MBT-01$$, $$MATERIALS$$, 0, $$The efforts described in this Program Element (PE) address the Applied Research associated with the Materials and Biological Technology Program that is focused on developing materials and biological technologies that make possible a wide range of new military capabilities. This PE also supports innovation and robust transition planning in the technology cycle by working with entrepreneurs to increase the likelihood that DARPA funded technologies take root in the U.S. and provide new capabilities for national defense. The Materials Processing Technology project will develop novel materials, fabrication and processing techniques, models, devices and components that will lower the cost, increase the performance, and/or enable new missions for military platforms and systems. Included in this project are efforts across a wide range of technology areas including manufacturing, electronics, sensors, optics, and complex and autonomous systems. The Biologically Based Materials and Devices project will leverage the growing application space of the biological sciences for the development of new DoD capabilities to improve the sustainability of warfighters, and operational platforms in varied environments. This project will develop solutions for critical resource processing, materials development, threat detection and characterization, environmental remediation, and warfighter resilience to infectious disease and environmental stressors. The materials developed through this project will protect and sustain warfighters and operations in austere environments. Beginning in FY 2026, efforts in this PE will be funded in PE 0602024E, Warfighting Performance, and PE 0602025E, Making, Maintaining, Supply Chain and Logistics. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                                   Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:        PE 0602715E / MATERIALS AND BIOLOGICAL TECHNOLOGY Applied Research$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602751D8Z_278$$, $$0602751D8Z$$, $$278$$, $$Software Engineering Institute (SEI)$$, 8883000, $$Work conducted under this Program Element (PE) will enable resilient mission assurance in heterogeneous and contested environments through the verification and validation of system performance and architecture. The program will also assist the Department of Defense (DoD) in retaining a long-term advantage in the areas of software-intensive systems and cyber security by enhancing assurance, exploiting automation and Artificial Intelligence (AI), and understanding human-computer interaction. The Software Engineering Institute (SEI) Applied Research PE has two main research thrusts with known military applications: (1) Software Engineering, Systems Verification and Validation, and Mission Assurance (formerly Mission Assurance); and (2) Information Assurance. This area is increasingly being applied to AI and autonomous systems.$$, 8883000, NULL, NULL, NULL, NULL, 9788000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602715E_MBT-02$$, $$0602715E$$, $$MBT-02$$, $$BIOLOGICALLY$$, 0, $$The efforts described in this Program Element (PE) address the Applied Research associated with the Materials and Biological Technology Program that is focused on developing materials and biological technologies that make possible a wide range of new military capabilities. This PE also supports innovation and robust transition planning in the technology cycle by working with entrepreneurs to increase the likelihood that DARPA funded technologies take root in the U.S. and provide new capabilities for national defense. The Materials Processing Technology project will develop novel materials, fabrication and processing techniques, models, devices and components that will lower the cost, increase the performance, and/or enable new missions for military platforms and systems. Included in this project are efforts across a wide range of technology areas including manufacturing, electronics, sensors, optics, and complex and autonomous systems. The Biologically Based Materials and Devices project will leverage the growing application space of the biological sciences for the development of new DoD capabilities to improve the sustainability of warfighters, and operational platforms in varied environments. This project will develop solutions for critical resource processing, materials development, threat detection and characterization, environmental remediation, and warfighter resilience to infectious disease and environmental stressors. The materials developed through this project will protect and sustain warfighters and operations in austere environments. Beginning in FY 2026, efforts in this PE will be funded in PE 0602024E, Warfighting Performance, and PE 0602025E, Making, Maintaining, Supply Chain and Logistics. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                                   Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:        PE 0602715E / MATERIALS AND BIOLOGICAL TECHNOLOGY Applied Research$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602716E_ELT-01$$, $$0602716E$$, $$ELT-01$$, $$ELECTRONIC$$, 0, $$The efforts described in this Program Element (PE) address the Applied Research associated with the Electronics Technology Program that is directed towards developing electronics that make a wide range of military applications possible. The PE focuses on turning basic advancements into the underpinning technologies required to address critical national security issues and to enable an information-driven warfighter. This PE also supports innovation and robust transition planning in the technology cycle by working with entrepreneurs to increase the likelihood that DARPA funded technologies take root in the U.S. and provide new capabilities for national defense. Advances in microelectronic device technologies continue to significantly benefit improved weapons effectiveness, intelligence capabilities, and information superiority. The Electronic Technology project supports continued advancement in microelectronics, including electronic and optoelectronic devices, Microelectromechanical Systems (MEMS), semiconductor device design and fabrication, and new materials and material structures. Areas of particular emphasis of this work include reducing the barriers to designing and fabricating custom electronics and exploiting improved manufacturing techniques to provide low-cost, high-performance sensors. Programs in this project will also greatly improve the size, weight, power, and performance characteristics of electronic systems; support positioning, navigation, and timing in GPS-denied environments; and develop sensors more sensitive and robust than today's standards. This project has six major focus areas: Electronics, Photonics, Microelectromechanical Systems, Architectures, Algorithms, and other Electronic Technology research. The Beyond Scaling Technology project pursues electronics performance advancements that exploit new concepts in circuit specialization and three-dimensional heterogeneous integration (3DHI) by the optimization of materials, devices, architectures, and designs to achieve specific circuit function at high performance. Because electronics advancements must simultaneously make progress in performance and secure the foundation on which our microelectronics infrastructure relies, this envisioned specialization will require incorporation of security safeguards and advancing manufacturing tools and process automation. Accordingly, programs within the Beyond Scaling Technology project will reduce barriers to making specialized circuits in today's silicon hardware and 3DHI by improving producibility. This will significantly increase the ease with which DoD can design, deliver, and eventually upgrade critical, customized microelectronics, particularly for operation in extreme environments. Programs also explore alternatives to traditional circuit architectures, for instance by exploiting 3DHI to optimize electronic devices and by incorporating novel materials and new techniques for securing DoD and commercial data and hardware. Beginning in FY 2026, efforts in this PE will be funded in PE 0602025E, Making, Maintaining, Supply Chain and Logistics. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                                         Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:           PE 0602716E / ELECTRONICS TECHNOLOGY Applied Research$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602716E_ELT-02$$, $$0602716E$$, $$ELT-02$$, $$BEYOND SCALING$$, 0, $$The efforts described in this Program Element (PE) address the Applied Research associated with the Electronics Technology Program that is directed towards developing electronics that make a wide range of military applications possible. The PE focuses on turning basic advancements into the underpinning technologies required to address critical national security issues and to enable an information-driven warfighter. This PE also supports innovation and robust transition planning in the technology cycle by working with entrepreneurs to increase the likelihood that DARPA funded technologies take root in the U.S. and provide new capabilities for national defense. Advances in microelectronic device technologies continue to significantly benefit improved weapons effectiveness, intelligence capabilities, and information superiority. The Electronic Technology project supports continued advancement in microelectronics, including electronic and optoelectronic devices, Microelectromechanical Systems (MEMS), semiconductor device design and fabrication, and new materials and material structures. Areas of particular emphasis of this work include reducing the barriers to designing and fabricating custom electronics and exploiting improved manufacturing techniques to provide low-cost, high-performance sensors. Programs in this project will also greatly improve the size, weight, power, and performance characteristics of electronic systems; support positioning, navigation, and timing in GPS-denied environments; and develop sensors more sensitive and robust than today's standards. This project has six major focus areas: Electronics, Photonics, Microelectromechanical Systems, Architectures, Algorithms, and other Electronic Technology research. The Beyond Scaling Technology project pursues electronics performance advancements that exploit new concepts in circuit specialization and three-dimensional heterogeneous integration (3DHI) by the optimization of materials, devices, architectures, and designs to achieve specific circuit function at high performance. Because electronics advancements must simultaneously make progress in performance and secure the foundation on which our microelectronics infrastructure relies, this envisioned specialization will require incorporation of security safeguards and advancing manufacturing tools and process automation. Accordingly, programs within the Beyond Scaling Technology project will reduce barriers to making specialized circuits in today's silicon hardware and 3DHI by improving producibility. This will significantly increase the ease with which DoD can design, deliver, and eventually upgrade critical, customized microelectronics, particularly for operation in extreme environments. Programs also explore alternatives to traditional circuit architectures, for instance by exploiting 3DHI to optimize electronic devices and by incorporating novel materials and new techniques for securing DoD and commercial data and hardware. Beginning in FY 2026, efforts in this PE will be funded in PE 0602025E, Making, Maintaining, Supply Chain and Logistics. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                                         Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:           PE 0602716E / ELECTRONICS TECHNOLOGY Applied Research$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602718BR_RA$$, $$0602718BR$$, $$RA$$, $$CWMD CROSS-$$, 16672000, $$The Counter Weapons of Mass Destruction (CWMD) Cross-Cutting Technical and Information Sciences project develops concepts and technologies in the areas of high-speed information processing, modeling and simulation, signal detection, and data-driven decision analysis in support of the Defense Threat Reduction Agency's (DTRA's) technical reachback teams. This project develops and maintains continuously improving collaborative architectures and Weapons of Mass Destruction (WMD) modeling and simulation codes that drive an integrated suite of decision support tools serving the Combatant Commands, other Department of Defense (DoD) agencies, and national and international CWMD partners. This effort also funds research activities that benefit the public through analysis and engagement to reduce and counter threats posed by WMD via the Strategic Trends Research Initiative. Strategic Trends Research Initiative cultivates national and international research community partnerships across domains, bringing scientific, technical, and social science experts together to help understand and anticipate WMD capabilities and threats. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Threat Reduction Agency                                                   Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:           PE 0602718BR / COUNTER WEAPONS OF MASS DESTRUCTION APPLIED RESEAR Applied Research                                                               CH$$, 16672000, NULL, NULL, NULL, NULL, 457310000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602718BR_RD$$, $$0602718BR$$, $$RD$$, $$NUCLEAR$$, 99178000, $$The Counter Weapons of Mass Destruction (CWMD) Cross-Cutting Technical and Information Sciences project develops concepts and technologies in the areas of high-speed information processing, modeling and simulation, signal detection, and data-driven decision analysis in support of the Defense Threat Reduction Agency's (DTRA's) technical reachback teams. This project develops and maintains continuously improving collaborative architectures and Weapons of Mass Destruction (WMD) modeling and simulation codes that drive an integrated suite of decision support tools serving the Combatant Commands, other Department of Defense (DoD) agencies, and national and international CWMD partners. This effort also funds research activities that benefit the public through analysis and engagement to reduce and counter threats posed by WMD via the Strategic Trends Research Initiative. Strategic Trends Research Initiative cultivates national and international research community partnerships across domains, bringing scientific, technical, and social science experts together to help understand and anticipate WMD capabilities and threats. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Threat Reduction Agency                                                   Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:           PE 0602718BR / COUNTER WEAPONS OF MASS DESTRUCTION APPLIED RESEAR Applied Research                                                               CH$$, 99178000, NULL, NULL, NULL, NULL, 436687000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602718BR_RG$$, $$0602718BR$$, $$RG$$, $$CWMD TECHNOLOGIES$$, 27182000, $$The Counter Weapons of Mass Destruction (CWMD) Cross-Cutting Technical and Information Sciences project develops concepts and technologies in the areas of high-speed information processing, modeling and simulation, signal detection, and data-driven decision analysis in support of the Defense Threat Reduction Agency's (DTRA's) technical reachback teams. This project develops and maintains continuously improving collaborative architectures and Weapons of Mass Destruction (WMD) modeling and simulation codes that drive an integrated suite of decision support tools serving the Combatant Commands, other Department of Defense (DoD) agencies, and national and international CWMD partners. This effort also funds research activities that benefit the public through analysis and engagement to reduce and counter threats posed by WMD via the Strategic Trends Research Initiative. Strategic Trends Research Initiative cultivates national and international research community partnerships across domains, bringing scientific, technical, and social science experts together to help understand and anticipate WMD capabilities and threats. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Threat Reduction Agency                                                   Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:           PE 0602718BR / COUNTER WEAPONS OF MASS DESTRUCTION APPLIED RESEAR Applied Research                                                               CH$$, 27182000, NULL, NULL, NULL, NULL, 216736000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602751D8Z_817$$, $$0602751D8Z$$, $$817$$, $$Cyber Security, Applied Research$$, 0, $$Work conducted under this project will enable resilient mission assurance in heterogeneous and contested environments through the verification and validation of system performance and architecture. The program will also assist the DoD in retaining a long-term advantage in the area of cybersecurity by enhancing assurance, exploiting automation, and understanding human-computer interaction.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603342D8Z_486$$, $$0603342D8Z$$, $$486$$, $$Industrial_foreign_influence$$, 0, $$DIU increases the Department's access to commercial technologies and talent, with the ultimate goal of fielding technology at a pace that effectively deters our adversaries and helps ensure victory if we are forced to fight. Consistent with the Administration's 2026 interim National Defense Strategy and the National Defense Science and Technology Strategy, this new era of competition requires technological superiority to ensure the United States’ ability to project power, maintain international norms and rule of law, provide credible deterrence, and prevail in conflict.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602718BR_RR$$, $$0602718BR$$, $$RR$$, $$CWMD TEST AND$$, 18463000, $$The Counter Weapons of Mass Destruction (CWMD) Cross-Cutting Technical and Information Sciences project develops concepts and technologies in the areas of high-speed information processing, modeling and simulation, signal detection, and data-driven decision analysis in support of the Defense Threat Reduction Agency's (DTRA's) technical reachback teams. This project develops and maintains continuously improving collaborative architectures and Weapons of Mass Destruction (WMD) modeling and simulation codes that drive an integrated suite of decision support tools serving the Combatant Commands, other Department of Defense (DoD) agencies, and national and international CWMD partners. This effort also funds research activities that benefit the public through analysis and engagement to reduce and counter threats posed by WMD via the Strategic Trends Research Initiative. Strategic Trends Research Initiative cultivates national and international research community partnerships across domains, bringing scientific, technical, and social science experts together to help understand and anticipate WMD capabilities and threats. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Threat Reduction Agency                                                   Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 2:           PE 0602718BR / COUNTER WEAPONS OF MASS DESTRUCTION APPLIED RESEAR Applied Research                                                               CH$$, 18463000, NULL, NULL, NULL, NULL, 182703000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602747N_0000$$, $$0602747N$$, $$0000$$, $$Undersea Warfare Applied Res$$, 64335000, $$This PE funds applied research efforts in undersea target detection, classification, localization, tracking, and neutralization. Associated efforts focus on new Anti- Submarine Warfare (ASW) operational concepts that promise to improve wide-area surveillance, detection, localization, tracking, and attack capabilities against quiet adversary submarines operating in noisy and cluttered shallow water environments. Related efforts are aimed at leveraging technologies that will protect the country's current capital investment in surveillance, submarine, surface ship, and air ASW assets.$$, 64335000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602747N_9999$$, $$0602747N$$, $$9999$$, $$Congressional Adds$$, 0, $$Congressional Interest Items not included in other Projects.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602750N_0000$$, $$0602750N$$, $$0000$$, $$Future Naval Capabilities Applied$$, 3128000, $$This Project funds applied research for Future Naval Capabilities (FNC) Technology Candidates (TC) supporting Warfighter Protection and also contains the estimated Applied Research funding for Innovative Naval Prototypes (INP) yet to be selected. Most of the work in this PE can be characterized between Technology Readiness Level (TRL) 2 (technology concept and/or application formulation) and TRL 4 (component and/or breadboard validation in laboratory environments). Warfighter Protection TCs focus on maturing technologies that enhance Naval warfighting effectiveness and efficiency within the Manpower, Personnel, Training and Education to a point where they can be proposed and continued as Future Naval Capabilities (FNC) in program element (PE) 0603673N, Future Naval Capabilities Advanced Technology Development. INPs are larger in scope, scale, and risk. They are selected for their high-payoff and potential to revolutionize operational concepts. Due to high technical risk, INPs typically have long durations with no more than three years between decision points. INPs require both the Applied Research, detailed within the Projects of this PE; and Advanced Technology Development (ATD) funding, detailed in PE 0603673N Project 2966 S&T Campaigns. After new INPs are selected, the Applied Research funding within this Project gets moved into other Projects within this PE. There are specific R2As within these projects for each INP, so they are uniquely identified.$$, 3128000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602750N_1385$$, $$0602750N$$, $$1385$$, $$Aerospace Sciences$$, 0, $$The Aerospace Sciences activity develops technologies for the science and engineering of flight from the land and sea surfaces to the edge of the atmosphere, and as applicable to the utilization of flight for aircraft, missiles, rockets, munitions, and unmanned systems (UxS) employed by the Navy and Marine Corps forces operating from naval platforms or land locations.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602750N_1386$$, $$0602750N$$, $$1386$$, $$Biomedical$$, 0, $$The objective of this project is to conduct biomedical research and mature technologies that enhance the health, survivability, and recovery of Sailors and Marines operating in austere, distributed, and isolated maritime environments by enabling naval forces to bring biomedical capacity forward, create it on-demand, support prolonged field care, enable casualty evacuation, and provide en route care. Projects translate basic and applied science to meet a specific Naval need and if successful, will continue to advance in program element (PE) 0603673N, Future Naval Capabilities Advanced Technology Development.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602750N_1388$$, $$0602750N$$, $$1388$$, $$Directed Energy$$, 0, $$The Directed Energy (DE) activity develops technologies that enable laser and high-power microwave (HPM) weapon systems, within Navy and Marine Corps size, weight, and power (SWAP) constraints, to strike enemy targets and to defend naval platforms and land bases from threats. Additionally, the DE activity develops technologies that enable defense against adversary DE systems.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602750N_1389$$, $$0602750N$$, $$1389$$, $$Electromagnetic Spectrum$$, 0, $$Electromagnetic Spectrum researches and develops electronics, sensors, electronic warfare, and alternate positioning, navigation, and timing to understand, shape, and operate in the battlespace. This can include system studies, system architecture development, and component and/or breadboard validation in laboratory environments.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602750N_1391$$, $$0602750N$$, $$1391$$, $$Full Spectrum Cyber$$, 0, $$Full Spectrum Cyber explores and develops technologies necessary to conduct successful offensive and defensive naval and expeditionary force operations in the information age. This can include system studies, system architecture development, and component and/or breadboard validation in laboratory environments.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602750N_1392$$, $$0602750N$$, $$1392$$, $$Human Systems$$, 0, $$The objective of this project is to conduct human systems research and mature technologies that enhance Naval warfighting effectiveness and efficiency within the broad array of Warfighter Performance science and technology domains (Decision Sciences, Information Warfare and Future Conflict, Manpower, Personnel, Training and Education, Intelligent and Autonomous Systems) to a point where they can be proposed and continued as Future Naval Capabilities (FNC) in program element (PE) 0603673N, Future Naval Capabilities Advanced Technology Development.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602750N_1393$$, $$0602750N$$, $$1393$$, $$Kinetic Weapons$$, 0, $$The Kinetic Weapons activity develops technologies to address the Navy and Marine Corps fires requirements for extended range, increased precision, decreased weapons fly-out times, greater destructive power, novel weapons effects, autonomy, human-machine teaming, reduced weapons costs, mission planning, and mass- producible swarming munitions.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602750N_1399$$, $$0602750N$$, $$1399$$, $$Ocean Battle Space Applications$$, 0, $$The objective of this project is to enable maritime domain access and distributed operations for Naval forces in contested environments through superior maritime battlespace awareness and threat detection, identification and neutralization. Specifically, activities will develop and mature technologies that ultimately support Mine and Expeditionary Warfare, Undersea Warfare, and Environmental Information Warfare. Activities will also develop and mature methods and technological approaches for environmental sensing and prediction for the maritime battlespace. The desired outcome for efforts in this activity is to mature the applied research results to a point where they can be focused on particular enabling capabilities and proposed to be continued as Future Naval Capabilities (FNC) in program element (PE) 0603673N, Future Naval Capabilities Advanced Technology Development. Additionally, a subset of technologies explored herein are intended to support expeditionary access and will be further matured, focused, and ultimately demonstrated under the USMC's Advanced Technology Demonstration effort in PE 0603640M MC Advanced Technology Demo.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602750N_1400$$, $$0602750N$$, $$1400$$, $$Power and Energy$$, 4544000, $$This project develops and matures technologies that enable superior warfighting capabilities for surface and sub-surface naval platforms, undersea weapons and countermeasures, and Marine Corps technologies to a point where they can be proposed and continued as Future Naval Capabilities in program element (PE) 0603673N, Future Naval Capabilities Advanced Technology Development.$$, 4544000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602750N_1401$$, $$0602750N$$, $$1401$$, $$Undersea Systems Payloads and$$, 0, $$This project develops and matures technologies that enable superior warfighting capabilities for surface and sub-surface naval platforms, undersea weapons and countermeasures, and Marine Corps technologies to a point where they can be proposed and continued as Future Naval Capabilities in program element (PE) 0603673N, Future Naval Capabilities Advanced Technology Development.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602750N_1502$$, $$0602750N$$, $$1502$$, $$C5ISR/Naval Space$$, 104837000, $$The Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, Reconnaissance, and Naval Space activity researches and develops technology for the naval force to obtain decisive competitive advantage across the range of naval missions and levels of warfare. The objective of this project is to develop and mature technologies in data science, mathematical optimization, computational and information sciences, electronics, electronic warfare (EW), command and control (C2), combat systems, communications, cyber security, cyber operations, microelectronics, electromagnetic warfare (EMW), sensing and surveillance, and quantum precision timing and navigation (PNT). These technologies, if successful, will continue to advance in program element (PE) 0603673N, Future Naval Capabilities Advanced Technology Development.$$, 104837000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602750N_1503$$, $$0602750N$$, $$1503$$, $$Directed Energy & Kinetic Systems$$, 33682000, $$The Directed Energy & Kinetic Systems activity develops technologies to advance Naval applications of both directed energy (DE) and kinetic weapons. The main focus of DE weapons is to develop technologies that enable laser and high-power microwave (HPM) weapon systems, within Navy and Marine Corps size, weight, and power (SWAP) constraints, to strike enemy targets and to defend naval platforms and land bases from threats. Additionally, the DE activity develops technologies that enable defense against adversary DE systems. The main focus of kinetic weapons is to develop technologies that address the Navy and Marine Corps fires requirements for extended range; increased precision; decreased weapons fly-out times; greater destructive power and novel effects; autonomy, swarming, and human-machine teaming; mission planning and decision making; reduced production costs, and increased inventory and availability.$$, 33682000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602750N_1505$$, $$0602750N$$, $$1505$$, $$Human & Biological Systems$$, 19598000, $$Increasing the understanding of how human and biological systems operate and then applying those principles to integrated human and technological systems is essential for winning during military operations. The objective of this project is to develop and deploy knowledge and technologies that maximize and enhance warfighter performance, safety, and medical care.$$, 19598000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602750N_1506$$, $$0602750N$$, $$1506$$, $$Materials/Electronics$$, 1514000, $$This project develops and matures technologies that enable superior warfighting capabilities for surface and sub-surface naval platforms, undersea weapons and countermeasures, and Marine Corps technologies to a point where they can be proposed and continued as Future Naval Capabilities in program element (PE) 0603673N, Future Naval Capabilities Advanced Technology Development.$$, 1514000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602750N_1507$$, $$0602750N$$, $$1507$$, $$Naval Aerospace$$, 22575000, $$The Naval Aerospace activity develops technologies for the science and engineering of flight from the land and sea surfaces to the edge of the atmosphere, and as applicable to the utilization of flight for aircraft, missiles, rockets, munitions, and unmanned systems (UxS) employed by the Navy and Marine Corps forces operating from naval platforms or land locations.$$, 22575000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602750N_1508$$, $$0602750N$$, $$1508$$, $$Undersea Systems$$, 66338000, $$This project develops and matures technologies that enable superior warfighting capabilities for surface and sub-surface naval platforms, undersea weapons and countermeasures, and Marine Corps technologies to a point where they can be proposed and continued as Future Naval Capabilities in program element (PE) 0603673N, Future Naval Capabilities Advanced Technology Development.$$, 66338000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602750N_5891$$, $$0602750N$$, $$5891$$, $$Naval S&T Ops Analysis, Supp &$$, 4763000, $$Operational Analysis, Support and Experimentation Activity was established to broaden the spectrum of promising applied research efforts investigated within this Project and to provide additional acquisition oversight, fiscal clarity, and adherence to financial management practices at the Project level. The efforts described in this Project address the Applied Research associated with Innovative Naval Prototype (INP) and Future Naval Capability (FNC) Operational Analysis, Support and Experimentation Activity efforts that are used to further explore the development of future INP and FNC topics and proposals. These efforts evaluate, study/analyze and/or perform any basic applied research-focused investigative experimentation activities which will support the identification of potential INP and FNC topics for future investment consideration. The use of Operational Analysis, Support and Experimentation Activity funds can help accelerate and/or create a flexible response to emerging requirements or threats by identifying a potential INP or FNC topic for consideration in a more time-efficient and/or effective manner.$$, 4763000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602750N_5893$$, $$0602750N$$, $$5893$$, $$Decision Superiority$$, 0, $$Decision Superiority researches and develops communications, networking, information processing, analysis, decision making, and understanding to obtain decisive advantage across the spectrum of naval missions and warfare.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602782N_0000$$, $$0602782N$$, $$0000$$, $$Mine and Expeditionary Warfare$$, 29081000, $$This Project focuses on reducing the time involved in conducting Mine Countermeasure (MCM) operations and increasing safe standoff from minefields. It develops and transitions technologies for MCM-related and UAEO-related Future Naval Capabilities (FNC). The MIW effort includes technologies for clandestine and overt minefield reconnaissance, organic ship self-protection, organic mine-hunting, neutralization/breaching and clearance. The Littoral Warfare effort includes critical warfighting functions such as C4ISR, fires, maneuver, sustainment. The sea mining effort emphasizes technologies for future sea mines. The Naval Special Warfare and Explosive Ordnance technology efforts concentrate on the development of technologies to enhance diver capabilities including: safe near-shore mine sensing, mobility and survivability, and ordnance disposal operations.$$, 29081000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602782N_9999$$, $$0602782N$$, $$9999$$, $$Congressional Adds$$, 0, $$Congressional Interest Items not included in other Projects.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602785A_790$$, $$0602785A$$, $$790$$, $$Personnel Performance & Training$$, 17191000, $$This Project conducts applied behavioral and social science research to enhance the Soldier Lifecycle (e.g., selection, assignment, training, leader development) and human relations (e.g., unit cohesion). This Project develops new personnel measures and methods that more fully assess potential and predict performance, behavior, attitudes, and resilience. These technologies also provide innovative and effective Talent Management methods to optimize individual and team performance to ensure the Army can meet mission requirements in uncertain and complex environments. This Project develops new performance measures and metrics for individuals and units, designs innovative training methods, and conducts scientific assessments to inform Human Capital policy and programs. Research in this Project will result in effective non-materiel solutions to help the Army adjust to changes in force size and structure, a variety of mission demands and contexts, challenges in human relations, and budgetary constraints. Work in this Project complements PE 0603007A (Personnel Performance & Training). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas, the Army Vision, the Army People Strategy, the Army's Talent Management Strategy, Army Human Capital Strategy, and the Army Modernization Strategy. Research is performed by the United States Army Research Institute (ARI) for the Behavioral and Social Sciences in Fort Belvoir, VA.$$, 17191000, NULL, NULL, NULL, NULL, 19667000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602787A_BS7$$, $$0602787A$$, $$BS7$$, $$Medical Technology (CA)$$, NULL, $$Congressional Interest Item funding provided for Medical Technology. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy.$$, NULL, NULL, NULL, NULL, NULL, 75234000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602787A_MK4$$, $$0602787A$$, $$MK4$$, $$Warfigher Health Applied Rsch$$, 141755000, $$This Project conducts research to prevent and protect Warfighters from training and operational injuries; refine mechanisms for detection of physiological (human physical and biochemical function) and psychological (mental) health problems; reduce the effects of trauma and promote rapid recovery from acute stress in far forward operational environments; evaluate hazards to head, neck, spine, eyes, and ears; set the standards for rapid return to duty; and determine new methods to sustain and enhance performance and readiness across the operational spectrum. This research provides medical information important to the design and operational use of military systems, and this work forms the basis for behavioral, training, and nutritional interventions. The four main areas of study are: (1) Physiological Health and Performance (2) Environmental Health and Protection (3) Injury Prevention and Reduction (4) Psychological Health and Resilience Research in this Project is coordinated with and complimentary to work done in Program Element (PE) 0602143A (Soldier Lethality Technology) and PE 0603118A (Soldier Lethality Advanced Technology). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the United States Army Medical Research and Development Command (USAMRDC) and Army Research Laboratory (ARL).$$, 141755000, NULL, NULL, NULL, NULL, 62391000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602787A_MM4$$, $$0602787A$$, $$MM4$$, $$Cbt Casualty Care Applied Rsch$$, 1538000, $$This Project refines and assesses concepts, techniques, and materiel that improve survivability and treatment outcomes for Warfighters wounded during combat operations and treated under austere field conditions, including prolonged field care, and during medical evacuation, and maintains laboratory capability to perform these functions. Combat casualty care research addresses control of severe bleeding; resuscitation and stabilization; advanced automated life support systems suitable for use in forward areas, treatment of severe orthopedic injuries, treatment of severe burns, and combat-related brain injury. Promising efforts identified in this Project are further matured under Program Element (PE) 0603002A (Medical Advanced Technology). The cited research is consistent with the Under Secretary of Defense (Research and Engineering) science and technology focus areas and the Army Modernization Strategy. Research in this Project is performed by the United States Army Medical Research and Development Command (USAMRDC), Fort Detrick, MD.$$, 1538000, NULL, NULL, NULL, NULL, 1770000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602787A_MM6$$, $$0602787A$$, $$MM6$$, $$Medical Technologies to Support$$, NULL, $$This Project supports applied research in two task areas: 1) Medical Robotic and Autonomous Systems (Med-RAS) - will a) leverage emerging technologies in biomedical engineering, robotics, autonomy, unmanned systems, and assured position navigation and timing, to improve capabilities and expand capacity to deliver prolonged care, perform evacuation, delivery emergency resupply of medical material supplies (Class VIII), such as blood products, by ground or air, in dispersed and Multi-Domain Operations and b) establish medical performance criteria to ensure Soldiers are able to effectively perform manned-unmanned teaming tasks; and, 2) Virtual Health - will leverage emerging technologies in information science, artificial intelligence, telecommunications network engineering, and cyber security to enable prolonged care, remote telemonitoring, automated decision support, and telementoring between providers in Role of Care 3 and 4 to patients in Role of Care 1 and 2. Promising work in this Project will be further matured in PE 0603002A (Medical Advanced Technology) / Project MM7 (Enabling Med Cap to Support Dispersed OPS Adv Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the United States Army Medical Research and Development Command (USAMRDC), Fort Detrick, MD.$$, NULL, NULL, NULL, NULL, NULL, 120000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603342D8Z_487$$, $$0603342D8Z$$, $$487$$, $$Nuclear advanced propulsion and$$, 0, $$DIU increases the Department's access to commercial technologies and talent, with the ultimate goal of fielding technology at a pace that effectively deters our adversaries and helps ensure victory if we are forced to fight. Consistent with the Administration's 2026 interim National Defense Strategy and the National Defense Science and Technology Strategy, this new era of competition requires technological superiority to ensure the United States’ ability to project power, maintain international norms and rule of law, provide credible deterrence, and prevail in conflict.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602788F_625319$$, $$0602788F$$, $$625319$$, $$Cyberspace Dominance$$, 42563000, $$This project will execute mission-driven applied research to develop and transition advanced technologies that secure and sustain superiority in the cyberspace domain, fully aligned with joint operations across air, land, sea, and space. The efforts under this Project will focus on three key pillars: (1) cyber offense—enabling precision effects and proactive disruption of adversarial capabilities; (2) cyber defense—ensuring robust protection of critical infrastructure, systems, and platforms against persistent and adaptive threats; and (3) cyber resilience—designing systems that can anticipate, absorb, and recover from attacks with speed and agility. By integrating these capabilities across multi-domain operations, these technologies support the Department of the Air Force's (DAF) and Department of Defense's (DoD) strategic vision for a secure, interoperable, and resilient digital ecosystem. It directly contributes to the development of agile, lethal, and networked forces capable of operating with decision advantage in highly dynamic threat environments.$$, 42563000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602792N_3456$$, $$0602792N$$, $$3456$$, $$Full Spectrum Undersea Warfare$$, 0, $$The Full Spectrum Undersea Warfare (FSUSW) Project will develop new technology for offensive and defensive warfare conducted on the seabed, in the sea (i.e. subsea), and from the sea. FSUSW focuses on Theatre Undersea Warfare (TUSW), Joint Targeting and Strike, and Subsea and Seabed Warfare (SSW). There are five thrust areas of FSUSW that are key to enabling Chief of Naval Operations Guidance (CNOG), Distributed Maritime Operations (DMO), and the Commandant's Stand in Force with manned and unmanned warfighting capability. These thrust areas were specifically chosen in direct collaboration with STRATCOM, INDO-PACOM, Fleet and Undersea Warfare Commanders and validated with regular Flag officer engagements. These applied research efforts will enable future undersea weapon systems (e.g., Maritime Strike Tomahawk and ADCAP variants), COCOM campaigns, and operational plans. FSUSW thrust areas include 1) Undersea effectors, 2) Integrated expeditionary subsea system of systems, 3) Multi-Vehicle Torpedo Tube Development System (MVTTDS), 4) Undersea UAV for Over-The-Horizon (OTH) effects and 5) Undersea Launched Devices to enable Commanding Officers and Regional Combatant Commander effects. The five thrust areas are technically and operationally interconnected. The efforts described in this Project address the Applied Research associated with the Innovative Naval Prototypes (INP) Program. These investments represent game changing technologies with the potential to revolutionize operational concepts. They are disruptive in nature, as they would dramatically change the way naval forces fight. Due to high technical risk, INPs typically have long duration but have no more than three years between decision points. They mature technologies from a Technology Readiness Level (TRL) of 2 or 3 to a TRL of 6. As such, INPs require both Budget Activity (BA) 2 and BA3 funding. The BA3 INP funds are specified in a separate Program Element (PE), 0603801N Innovative Naval Prototypes (INP) Adv Tec Dev in the Undersea Warfare Efforts, Project 3458. Information security concerns preclude fully detailed descriptions of project efforts, research activities, and technology development plans. Specific information on each project and activity will be provided separately to the Congressional oversight committees.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602792N_3461$$, $$0602792N$$, $$3461$$, $$MASS$$, 0, $$The rising use of air, surface, and sub-surface unmanned and autonomous systems requires a paradigm shift in the development, production, and life-cycle management of these systems in order to gain a competitive advantage against adversarial capabilities as well as allow for fielding of significant numbers (1000's to 10,000's) in an increasingly budget-constrained acquisition environment. The growth in rapid prototyping and additive manufacturing technologies presents an opportunity to capitalize on these advances though applied research efforts focused on scale-up both in terms of rapid production of relevant quantities as well as greatly increasing the physical size of platforms produced far beyond what is currently achievable. Manufacturing of Autonomous Systems at Scale (MASS) efforts will utilize wide range of advanced manufacturing methods combined with adaptive digital design processes with "Design for Low-Cost Platform Attriteability" as a major attribute to avoid the platform cost growths normally associated with exquisite systems development. This also represents the ability to rapidly modify platform attributes based on evolving operational needs and quickly insert into build process without costly retooling. Secondary goals focus on increasing commonality of critical components across platforms and design of these in modular fashion in order to manage supply chain vulnerability. Lastly, the project will look at ability to place manufacturing capability as far forward/afloat as possible to reduce the logistics tail and speed delivery of capability at-scale into the fleet. The activity identified in Project Unit 3461 MASS specifically addresses Applied Research in support of the MASS effort.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602792N_3462$$, $$0602792N$$, $$3462$$, $$DEALRS$$, 0, $$Adversary Anti-Access and Area Denial (A2/AD) capabilities continue to improve but remain focused on targeting specific US and joint force capabilities. The Deployment and Employment of Autonomous Long Range Systems (DEALRS) project will develop technologies that sidestep, operate below the threshold, or deplete adversary A2/AD capabilities. DEALRS will specifically develop technologies to enable low-cost unmanned systems that can maneuver across theater-level ranges to penetrate, operate within, and launch strikes from within adversary A2/AD system coverage. This project will develop technologies to increase the range and endurance of autonomous systems while maintaining tactically relevant speeds, loiter times, and signatures with low cost. It will also address technologies that enable the marsupial launch of terminal engagement autonomous unmanned systems across all domains from larger and/or longer-range host systems that bring them to the launch area and the associated technologies needed to ensure roboticized and autonomous startup and launch of the marsupial systems without human intervention. The Activity identified in Project Unit 3462 DEALRS specifically addresses Applied Research in support of the INP effort.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602792N_3463$$, $$0602792N$$, $$3463$$, $$MATes$$, 0, $$Traditionally, the utilization of autonomous systems is either operationally segregated from manned operations or requires a significant amount of human oversight when operating in conjunction with manned assets, which mitigates some of the advantage from using them. The goal of the Manned and Autonomous Teams (MATes) project is to develop autonomic robotic technology and collaborative autonomous behaviors that seamlessly operate across all domains in conjunction with manned units, allowing for real-time adaptation and optimization in a manner that streamlines the element of human interaction needed to share mission goals. This technology will monitor human or manned system teammate state, behavior, mission, and adversary threat status to anticipate and act in a tactically appropriate manner that is predictable, communicable, and trusted by the human/manned teammates and which enables autonomous system optimization in coordination with the human/ manned teammate and mission objectives. Intuitive human/autonomous system interfaces will be developed to allow focus on higher-order decision-making tasks by the operators allowing for large numbers of autonomous systems (100's or 1000's) to be managed in support of manned operations. The activity identified in Project Unit 3463 MATes specifically addresses Applied Research in support of the MATes effort.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602792N_3506$$, $$0602792N$$, $$3506$$, $$Compact Agile Interceptors$$, 0, $$The US Navy lacks both in capability and capacity interceptors that have the ability to defeat complex raids of hypersonic missiles, cruise missiles and surface vessels. The Compact Agile Interceptor INP will use small diameter missiles to achieve a higher packing efficiency. Disruptive seeker technology, which weighs mere ounces will replace wasted pounds of payload weight and allow for higher speed missile interceptors. The seedling will evaluate multiple propulsion technologies including solid fuel ramjets, highly loaded grain propellants, and active throttling of solid rockets. The missiles airframe may be staged to enable the interceptor(s) the greatest agility to overmatch the threat. Multiple warhead technologies will be evaluated including reactive materials, kinetic warheads, and tailorable fragment warheads. The Activity identified in Project Unit 3506 specifically addresses Applied Research in support of the Compact Agile Interceptors INP effort.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602792N_3507$$, $$0602792N$$, $$3507$$, $$Chimera$$, 0, $$Details at a higher classification$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602792N_3508$$, $$0602792N$$, $$3508$$, $$Curious Orion$$, 0, $$The USN lacks a breadth of tools to find fix and finish high end maritime threats across specific environments and conditions. Curious Orion will develop a unique capability to exploit specific phenomenology produced by submerged bodies in operationally relevant areas that are of specific interest to the U.S. Navy. The Activity identified in Project Unit 3508 specifically addresses Applied Research in support of the Curious Orion INP effort.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602792N_5891$$, $$0602792N$$, $$5891$$, $$Naval S&T Ops Analysis, Supp &$$, 0, $$Operational Analysis, Support and Experimentation Activity was established to broaden the spectrum of promising applied research efforts investigated within this Project and to provide additional acquisition oversight, fiscal clarity, and adherence to financial management practices at the Project level. The efforts described in this Project address the Applied Research associated with Innovative Naval Prototype (INP) Operational Analysis, Support and Experimentation Activity efforts that are used to further explore the development of future INP topics and proposals. These efforts evaluate, study/analyze and/or perform any basic applied research-focused investigative experimentation activities which will support the identification of potential INP topics for future investment consideration. The use of Operational Analysis, Support and Experimentation Activity funds can help accelerate and/or create a flexible response to emerging requirements or threats by identifying a potential INP topic for consideration in a more time-efficient and/or effective manner.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602792N_5892$$, $$0602792N$$, $$5892$$, $$Full Spectrum Information Warfare$$, 0, $$The Full Spectrum Information Warfare (FSIW) effort will develop integrated holistic Counter-C5ISRT capability, techniques and CONOPS to defeat adversarial capacity growth to include the effects of the maritime environment on tactics and effectiveness in order to provide the proliferation of C-C5ISRT payloads on small to large platforms and software to calculate EM propagation and take into account environmental conditions from "DC to Daylight" e.g. from VLF/HF through optical frequencies to optimize both passive and active C-C5ISRT technology use. The efforts described in this Project address the Applied Research associated with concept of a "Seedling". These "Seedling" efforts are short duration applied research efforts to explore technology concepts which have the potential to provide revolutionary and/or disruptive warfighting capability. As a "Seedling" concept matures, a determination is made whether or not a continuing INP effort is warranted or appropriate. "Seedlings" are typically one to two year efforts and use applied research to analyze the feasibility of technology and subsystems to assess if the technologies can be proposed as an INP. They will research lower TRL technologies to explore technology concepts and lay preliminary groundwork for an INP proposal to continue technology development and full-scale technology/operational demonstrations. The Activity identified in this Project Unit specifically addresses Applied Research in support of the FSIW INP effort.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602792N_5893$$, $$0602792N$$, $$5893$$, $$Decision Superiority$$, 0, $$The Decision Superiority (DS) effort will improve the speed and quality of decisions when conducting undersea warfare activities at the tactical edge that does not require persistent communication reach back. This will be achieved through the development of Decision Aids (DAs) using a holistic Human-Machine-Teaming (HMT) and training approaches and processes to optimize warfighter decisions (e.g. sonar operations, maintenance repair, personnel rotations). The efforts described in this Project address the Applied Research associated with concept of a "Seedling". These "Seedling" efforts are short duration applied research efforts to explore technology concepts which have the potential to provide revolutionary and/or disruptive warfighting capability. As a "Seedling" concept matures, a determination is made whether or not a continuing INP effort is warranted or appropriate. "Seedlings" are typically one to two year efforts and use applied research to analyze the feasibility of technology and subsystems to assess if the technologies can be proposed as an INP. They will research lower TRL technologies to explore technology concepts and lay preliminary groundwork for an INP proposal to continue technology development and full-scale technology/operational demonstrations. The Activity identified in this Project Unit specifically addresses Applied Research in support of the Decision Superiority INP effort.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602792N_5894$$, $$0602792N$$, $$5894$$, $$Direct-X$$, 0, $$The Direct-X effort will develop space based ISRT with direct downlink into kill chains supporting all domain effects in a Distributed Maritime Operations construct. The focus is on advances in the following lines of effort: P1 - Orchestration, tasking and resilient C3 P2 - Threat prioritized low cost on orbit payloads P3 - On orbit processing and analyitic AI/ML P4 - Direct-to-shooter kill chains P5 - On orbit effects The efforts described in this Project address the Applied Research associated with concept of a "Seedling". These "Seedling" efforts are short duration applied research efforts to explore technology concepts which have the potential to provide revolutionary and/or disruptive warfighting capability. As a "Seedling" concept matures, a determination is made whether or not a continuing INP effort is warranted or appropriate. "Seedlings" are typically one to two year efforts and use applied research to analyze the feasibility of technology and subsystems to assess if the technologies can be proposed as an INP. They will research lower TRL technologies to explore technology concepts and lay preliminary groundwork for an INP proposal to continue technology development and full-scale technology/operational demonstrations. The Activity identified in this Project Unit specifically addresses Applied Research in support of the Direct-X INP effort.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602792N_5895$$, $$0602792N$$, $$5895$$, $$DMO through IAS$$, 0, $$The Distributed Maritime Operations though Intelligent Autonomous Systems (DMO-IAS) effort will demonstrate IAS teams that can maneuver and close sea denial detect through engage/ assess kill-chains over tactically relevant ranges and extended mission durations, that maintain survivability through avoidance of detection, and that do not rely on vulnerable command and control systems. It will explore novel sensing, autonomy, and communications approaches that can be applied to other Navy IAS programs that enable robust, resilient IAS kill-chains. The efforts described in this Project address the Applied Research associated with concept of a "Seedling". These "Seedling" efforts are short duration applied research efforts to explore technology concepts which have the potential to provide revolutionary and/or disruptive warfighting capability. As a "Seedling" concept matures, a determination is made whether or not a continuing INP effort is warranted or appropriate. "Seedlings" are typically one to two year efforts and use applied research to analyze the feasibility of technology and subsystems to assess if the technologies can be proposed as an INP. They will research lower TRL technologies to explore technology concepts and lay preliminary groundwork for an INP proposal to continue technology development and full-scale technology/operational demonstrations. The Activity identified in this Project Unit specifically addresses Applied Research in support of the DMO through IAS INP effort.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602792N_5896$$, $$0602792N$$, $$5896$$, $$Echidna$$, 0, $$The Echidna effort will develop additive capability and additive capacity which is classified. It will explore new mine development, to include improved sensing for a highly complex environment and target, improved lethality, endurance and power technologies, cost-effective additive manufacturing subcomponent technologies, and flexible, platform-agnostic engineering design (to include safe & arming device) to allow for novel and adaptable concepts of employment (CONEMP) The efforts described in this Project address the Applied Research associated with concept of a "Seedling". These "Seedling" efforts are short duration applied research efforts to explore technology concepts which have the potential to provide revolutionary and/or disruptive warfighting capability. As a "Seedling" concept matures, a determination is made whether or not a continuing INP effort is warranted or appropriate. "Seedlings" are typically one to two year efforts and use applied research to analyze the feasibility of technology and subsystems to assess if the technologies can be proposed as an INP. They will research lower TRL technologies to explore technology concepts and lay preliminary groundwork for an INP proposal to continue technology development and full-scale technology/operational demonstrations. The Activity identified in this Project Unit specifically addresses Applied Research in support of the Echidna INP effort.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602792N_5897$$, $$0602792N$$, $$5897$$, $$Hypersonic Technologies$$, 0, $$The Hypersonic Technologies effort will develop technologies that support the unique operational and environment aspects of hypersonic weapon systems. Efforts include: advanced materials; propulsion; stability and control; seekers and sensors; guidance, navigation, and control; and payloads and energetics. The efforts described in this Project address the Applied Research associated with concept of a "Seedling". These "Seedling" efforts are short duration applied research efforts to explore technology concepts which have the potential to provide revolutionary and/or disruptive warfighting capability. As a "Seedling" concept matures, a determination is made whether or not a continuing INP effort is warranted or appropriate. "Seedlings" are typically one to two year efforts and use applied research to analyze the feasibility of technology and subsystems to assess if the technologies can be proposed as an INP. They will research lower TRL technologies to explore technology concepts and lay preliminary groundwork for an INP proposal to continue technology development and full-scale technology/operational demonstrations. The Activity identified in this Project Unit specifically addresses Applied Research in support of the Hypersonic Technologies INP effort.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602792N_5899$$, $$0602792N$$, $$5899$$, $$Precision Fire Control$$, 0, $$The Precision Fire Control (PFC) effort will develop a fire control architecture that delivers high precision, high update rate guidance solutions to enable cruise missile defense with small, low-cost interceptors and dramatically increase number of interceptors per ship or Expeditionary Advanced Base. It will develop fire control capability for multiple interceptors (missiles and gun projectiles) that contribute to layered defense of surface combatants, expeditionary forces, and homeland protection. Develop PFC-enabled low-cost missile (LCM) based on existing 2.75" rocket components. The Activity identified in this Project Unit specifically addresses Applied Research in support of the PFC INP effort.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602792N_5901$$, $$0602792N$$, $$5901$$, $$STARDANCAR-M$$, 0, $$The Small Turbofan Augmentor with Rotating Detonation for Autonomous Collaborative Aircraft and Missiles (STARDANCAR-M) effort will add a Rotating Detonation Augmentor (RDA) to small engines, decreasing the burning length: - Autonomous Collaborative Aircraft (ACA) with RDA will keep up with tactical vehicles - Missiles with RDA will achieve higher speeds - Subsonic missiles will have increased evasion capabilities and terminal velocity The efforts described in this Project address the Applied Research associated with concept of a "Seedling". These "Seedling" efforts are short duration applied research efforts to explore technology concepts which have the potential to provide revolutionary and/or disruptive warfighting capability. As a "Seedling" concept matures, a determination is made whether or not a continuing INP effort is warranted or appropriate. "Seedlings" are typically one to two year efforts and use applied research to analyze the feasibility of technology and subsystems to assess if the technologies can be proposed as an INP. They will research lower TRL technologies to explore technology concepts and lay preliminary groundwork for an INP proposal to continue technology development and full-scale technology/operational demonstrations. The Activity identified in this Project Unit specifically addresses Applied Research in support of the STARDANCAR-M INP effort.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603042A_CN3$$, $$0603042A$$, $$CN3$$, $$Network Enabling University Adv$$, NULL, $$This Project matures and demonstrates advanced Network Command, Control, Communications, and Intelligence (C3I) technologies into future equipment and systems. This Project accelerates advanced technologies originating from extramural research in academia, will enable intelligent networks, self-sensing/self-healing network, network security, advanced teaming and operations in a Global Positioning System (GPS) degraded or denied GPS environment. This Project also accelerates the Army modernization in next generation Network and Assured Positioning, Navigation, and Timing (APNT) systems. Work in this Project will lead to emerging technologies in areas of strategic importance to the Army in communications and networking, by engaging competitively selected Universities. Work in this Project complements Program Element (PE) 0602182A (C3I Applied Research) / Project CN4 (Network Enabling University Applied Research). The work cited is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Army Research Laboratory (ARL).$$, NULL, NULL, NULL, NULL, NULL, 3884000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602792N_5902$$, $$0602792N$$, $$5902$$, $$TALISMAN$$, 0, $$The Tactical Autonomous Layered Infrastructure for Spectrum Maneuvers And Networking (TALISMAN) effort distributes sensors across a network of many small, low-cost, high-endurance platforms that provide resilience in a contested environment and use autonomy to enable agile adaptability to threats and changing mission objectives. Innovative airframe designs and controls enable small deck ships to organically deploy TALISMAN sensing & EW networks and engage long-range fires with weapons quality tracks out to 450 NM from the ship. TALISMAN's size allows the ship to carry enough platforms to maintain 24hr coverage. The efforts described in this Project address the Applied Research associated with concept of a "Seedling". These "Seedling" efforts are short duration applied research efforts to explore technology concepts which have the potential to provide revolutionary and/or disruptive warfighting capability. As a "Seedling" concept matures, a determination is made whether or not a continuing INP effort is warranted or appropriate. "Seedlings" are typically one to two year efforts and use applied research to analyze the feasibility of technology and subsystems to assess if the technologies can be proposed as an INP. They will research lower TRL technologies to explore technology concepts and lay preliminary groundwork for an INP proposal to continue technology development and full-scale technology/operational demonstrations. The Activity identified in this Project Unit specifically addresses Applied Research in support of the TALISMAN INP effort.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602792N_9999$$, $$0602792N$$, $$9999$$, $$Congressional Adds$$, 0, $$Congressional add projects not included in other efforts.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602861N_0000$$, $$0602861N$$, $$0000$$, $$Science & Tech Management - ONR$$, 72085000, $$This project supports ONR leadership, management and direction for the Naval S&T program. This project funds ONR HQ Non-Management Headquarters Activities (Non-MHA) salaries, communications, and other fixed costs. ONR sponsors scientific advances, which lead to Future Naval Capabilities (FNCs), supporting the Fleet's ability to operate from a position of technological superiority. Functions performed include (1) scientific and technical direction of the nationwide 6.1 basic research program with colleges, universities, non-profit organizations and Naval Laboratories and Warfare Centers; (2) scientific and technical direction of the 6.2 applied research program through the Naval R&D laboratories and Warfare Centers and industry; (3) scientific and technical direction of the Naval 6.3 advanced technology development program through the Navy's R&D laboratories, Warfare Centers and industry; (4) management, resource formulation, program assessment, and contract negotiation/administration of the Navy basic research, applied research and advanced technology development program; and (5) coordination of the Navy's Technology Base program within the context of total DoD/Government (e.g., National Science Foundation, National Academy of Sciences) R&D initiatives in order to maximize scientific advances. This project also supports ONR Non-MHA management and direction for the following Navy-wide programs: Small Business Innovation Research, Naval Research Advisory Committee, Navy Patent Program, Historically Black Colleges and Universities/Minority Institutions Program, Navy Manufacturing Technology Program and the Ballistic Missile Submarine Nuclear (SSBN) Security Technology Program. Additionally, this project funds ONR field salaries, communications, and other fixed costs.$$, 72085000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602861N_0824$$, $$0602861N$$, $$0824$$, $$Science & Technology Managment$$, 9338000, $$This Project provides funds for Non-Labor costs associated with executing ONR's mission to discover, develop, and transition innovative science and technology (S&T) to meet current and future needs of naval forces. Most all the funds in this project are fixed costs, such as communications, training, and other support functions.$$, 9338000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602890D8Z_890$$, $$0602890D8Z$$, $$890$$, $$High Energy Laser Development$$, 48738000, $$This project is part of an overall Department of Defense strategy in Joint directed energy applied research. Efforts within this project will focus on the advanced technologies necessary to increase lethality, expand the mission set, and counter future adversaries. Advancements provided by this project are essential to improve the performance of existing and new directed energy weapon systems. This project builds upon other investments in directed energy applied research by the Services and Agencies to harmonize Department efforts and eliminate duplication. In support, efforts in this project have been coordinated with the Department of Defense Directed Energy and Non-Lethal Weapons Science and Technology Community of Interest. This project is executed via a technical program within the JDETO referred to as the Directed Energy Enabling Tech Program, which enables (1) applied research in high energy laser and high power microwave technologies that support eventual system-level integration and (2) proof of concept tech demonstrations in a laboratory environment with Joint-international participation. Note that (1) and (2) are in alignment with the near-, mid-, and long-term goals of Department of Defense Directed Energy Roadmap and encourage transition.$$, 48738000, NULL, NULL, NULL, NULL, 91836000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0602891D8Z_360$$, $$0602891D8Z$$, $$360$$, $$FSRM$$, 994000, $$The FY 2026 request for FSRM Modeling includes $994 thousands of discretionary and $5,000 thousand of mandatory (reconciliation) for a total of $5,994 thousands. The mandatory funds Golden Dome Cyber Resilience and Readiness Exercises. Further information for this reconciliation request is provided in Section 20003 Missile Defense of the Reconciliation Exhibit. The FSRM Modeling requirement is inclusive of the development of a computer system, development of software, development of standards for the FSRM prioritization. This will aid in the establishment metrics for adjudicating FSRM funding sufficiency for use in future program and budget reviews. Golden Dome Cyber Resilience and Readiness Exercises funding ($5M) supports the assessment of the control systems which allow for the Golden Dome mission execution. The funding will be used to develop "live fire" cyber resilience exercises to assess the readiness and resilience of the control systems at Golden Dome installations. These live exercises will afford the system owners and operators hands on experience in detecting and providing defense against APT- actor cyber-attacks and the physical disruptions that can result.$$, 994000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603042A_DI6$$, $$0603042A$$, $$DI6$$, $$Anti-Tamper Advanced Tech$$, 1224000, $$This Project matures and demonstrates Anti-Tamper tools, devices, and techniques that protect acquisition program systems and Critical Program Information (CPI) from evolving adversarial reverse engineering threats. Efforts are coordinated with Department of Defense (DoD) Executive Agent for Anti-Tamper. Work in this Project complements Program Element (PE) 0602146 (Protective Technologies) / Project AV5 (Protective Technologies). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the Aviation and Missile Center (AvMC).$$, 1224000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603000D8Z_077$$, $$0603000D8Z$$, $$077$$, $$Enhanced Munitions Advanced$$, 8433000, $$The Enhanced Munitions Advanced Technology project demonstrates advanced technologies that improve the performance, range, and lethality of existing and future weapons systems. This effort takes promising technologies demonstrated at the laboratory scale and matures them into demonstration programs with a focus on operationally relevant key munitions. Enhanced Munitions technologies that are matured and demonstrated at Technology Readiness Level 5 inform service requirements and transition into operational use, thereby decreasing program executive office program cost and risk. In FY 2026, the project continues the development of critical munitions technologies, such as advanced materials and designs, fuzing, power sources, seeker technologies, and counter countermeasure technologies that, when combined with advanced energetics, provide significant performance enhancements in range, speed, and target damage effects. This project applies machine learning, artificial intelligence, and advanced material technologies to inform and refine research efforts and enable next-generation kinetic weapons capabilities, including advances in propulsion, warhead effects, fuze technologies, and targeting technologies. In FY 2026, the Munitions Advanced Technology project continues to address the critical munitions technologies that are necessary for realizing weapon performance improvements particularly for low-cost alternative munitions and defensive munitions. Increases in weapon range and run time require higher energy density power sources for guidance, seekers, and other subsystems. Lethality increases are not only dependent on advanced energetics, but also depend on optimized munitions placement, burst point control, and survivable fuzing. Operations in highly contested scenarios also require technical resiliency, with systems capable of defeating adversary kinetic and non-kinetic countermeasures. In FY 2026, the Munitions Advanced Technology project will continue to address the critical munitions technologies that are necessary for realizing performance improvements from Energetics Advanced Technology investments. Increases in weapon range and run time require higher energy density power sources for guidance, seekers, and other subsystems. Lethality increases are not only dependent on advanced energetics, but also depend on optimized munitions placement, burst point control, and survivable fuzing. Operations in contested environments requires technical resiliency, with systems capable of defeating adversary kinetic and non-kinetic countermeasures.$$, 8433000, NULL, NULL, NULL, NULL, 33577000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603000D8Z_356$$, $$0603000D8Z$$, $$356$$, $$Energetics Advanced Technology$$, 42230000, $$U.S. weapons systems still largely rely on decades-old explosive and propellant technologies that limit Joint Force options to deter, and if necessary, defeat adversaries in conflict. The Energetics Technology project was established to expedite investigation, research, and transition of novel energetics materials, chemicals, and processes that enable improvements to existing and future munitions performance. The investments and efforts under this project enable modern manufacturing and processing while helping to bolster U.S. energetics supply chain resiliency. The Joint Enhanced Munitions Technology Program, Services, and OUSD(R&E) munitions stakeholders collaborate to generate technology roadmaps for advanced energetic research and development that include high-energy materials, such as CL-20, and missile delivered submunitions and payloads.$$, 42230000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603002A_MM2$$, $$0603002A$$, $$MM2$$, $$MEDICAL ADVANCE$$, NULL, $$Congressional Interest Item funding for Medical Advanced Technology Initiatives. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy.$$, NULL, NULL, NULL, NULL, NULL, 14734000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603002A_MM7$$, $$0603002A$$, $$MM7$$, $$Enabling Med Cap to Support$$, 917000, $$Matures and demonstrates a tele-monitored and remote-controlled Combat Evacuation Mission Module to support medical resupply and casualty evacuation using future multi-purpose Vertical Take-Off and Landing (VTOL) unmanned aircraft systems (UAS). Provides a self-contained medical module capability adaptable to various future multi- purpose VTOL UAS. Matures and demonstrates an intelligent decision-support capability that can be operated on an Army or Navy provided End User Device (EUD), such as the NETT Warrior system, to assist medics with patient assessment, triage, treatment, and disposition in a Prolonged Field Care (PFC) environment by assessing patient conditions to provide adaptive care guidelines.$$, 917000, NULL, NULL, NULL, NULL, 825000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603002A_MN7$$, $$0603002A$$, $$MN7$$, $$Musculoskeletal Injury Screening Tool$$, 482000, $$This Project develops strategies and technologies to reduce musculoskeletal injury (MSKI) rates and improve outcomes following Return to Duty (RTD) in the Army training, operational, and medical communities to improve Soldier readiness. This research will inform the development of technologies and strategies to detect and provide actionable information to unit leader/Soldier about hazardous exposure to blast and head impact. This capability will help prevent degradation to Soldier cognitive readiness and performance and enhance combat power. The cited research is fully coordinated with Program Element (PE) 0602143A (Soldier Lethality Technology) and complimentary to PE 0603118A (Soldier Lethality Advanced Technology) and is fully coordinated with the Army Training and Doctrine Command (TRADOC) and other Services in order to avoid duplication of effort. The cited work is consistent with the Under Secretary of Defense (Research and Engineering) science and technology focus areas and the Army Modernization Strategy.$$, 482000, NULL, NULL, NULL, NULL, 734000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603002A_MO8$$, $$0603002A$$, $$MO8$$, $$Expeditionary Performance Nutrition$$, 106000, $$This Project covers the development of real-time, specific, and individualized interventions to optimize mental acuity and fatigue and manage metabolic and nutritional needs to sustain Soldier physical, mental, and immunological performance. The cited research is fully coordinated with Program element (PE) 0602143A (Soldier Lethality Technology) and complimentary to PE 0603118A (Soldier Lethality Advanced Technology) and is fully coordinated with other Services in order to avoid duplication of effort. The cited research is consistent with the Under Secretary of Defense (Research and Engineering) science and technology focus areas and the Army Modernization Strategy.$$, 106000, NULL, NULL, NULL, NULL, 705000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603002A_MP3$$, $$0603002A$$, $$MP3$$, $$Phys Chem Toxicity Assessment Sys$$, 355000, $$This Project covers the development of products and solutions that will protect and prevent degradation of Soldier health, readiness and performance from environmental stressors (heat, cold, altitude, and chemical toxicants) while conducting prolonged operations in Multi-Domain Operations (MDO). Develop algorithms and physiological models to inform unit leaders and Soldiers and provide actionable information and interventions to manage metabolic needs, maintain performance, and avoid non-battle injuries while operating in extreme environments. This Project contains no duplication with any effort within the Military Departments and includes direct participation by other Services. The cited research is fully coordinated with Program Element (PE) 0602143A (Soldier Lethality Technology) and complimentary to PE 0603118A (Soldier Lethality Advanced Technology). The cited research is consistent with the Under Secretary of Defense, Research and Engineering Science and Technology, focus areas and the Army Modernization Strategy.$$, 355000, NULL, NULL, NULL, NULL, 1732000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603041A_CM2$$, $$0603041A$$, $$CM2$$, $$Collaborative Convergence Adv Tech$$, 10560000, $$This Project develops and integrates critical persistent experimentation technologies and the architecture through which the persistent experimentation technologies will operate. This is accomplished using adaptive data fusion and task allocation algorithm to support the development of Artificial Intelligence (AI) decision support agents. This Project includes development of advanced methods for processing and information extraction for mission oriented tasks in support of tactical decision makers. Additionally, this Project will develop the scalable architecture solutions necessary to facilitate tactical data collection, movement, processing, storage and modeling and simulation necessary to enable mission command in multi-domain operations. Also, the Project will shape early programs to accelerate technologies and achieve sensor to shooter dominance. Work in this Project complements Program Element (PE) 0602181A (All Domain Convergence Applied Research). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Analysis Center, Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Center, Ground Vehicle Systems Center (GVSC), and Aviation & Missile Center (AvMC).$$, 10560000, NULL, NULL, NULL, NULL, 17710000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603007A_792$$, $$0603007A$$, $$792$$, $$Personnel Performance & Training$$, 13559000, $$This Project matures and demonstrate applied behavioral and social science technologies that enhance the Soldier Lifecycle (e.g., selection, assignment, training, leader development) and human relations (e.g., unit cohesion). These technologies provide advanced personnel measures that more fully assess potential and predict performance, behavior, attitudes, and resilience. These technologies also provide innovative and effective Talent Management methods to optimize individual and team performance to ensure the Army can meet mission requirements in uncertain and complex environments. This demonstrates new selection measures, assignment methods, and performance metrics for individuals and units; assesses innovative leader development and learning methods, and conducts scientific assessments to inform Human Capital policy and programs. Research will result in effective non-materiel solutions to help the Army adjust to changes in force size and structure, a variety of mission demands and contexts, challenges in human relations, and budgetary constraints. Work in this Project complements PE 0602785A (Personnel Performance & Training Technology) The cited work is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology priority focus areas, the Army Vision, the Army People Strategy, the Army's Talent Management Strategy, and the Army Modernization Strategy. Work is performed by the United States Army Research Institute (ARI) for the Behavioral and Social Sciences in Fort Belvoir, VA.$$, 13559000, NULL, NULL, NULL, NULL, 15845000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603021D8Z_459$$, $$0603021D8Z$$, $$459$$, $$National Security Innovation Capital$$, 1395000, $$The mission of NSIC is to accelerate the development of dual-use hardware technologies critical to our national security and economic competitiveness. It is an initiative that enables dual-use hardware startups to advance key milestones in their product development by addressing the shortfall of private investment from trusted sources. NSIC's support enables companies to develop their technologies and products more rapidly. The resulting reductions in technical risk, along with the signaling of DoD interest in such dual-use companies, attracts trusted private investment that might otherwise sit on the sidelines. The overall result is more rapid and robust development of hardware in the United States, the expansion of the defense industrial base, and reduction of technology flow to adversaries. Areas of focus are autonomy, communications, power, sensors and space.$$, 1395000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603025A_CK8$$, $$0603025A$$, $$CK8$$, $$Advanced Technology Development$$, 10068000, $$The Army aims to accelerate finding innovative solutions for the warfighter's difficult technological problems. This effort develops new ways of doing business to include strategic and non-traditional partnerships while working with traditional vendors in novel ways to allow for agile integration of leading-edge technology. This effort enables the Army to quickly implement novel solutions garnered from operational experimentation. It allows the Army to accelerate efforts with industry to better inform requirements. Army Futures Command senior leadership approves innovation projects in the budget year and year of execution based on priority and opportunity, ensuring that innovations have a high potential for filling capability gaps. These efforts transition to programs of record; transition to Army Science and Technology (S&T) projects; inform requirements and concepts; and, when appropriate, transition directly to the warfighter. The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas. Work is performed by the Army Applications Laboratory (AAL).$$, 10068000, NULL, NULL, NULL, NULL, 13500000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603025A_DA3$$, $$0603025A$$, $$DA3$$, $$Army Advanced Innovation$$, 9611000, $$This Project funds the Advanced Development portion of the Army Innovation Plan, the Army's investment strategy to rapidly accelerate innovative solutions to challenging Warfighter problems. This Project will provide the Army with the most advanced and cutting-edge solutions with the ability to adapt and integrate multi- disciplinary innovative technologies by bridging the interfaces between internal and external efforts for a holistic entry into the acquisition pipeline at the most appropriate milestone. Cross-cutting modernization initiatives leverage strategic partnerships that foster an environment to bring knowledge and expertise to demonstrate innovative technologies that will benefit the warfighter. The pace of advancing technology and the flexibility to respond to cutting-edge technology at the Speed of Innovation, will accelerate the development of unanticipated technology opportunities, and allow the Army to rapidly deliver capabilities to the Soldier. Through the Army's Innovation Oversight Board, the Army senior leadership approves the Innovation projects in the budget year and year of execution based on priority and opportunity, ensuring that innovations have a high potential for filling capability gaps and transitioning to Army S&T projects to inform an optimal technology investment strategy and rapidly deliver capabilities to the Soldier. This Project is coordinated with Program Element (PE) 0602002A (Army Agile Innovation and Development-Applied Research) / Project DC4 (Army Applied Innovation). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas. Work is performed by the United States Army Combat Capabilities Development Command (DEVCOM), Army Artificial Intelligence Integration Center (AI2C), the Engineering Research and Development Center, Space and Missile Defense Technical Center, the United States Army Research Institute for the Behavioral and Social Sciences, and the Army Research Laboratory (ARL).$$, 9611000, NULL, NULL, NULL, NULL, 12013000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603032F_630320$$, $$0603032F$$, $$630320$$, $$Air Force Vanguards$$, 268754000, $$This Program is a concentrated effort to evolve Air Force Research Laboratory (AFRL) business practices to accelerate transition of emerging technologies into the hands of the warfighter. Vanguard programs draw the operational, acquisition, and technology communities together into coherent teams to solve hard Science & Technology (S&T) problems based on Department of the Air Force (DAF) strategic priorities which do not have readily available emerging technology solutions. Teams follow a disciplined process to accelerate efforts as deemed necessary by the department. This process (known as WARTECH, for WARfighter / TECHnologist) utilizes discrete progress gates to deliver S&T efforts organized as Vanguard Pathfinders, Vanguard Prospects, and Vanguards. This construct organizes these multi- disciplinary, capability-focused investments based on characteristics such as effort maturity, established military utility, technical viability and transitionability. Each progress gate has built-in off-ramps to promote transition. The process is overseen by an Executive Committee, whose membership includes the DAF Technical Leadership, operational requirements representatives, and acquisitions communities. Vanguard Pathfinders are focused thrust areas which comprise numerous exploratory efforts intended to establish military utility and technical viability of concepts under exploration. Extensive socialization occurs within these efforts to inform activities inherent to these emerging investment areas. Concept socialization activities include but are not limited to the codification of the operational champion, planning engagements with other government R&D, exploratory outreach to industry and other non- traditional partners, and the initial identification of potential transition partners. These investments seek to identify and integrate emerging applied research efforts from government labs and/or industry into integrated technology demonstrations. Vanguard pathfinder teams seek to bring appropriate communities together to answer the question "are we solving the right problem” while establishing technical viability of the concepts under consideration. This phase can be accelerated or bypassed for efforts with well understood operational requirements and concepts with established technical viability. Pathfinders serve as the pipeline for DAF's future Vanguards Prospects and Vanguards. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0603032F / Future AF Integrated Technology Demos Technology Development (ATD) Vanguard Prospects focus on maturing contributing technologies in accordance with the technical objectives of the effort while further engaging acquisitions communities and industry partners. Teams draw in technologies from multiple sources and ensure use of the right technologies. By establishing fielding strategies, teams solve the problem in a transitionable way. Vanguard Prospects provide focused S&T investment to accelerate the maturation of contributing technologies while laying the foundation for the effort to achieve full Vanguard status or transition into a Program of record. Vanguards build on the foundational work of the earlier stages, maturing and integrating contributing technologies to demonstrate solutions to the department's most pressing S&T problems based on DAF strategic requirements. Vanguard Programs - high risk by design - are focused, Secretary of the Air Force-priority initiatives with enterprise commitment. They are commissioned by the Assistant Secretary of the Air Force for Acquisition, Technology and Logistics, the Vice Chief of Staff of the Air Force, and the Vice Chief of Space Operations as DAF investments. This program element may include necessary civilian pay expenses required to manage, execute, and deliver science & technology capabilities. This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. The FY 2026 request was reduced by $0.487 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment.$$, 268754000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603040A_CL1$$, $$0603040A$$, $$CL1$$, $$AI Enhanced Intel Operations$$, 1859000, $$Artificial Intelligence (AI) Enabled Intelligence Fusion for Targeting will address a "multi-INT" fusion problem and mature and demonstrate how AI algorithms can fuse data from various military intelligence systems to support sensor to shooter automation for the strategic, operational, and tactical levels. This effort will mature and demonstrate AI capabilities for support of Long-Range Precision Fires, Mission Command, and Maneuver Commanders by exploiting Intelligence Community enterprise investments in sensing, data transport, and Machine Learning (ML) / AI frameworks. These technologies will produce software, novel algorithms and models, and knowledge products. Work in this project complements Program Element (PE) 0602180A (Artificial Intelligence and Machine Learning Advanced Technologies) / Project CL2 (AI Enhanced Intel Operations Technologies). The cited work is consistent with Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the Artificial Intelligence Integration Center (AI2C).$$, 1859000, NULL, NULL, NULL, NULL, 1309000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603040A_CL6$$, $$0603040A$$, $$CL6$$, $$ATR Using Multiple Cooperative$$, 6525000, $$This Project will mature and demonstrate Artificial Intelligence (AI) algorithms/models and supporting systems that leverage a team of air and ground sensors to autonomously navigate and collaborate through shared perception of the optical, thermal, and electromagnetic spectrums to find, identify, geo-locate, track, and help engage targets during reconnaissance missions. These technologies will produce a mix of fully integrated software, AI algorithms/models, and ground-based/aerial- based drones to execute reconnaissance and engagement tasks in battlefield conditions. Work in this project complements Program Element (PE) 0602180A (Artificial Intelligence and Machine Learning Advanced Technologies) / Project CL7 (ATR Using Multiple Cooperative Sensors App Tech) The cited work is consistent with Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project supports the Army Science and Technology Lethality Portfolio and the Joint Artificial Intelligence Center (JAIC).$$, 6525000, NULL, NULL, NULL, NULL, 4730000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603040A_CN6$$, $$0603040A$$, $$CN6$$, $$Predictive Maintenance Advanced$$, 5328000, $$This Project matures and demonstrates artificial intelligence (AI) and machine learning (ML) tools and capabilities to predict and analyze maintenance status for emerging and legacy aviation and ground platforms. Will extract maintenance data from databases and sensors and make inferences of missing data via virtual simulations and improve and provide AI data capture and other AI tools for enterprise maintenance resource planning for military aviation and ground vehicles. Platforms of focus will be prioritized by cost and value to Army missions and include the UH60, AH64, CH47, Stryker, and Abrams. Each platform will be sequentially evaluated both at the component (i.e. engine health) and fleet level. This Project matures and demonstrates the use of predictive maintenance to increase fleet operational readiness through reduced downtime by preventing critical failure during missions to maximize availability to combatant commands. Results from this project will inform requirements and technical architectures for a predicative maintenance platform that will include data engineering, data pipelines, AI development eco-system, and application delivery. These technologies will produce a suite of applications hosted at both the enterprise and at the edge that provide AI-enabled support tools decision- making for maintainers and commanders. Work in this project complements Program Element (PE) 0602180A (Artificial Intelligence and Machine Learning Advanced Technologies) / Project CN7 (Predictive Maintenance Applied Research). The cited work is consistent with Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the Artificial Intelligence Integration Center (AI2C).$$, 5328000, NULL, NULL, NULL, NULL, 3967000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603040A_CT8$$, $$0603040A$$, $$CT8$$, $$Army AI Integration Center Adv$$, NULL, $$Congressional Interest Item funding provided for Army AI Integration Center Advanced Research. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy.$$, NULL, NULL, NULL, NULL, NULL, 11500000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603040A_DA7$$, $$0603040A$$, $$DA7$$, $$AI-Enabled Command and$$, 3250000, $$This Project matures and demonstrates solutions for Artificial Intelligence (AI)-enabled Command and Coordination (C2) that provide timely understanding and application of the commander's intent. This Project improves sensor-to-shooter and course of action development timelines by developing algorithms, software, and hardware to efficiently capture, transport, process, and convey complex battlefield data into user friendly, streamlined, interfaces. This Project also exploits advances in the application of game theory to explore hypothetical operational scenarios that inform mission planning. These technologies will optimize mission command and network capabilities to fully realize AI on the battlefield. These technologies will produce software, novel algorithms and models, and knowledge products that focus on enabling commanders and their staffs with the ability to conduct mission command to achieve C2 overmatch. Work in this Project complements Program Element (PE) 0602180A (Artificial Intelligence and Machine Learning Technologies) / Project DA6 (AI-Enabled Command and Coordination Apl Research). The cited work is consistent with Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the Artificial Intelligence Integration Center (AI2C).$$, 3250000, NULL, NULL, NULL, NULL, 1345000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603040A_DE9$$, $$0603040A$$, $$DE9$$, $$AI Development Environment$$, 2777000, $$This Project funds the Army lacking a common platform to develop AI/ML. This results in siloed and duplicative work that is inefficient. Many current solutions have narrow application and are proprietary, requiring additional funding, time, and labor to make even minor modifications. The AI-enabled Army of the future will require low cost, rapid AI/ML solutions at the edge. This project will mature and demonstrate a set of platform(s), and infrastructure optimized for Army use and ready for rapid employment in enterprise, multi, and hybrid cloud environments to support modular software (cloud native) intended to continuously develop and integrate AI/ ML models. It will mature and demonstrate hardware and software technologies, including cloud native applications and infrastructure for globally dispersed AI/ML development collaboration, artifact sharing, automated resource provisioning, and continuous ML Operations. The AI Development Environment will provide the AI-enabled Army of the future with low cost, rapid AI/ML solutions at the edge and accelerated algorithm development for faster delivery to the field.as well as less expensive AI/ML development by leveraging shared resources.These technologies will produce a software prototype deployed in a cloud environment to demonstrate ability to conduct distributed development of AI/ML solutions. Work in this project complements Program Element (PE) 0602180A (Artificial Intelligence and Machine Learning Advanced Technologies) / Project DE8 (AI Development Environment Applied Research). The cited work is consistent with Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the Artificial Intelligence Integration Center (AI2C).$$, 2777000, NULL, NULL, NULL, NULL, 1058000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603040A_DN3$$, $$0603040A$$, $$DN3$$, $$AI Enabled Contested Logistics Spt$$, 748000, $$This project provides AI-enabled contested logistics tools to warfighters for all platforms (legacy and future) at all echelons. This effort will improve data from systems of record and leverage additional data streams to provide a complete picture of logistics and sustainment operations in contested environments. This project will provide analysis of maintenance operations, asset visibility, and people personnel capacity to assess current and predict future unit readiness and reduce to logistics and sustainment decision making timelines in contested environments. These technologies will provide a suite of applications uniquely tailored to the end-user that demonstrates machine learning capabilities across the force with regards to contested logistics. Work in this Project complements Program Element (PE) 0603040A (Artificial Intelligence and Ma chine Learning Advanced Technologies) / Project CN6 (Predictive Maintenance Advanced Technology). The cited work is consistent with Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the Artificial Intelligence Integration Center (AI2C).$$, 748000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603041A_CM8$$, $$0603041A$$, $$CM8$$, $$Convergence Battlefield Integration$$, NULL, $$This Project integrates and demonstrates aided target detection and recognition, autonomous tactical behaviors, Artificial Intelligence (AI)-enabled decision support agent, and data management technologies in Multi-Domain Operations (MDO) field experiments. This Project integrates these technologies on tactical ground, air, air and missile defense, fires, network platforms and other missions to demonstrate reduced sensor to shooter timelines and evaluate operational performance in representative MDO scenarios during annual field experiments. Work in this Project complements Program Element (PE) 0602181A (All Domain Convergence Applied Research). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy.$$, NULL, NULL, NULL, NULL, NULL, 1011000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603042A_CX7$$, $$0603042A$$, $$CX7$$, $$Intelligent Env Battlefield Awareness$$, 7448000, $$This Project optimizes and demonstrates technologies to allow Soldiers to maneuver faster around or through existing environmental (urban/industrial) conditions and physical landscape constraints. This effort matures and demonstrates web modules/software tools delivering advanced knowledge of geo-environmental infrastructure to mission planners. This Project delivers critical technologies that provide situational awareness for multi-source intelligence, particularly for anti-access/area denial (A2/ AD) outside the continental United States (OCONUS) sites. Work in this Project complements Program Element (PE) 0602182A (C3I Applied Research) / Project CX3 (Intelligent Env Battlefield Awareness Apl Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the United States Army Engineer Research and Development Center Environmental Laboratory, Geospatial Research Laboratory, Information Technology Laboratory, Cold Regions Research and Engineering Laboratory, Construction Research Engineering Laboratory, and Geotechnical and Structures Laboratory.$$, 7448000, NULL, NULL, NULL, NULL, 6162000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603042A_CX8$$, $$0603042A$$, $$CX8$$, $$Persistent Geophysical Sensing-$$, 1951000, $$This Project matures and demonstrates kitted hardware and software solutions that provide passive, persistent, non-line-of-sight, multi-modal sensing capable of providing fused battlefield intelligence for increased situational awareness in a dynamic operational environment. These technologies provide near-real-time data collection, processing, and alerting on evolving cross-domain threats including strategic and tactical fires, air and ground platforms, as well as critical transportation infrastructure (bridges) and explosive events with applications for deep sensing. These technologies deliver time-critical intelligence for engineer and intelligence communities to provide decisive advantage. Work in this Project complements Program Element (PE) 0602182A (C3I Applied Research) / Project CX4 (Persistent Geophysical Sensing-Infrasound Apl Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed at the United States Army Engineer Research and Development Center Geotechnical and Structures Laboratory, Coastal and Hydraulics Laboratory, Construction Engineering Research Laboratory, Cold Regions Research and Engineering Laboratory, Environmental Laboratory, and Information Technology Laboratory.$$, 1951000, NULL, NULL, NULL, NULL, 2539000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603042A_CX9$$, $$0603042A$$, $$CX9$$, $$Sensing in Contested Environments$$, NULL, $$This Project matures and demonstrates advanced sensor technologies that characterize hazards posed to warfighters by non-weaponized biological hazards in subterranean environments. Demonstrations of previously developed sensor packages and adaptive commercial off the shelf sensor technologies on existing unmanned ground vehicles (UGV) platforms to gather end-user feedback. The capabilities resulting from this project provide Soldiers the capability to understand biological hazards present in subterranean environments and take necessary steps to mitigate or avoid these threats. Work in this Project complements Program Element (PE) 0602182A (C3I Applied Research) / Project CX5 (Sensing in Contested Environments Technologies). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed at the United States Army Engineer Research and Development Center Environmental Laboratory.$$, NULL, NULL, NULL, NULL, NULL, 1064000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603042A_CZ5$$, $$0603042A$$, $$CZ5$$, $$Subterranean Detection and$$, 1819000, $$This Project validates and demonstrates advanced subterranean monitoring and vulnerability assessment technologies providing mobile and man-portable solutions to enhance survivability and threat awareness during urban operations and negate enemy subterranean operation advantage. This Project also optimizes and demonstrates enhanced technologies to detect tunnels and tunneling activity in complex and varied environments. These capabilities are critical to provide greater situational awareness of the subterranean domain and enhanced survivability for the Soldier. Work in this Project complements Program Element (PE) 0602182A (C3I Applied Research) / Project CX6 (Subterranean Detection and Monitoring Apl Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the United States Army Engineer Research and Development Center Geotechnical and Structures Laboratory, Construction Engineering Research Laboratory, Coastal and Hydraulics Laboratory and Cold Regions Research and Engineering Laboratory.$$, 1819000, NULL, NULL, NULL, NULL, 1226000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603042A_DB5$$, $$0603042A$$, $$DB5$$, $$Enabling Long Standoff 3D (ELS3D)$$, 2586000, $$This Project will integrate and demonstrate and mature a low size, weight, and power (SWAP) laser transmitter, processing algorithms and calibration models tailored for higher resolution 3D data collections over larger areas from longer stand-off for mapping, Intelligence Surveillance and Reconnaissance (ISR) and targeting. Long standoff airborne collection of high-resolution quick turnaround 3D data is vital for mission planning, target detection and identification, fire control, autonomous navigation, kinetic targeting, and battle damage assessment. Existing light detection and ranging (LIDAR) systems are limited to short standoff and/or near-nadir collection, limiting their use against near-peer adversaries and restricting the provision of 3D data. The payoff will enable long standoff airborne collection of high- resolution quick turnaround 3D data through the development LIDAR subsystems and processing algorithms. Work in this Project complements Program Element (PE) 0602182A (C3I Applied Research) / Project DB4 (Enabling Long Standoff 3D (ELS3D) Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the United States Army Engineer Research and Development Center Geospatial Research Laboratory.$$, 2586000, NULL, NULL, NULL, NULL, 1007000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603042A_DE7$$, $$0603042A$$, $$DE7$$, $$Understanding Environment as a$$, NULL, $$This Project matures and demonstrates tools that provide capability to inform the Solider of different routes through a complex urban landscape. Optimizes tools that balance exposure to environmental threats with mission constraints to provide a risk versus reward capability of operating in different areas of the urban theater. This Project matures and demonstrates predictive software accurately integrating the risks of physical, chemical, and biological threats in an urban environment into route planning tools. Work in this Project complements Program Element (PE) 0602182A (C3I Applied Technology) / Project DE6 (Understanding the Environment as a Threat Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the United States Army Engineer Research and Development Center Environmental Laboratory, Geospatial Research Laboratory, and Information Technology Laboratory.$$, NULL, NULL, NULL, NULL, NULL, 2708000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603043A_CL4$$, $$0603043A$$, $$CL4$$, $$Air Platform Enabling University Adv$$, NULL, $$This Project focuses on experimentation and demonstration of advanced technologies originating from extramural applied research in academia pertaining to navigation/ routing, autonomous robotic vehicles, artificial intelligence and machine learning as applied to aerial mobility and maneuver, holistic survivability, teaming, integrated mission systems, air-launched effects, and other innovative air enabling applied research technologies, that will accelerate the Army modernization in next generation aerial vehicles. This Project will mature and integrate advanced efforts to focus more on mid to far-term Army modernization priorities while also maintaining delivery of near-term technologies fundamental to the modernization priorities. This effort conducts and demonstrates advanced technology efforts arising from academic research in all areas of strategic importance to Army Aviation in artificial intelligence / machine learning (AI/ML), autonomous teaming systems, survivability, aeromechanics, advanced vertical take-off and landing (VTOL) design & concepts, flight dynamics, vibration & noise control, propulsion, human factor engineering and structures and materials, etc., by bringing competitively selected Universities with research and development teams into Technical Alliances. The Project will continuously experiment with methods to identify, demonstrate and transition novel technology from entities that might not otherwise collaborate with the Department of Defense (DoD), with the end goal of accelerating the adoption of cutting-edge applied research technology for the warfighter in the Army aviation portfolio. Work in this Project complements Program Element (PE) 0603465A (Future Vertical Lift Advanced Technology), PE 0603119A (Ground Advanced Technology), PE 0602148A (Future Vertical Lift Technology) and PE 0602183A (Air Platform Applied Research). The work cited is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Army Research Laboratory (ARL).$$, NULL, NULL, NULL, NULL, NULL, 1317000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603043A_CV1$$, $$0603043A$$, $$CV1$$, $$Control & Autonomy for Tactical$$, 10271000, $$This Project will deliver advanced flight controls, autonomy technologies, and new handling qualities criteria are implemented and tested in a realistic environment to demonstrate their functionality and increase their technology readiness level (TRL). This Project also delivers demonstrated and matured flight controls and autonomy technologies at TRL 6 to transition partners. Work in this Project complements Program Element (PE) 0602183A (Air Platform Applied Technology) / Project CU7 (Control & Autonomy for Tactical Superiority Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Aviation & Missile Center (AvMC).$$, 10271000, NULL, NULL, NULL, NULL, 1208000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603043A_CV2$$, $$0603043A$$, $$CV2$$, $$Structures Platform Int Resilience &$$, 6520000, $$This Project will ensure a continuous stream of transition-ready critical structures advanced technologies for improvement of performance (via weight efficiency and multifunctionality for parasitic weight avoidance) and resilience (survivability, sustainment, and operational availability). Work in this Project is fully coordinated with Program element (PE) 0602183A (Air Platform Applied Technology) / Project CU8 (Structures Tech for Enduring Efficient Resilience). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Aviation & Missile Center (AvMC).$$, 6520000, NULL, NULL, NULL, NULL, 3236000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603043A_CX1$$, $$0603043A$$, $$CX1$$, $$Advanced Rotors Advanced Tech$$, 7463000, $$This Project investigates Future Vertical Lift (FVL) and other Army and Department of Defense (DoD) advanced drive train technologies that increase performance and double current drivetrain life cycles while improving their reliability and maintainability. Work in this Project is fully coordinated with PE 0602183A (Air Platform Applied Technology) / Project CW3 (Advanced Rotors Applied Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Aviation & Missile Center (AvMC).$$, 7463000, NULL, NULL, NULL, NULL, 2560000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603043A_DC3$$, $$0603043A$$, $$DC3$$, $$HPC For Army Aviation Concepts$$, 7234000, $$This Project matures and demonstrates the use of high-fidelity computational fluid dynamics for Future Vertical Lift (FVL) platforms through the utilization of Department of Defense (DoD) High- Performance Computing (HPC) and software tools for cutting-edge modeling and simulation, as well as adding software capabilities for workflow automation and design space exploration. Efforts in this Project are also applicable to the family of FVL and Future Tactical Unmanned Aircraft System (FTUAS) platforms. Work in this Project complements PE 0602183A (Air Platform Applied Research). The work cited is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology focus areas and the Army Modernization Strategy. Work in this Project is performed by the United States Army Engineer Research and Development Center Information Technology Laboratory.$$, 7234000, NULL, NULL, NULL, NULL, 5327000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603043A_DK2$$, $$0603043A$$, $$DK2$$, $$Air Vehicle Improvement & Adv Tech$$, 9778000, $$This project enhances Army aviation mission capability and address operational energy and environmental challenges. Includes the maturation, system integration, and demonstration of technologies including advanced engines, hybrid and electric systems, power and control allocation, propulsive power delivery, electric actuation, structures, and other technologies that enhance performance, efficiency or are critical to implementation up to the aircraft system level. Work in this Project complements Program Element (PE) 0602183A (Air Platform Applied Technology) / Project DK1 (Air Vehicle Integrated & Alternative Tech (AVIATe)). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Aviation & Missile Center (AvMC).$$, 9778000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
